# SQL clause to identify/hide Microsoft first-party identities.
# The is_microsoft_system flag is the single source of truth, set by:
#   - Discovery engine: _is_microsoft_system_app() uses appOwnerOrganizationId
#   - Database backfill: sets flag based on naming conventions for old data
# No LIKE patterns needed at query time — the flag is authoritative.
IS_MICROSOFT_SQL = "COALESCE(i.is_microsoft_system, false)"

# HIDE_MICROSOFT_SQL: AND NOT clause to exclude Microsoft first-party identities
HIDE_MICROSOFT_SQL = "\n    AND NOT COALESCE(i.is_microsoft_system, false)\n"

# HIDE_DELETED_SQL: AND clause to exclude soft-deleted identities by default
HIDE_DELETED_SQL = "\n    AND i.deleted_at IS NULL\n"

# ACTIVATED_SUB_FILTER_SQL: restricts identities to those relevant to the org's
# activated subscriptions.  Three-way OR:
#   (A) has RBAC access to at least one monitored subscription
#   (B) Entra-only — has no subscription-scope roles in *any* of the org's
#       discovered subs (pure directory objects like guests, app regs, etc.)
#   (C) managed identity whose parent resource lives in a monitored sub
# Requires three %s parameters: mon_sub_ids (list), org_id (int), mon_sub_ids (list).
ACTIVATED_SUB_FILTER_SQL = """
    AND (
        EXISTS (
            SELECT 1 FROM identity_subscription_access isa_m
            WHERE isa_m.identity_db_id = i.id
              AND isa_m.subscription_id = ANY(%s)
        )
        OR NOT EXISTS (
            SELECT 1 FROM identity_subscription_access isa_n
            JOIN cloud_subscriptions cs_n ON isa_n.subscription_id = cs_n.account_id
            WHERE isa_n.identity_db_id = i.id
              AND cs_n.organization_id = %s
              AND cs_n.deleted = false
        )
        OR (i.associated_subscription_id IS NOT NULL
            AND i.associated_subscription_id = ANY(%s))
    )
"""


def _scalar(cursor, default=None):
    """Safe fetchone-then-index-zero helper.
    Returns default if no rows or value is None.
    Prevents TypeError crashes on empty result sets.
    """
    row = cursor.fetchone()
    if row is None:
        return default
    val = row[0] if isinstance(row, (tuple, list)) \
          else next(iter(row.values()), None)
    return val if val is not None else default


def _get_pillar_filter_sql(pillar: str) -> str:
    """Return SQL AND clause matching the attack-surface-score engine's
    pillar counting logic.  This ensures ?contributing_pillar=X returns
    the EXACT identities the engine counted for each pillar."""
    PILLAR_SQL = {
        # Matches the engine's t0t1_count FILTER exactly (lines 2955-2965):
        # T1 Entra roles + Owner/Contributor/UAA RBAC at any scope
        "effective_privilege": """
            AND (
                EXISTS (SELECT 1 FROM entra_role_assignments era WHERE era.identity_db_id = i.id
                    AND LOWER(era.role_name) IN (
                        'user administrator','exchange administrator',
                        'sharepoint administrator','teams administrator',
                        'security administrator','conditional access administrator',
                        'authentication administrator','helpdesk administrator'
                    ))
                OR EXISTS (SELECT 1 FROM role_assignments ra WHERE ra.identity_db_id = i.id
                    AND LOWER(ra.role_name) IN ('owner','contributor','user access administrator'))
            )""",
        "credential_risk": CredentialRiskSQL.NHI_CREDENTIAL_RISK_FILTER,
        "trust_federation": """
            AND COALESCE(i.identity_category, '') = 'guest'
            AND (
                EXISTS (SELECT 1 FROM entra_role_assignments era WHERE era.identity_db_id = i.id)
                OR EXISTS (SELECT 1 FROM role_assignments ra WHERE ra.identity_db_id = i.id)
            )""",
        "usage_dormancy": """
            AND i.activity_status IN ('stale', 'never_used')
            AND NOT (i.activity_status = 'never_used' AND i.federated_workload_type IS NOT NULL)""",
        "ownership_governance": """
            AND i.recommended_action = 'ORPHANED'
            AND i.deleted_at IS NULL
            AND COALESCE(i.is_microsoft_system, FALSE) = FALSE""",
        "external_exposure": """
            AND (
                EXISTS (SELECT 1 FROM entra_role_assignments era WHERE era.identity_db_id = i.id
                    AND (era.directory_scope IS NULL OR era.directory_scope = '/'))
                OR EXISTS (SELECT 1 FROM role_assignments ra WHERE ra.identity_db_id = i.id
                    AND ra.scope_type = 'tenant')
            )""",
    }
    # Normalize hyphens to underscores (frontend sends e.g. "effective-privilege")
    return PILLAR_SQL.get(pillar, "") or PILLAR_SQL.get(pillar.replace("-", "_"), "")


def _get_agirs_factor_sql(factor: str) -> str:
    """Return SQL AND clause that replicates the EXACT counting logic from
    agirs_engine.py for each HIRI/NHIRI sub-metric.  This ensures the
    drill-down count matches the AGIRS dashboard number precisely."""
    AGIRS_SQL = {
        # HIRI — H1: Ghost humans (disabled/deleted but still has roles)
        "h1_ghost": """
            AND i.identity_category IN ('human_user', 'guest')
            AND (i.enabled = FALSE OR i.deleted_at IS NOT NULL OR i.status IN ('disabled', 'deleted'))
            AND (
                EXISTS (SELECT 1 FROM role_assignments ra WHERE ra.identity_db_id = i.id)
                OR EXISTS (SELECT 1 FROM entra_role_assignments era WHERE era.identity_db_id = i.id)
            )""",
        # HIRI — H2: Dormant privileged (stale + has T0/T1/T2 role)
        "h2_dormant_priv": """
            AND i.identity_category IN ('human_user', 'guest')
            AND i.activity_status IN ('stale', 'never_used')
            AND (
                EXISTS (SELECT 1 FROM entra_role_assignments era WHERE era.identity_db_id = i.id)
                OR EXISTS (SELECT 1 FROM role_assignments ra WHERE ra.identity_db_id = i.id
                    AND LOWER(ra.role_name) IN ('owner', 'contributor', 'user access administrator'))
            )""",
        # HIRI — H3: Over-privileged (risk_score >= 70 OR tier = 'T0')
        "h3_over_priv": """
            AND i.identity_category IN ('human_user', 'guest')
            AND (COALESCE(i.risk_score, 0) >= 70 OR i.privilege_tier = 'T0')""",
        # HIRI — H4: External guests with privileged roles
        "h4_ext_guest": """
            AND i.identity_category = 'guest'
            AND (
                EXISTS (SELECT 1 FROM entra_role_assignments era WHERE era.identity_db_id = i.id)
                OR EXISTS (SELECT 1 FROM role_assignments ra WHERE ra.identity_db_id = i.id
                    AND LOWER(ra.role_name) IN ('owner', 'contributor', 'user access administrator'))
            )""",
        # NHIRI — N1: Orphaned NHI (no owner)
        "n1_orphaned": """
            AND i.identity_category IN ('service_principal', 'managed_identity_system', 'managed_identity_user')
            AND COALESCE(i.is_microsoft_system, FALSE) = FALSE
            AND NOT EXISTS (SELECT 1 FROM spn_owners so WHERE so.identity_db_id = i.id)""",
        # NHIRI — N2: Dormant NHI (inactive + has roles)
        "n2_dormant": """
            AND i.identity_category IN ('service_principal', 'managed_identity_system', 'managed_identity_user')
            AND COALESCE(i.is_microsoft_system, FALSE) = FALSE
            AND i.activity_status IN ('stale', 'never_used', 'inactive')
            AND NOT (i.activity_status = 'never_used' AND i.federated_workload_type IS NOT NULL)
            AND (
                EXISTS (SELECT 1 FROM role_assignments ra WHERE ra.identity_db_id = i.id)
                OR EXISTS (SELECT 1 FROM entra_role_assignments era WHERE era.identity_db_id = i.id)
            )""",
        # NHIRI — N3: Zombie NHI (stale + high risk + valid creds)
        "n3_zombie": """
            AND i.identity_category IN ('service_principal', 'managed_identity_system', 'managed_identity_user')
            AND COALESCE(i.is_microsoft_system, FALSE) = FALSE
            AND i.activity_status IN ('stale', 'never_used')
            AND NOT (i.activity_status = 'never_used' AND i.federated_workload_type IS NOT NULL)
            AND COALESCE(i.risk_score, 0) >= 70
            AND i.credential_count > 0
            AND (i.credential_expiration IS NULL OR i.credential_expiration > NOW())""",
        # NHIRI — N4: Expired/expiring credentials
        "n4_expired": """
            AND i.identity_category IN ('service_principal', 'managed_identity_system', 'managed_identity_user')
            AND COALESCE(i.is_microsoft_system, FALSE) = FALSE
            AND i.credential_count > 0
            AND i.credential_expiration IS NOT NULL
            AND i.credential_expiration < NOW() + INTERVAL '30 days'""",
    }
    return AGIRS_SQL.get(factor, "")


def _is_demo() -> bool:
    """Check if the current user belongs to a demo tenant."""
    user = getattr(g, 'current_user', None)
    return bool(user and user.get('is_demo'))


def _demo_write_guard():
    """Return a 403 response tuple if the current tenant is a demo tenant.

    Call at the top of any mutation handler (POST/PATCH/DELETE) that should
    be blocked in demo mode.  Returns None if the request is allowed.
    """
    if _is_demo():
        return jsonify({'error': 'Demo tenant is read-only.'}), 403
    return None


def _db() -> Database:
    """Create a Database connection with RLS organization context from JWT.

    - Normal org user (tid=5): sets context, RLS filters to org 5
    - Sentinel (tid=-1): sets context, RLS matches nothing (safe)
    - Superadmin (tid=None): no context set, RLS NULL bypass → all rows
    """
    tid = _org_id()
    return Database(organization_id=tid)


def _safe_handler(fn, fallback_response):
    """Wrap an optional handler so missing tables / broken methods return
    *fallback_response* as 200 JSON instead of crashing with 500."""
    try:
        return fn()
    except Exception as exc:
        logger.warning("Optional handler %s failed: %s", fn.__name__, exc)
        return jsonify(fallback_response)


def _org_id():
    """Get organization_id from current authenticated user context.

    Returns:
        int: The user's organization_id if assigned.
        -1:  Sentinel for non-superadmin users without an org (matches nothing in DB).
        None: Only for superadmins without an org override (permits unscoped queries).
    """
    user = getattr(g, 'current_user', None)
    if not user:
        return -1  # No auth context — return sentinel, never allow unscoped
    tid = user.get('organization_id')
    if tid:
        return tid
    # User has no organization_id assigned
    if user.get('is_superadmin'):
        return None  # Superadmins intentionally see all data
    # Non-superadmin with no org — sentinel prevents cross-org leakage
    return -1


def _tenant_id():
    """Alias for _org_id(). Do not add new calls — use _org_id() instead."""
    return _org_id()


def _current_user_id():
    """Get the authenticated user's ID (never overridden)."""
    user = getattr(g, 'current_user', None)
    return user.get('id') if user else None


def _log(db, action_type, description, metadata=None):
    """Log activity with auto-injected user/org context.

    Safe: catches DB errors and rolls back to prevent transaction poisoning.
    Logging should never crash the request.
    """
    try:
        user = getattr(g, 'current_user', None)
        uid = user.get('id') if user else None
        tid = user.get('organization_id') if user else None
        db.log_activity(action_type, description, metadata, user_id=uid, organization_id=tid)
    except Exception as e:
        try: db.conn.rollback()
        except Exception: pass
        logger.debug("_log failed (%s): %s", action_type, e)


def _log_ai_audit(db, query_type, input_payload, output_payload,
                  identity_id=None, duration_ms=0):
    """Log an AI audit entry with auto-injected org/user/model context."""
    try:
        user = getattr(g, 'current_user', None)
        uid = user.get('id') if user else None
        org_id = user.get('organization_id') if user else None
        # Model version from copilot_service
        import os
        model_version = os.getenv('LLM_MODEL', 'claude-sonnet-4-5-20250514')
        # Confidence heuristic
        if output_payload is None:
            confidence = None
        elif isinstance(output_payload, dict):
            confidence = 1.0
        elif isinstance(output_payload, str) and output_payload:
            confidence = 0.9
            # Truncate large string outputs
            if len(output_payload) > 50000:
                output_payload = output_payload[:50000] + '...[truncated]'
            output_payload = {'response': output_payload}
        else:
            confidence = None
        db.log_ai_audit(
            organization_id=org_id,
            user_id=uid,
            identity_id=identity_id,
            query_type=query_type,
            model_version=model_version,
            input_payload=input_payload,
            output_payload=output_payload,
            confidence_score=confidence,
            duration_ms=duration_ms,
        )
    except Exception as e:
        try: db.conn.rollback()
        except Exception: pass
        logger.warning(f"AI audit log failed: {e}")


def get_ai_audit_log_handler():
    """GET /api/ai/audit-log — admin-only AI audit log retrieval."""
    db = _db()
    try:
        limit = _safe_query_int('limit', 50, 200)
        offset = _safe_query_int('offset', 0)
        query_type = request.args.get('query_type')
        identity_id = request.args.get('identity_id')
        user_id = request.args.get('user_id')
        entries = db.get_ai_audit_log(
            limit=limit, offset=offset, query_type=query_type,
            identity_id=identity_id, user_id=user_id,
        )
        return jsonify({'entries': entries, 'limit': limit, 'offset': offset})
    finally:
        db.close()


def _get_org_plan(db, org_id):
    """Fetch the billing plan tier for an organization. Returns 'free' as default."""
    if not org_id or org_id == -1:
        return 'free'
    try:
        cursor = db.conn.cursor()
        cursor.execute("SELECT plan FROM tenants WHERE id = %s", (org_id,))
        row = cursor.fetchone()
        cursor.close()
        return (row[0] if row and row[0] else 'free')
    except Exception:
        try: db.conn.rollback()
        except Exception: pass
        return 'free'


def _connection_id():
    """Read optional connection_id from query string."""
    val = request.args.get('connection_id')
    return int(val) if val else None


def _active_subscription_ids(cursor, org_id, connection_id=None):
    """Return subscription IDs that are activated (monitored=true) for the given org/connection.

    Used to gate resource endpoints (Key Vaults, Storage, Resources) to only show data
    from subscriptions the customer has paid for. Identity data is tenant-scoped
    (Entra ID level) and should NOT be filtered by this function.

    Returns:
        tuple: (active_ids: list[str], total_count: int, active_count: int)
    """
    try:
        if connection_id:
            cursor.execute("""
                SELECT account_id, monitored FROM cloud_subscriptions
                WHERE organization_id = %s AND cloud_connection_id = %s AND deleted = false
            """, (org_id, connection_id))
        else:
            cursor.execute("""
                SELECT account_id, monitored FROM cloud_subscriptions
                WHERE organization_id = %s AND deleted = false
            """, (org_id,))
        rows = cursor.fetchall()
        all_ids = []
        active_ids = []
        for r in rows:
            aid = r[0] if not isinstance(r, dict) else r.get('account_id')
            mon = r[1] if not isinstance(r, dict) else r.get('monitored')
            all_ids.append(aid)
            if mon:
                active_ids.append(aid)
        return active_ids, len(all_ids), len(active_ids)
    except Exception:
        try: cursor.connection.rollback()
        except Exception: pass
        return [], 0, 0


def _monitored_sub_ids(cursor, org_id, connection_id=None):
    """Return list of activated (monitored) subscription account_ids for the org/connection."""
    try:
        if connection_id:
            cursor.execute("""
                SELECT account_id FROM cloud_subscriptions
                WHERE organization_id = %s AND cloud_connection_id = %s
                  AND monitored = true AND deleted = false
            """, (org_id, connection_id))
        else:
            cursor.execute("""
                SELECT account_id FROM cloud_subscriptions
                WHERE organization_id = %s AND monitored = true AND deleted = false
            """, (org_id,))
        return [r[0] if not isinstance(r, dict) else r['account_id'] for r in cursor.fetchall()]
    except Exception:
        try: cursor.connection.rollback()
        except Exception: pass
        return []


def _apply_sub_filter(query, params, cursor, org_id, connection_id=None):
    """Append activated-subscription filter to an identity query. Returns (query, params)."""
    mon_subs = _monitored_sub_ids(cursor, org_id, connection_id)
    if mon_subs:
        query += ACTIVATED_SUB_FILTER_SQL
        params.extend([mon_subs, org_id, mon_subs])
    # If no monitored subs exist at all (new org, no activations), don't filter
    # — this preserves backward compat for orgs that haven't activated anything yet.
    return query, params


def _resolve_identity_id(cursor, identity_id: str, run_ids: list) -> str:
    """Resolve an identity param to UUID identity_id.

    Accepts either a UUID string (returned as-is) or a numeric DB id
    (looked up in the identities table). This allows frontend links that
    use the numeric DB id (e.g. from dangerous_identities) to work.
    """
    try:
        db_id = int(identity_id)
    except (ValueError, TypeError):
        return identity_id  # already a UUID
    cursor.execute(
        "SELECT identity_id FROM identities WHERE id = %s AND discovery_run_id = ANY(%s) LIMIT 1",
        (db_id, run_ids),
    )
    row = cursor.fetchone()
    if row:
        return row[0] if isinstance(row, (tuple, list)) else row.get('identity_id', identity_id)
    return identity_id  # fallback — let the main query 404 naturally


def _latest_run_ids(cursor, organization_id=None, connection_id=None):
    """Get latest completed discovery run IDs — one per ACTIVE cloud_connection_id.

    Returns a list of run_ids. Only includes runs whose cloud_connection_id
    still exists in the cloud_connections table (i.e. not deleted).
    When connection_id is specified, returns only the latest run for that
    specific connection.
    """
    def _extract_id(row):
        """Extract id from a row that may be a dict (RealDictCursor) or tuple."""
        if isinstance(row, dict):
            return row.get('id') or row.get('max')
        return row[0]

    if connection_id and str(connection_id) != 'all':
        # Case 1: Single connection — latest run for this connection
        cursor.execute("""
            SELECT MAX(id) AS id FROM discovery_runs
            WHERE status IN ('completed', 'partial') AND organization_id = %s AND cloud_connection_id = %s
        """, (organization_id, connection_id))
        row = cursor.fetchone()
        run_id = _extract_id(row) if row else None
        return [run_id] if run_id else []

    if organization_id is not None:
        # Case 2: All connections — latest run PER connection across org
        # DISTINCT ON gets one row per connection_id (the most recent)
        # Only include runs from connections with status='connected' (active).
        cursor.execute("""
            SELECT DISTINCT ON (dr.cloud_connection_id)
                dr.id
            FROM discovery_runs dr
            JOIN cloud_connections cc ON cc.id = dr.cloud_connection_id
            WHERE dr.status IN ('completed', 'partial') AND dr.organization_id = %s
              AND dr.cloud_connection_id IS NOT NULL AND dr.cloud_connection_id > 0
              AND cc.status = 'connected'
            ORDER BY dr.cloud_connection_id, dr.id DESC
        """, (organization_id,))
        rows = cursor.fetchall()
        return [_extract_id(r) for r in rows]

    user = getattr(g, 'current_user', None)
    if not user or not user.get('is_superadmin'):
        return []
    # Only include runs whose cloud_connection_id still exists and is active
    cursor.execute("""
        SELECT DISTINCT ON (dr.cloud_connection_id)
            dr.id
        FROM discovery_runs dr
        JOIN cloud_connections cc ON cc.id = dr.cloud_connection_id
        WHERE dr.status IN ('completed', 'partial')
          AND dr.cloud_connection_id IS NOT NULL AND dr.cloud_connection_id > 0
          AND cc.status = 'connected'
        ORDER BY dr.cloud_connection_id, dr.id DESC
    """)

    rows = cursor.fetchall()
    return [_extract_id(r) for r in rows]


def _previous_run_ids(cursor, organization_id=None, connection_id=None):
    """Get PREVIOUS completed discovery run IDs — second-most-recent per connection."""
    latest_ids = _latest_run_ids(cursor, organization_id, connection_id)
    if not latest_ids:
        return []

    def _extract_id(row):
        if isinstance(row, dict):
            return row.get('id') or row.get('max')
        return row[0]

    if connection_id:
        cursor.execute("""
            SELECT MAX(id) AS id FROM discovery_runs
            WHERE status = 'completed' AND organization_id = %s AND cloud_connection_id = %s
              AND id != ALL(%s)
        """, (organization_id, connection_id, latest_ids))
        row = cursor.fetchone()
        run_id = _extract_id(row) if row else None
        return [run_id] if run_id else []

    if organization_id is not None:
        cursor.execute("""
            SELECT DISTINCT ON (dr.cloud_connection_id) dr.id
            FROM discovery_runs dr
            JOIN cloud_connections cc ON cc.id = dr.cloud_connection_id
            WHERE dr.status = 'completed' AND dr.organization_id = %s
              AND dr.cloud_connection_id IS NOT NULL AND dr.cloud_connection_id > 0
              AND dr.id != ALL(%s)
            ORDER BY dr.cloud_connection_id, dr.id DESC
        """, (organization_id, latest_ids))
        rows = cursor.fetchall()
        return [_extract_id(r) for r in rows]

    return []


def _latest_run_query(cursor, organization_id=None, connection_id=None):
    """Backward-compat wrapper — returns single run_id or None."""
    ids = _latest_run_ids(cursor, organization_id, connection_id)
    return ids[0] if ids else None


def _parse_risk_reasons(value):
    if value is None:
        return []
    if isinstance(value, list):
        return value
    if isinstance(value, str):
        try:
            parsed = json.loads(value)
            if isinstance(parsed, list):
                return parsed
        except Exception:
            pass
        return [value]
    return []


def health_check():
    return jsonify(
        {
            "service": "AuditGraph API",
            "status": "healthy",
            "timestamp": datetime.now(timezone.utc).isoformat(),
        }
    )


def get_stats():
    """
    Dashboard summary statistics — aggregated across all connections (same as other endpoints).
    """
    db = _db()
    cursor = db.conn.cursor()

    try:
        tid = _org_id()

        if tid:
            cursor.execute("SELECT COUNT(*) FROM discovery_runs WHERE organization_id = %s", (tid,))
        else:
            cursor.execute("SELECT COUNT(*) FROM discovery_runs")
        total_runs = _scalar(cursor, 0)

        run_ids = _latest_run_ids(cursor, tid, _connection_id())
        if not run_ids:
            return jsonify({"latest_run": None, "total_discovery_runs": total_runs})

        # Most recent completed_at across selected runs
        cursor.execute("""
            SELECT MAX(completed_at) FROM discovery_runs WHERE id = ANY(%s)
        """, (run_ids,))
        completed_at = _scalar(cursor)

        # Activated-subscription filter for identity counts
        mon_subs = _monitored_sub_ids(cursor, tid, _connection_id())
        sub_filter_sql = ACTIVATED_SUB_FILTER_SQL if mon_subs else ""

        # Live-count excluding Microsoft first-party SPNs (across all connection runs)
        stats_sql = f"""
            SELECT COUNT(*),
                   SUM(CASE WHEN i.risk_level = 'critical' THEN 1 ELSE 0 END),
                   SUM(CASE WHEN i.risk_level = 'high' THEN 1 ELSE 0 END),
                   SUM(CASE WHEN i.risk_level = 'medium' THEN 1 ELSE 0 END)
            FROM identities i
            WHERE i.discovery_run_id = ANY(%s)
            {HIDE_MICROSOFT_SQL}
            {sub_filter_sql}
        """
        stats_params = [run_ids] + ([mon_subs, tid, mon_subs] if mon_subs else [])
        cursor.execute(stats_sql, tuple(stats_params))
        filt = cursor.fetchone()

        latest = {
            "id": run_ids[0],
            "completed_at": completed_at.isoformat() if completed_at else None,
            "total_identities": filt[0] if filt else 0,
            "critical_count": filt[1] if filt else 0,
            "high_count": filt[2] if filt else 0,
            "medium_count": filt[3] if filt else 0,
        }

        # Previous run comparison — query second-most-recent completed runs
        prev_ids = _previous_run_ids(cursor, tid, _connection_id())
        previous_run = None
        if prev_ids:
            cursor.execute("""
                SELECT MAX(completed_at) FROM discovery_runs WHERE id = ANY(%s)
            """, (prev_ids,))
            prev_completed = _scalar(cursor)
            prev_sql = f"""
                SELECT COUNT(*),
                       SUM(CASE WHEN i.risk_level = 'critical' THEN 1 ELSE 0 END),
                       SUM(CASE WHEN i.risk_level = 'high' THEN 1 ELSE 0 END),
                       SUM(CASE WHEN i.risk_level = 'medium' THEN 1 ELSE 0 END),
                       ROUND(COALESCE(AVG(i.risk_score), 0), 1)
                FROM identities i
                WHERE i.discovery_run_id = ANY(%s)
                {HIDE_MICROSOFT_SQL}
                {sub_filter_sql}
            """
            prev_params = [prev_ids] + ([mon_subs, tid, mon_subs] if mon_subs else [])
            cursor.execute(prev_sql, tuple(prev_params))
            pf = cursor.fetchone()
            previous_run = {
                "id": prev_ids[0],
                "completed_at": prev_completed.isoformat() if prev_completed else None,
                "total_identities": pf[0] if pf else 0,
                "critical_count": pf[1] if pf else 0,
                "high_count": pf[2] if pf else 0,
                "medium_count": pf[3] if pf else 0,
                "avg_risk_score": float(pf[4]) if pf and pf[4] else 0,
            }

        # Workload exposure summary
        workload_exposure = None
        try:
            cats = ("service_principal", "managed_identity_system", "managed_identity_user")
            we_sql = f"""
                SELECT
                    COUNT(*) FILTER (WHERE NOT COALESCE(i.is_microsoft_system, false)) AS total,
                    COUNT(*) FILTER (WHERE COALESCE(i.exposure_score, 0) >= 80 AND NOT COALESCE(i.is_microsoft_system, false)) AS critical,
                    COUNT(*) FILTER (WHERE i.recommended_action = 'ORPHANED' AND i.deleted_at IS NULL AND NOT COALESCE(i.is_microsoft_system, false)) AS orphaned,
                    COUNT(*) FILTER (WHERE COALESCE(i.can_escalate, false) AND NOT COALESCE(i.is_microsoft_system, false)) AS can_escalate,
                    COUNT(*) FILTER (WHERE COALESCE(i.exposure_score, 0) >= 60 AND COALESCE(i.exposure_score, 0) < 80 AND NOT COALESCE(i.is_microsoft_system, false)) AS we_high,
                    COUNT(*) FILTER (WHERE COALESCE(i.exposure_score, 0) >= 35 AND COALESCE(i.exposure_score, 0) < 60 AND NOT COALESCE(i.is_microsoft_system, false)) AS we_medium,
                    COUNT(*) FILTER (WHERE COALESCE(i.exposure_score, 0) < 35 AND NOT COALESCE(i.is_microsoft_system, false)) AS we_low,
                    COUNT(*) FILTER (WHERE COALESCE(i.lifecycle_state, 'blind') = 'blind' AND NOT COALESCE(i.is_microsoft_system, false)) AS we_blind,
                    ROUND(COALESCE(AVG(i.exposure_score) FILTER (WHERE NOT COALESCE(i.is_microsoft_system, false)), 0), 1) AS we_avg
                FROM identities i
                WHERE i.discovery_run_id = ANY(%s)
                  AND i.identity_category IN %s
                {sub_filter_sql}
            """
            we_params = [run_ids, cats] + ([mon_subs, tid, mon_subs] if mon_subs else [])
            cursor.execute(we_sql, tuple(we_params))
            we_row = cursor.fetchone()
            anomalies_unresolved = 0
            try:
                cursor.execute("""
                    SELECT COUNT(*) FROM workload_anomaly_events
                    WHERE discovery_run_id = ANY(%s) AND NOT resolved
                """, (run_ids,))
                anomalies_unresolved = _scalar(cursor, 0)
            except Exception:
                try: db.conn.rollback()
                except Exception: pass
            workload_exposure = {
                'total': we_row[0] or 0,
                'critical': we_row[1] or 0,
                'orphaned': we_row[2] or 0,
                'can_escalate': we_row[3] or 0,
                'anomalies_unresolved': anomalies_unresolved,
                'exposure_distribution': {
                    'critical': we_row[1] or 0,
                    'high': we_row[4] or 0,
                    'medium': we_row[5] or 0,
                    'low': we_row[6] or 0,
                },
                'blind_count': we_row[7] or 0,
                'avg_exposure_score': float(we_row[8] or 0),
            }
        except Exception:
            try: db.conn.rollback()
            except Exception: pass

        # Ghost identities: read from persisted risk_summary (canonical SSOT)
        ghost_count = 0
        try:
            rs = db.get_latest_risk_summary(tid)
            if rs:
                ghost_count = rs.get('ghost_accounts', 0)
        except Exception:
            try: db.conn.rollback()
            except Exception: pass

        # Disabled/deleted counts (regardless of role assignments)
        disabled_count = 0
        deleted_count = 0
        try:
            cursor.execute("""
                SELECT
                    COUNT(*) FILTER (WHERE i.enabled = false AND i.deleted_at IS NULL) AS disabled,
                    COUNT(*) FILTER (WHERE i.deleted_at IS NOT NULL) AS deleted
                FROM identities i
                WHERE i.discovery_run_id = ANY(%s)
            """, (run_ids,))
            row = cursor.fetchone()
            disabled_count = row[0] or 0
            deleted_count = row[1] or 0
        except Exception:
            try: db.conn.rollback()
            except Exception: pass

        # Zombie personas: disabled account with correlated active account
        zombie_count = 0
        try:
            cursor.execute("""
                SELECT COUNT(DISTINCT hi.id)
                FROM human_identities hi
                JOIN identity_links il1 ON il1.human_identity_id = hi.id
                JOIN identity_links il2 ON il2.human_identity_id = hi.id
                    AND il2.identity_db_id != il1.identity_db_id
                JOIN identities i1 ON i1.id = il1.identity_db_id
                JOIN identities i2 ON i2.id = il2.identity_db_id
                WHERE (i1.enabled = FALSE OR i1.deleted_at IS NOT NULL)
                  AND i2.enabled = TRUE AND i2.deleted_at IS NULL
            """)
            zombie_count = _scalar(cursor, 0)
        except Exception:
            try: db.conn.rollback()
            except Exception: pass

        # New/removed identity counts from latest drift report
        new_identities_count = 0
        removed_identities_count = 0
        try:
            cursor.execute("""
                SELECT
                    COALESCE(jsonb_array_length(changes->'new_identities'), 0),
                    COALESCE(jsonb_array_length(changes->'removed_identities'), 0)
                FROM drift_reports
                WHERE current_run_id = ANY(%s)
                ORDER BY created_at DESC LIMIT 1
            """, (run_ids,))
            drift_row = cursor.fetchone()
            if drift_row:
                new_identities_count = drift_row[0] or 0
                removed_identities_count = drift_row[1] or 0
        except Exception:
            try: db.conn.rollback()
            except Exception: pass

        # Identity count separation (total including Microsoft)
        customer_count = microsoft_count = total_including_microsoft = 0
        try:
            cursor.execute("""
                SELECT
                    COUNT(*) FILTER (WHERE NOT COALESCE(i.is_microsoft_system, false)),
                    COUNT(*) FILTER (WHERE COALESCE(i.is_microsoft_system, false)),
                    COUNT(*)
                FROM identities i WHERE i.discovery_run_id = ANY(%s)
            """, (run_ids,))
            ms_row = cursor.fetchone()
            customer_count = ms_row[0] or 0
            microsoft_count = ms_row[1] or 0
            total_including_microsoft = ms_row[2] or 0
        except Exception:
            try: db.conn.rollback()
            except Exception: pass

        # Lineage verdict distribution (recommended_action counts)
        lineage_verdicts = None
        try:
            cursor.execute("""
                SELECT
                    COALESCE(i.recommended_action, 'UNKNOWN') AS action,
                    COUNT(*) AS cnt,
                    AVG(i.verdict_score)::int AS avg_score
                FROM identities i
                WHERE i.discovery_run_id = ANY(%s)
                  AND NOT COALESCE(i.is_microsoft_system, false)
                  AND i.identity_category IN ('service_principal', 'managed_identity_system', 'managed_identity_user')
                GROUP BY COALESCE(i.recommended_action, 'UNKNOWN')
            """, (run_ids,))
            verdict_rows = cursor.fetchall()
            verdicts = {}
            for row in verdict_rows:
                verdicts[row[0]] = {'count': row[1], 'avg_score': row[2] or 0}
            lineage_verdicts = {
                'orphaned': verdicts.get('ORPHANED', {}).get('count', 0),
                'unused': verdicts.get('UNUSED', {}).get('count', 0),
                'stale': verdicts.get('STALE', {}).get('count', 0),
                'at_risk': verdicts.get('AT_RISK', {}).get('count', 0),
                'needs_review': verdicts.get('NEEDS_REVIEW', {}).get('count', 0),
                'healthy': verdicts.get('HEALTHY', {}).get('count', 0),
                'unknown': verdicts.get('UNKNOWN', {}).get('count', 0),
                'distribution': verdicts,
            }
        except Exception:
            try: db.conn.rollback()
            except Exception: pass

        result = {
            "latest_run": latest,
            "previous_run": previous_run,
            "total_discovery_runs": total_runs,
            "ghost_count": ghost_count,
            "zombie_count": zombie_count,
            "disabled_count": disabled_count,
            "deleted_count": deleted_count,
            "new_identities_count": new_identities_count,
            "removed_identities_count": removed_identities_count,
            "customer_count": customer_count,
            "microsoft_count": microsoft_count,
            "total_including_microsoft": total_including_microsoft,
        }
        if workload_exposure:
            result["workload_exposure"] = workload_exposure
        if lineage_verdicts:
            result["lineage_verdicts"] = lineage_verdicts

        return jsonify(result)

    finally:
        cursor.close()
        db.close()


def get_identities():
    """
    Get all identities from the latest discovery run.

    Query params:
        risk_level: Filter by risk level (critical, high, medium, low, info)
        identity_type: Filter by type (user, service_principal, managed_identity, group, unknown)
        identity_category: Filter by category (e.g., User Assigned Identity)
        cloud: Filter by cloud provider (azure, aws, gcp)
        search: Filter by display_name contains
        limit: Max results to return (default: no limit)
        offset: Skip N results (default: 0)
        status: Filter by status (disabled, deleted, active)
        hasRoles: boolean — only identities with RBAC or Entra role assignments
        activity_status: Filter by activity status (stale, never_used, inactive, active)
        privilege_tier: Filter by privilege tier (T0, T1, T2, T3)
        agirs_factor: AGIRS sub-metric filter (h1_ghost, h2_dormant_priv, h3_over_priv,
                       h4_ext_guest, n1_orphaned, n2_dormant, n3_zombie, n4_expired)
        credential_status: Filter by credential status (expired, expiring_soon, healthy, no_credentials)
        has_owner: boolean — filter by ownership (true/false)
        metric: Direct canonical metric filter from metric_queries registry
        lineage_verdict: Filter by lineage verdict (ORPHANED, UNUSED, STALE, AT_RISK, NEEDS_REVIEW, HEALTHY)
    """
    db = _db()
    risk_filter = request.args.get("risk_level") or request.args.get("risk")
    type_filter = request.args.get("identity_type")
    category_filter = request.args.get("identity_category")
    cloud_filter = request.args.get("cloud")
    search = request.args.get("search")
    limit = request.args.get("limit", type=int)
    if limit is not None:
        limit = min(limit, MAX_LIMIT)
    offset = request.args.get("offset", default=0, type=int)
    show_deleted = request.args.get('show_deleted', 'false').lower() == 'true'
    contributing_pillar = request.args.get("contributing_pillar") or request.args.get("pillar")
    status_filter = request.args.get("status")
    has_roles_filter = request.args.get("hasRoles")
    activity_filter = request.args.get("activity_status")
    privilege_tier_filter = request.args.get("privilege_tier")
    agirs_factor = request.args.get("agirs_factor")
    # CISO drawer flyout params (passed through from RISK_TYPE_ROUTES)
    workload_filter = request.args.get("workload")
    owner_param = request.args.get("owner")
    privileged_param = request.args.get("privileged")

    cursor = db.conn.cursor()

    try:
        run_ids = _latest_run_ids(cursor, _org_id(), _connection_id())

        if not run_ids:
            return jsonify({"error": "No completed discovery runs found"}), 404

        # Build WHERE clause on a lightweight base (no correlated subqueries)
        base_from = """FROM identities i
        LEFT JOIN discovery_runs dr_sub ON dr_sub.id = i.discovery_run_id"""
        where_clauses = " WHERE i.discovery_run_id = ANY(%s)"
        params = [run_ids]

        # Activated-subscription filter: only show identities from monitored subs (or Entra-only)
        _dummy = base_from + where_clauses
        _dummy, params = _apply_sub_filter(_dummy, params, cursor, _org_id(), _connection_id())
        # Extract appended SQL from _apply_sub_filter
        where_clauses = _dummy[len(base_from):]

        if not show_deleted:
            where_clauses += HIDE_DELETED_SQL

        where_clauses += HIDE_MICROSOFT_SQL

        # contributing_pillar: filter to identities the attack-surface-score
        # engine counted for a specific pillar (exact count match)
        if contributing_pillar:
            pillar_sql = _get_pillar_filter_sql(contributing_pillar)
            if pillar_sql:
                where_clauses += pillar_sql

        if risk_filter:
            risk_vals = [v.strip().lower() for v in risk_filter.split(',') if v.strip()]
            if len(risk_vals) == 1:
                where_clauses += " AND i.risk_level = %s"
                params.append(risk_vals[0])
            elif risk_vals:
                placeholders = ','.join(['%s'] * len(risk_vals))
                where_clauses += f" AND i.risk_level IN ({placeholders})"
                params.extend(risk_vals)

        if category_filter:
            where_clauses += " AND COALESCE(i.identity_category, '') = %s"
            params.append(category_filter)
        elif type_filter:
            where_clauses += " AND i.identity_type = %s"
            params.append(type_filter)

        if cloud_filter:
            where_clauses += " AND COALESCE(i.cloud, 'azure') = %s"
            params.append(cloud_filter.lower())

        if search:
            where_clauses += " AND LOWER(i.display_name) LIKE %s"
            params.append(f"%{search.lower()}%")

        # AGIRS-aligned filters — exact SQL matches agirs_engine.py counting
        if agirs_factor:
            agirs_sql = _get_agirs_factor_sql(agirs_factor)
            if agirs_sql:
                where_clauses += agirs_sql

        if status_filter:
            _sf = status_filter.lower()
            if _sf == 'disabled':
                where_clauses += " AND (i.enabled = FALSE OR i.status IN ('disabled', 'deleted'))"
            elif _sf == 'active':
                where_clauses += " AND COALESCE(i.enabled, TRUE) = TRUE AND COALESCE(i.status, 'active') NOT IN ('disabled', 'deleted')"

        if has_roles_filter and has_roles_filter.lower() == 'true':
            where_clauses += """ AND (
                EXISTS (SELECT 1 FROM role_assignments ra WHERE ra.identity_db_id = i.id)
                OR EXISTS (SELECT 1 FROM entra_role_assignments era WHERE era.identity_db_id = i.id)
            )"""

        # CISO drawer: workload=true → service principals + managed identities
        if workload_filter and workload_filter.lower() == 'true':
            where_clauses += " AND COALESCE(i.identity_category, '') IN ('service_principal', 'managed_identity_system', 'managed_identity_user')"

        # CISO drawer: owner=none/unowned → unowned identities (alias for has_owner=false)
        if owner_param and owner_param.lower() in ('none', 'unowned'):
            where_clauses += " AND COALESCE(i.owner_count, 0) = 0"

        # CISO drawer: privileged=true → T0 + T1 privilege tiers
        if privileged_param and privileged_param.lower() == 'true':
            where_clauses += " AND COALESCE(i.privilege_tier, 'T3') IN ('T0', 'T1')"

        if activity_filter:
            # Expand frontend shorthand: dormant_strict → stale + never_used
            if activity_filter.strip() == 'dormant_strict':
                activity_filter = 'stale,never_used'
            elif activity_filter.strip() == 'dormant':
                activity_filter = 'stale,never_used,inactive'
            allowed = {'stale', 'never_used', 'inactive', 'active', 'recently_created', 'unknown'}
            vals = [v.strip() for v in activity_filter.split(',') if v.strip() in allowed]
            if vals:
                placeholders = ','.join(['%s'] * len(vals))
                where_clauses += f" AND COALESCE(i.activity_status, 'unknown') IN ({placeholders})"
                params.extend(vals)

        if privilege_tier_filter:
            allowed_tiers = {'T0', 'T1', 'T2', 'T3'}
            tiers = [t.strip() for t in privilege_tier_filter.split(',') if t.strip() in allowed_tiers]
            if tiers:
                placeholders = ','.join(['%s'] * len(tiers))
                where_clauses += f" AND COALESCE(i.privilege_tier, 'T3') IN ({placeholders})"
                params.extend(tiers)

        # FIX1B: Credential status drill-down filter (matches dashboard posture counts)
        credential_status_filter = request.args.get("credential_status")
        if credential_status_filter:
            from app.api.metric_queries import get_metric_where, METRIC_REGISTRY
            cred_map = {
                'expired': 'credential_expired',
                'expiring_soon': 'credential_expiring',
                'healthy': 'credential_healthy',
                'no_credentials': 'no_credentials',
            }
            metric_key = cred_map.get(credential_status_filter)
            if metric_key and metric_key in METRIC_REGISTRY:
                where_clauses += get_metric_where(metric_key)

        # FIX1B: Owner status drill-down filter (matches dashboard unowned count)
        owner_filter = request.args.get("has_owner")
        if owner_filter:
            if owner_filter.lower() == 'false':
                from app.api.metric_queries import get_metric_where
                where_clauses += get_metric_where('unowned_nhi')
            elif owner_filter.lower() == 'true':
                where_clauses += " AND COALESCE(i.owner_count, 0) > 0"

        # FIX1B: Direct canonical metric filter — uses same WHERE as dashboard count
        # Accepts both ?metric=X and ?filter=X (IdentityRiskCardV31 uses filter=)
        metric_filter = request.args.get("metric") or request.args.get("filter")
        if metric_filter:
            from app.api.metric_queries import get_metric_where, METRIC_REGISTRY
            if metric_filter in METRIC_REGISTRY:
                where_clauses += get_metric_where(metric_filter)

        # Lineage verdict filter — dashboard tile drill-down
        verdict_filter = request.args.get("lineage_verdict")
        if verdict_filter:
            allowed_verdicts = {'ORPHANED', 'UNUSED', 'STALE', 'AT_RISK', 'NEEDS_REVIEW', 'HEALTHY'}
            vals = [v.strip().upper() for v in verdict_filter.split(',') if v.strip().upper() in allowed_verdicts]
            if vals:
                placeholders = ','.join(['%s'] * len(vals))
                where_clauses += f" AND COALESCE(i.recommended_action, 'UNKNOWN') IN ({placeholders})"
                params.extend(vals)

        access_tier_filter = request.args.get("access_tier")
        if access_tier_filter and access_tier_filter in ('control_plane', 'data_plane'):
            where_clauses += " AND COALESCE(i.access_tier, 'control_plane') = %s"
            params.append(access_tier_filter)

        subscription_filter = request.args.get("subscription_id")
        if subscription_filter:
            # Check junction table for ANY access (not just primary/discovery subscription)
            where_clauses += """ AND (dr_sub.subscription_id = %s
                OR i.identity_id IN (
                    SELECT isa.identity_id FROM identity_subscription_access isa
                    WHERE isa.subscription_id = %s
                ))"""
            params.extend([subscription_filter, subscription_filter])

        # Get total count using lightweight query (no correlated subqueries)
        count_query = f"SELECT COUNT(*) {base_from} {where_clauses}"
        cursor.execute(count_query, params)
        total_count = _scalar(cursor, 0)

        # Build the full query with correlated subqueries for the data fetch
        query = _identity_list_select() + where_clauses

        query += """
            ORDER BY
                CASE i.risk_level
                    WHEN 'critical' THEN 1
                    WHEN 'high' THEN 2
                    WHEN 'medium' THEN 3
                    WHEN 'low' THEN 4
                    ELSE 5
                END,
                i.display_name
        """

        if limit:
            query += " LIMIT %s OFFSET %s"
            params.extend([limit, offset])

        cursor.execute(query, params)
        rows = rows_as_dicts(cursor)

        identities = [_map_identity_row(row) for row in rows]

        # Compute governance summary counts from mapped identities
        gov_counts = {'orphaned': 0, 'ungoverned': 0, 'policy_violation': 0, 'privileged': 0, 'combo': 0, 'data_plane': 0}
        for ident in identities:
            gs = ident.get('governance_state') or 'Governed'
            pl = ident.get('privilege_level') or 'Standard'
            if gs == 'Orphaned':
                gov_counts['orphaned'] += 1
            elif gs == 'Ungoverned':
                gov_counts['ungoverned'] += 1
            elif gs == 'Policy Violation':
                gov_counts['policy_violation'] += 1
            if pl in ('Privileged', 'Highly Privileged'):
                gov_counts['privileged'] += 1
            if gs in ('Orphaned', 'Ungoverned', 'Policy Violation') and pl in ('Privileged', 'Highly Privileged'):
                gov_counts['combo'] += 1
            if ident.get('access_tier') == 'data_plane':
                gov_counts['data_plane'] += 1

        result = {"count": len(identities), "total": total_count, "identities": identities,
                  "governance_summary": gov_counts}
        if limit:
            result["limit"] = limit
            result["offset"] = offset
            result["has_more"] = (offset + len(identities)) < total_count
        return jsonify(result)

    finally:
        cursor.close()
        db.close()


def get_identity_details(identity_id: str):
    """
    Full identity detail view.
    """
    db = _db()
    cursor = db.conn.cursor()

    try:
        run_ids = _latest_run_ids(cursor, _org_id(), _connection_id())
        if not run_ids:
            return jsonify({"error": "Identity not found"}), 404

        # Build detail query with activated-subscription filter
        detail_sql = """
            SELECT i.id, i.identity_id, i.display_name, i.identity_type, i.identity_category, i.risk_level,
                   i.credential_count, i.credential_risk, i.credential_status, i.credential_expiration,
                   i.created_datetime, i.activity_status, i.risk_reasons,
                   -- Multi-cloud normalized fields
                   COALESCE(i.cloud, 'azure') as cloud,
                   i.identity_type_normalized,
                   i.canonical_name,
                   i.principal_id,
                   i.tenant_or_org_id,
                   COALESCE(i.source_normalized, 'entra') as source,
                   COALESCE(i.is_federated, false) as is_federated,
                   COALESCE(i.status, 'active') as status,
                   i.last_seen_auth,
                   -- Ownership fields
                   i.owner_display_name,
                   COALESCE(i.owner_count, 0) as owner_count,
                   -- Risk scoring fields
                   COALESCE(i.risk_score, 0) as risk_score,
                   COALESCE(i.api_permission_count, 0) as api_permission_count,
                   COALESCE(i.app_role_count, 0) as app_role_count,
                   i.ca_coverage_status,
                   COALESCE(i.ca_mfa_enforced, false) as ca_mfa_enforced,
                   i.risk_factors,
                   i.discovery_run_id,
                   dr.completed_at as run_completed_at,
                   i.enabled,
                   i.deleted_at,
                   i.last_sign_in,
                   COALESCE(i.is_microsoft_system, false) as is_microsoft_system,
                   i.observed_last_used,
                   i.last_noninteractive_signin,
                   COALESCE(i.is_discovery_connector, false) as is_discovery_connector,
                   i.federated_workload_type,
                   i.owner_status,
                   COALESCE(i.blast_radius_score,
                       (SELECT MAX(ap.risk_score) FROM attack_paths ap
                        WHERE ap.source_entity_id = i.identity_id
                          AND ap.organization_id = i.organization_id),
                       0) as blast_radius_score,
                   GREATEST(
                       (SELECT COUNT(*) FROM graph_attack_findings gaf
                        WHERE gaf.identity_id = i.id
                          AND gaf.status IN ('open', 'acknowledged', 'in_progress')),
                       (SELECT COUNT(*) FROM attack_paths ap
                        WHERE ap.source_entity_id = i.identity_id
                          AND ap.organization_id = i.organization_id)
                   ) as attack_path_count,
                   i.last_activity_date,
                   i.last_activity_source
            FROM identities i
            LEFT JOIN discovery_runs dr ON dr.id = i.discovery_run_id
            WHERE i.identity_id = %s AND i.discovery_run_id = ANY(%s)
        """
        detail_params = [identity_id, run_ids]
        mon_subs = _monitored_sub_ids(cursor, _org_id(), _connection_id())
        if mon_subs:
            detail_sql += ACTIVATED_SUB_FILTER_SQL
            detail_params.extend([mon_subs, _org_id(), mon_subs])
        detail_sql += """
            ORDER BY i.discovery_run_id DESC
            LIMIT 1
        """
        cursor.execute(detail_sql, tuple(detail_params))
        row = cursor.fetchone()
        if not row:
            return jsonify({"error": "Identity not found"}), 404

        from app.engines.status_resolver import resolve_status, STATUS_DISPLAY

        identity_db_id = row[0]
        display_name = row[2] or ''
        identity_type = row[3] or ''
        normalized_category = _normalize_category_key(row[4] or '')

        # Status resolver fields (row[32]=enabled, row[33]=deleted_at)
        enabled_val = row[32] if row[32] is not None else True
        deleted_at_val = row[33]
        resolved_status = resolve_status({
            'status': row[20] or 'active',
            'enabled': enabled_val,
            'deleted_at': deleted_at_val,
        })

        identity = {
            "db_id": identity_db_id,
            "identity_id": row[1],
            "display_name": display_name,
            "identity_type": identity_type,
            "identity_category": normalized_category,
            "risk_level": row[5],
            "credential_count": row[6] or 0,
            "credential_risk": row[7],
            "credential_status": row[8],
            "credential_expiration": row[9].isoformat() if row[9] else None,
            "created_datetime": row[10].isoformat() if row[10] else None,
            "activity_status": row[11],
            "risk_reasons": _parse_risk_reasons(row[12]),
            # Multi-cloud normalized fields
            "cloud": row[13] or "azure",
            "normalized_identity_type": row[14],
            "canonical_name": row[15],
            "principal_id": row[16],
            "tenant_or_org_id": row[17],
            "source": row[18] or "entra",
            "is_federated": row[19] or False,
            "status": resolved_status,
            "status_display": STATUS_DISPLAY.get(resolved_status, STATUS_DISPLAY['unknown']),
            "enabled": enabled_val,
            "deleted_at": deleted_at_val.isoformat() if deleted_at_val else None,
            "last_seen_auth": row[21].isoformat() if row[21] else None,
            # Ownership fields
            "owner_display_name": row[22],
            "owner_count": int(row[23] or 0),
            # Risk scoring fields
            "risk_score": int(row[24] or 0),
            "api_permission_count": int(row[25] or 0),
            "app_role_count": int(row[26] or 0),
            "ca_coverage_status": row[27] or None,
            "ca_mfa_enforced": bool(row[28]) if row[28] is not None else False,
            "risk_factors": row[29] if row[29] else [],
            "discovery_run_id": row[30],
            "last_sign_in": row[34].isoformat() if row[34] else None,
            "is_microsoft_system": bool(row[35]),
            "is_discovery_connector": bool(row[38]) if len(row) > 38 else False,
            "owner_status": row[40] if len(row) > 40 else None,
            "blast_radius_score": float(row[41]) if len(row) > 41 and row[41] is not None else 0,
            "attack_path_count": int(row[42]) if len(row) > 42 and row[42] is not None else 0,
            "last_activity_date": row[43].isoformat() if len(row) > 43 and row[43] and hasattr(row[43], 'isoformat') else None,
            "last_activity_source": row[44] if len(row) > 44 else None,
        }

        # Compute effective_last_used = MAX(observed, Azure sign-in)
        from datetime import datetime as _dt
        def _try_parse_dt(v):
            if not v:
                return None
            if hasattr(v, 'timestamp'):
                return v
            try:
                return _dt.fromisoformat(str(v).replace('Z', '+00:00').replace('+00:00', ''))
            except (ValueError, TypeError):
                return None

        obs_raw = row[36] if len(row) > 36 else None
        ni_raw = row[37] if len(row) > 37 else None
        signin_raw = row[34]  # last_sign_in

        eff_candidates = [
            (_try_parse_dt(obs_raw), 'auditgraph'),
            (_try_parse_dt(ni_raw), 'azure_signin'),
            (_try_parse_dt(signin_raw), 'azure_signin'),
        ]
        eff_last = None
        eff_src = None
        for dt, src in eff_candidates:
            if dt and (eff_last is None or dt > eff_last):
                eff_last = dt
                eff_src = src

        # Federated inference: federated identities (GitHub OIDC, AKS) don't
        # generate Azure sign-in logs. Infer usage from created_datetime.
        fed_wt_raw = row[39] if len(row) > 39 else None
        if fed_wt_raw and eff_last is None:
            created_dt = _try_parse_dt(row[10])  # created_datetime
            if created_dt:
                eff_last = created_dt
                eff_src = 'inferred_federated'

        identity["effective_last_used"] = eff_last.isoformat() if eff_last else None
        identity["effective_last_used_source"] = eff_src
        identity["federated_workload_type"] = fed_wt_raw

        # ── Sign-in authentication provenance ──
        last_signin_at = None
        last_signin_ip = None
        auth_source = 'static_analysis_only'
        try:
            cursor.execute("""
                SELECT created_datetime, ip_address
                FROM workload_signin_events
                WHERE identity_db_id = %s AND status = 'success'
                ORDER BY created_datetime DESC LIMIT 1
            """, (identity_db_id,))
            signin_row = cursor.fetchone()
            if signin_row:
                last_signin_at = signin_row[0].isoformat() if signin_row[0] else None
                last_signin_ip = signin_row[1]
                auth_source = 'entra_signin_log'
            elif identity.get('last_sign_in'):
                last_signin_at = identity['last_sign_in']
                auth_source = 'graph_sign_in_activity'
        except Exception:
            try: db.conn.rollback()
            except Exception: pass

        identity["last_signin_at"] = last_signin_at
        identity["last_signin_ip"] = last_signin_ip
        identity["auth_source"] = auth_source

        # ── ARM connections (last 3 activity events — no P2 required) ──
        arm_connections = []
        try:
            arm_connections = db.get_identity_arm_connections(identity_db_id, limit=3)
            for c in arm_connections:
                if c.get('event_timestamp') and hasattr(c['event_timestamp'], 'isoformat'):
                    c['event_timestamp'] = c['event_timestamp'].isoformat()
                op = c.get('operation_name', '')
                if '/' in op:
                    parts = op.split('/')
                    c['operation_short'] = '/'.join(parts[-2:]) if len(parts) >= 2 else op
                else:
                    c['operation_short'] = op
                rid = c.get('resource_id', '')
                if rid:
                    segments = rid.strip('/').split('/')
                    c['resource_name'] = segments[-1] if segments else rid
                else:
                    c['resource_name'] = None
        except Exception:
            try: db.conn.rollback()
            except Exception: pass
        identity["arm_connections"] = arm_connections

        # ── Rule 2: override misleading activity_status for federated identities ──
        if fed_wt_raw and identity.get("activity_status") in ('never_used', 'unknown', 'stale', None):
            if eff_src == 'inferred_federated':
                identity["activity_status"] = 'likely_active'

        # ── Rule 4: Activity source hierarchy for lineage panel ──
        activity_sources = []
        if _try_parse_dt(obs_raw):
            activity_sources.append({"type": ActivitySource.AUDITGRAPH, "label": ACTIVITY_SOURCE_LABELS[ActivitySource.AUDITGRAPH], "available": True})
        else:
            activity_sources.append({"type": ActivitySource.AUDITGRAPH, "label": ACTIVITY_SOURCE_LABELS[ActivitySource.AUDITGRAPH], "available": False})
        if _try_parse_dt(signin_raw) or _try_parse_dt(ni_raw):
            activity_sources.append({"type": ActivitySource.AZURE_SIGNIN, "label": ACTIVITY_SOURCE_LABELS[ActivitySource.AZURE_SIGNIN], "available": True})
        else:
            activity_sources.append({"type": ActivitySource.AZURE_SIGNIN, "label": ACTIVITY_SOURCE_LABELS[ActivitySource.AZURE_SIGNIN], "available": False,
                                     "detail": "Not available — log-independent mode"})
        # ARM role assignment analysis — always available (log-independent)
        _act_status = (identity.get('activity_status') or '').lower()
        _arm_available = _act_status in ('likely_active', 'active', 'recently_created')
        activity_sources.append({
            "type": "arm_analysis", "label": "ARM role assignments",
            "available": _arm_available,
            "detail": "Role assignments analyzed via static analysis" if _arm_available else "No recent role assignment changes detected",
        })
        if fed_wt_raw:
            activity_sources.append({"type": ActivitySource.FEDERATED_INFERENCE, "label": "Federated inference", "available": True,
                                     "detail": f"Inferred from {fed_wt_raw} workload configuration"})
        # AuditGraph snapshot source
        _run_id = identity.get('discovery_run_id')
        activity_sources.append({
            "type": "auditgraph_snapshot", "label": "AuditGraph snapshot",
            "available": True,
            "detail": f"Snapshot #{_run_id}" if _run_id else "Available",
        })
        identity["activity_sources"] = activity_sources

        # ── Rule 6: Active access hints for federated identities ──
        if fed_wt_raw and eff_src == 'inferred_federated':
            try:
                cursor.execute(
                    """SELECT DISTINCT role_name, scope, scope_type
                       FROM role_assignments
                       WHERE identity_db_id = %s
                       ORDER BY scope_type, role_name
                       LIMIT 10""",
                    (identity_db_id,),
                )
                access_rows = cursor.fetchall()
                if access_rows:
                    identity["federated_active_access"] = [
                        {"role": r[0], "scope": r[1], "scope_type": r[2]}
                        for r in access_rows
                    ]
            except Exception:
                try: db.conn.rollback()
                except Exception: pass

        run_completed_at = row[31].isoformat() if row[31] else None
        current_run_id = row[30]

        # Trend comparison: get this identity's state from the previous run (Pillar 6)
        trend = None
        if current_run_id:
            try:
                tid = _org_id()
                if tid:
                    cursor.execute(
                        """
                        SELECT risk_level, risk_score, credential_count, credential_expiration
                        FROM identities
                        WHERE identity_id = %s
                          AND discovery_run_id = (
                              SELECT MAX(id) FROM discovery_runs
                              WHERE status = 'completed' AND id < %s AND organization_id = %s
                          )
                        LIMIT 1
                        """,
                        (identity_id, current_run_id, tid),
                    )
                else:
                    cursor.execute(
                        """
                        SELECT risk_level, risk_score, credential_count, credential_expiration
                        FROM identities
                        WHERE identity_id = %s
                          AND discovery_run_id = (
                              SELECT MAX(id) FROM discovery_runs
                              WHERE status = 'completed' AND id < %s AND organization_id = %s
                          )
                        LIMIT 1
                        """,
                        (identity_id, current_run_id, _org_id()),
                    )
                prev = cursor.fetchone()
                if prev:
                    trend = {
                        "previous_risk_level": prev[0],
                        "previous_risk_score": int(prev[1] or 0),
                        "risk_direction": (
                            "worsened" if (identity["risk_score"] or 0) > (prev[1] or 0)
                            else "improved" if (identity["risk_score"] or 0) < (prev[1] or 0)
                            else "unchanged"
                        ),
                        "is_new": False,
                    }
                else:
                    # Identity not found in previous run → it's new
                    trend = {
                        "previous_risk_level": None,
                        "previous_risk_score": None,
                        "risk_direction": "new",
                        "is_new": True,
                    }
            except Exception:
                try: db.conn.rollback()
                except Exception: pass

        # ✅ FIXED: clean try/except blocks
        try:
            graph_permissions = db.get_graph_permissions(identity_db_id)
        except Exception as e:
            try: db.conn.rollback()
            except Exception: pass
            logger.error("Error getting graph permissions: %s", e)
            graph_permissions = []

        try:
            app_roles = db.get_app_roles(identity_db_id)
        except Exception as e:
            try: db.conn.rollback()
            except Exception: pass
            logger.error("Error getting app roles: %s", e)
            app_roles = []

        try:
            owners = db.get_ownership(identity_db_id)
        except Exception as e:
            try: db.conn.rollback()
            except Exception: pass
            logger.error("Error getting owners: %s", e)
            owners = []

        roles = db.get_identity_roles_enriched(identity_db_id)

        # Enrich each role with derived usage fields
        from datetime import datetime, timezone
        _now = datetime.now(timezone.utc)
        identity_has_effective_activity = bool(eff_last)
        removable_count = 0
        for role in roles:
            lu = role.get("last_used_at")
            if lu:
                role["last_used_at"] = lu.isoformat() if hasattr(lu, 'isoformat') else lu
                delta = (_now - lu).days if hasattr(lu, 'date') else None
                role["days_since_used"] = delta
                if delta is not None:
                    if delta == 0:
                        role["last_used_display"] = "Today"
                    elif delta == 1:
                        role["last_used_display"] = "Yesterday"
                    elif delta < 30:
                        role["last_used_display"] = f"{delta} days ago"
                    elif delta < 365:
                        months = delta // 30
                        role["last_used_display"] = f"{months} month{'s' if months > 1 else ''} ago"
                    else:
                        role["last_used_display"] = f"{delta // 365}+ years ago"
                else:
                    role["last_used_display"] = "Unknown"
                role["last_used_source"] = "ARM activity logs" if role.get("last_used_operation") else "identity sign-in (proxy)"
            else:
                role["last_used_at"] = None
                role["days_since_used"] = None
                # When the identity authenticated but this role has no
                # role-scoped activity, say so explicitly instead of the
                # misleading "Never used" (which implies the identity
                # itself was never used).
                if identity_has_effective_activity:
                    role["last_used_display"] = "No activity in 90 days"
                else:
                    role["last_used_display"] = "Never used"
                role["last_used_source"] = "static analysis"
            # Determine if role is removable
            us = role.get("usage_status", "unknown")
            role["is_removable"] = us in ("stale", "dormant", "never_used")
            if role["is_removable"]:
                removable_count += 1
            # Serialize created_on
            co = role.get("created_on")
            if co and hasattr(co, 'isoformat'):
                role["created_on"] = co.isoformat()
            # Serialize last_activity_date
            lad = role.get("last_activity_date")
            if lad and hasattr(lad, 'isoformat'):
                role["last_activity_date"] = lad.isoformat()

        identity["removable_role_count"] = removable_count

        # ── Contradiction guard: identity authenticated but all roles
        # show no role-scoped activity ──
        all_roles_no_activity = (
            len(roles) > 0
            and all(r.get("last_used_at") is None for r in roles)
        )
        if eff_last and all_roles_no_activity:
            identity["activity_mismatch_warning"] = (
                "Identity authenticated recently but no role-scoped activity "
                "detected. Last sign-in may not correspond to Azure resource access."
            )
            if eff_src == 'auditgraph':
                identity["activity_source_qualifier"] = "via AuditGraph (not role activity)"
            elif eff_src == 'azure_signin':
                identity["activity_source_qualifier"] = "via sign-in (not role activity)"
            elif eff_src == 'inferred_federated':
                identity["activity_source_qualifier"] = "inferred"
            else:
                identity["activity_source_qualifier"] = "via sign-in"

        # Entra group count + top privileged groups for this identity (FIX C)
        try:
            cursor.execute("""
                SELECT COUNT(DISTINCT egm.group_db_id)
                FROM entra_group_memberships egm
                JOIN entra_groups eg ON eg.id = egm.group_db_id
                WHERE egm.member_object_id = %s AND eg.discovery_run_id = ANY(%s)
            """, (row[1], run_ids))  # row[1] = identity_id (Azure object_id)
            identity['group_count'] = _scalar(cursor, 0)

            # Top 5 privileged groups this identity belongs to
            cursor.execute("""
                SELECT eg.display_name,
                       CASE WHEN eg.is_role_assignable THEN 'Role-Assignable' ELSE 'Security' END AS group_type,
                       jsonb_array_length(COALESCE(eg.rbac_roles, '[]'::jsonb)) AS inherited_role_count,
                       COALESCE(
                           (SELECT MAX(CASE
                               WHEN r->>'scope_type' = 'subscription' THEN 'subscription'
                               WHEN r->>'scope_type' = 'resource_group' THEN 'resource_group'
                               ELSE r->>'scope_type'
                           END) FROM jsonb_array_elements(eg.rbac_roles) r),
                           'none'
                       ) AS highest_scope
                FROM entra_group_memberships egm
                JOIN entra_groups eg ON eg.id = egm.group_db_id
                WHERE egm.member_object_id = %s
                  AND eg.discovery_run_id = ANY(%s)
                  AND eg.is_privileged = true
                ORDER BY jsonb_array_length(COALESCE(eg.rbac_roles, '[]'::jsonb)) DESC
                LIMIT 5
            """, (row[1], run_ids))
            priv_groups = []
            for pg in cursor.fetchall():
                priv_groups.append({
                    'group_name': pg[0],
                    'group_type': pg[1],
                    'inherited_role_count': pg[2],
                    'highest_scope': pg[3] or 'none',
                })
            identity['privileged_groups'] = priv_groups

            # Count groups with active rbac_roles (for ghost access warning)
            cursor.execute("""
                SELECT COUNT(DISTINCT egm.group_db_id)
                FROM entra_group_memberships egm
                JOIN entra_groups eg ON eg.id = egm.group_db_id
                WHERE egm.member_object_id = %s
                  AND eg.discovery_run_id = ANY(%s)
                  AND eg.rbac_roles != '[]'::jsonb
            """, (row[1], run_ids))
            identity['groups_with_roles_count'] = _scalar(cursor, 0)
        except Exception:
            try: db.conn.rollback()
            except Exception: pass
            identity['group_count'] = 0
            identity['privileged_groups'] = []
            identity['groups_with_roles_count'] = 0

        # Resource context for SAMIs (associated resource info)
        try:
            cursor.execute("""
                SELECT associated_resource_id, associated_resource_type,
                       associated_resource_name, associated_resource_group,
                       associated_subscription_id
                FROM identities
                WHERE identity_id = %s AND discovery_run_id = ANY(%s)
                  AND associated_resource_id IS NOT NULL
                LIMIT 1
            """, (row[1], run_ids))
            res_row = cursor.fetchone()
            if res_row and res_row[0]:
                identity['resource_context'] = {
                    'resource_id': res_row[0],
                    'resource_type': res_row[1],
                    'resource_name': res_row[2],
                    'resource_group': res_row[3],
                    'subscription_id': res_row[4],
                }
            else:
                identity['resource_context'] = None
        except Exception:
            try: db.conn.rollback()
            except Exception: pass
            identity['resource_context'] = None

        # Gather compliance and attack intelligence for each role
        role_intelligence = []
        seen_roles = set()
        for role in roles:
            rn = role.get("role_name", "")
            if rn in seen_roles:
                continue
            seen_roles.add(rn)
            try:
                attacks = db.get_role_attack_patterns(rn)
            except Exception:
                try: db.conn.rollback()
                except Exception: pass
                attacks = []
            try:
                hipaa = db.get_role_hipaa_violations(rn)
            except Exception:
                try: db.conn.rollback()
                except Exception: pass
                hipaa = []
            if attacks or hipaa:
                role_intelligence.append({
                    "role_name": rn,
                    "attack_patterns": attacks,
                    "hipaa_violations": hipaa,
                })

        # Phase 3A: Database admin context
        database_admin_context = []
        try:
            database_admin_context = db.get_identity_database_admin_context(identity['id'])
        except Exception:
            try: db.conn.rollback()
            except Exception: pass

        analytics_context = {}
        try:
            analytics_context = db.get_identity_analytics_context(identity['id'])
        except Exception:
            try: db.conn.rollback()
            except Exception: pass

        devops_context = []
        try:
            devops_context = db.get_identity_devops_context(identity['id'])
        except Exception:
            try: db.conn.rollback()
            except Exception: pass

        # ── Compute privilege_tier from roles for governance service ──
        _T0_ENTRA = {'global administrator', 'privileged role administrator',
                     'privileged authentication administrator', 'security operator',
                     'application administrator', 'cloud application administrator',
                     'hybrid identity administrator', 'domain name administrator',
                     'external identity provider administrator'}
        _T0_ARM = {'owner', 'user access administrator'}
        _T1_ENTRA = {'user administrator', 'exchange administrator',
                     'sharepoint administrator', 'teams administrator',
                     'intune administrator', 'conditional access administrator',
                     'authentication administrator', 'groups administrator',
                     'license administrator', 'password administrator',
                     'security administrator', 'compliance administrator',
                     'billing administrator', 'helpdesk administrator'}
        _T1_ARM = {'owner', 'contributor', 'user access administrator'}
        _priv_tier = 3
        for r in roles:
            rn = (r.get('role_name') or '').lower()
            rt = (r.get('role_type') or '').lower()
            if rt == 'entra' and rn in _T0_ENTRA:
                _priv_tier = 0; break
            st = (r.get('scope_type') or '').lower()
            if rt == 'azure' and rn in _T0_ARM and st in ('subscription', 'tenant', ''):
                _priv_tier = 0; break
        if _priv_tier > 0:
            for r in roles:
                rn = (r.get('role_name') or '').lower()
                rt = (r.get('role_type') or '').lower()
                if rt == 'entra' and rn in _T1_ENTRA:
                    _priv_tier = min(_priv_tier, 1); break
                if rt == 'azure' and rn in _T1_ARM:
                    _priv_tier = min(_priv_tier, 1); break
        if _priv_tier > 1:
            for r in roles:
                if r.get('role_type', '').lower() in ('entra', 'azure'):
                    _priv_tier = min(_priv_tier, 2); break
        identity['privilege_tier'] = _priv_tier

        # ── Canonical identity state via governance service ──
        try:
            from app.services.governance_service import build_identity_state
            _identity_state = build_identity_state(
                identity,
                roles=roles,
                attack_path_count=identity.get('attack_path_count', 0),
            )
            identity.update(_identity_state)
        except Exception as e:
            logger.warning("build_identity_state failed: %s", e)

        # ── NHI lineage data (from identities table + lineage_verdicts) ──
        lineage = None
        _nhi_cats = ('service_principal', 'managed_identity_system',
                     'managed_identity_user', 'workload_identity')
        if (identity.get('identity_category') or identity.get('identity_type', '')).lower() in _nhi_cats:
            try:
                _lid = identity.get('_db_id') or identity_db_id
                cursor.execute("""
                    SELECT i.lineage_narrative, i.workload_origin, i.workload_origin_source,
                           i.audit_created_by, i.audit_creation_method,
                           lv.verdict, lv.confidence_score, lv.contributing_factors,
                           lv.verdict_source
                    FROM identities i
                    LEFT JOIN LATERAL (
                        SELECT verdict, confidence_score, contributing_factors, verdict_source
                        FROM lineage_verdicts
                        WHERE identity_id = i.id
                        ORDER BY scored_at DESC
                        LIMIT 1
                    ) lv ON true
                    WHERE i.id = %s
                    LIMIT 1
                """, (_lid,))
                _row = cursor.fetchone()

                lineage = {
                    "narrative": (_row[0] if _row else None) or None,
                    "workload_origin": (_row[1] if _row else None) or None,
                    "workload_origin_source": (_row[2] if _row else None) or None,
                    "provisioned_by": (_row[3] if _row else None) or None,
                    "creation_method": (_row[4] if _row else None) or None,
                    "verdict": (_row[5] if _row else None) or None,
                    "confidence": float(_row[6]) if _row and _row[6] is not None else None,
                    "contributing_factors": (_row[7] if _row else None) or None,
                    "verdict_source": (_row[8] if _row else None) or None,
                }
            except Exception as e:
                try: db.conn.rollback()
                except Exception: pass
                logger.warning("Lineage fetch failed: %s", e)

        return jsonify(
            {
                "identity": identity,
                "roles": roles,
                "graph_permissions": graph_permissions,
                "app_roles": app_roles,
                "owners": owners,
                "role_intelligence": role_intelligence,
                "database_admin_context": database_admin_context,
                "analytics_context": analytics_context,
                "devops_context": devops_context,
                "lineage": lineage,
                "trend": trend,
                "evidence": {
                    "run_id": identity.get("discovery_run_id"),
                    "collected_at": run_completed_at,
                    "sources": {
                        "identity": "Microsoft Graph API /servicePrincipals or /users",
                        "roles_azure": "Azure Resource Manager /roleAssignments",
                        "roles_entra": "Microsoft Graph API /roleManagement/directory",
                        "permissions": "Microsoft Graph API /servicePrincipals/{id}/appRoleAssignments",
                        "credentials": "Microsoft Graph API /applications/{id}/passwordCredentials + keyCredentials",
                        "owners": "Microsoft Graph API /servicePrincipals/{id}/owners",
                        "pim": "Microsoft Graph API /roleManagement/directory/roleEligibilityScheduleInstances",
                        "ca_policies": "Microsoft Graph API /identity/conditionalAccess/policies",
                    },
                },
            }
        )

    finally:
        cursor.close()
        db.close()


def get_risks():
    """
    Returns high-risk identities (critical/high) for latest run.
    """
    db = _db()
    cursor = db.conn.cursor()
    try:
        run_ids = _latest_run_ids(cursor, _org_id(), _connection_id())
        if not run_ids:
            return jsonify({"error": "No completed discovery runs found"}), 404

        risk_sql = f"""
            SELECT i.identity_id, i.display_name, i.identity_type, i.identity_category, i.risk_level, i.risk_reasons
            FROM identities i
            WHERE i.discovery_run_id = ANY(%s)
              AND i.risk_level IN ('critical','high')
              {HIDE_MICROSOFT_SQL}
        """
        risk_params = [run_ids]
        risk_sql, risk_params = _apply_sub_filter(risk_sql, risk_params, cursor, _org_id(), _connection_id())
        risk_sql += " ORDER BY i.risk_level, i.display_name"
        cursor.execute(risk_sql, tuple(risk_params))
        rows = cursor.fetchall()

        items = []
        for r in rows:
            display_name = r[1] or ''
            identity_type = r[2] or ''
            normalized_category = _normalize_category_key(r[3] or '')

            items.append(
                {
                    "identity_id": r[0],
                    "display_name": display_name,
                    "identity_type": identity_type,
                    "identity_category": normalized_category,
                    "risk_level": r[4],
                    "risk_reasons": _parse_risk_reasons(r[5]),
                }
            )

        return jsonify({"count": len(items), "items": items})
    finally:
        cursor.close()
        db.close()


