def verify_snapshot_integrity():
    """
    GET /api/snapshots/<run_id>/verify
    Verify the integrity of a completed discovery run snapshot.
    Re-computes hash from immutable fields and compares with stored hash.
    """
    from app.middleware.snapshot_integrity import verify_snapshot
    run_id = request.view_args.get('run_id')
    db = _db()
    cursor = db.conn.cursor()
    try:
        cursor.execute(
            """
            SELECT id, subscription_id, started_at, completed_at,
                   total_identities, critical_count, high_count, medium_count, low_count,
                   organization_id, snapshot_hash, snapshot_signature, status
            FROM discovery_runs
            WHERE id = %s AND organization_id = %s
            """,
            (run_id, _org_id()),
        )
        row = cursor.fetchone()
        if not row:
            return jsonify({"error": "Snapshot not found"}), 404

        run_data = {
            'id': row[0],
            'subscription_id': row[1],
            'started_at': row[2],
            'completed_at': row[3],
            'total_identities': row[4],
            'critical_count': row[5],
            'high_count': row[6],
            'medium_count': row[7],
            'low_count': row[8],
            'organization_id': row[9],
            'snapshot_hash': row[10],
            'snapshot_signature': row[11],
            'status': row[12],
        }

        result = verify_snapshot(run_data)
        result['run_id'] = run_data['id']
        result['status'] = run_data['status']

        _log(db, 'snapshot_verified', f'Snapshot integrity check for run {run_id}: valid={result["valid"]}',
             {'run_id': run_id, 'valid': result['valid']})

        return jsonify(result)
    finally:
        cursor.close()
        db.close()


def get_snapshot_state():
    """
    GET /api/snapshots/state?date=YYYY-MM-DD[&connection_id=N]
    Returns identity/access/compliance state from the discovery run
    closest to (but not after) the requested date.
    """
    date_str = request.args.get('date')
    if not date_str:
        return jsonify({"error": "date query parameter required (YYYY-MM-DD)"}), 400

    try:
        target_date = datetime.strptime(date_str, '%Y-%m-%d').replace(hour=23, minute=59, second=59)
    except ValueError:
        return jsonify({"error": "Invalid date format. Use YYYY-MM-DD."}), 400

    conn_id = _connection_id()
    tid = _org_id()
    db = _db()
    cursor = db.conn.cursor()
    try:
        # Find the latest completed run on or before the target date
        if conn_id:
            cursor.execute("""
                SELECT id, subscription_id, subscription_name,
                       started_at, completed_at, total_identities,
                       critical_count, high_count, medium_count, low_count
                FROM discovery_runs
                WHERE organization_id = %s AND status = 'completed'
                  AND cloud_connection_id = %s
                  AND completed_at <= %s
                ORDER BY completed_at DESC
                LIMIT 1
            """, (tid, conn_id, target_date))
        else:
            cursor.execute("""
                SELECT id, subscription_id, subscription_name,
                       started_at, completed_at, total_identities,
                       critical_count, high_count, medium_count, low_count
                FROM discovery_runs
                WHERE organization_id = %s AND status = 'completed'
                  AND completed_at <= %s
                ORDER BY completed_at DESC
                LIMIT 1
            """, (tid, target_date))

        run_row = cursor.fetchone()
        if not run_row:
            return jsonify({"error": f"No snapshot found on or before {date_str}"}), 404

        run_id = run_row[0]

        # Fetch identities from that specific run
        cursor.execute(
            _identity_list_select()
            + """
            WHERE i.discovery_run_id = %s
            ORDER BY i.risk_score DESC, i.display_name ASC
            """,
            (run_id,),
        )
        identity_rows = rows_as_dicts(cursor)
        identities = [_map_identity_row(r) for r in identity_rows]

        # Risk distribution
        risk_dist = {"critical": 0, "high": 0, "medium": 0, "low": 0, "info": 0}
        for ident in identities:
            rl = ident.get("risk_level", "info")
            if rl in risk_dist:
                risk_dist[rl] += 1
            else:
                risk_dist["info"] += 1

        # Category breakdown
        cat_counts = {}
        for ident in identities:
            cat = ident.get("identity_category", "unknown")
            cat_counts[cat] = cat_counts.get(cat, 0) + 1

        # Compliance state from that run (if available)
        compliance_snapshot = None
        try:
            cursor.execute("""
                SELECT framework_key, overall_score, controls_passed, controls_warned,
                       controls_failed, total_controls, evaluated_at
                FROM compliance_evaluations
                WHERE discovery_run_id = %s
            """, (run_id,))
            comp_rows = cursor.fetchall()
            if comp_rows:
                compliance_snapshot = []
                for cr in comp_rows:
                    compliance_snapshot.append({
                        "framework": cr[0],
                        "score": float(cr[1]) if cr[1] else 0,
                        "passed": cr[2] or 0,
                        "warned": cr[3] or 0,
                        "failed": cr[4] or 0,
                        "total": cr[5] or 0,
                        "evaluated_at": cr[6].isoformat() if cr[6] else None,
                    })
        except Exception:
            try: db.conn.rollback()
            except Exception: pass

        # Resource counts from that run
        resource_counts = {"storage_accounts": 0, "key_vaults": 0}
        try:
            cursor.execute("""
                SELECT COUNT(*) FROM azure_storage_accounts WHERE discovery_run_id = %s
            """, (run_id,))
            resource_counts["storage_accounts"] = _scalar(cursor, 0)
            cursor.execute("""
                SELECT COUNT(*) FROM azure_key_vaults WHERE discovery_run_id = %s
            """, (run_id,))
            resource_counts["key_vaults"] = _scalar(cursor, 0)
        except Exception:
            try: db.conn.rollback()
            except Exception: pass

        snapshot = {
            "snapshot_date": date_str,
            "run_id": run_id,
            "subscription_id": run_row[1],
            "subscription_name": run_row[2],
            "started_at": run_row[3].isoformat() if run_row[3] else None,
            "completed_at": run_row[4].isoformat() if run_row[4] else None,
            "total_identities": len(identities),
            "risk_distribution": risk_dist,
            "category_breakdown": cat_counts,
            "compliance": compliance_snapshot,
            "resource_counts": resource_counts,
            "identities": identities,
        }

        _log(db, 'snapshot_viewed', f'Snapshot state viewed for {date_str} (run #{run_id})', {
            'date': date_str,
            'run_id': run_id,
            'total_identities': len(identities),
        })

        return jsonify(snapshot)
    finally:
        cursor.close()
        db.close()


def get_snapshot_compare():
    """
    GET /api/snapshots/compare?from=YYYY-MM-DD&to=YYYY-MM-DD[&connection_id=N]
    Compare identity state between two point-in-time snapshots.
    Returns added/removed identities, risk changes, permission changes.
    """
    from_date = request.args.get('from')
    to_date = request.args.get('to')
    if not from_date or not to_date:
        return jsonify({"error": "Both 'from' and 'to' date parameters required (YYYY-MM-DD)"}), 400

    try:
        from_dt = datetime.strptime(from_date, '%Y-%m-%d').replace(hour=23, minute=59, second=59)
        to_dt = datetime.strptime(to_date, '%Y-%m-%d').replace(hour=23, minute=59, second=59)
    except ValueError:
        return jsonify({"error": "Invalid date format. Use YYYY-MM-DD."}), 400

    if from_dt >= to_dt:
        return jsonify({"error": "'from' date must be before 'to' date"}), 400

    conn_id = _connection_id()
    tid = _org_id()
    db = _db()
    cursor = db.conn.cursor()
    try:
        # Find the run closest to each date
        def _find_run(dt):
            if conn_id:
                cursor.execute("""
                    SELECT id, completed_at, total_identities
                    FROM discovery_runs
                    WHERE organization_id = %s AND status = 'completed'
                      AND cloud_connection_id = %s AND completed_at <= %s
                    ORDER BY completed_at DESC LIMIT 1
                """, (tid, conn_id, dt))
            else:
                cursor.execute("""
                    SELECT id, completed_at, total_identities
                    FROM discovery_runs
                    WHERE organization_id = %s AND status = 'completed'
                      AND completed_at <= %s
                    ORDER BY completed_at DESC LIMIT 1
                """, (tid, dt))
            return cursor.fetchone()

        from_run = _find_run(from_dt)
        to_run = _find_run(to_dt)

        if not from_run:
            return jsonify({"error": f"No snapshot found on or before {from_date}"}), 404
        if not to_run:
            return jsonify({"error": f"No snapshot found on or before {to_date}"}), 404
        if from_run[0] == to_run[0]:
            return jsonify({"error": "Both dates resolve to the same discovery run. Choose a wider range."}), 400

        from_run_id = from_run[0]
        to_run_id = to_run[0]

        # Get identity sets for each run
        def _get_identity_set(run_id):
            cursor.execute("""
                SELECT identity_id, display_name, risk_level, risk_score,
                       COALESCE(identity_category, '') as identity_category,
                       activity_status
                FROM identities
                WHERE discovery_run_id = %s
            """, (run_id,))
            rows = cursor.fetchall()
            return {r[0]: {
                "identity_id": r[0],
                "display_name": r[1],
                "risk_level": r[2] or "info",
                "risk_score": int(r[3] or 0),
                "identity_category": r[4],
                "activity_status": r[5] or "unknown",
            } for r in rows}

        from_identities = _get_identity_set(from_run_id)
        to_identities = _get_identity_set(to_run_id)

        from_ids = set(from_identities.keys())
        to_ids = set(to_identities.keys())

        # Added / Removed
        added_ids = to_ids - from_ids
        removed_ids = from_ids - to_ids
        common_ids = from_ids & to_ids

        added = [to_identities[iid] for iid in sorted(added_ids)]
        removed = [from_identities[iid] for iid in sorted(removed_ids)]

        # Risk changes
        risk_changes = []
        for iid in common_ids:
            old = from_identities[iid]
            new = to_identities[iid]
            if old["risk_level"] != new["risk_level"] or old["risk_score"] != new["risk_score"]:
                risk_changes.append({
                    "identity_id": iid,
                    "display_name": new["display_name"],
                    "old_risk_level": old["risk_level"],
                    "new_risk_level": new["risk_level"],
                    "old_risk_score": old["risk_score"],
                    "new_risk_score": new["risk_score"],
                    "score_delta": new["risk_score"] - old["risk_score"],
                })
        risk_changes.sort(key=lambda x: abs(x["score_delta"]), reverse=True)

        # Risk distribution comparison
        def _risk_dist(id_set):
            dist = {"critical": 0, "high": 0, "medium": 0, "low": 0, "info": 0}
            for ident in id_set.values():
                rl = ident.get("risk_level", "info")
                if rl in dist:
                    dist[rl] += 1
                else:
                    dist["info"] += 1
            return dist

        comparison = {
            "from_date": from_date,
            "to_date": to_date,
            "from_run": {
                "run_id": from_run_id,
                "completed_at": from_run[1].isoformat() if from_run[1] else None,
                "total_identities": len(from_identities),
            },
            "to_run": {
                "run_id": to_run_id,
                "completed_at": to_run[1].isoformat() if to_run[1] else None,
                "total_identities": len(to_identities),
            },
            "summary": {
                "added_count": len(added),
                "removed_count": len(removed),
                "risk_changed_count": len(risk_changes),
                "net_identity_change": len(to_identities) - len(from_identities),
            },
            "from_risk_distribution": _risk_dist(from_identities),
            "to_risk_distribution": _risk_dist(to_identities),
            "added_identities": added[:50],
            "removed_identities": removed[:50],
            "risk_changes": risk_changes[:50],
        }

        _log(db, 'snapshot_compared', f'Snapshot comparison: {from_date} vs {to_date}', {
            'from_date': from_date, 'to_date': to_date,
            'from_run_id': from_run_id, 'to_run_id': to_run_id,
            'added': len(added), 'removed': len(removed), 'risk_changed': len(risk_changes),
        })

        return jsonify(comparison)
    finally:
        cursor.close()
        db.close()


def get_drift_report(run_id: int):
    """Get drift report for a specific discovery run."""
    db = _db()
    try:
        # Try persisted report first
        report = db.get_drift_report(run_id)
        if report:
            report['created_at'] = report['created_at'].isoformat() if report.get('created_at') else None
            _log(db,'drift_reviewed', f'Drift report reviewed for run #{run_id}', {
                'run_id': run_id,
                'total_changes': report.get('total_changes', 0),
            })
            return jsonify(report)

        # Validate that the requested run is completed with identities
        cursor = db.conn.cursor()
        cursor.execute("""
            SELECT status, COALESCE(total_identities, 0) FROM discovery_runs
            WHERE id = %s AND organization_id = %s
        """, (run_id, _org_id()))
        run_row = cursor.fetchone()
        cursor.close()

        if not run_row:
            return jsonify({"error": "Discovery run not found"}), 404
        if run_row[0] != 'completed':
            return jsonify({"error": f"Cannot compute drift for run in '{run_row[0]}' status — only completed runs are supported"}), 400
        if run_row[1] == 0:
            return jsonify({"error": "Cannot compute drift — run has 0 discovered identities"}), 400

        # Fall back to live computation: find the previous COMPLETED run (org-scoped)
        cursor = db.conn.cursor()
        cursor.execute("""
            SELECT id FROM discovery_runs
            WHERE status = 'completed' AND id < %s AND organization_id = %s
              AND completed_at IS NOT NULL AND COALESCE(total_identities, 0) > 0
            ORDER BY id DESC
            LIMIT 1
        """, (run_id, _org_id()))
        prev_row = cursor.fetchone()
        cursor.close()

        if not prev_row:
            return jsonify({"error": "No previous run to compare against"}), 404

        previous_run_id = prev_row[0]
        detector = DriftDetector(db)
        result = detector.compare_runs_v2(run_id, previous_run_id)
        changes = result['legacy']
        events = result['events']

        # Persist for future use
        db.save_drift_report(run_id, previous_run_id, changes, events=events)

        # Intelligence enrichment (non-critical)
        intel_summary = {}
        try:
            from app.engines.analysis import DriftIntelligenceEngine
            intel = DriftIntelligenceEngine(db)
            result = intel.enrich(events, run_id, previous_run_id)
            events = result['events']
            intel_summary = {
                'max_severity': result.get('max_severity'),
                'privilege_escalation_count': result.get('privilege_escalation_count', 0),
                'attack_path_created_count': result.get('attack_path_created_count', 0),
                'identity_resurrection_count': result.get('identity_resurrection_count', 0),
            }
        except Exception:
            try: db.conn.rollback()
            except Exception: pass

        return jsonify({
            "current_run_id": run_id,
            "previous_run_id": previous_run_id,
            "new_identities_count": len(changes.get('new_identities', [])),
            "removed_identities_count": len(changes.get('removed_identities', [])),
            "permission_changes_count": len(changes.get('permission_changes', [])),
            "risk_changes_count": len(changes.get('risk_changes', [])),
            "credential_changes_count": len(changes.get('credential_changes', [])),
            "total_changes": sum(len(v) for v in changes.values() if isinstance(v, list)),
            "changes": changes,
            "events": events,
            **intel_summary,
        })
    finally:
        db.close()


