def get_drift_history():
    """Get drift report history for change timeline."""
    db = _db()
    try:
        limit = min(request.args.get('limit', 20, type=int), MAX_LIMIT)
        conn_id = _connection_id()

        # Auto-generate drift reports if none exist yet
        org_id = _org_id()
        try:
            cursor = db.conn.cursor()
            cursor.execute("SELECT COUNT(*) FROM drift_reports WHERE organization_id = %s", (org_id,))
            drift_count = cursor.fetchone()[0]
            cursor.close()
            if drift_count == 0:
                _backfill_drift_reports(db, org_id)
        except Exception:
            try:
                db.conn.rollback()
            except Exception:
                pass

        reports = db.get_drift_history(limit=limit, connection_id=conn_id)

        for r in reports:
            r['created_at'] = r['created_at'].isoformat() if r.get('created_at') else None
            r['run_completed_at'] = r['run_completed_at'].isoformat() if r.get('run_completed_at') else None

        return jsonify({"count": len(reports), "reports": reports})
    finally:
        db.close()


def _backfill_drift_reports(db, org_id):
    """Generate drift reports for all consecutive completed run pairs."""
    from app.engines.drift_detector import DriftDetector
    cursor = db.conn.cursor()
    cursor.execute("""
        SELECT id FROM discovery_runs
        WHERE organization_id = %s AND status = 'completed'
          AND cloud_connection_id IS NOT NULL AND cloud_connection_id > 0
          AND completed_at IS NOT NULL
          AND COALESCE(total_identities, 0) > 0
        ORDER BY id ASC
    """, (org_id,))
    run_ids = [r[0] for r in cursor.fetchall()]
    cursor.close()

    if len(run_ids) < 2:
        return

    detector = DriftDetector(db)
    for i in range(1, len(run_ids)):
        prev_id, curr_id = run_ids[i - 1], run_ids[i]
        try:
            result = detector.compare_runs_v2(curr_id, prev_id)
            db.save_drift_report(curr_id, prev_id, result['legacy'], events=result['events'])
        except Exception as e:
            try:
                db.conn.rollback()
            except Exception:
                pass


def generate_drift_reports():
    """POST /api/drift/generate — manually trigger drift report generation."""
    db = _db()
    try:
        org_id = _org_id()
        _backfill_drift_reports(db, org_id)

        cursor = db.conn.cursor()
        cursor.execute("SELECT COUNT(*) FROM drift_reports WHERE organization_id = %s", (org_id,))
        count = cursor.fetchone()[0]
        cursor.close()

        return jsonify({"status": "ok", "reports_generated": count})
    finally:
        db.close()


def get_trends():
    """
    Historical trend data: risk counts per discovery run for the last N completed runs.
    Used by frontend sparklines to visualize risk level trends over time.

    Query params:
        limit: Number of runs to return (default 10, max 30)
    """
    db = _db()
    cursor = db.conn.cursor()

    try:
        limit = request.args.get('limit', 10, type=int)
        limit = min(max(limit, 2), 30)
        conn_id = _connection_id()

        conn_filter = "AND dr.cloud_connection_id IS NOT NULL AND dr.cloud_connection_id > 0"
        params = [_org_id()]
        if conn_id:
            conn_filter += " AND dr.cloud_connection_id = %s"
            params.append(conn_id)
        params.append(limit)

        cursor.execute(
            f"""
            SELECT * FROM (
                SELECT
                    dr.id,
                    dr.completed_at,
                    dr.total_identities,
                    dr.critical_count,
                    dr.high_count,
                    dr.medium_count,
                    dr.low_count,
                    COALESCE((
                        SELECT COUNT(*)
                        FROM identities i
                        WHERE i.discovery_run_id = dr.id
                          AND i.activity_status IN ('stale', 'inactive')
                    ), 0) as dormant_count,
                    CASE WHEN COALESCE(dr.total_identities, 0) > 0
                        THEN ROUND(
                            (COALESCE(dr.total_identities, 0)
                             - COALESCE(dr.critical_count, 0)
                             - COALESCE(dr.high_count, 0)
                             - COALESCE(dr.medium_count, 0)
                            )::numeric / dr.total_identities * 100, 1
                        )
                        ELSE 0
                    END as posture_score,
                    COALESCE((
                        SELECT ROUND(AVG(COALESCE(i.risk_score, 0))::numeric, 1)
                        FROM identities i
                        WHERE i.discovery_run_id = dr.id
                    ), 0) as avg_risk_score
                FROM discovery_runs dr
                WHERE dr.status = 'completed' AND dr.organization_id = %s
                  {conn_filter}
                ORDER BY dr.id DESC
                LIMIT %s
            ) sub ORDER BY sub.id ASC
            """,
            tuple(params),
        )
        rows = cursor.fetchmany(MAX_QUERY_ROWS)

        # Already in chronological order (oldest first) — sorted by SQL subquery
        runs = []
        for r in rows:
            runs.append({
                "run_id": r[0],
                "date": r[1].isoformat() if r[1] else None,
                "total": r[2] or 0,
                "critical": r[3] or 0,
                "high": r[4] or 0,
                "medium": r[5] or 0,
                "low": r[6] or 0,
                "dormant": r[7] or 0,
                "posture_score": float(r[8] or 0),
                "avg_risk_score": float(r[9] or 0),
            })

        return jsonify({
            "count": len(runs),
            "runs": runs,
        })

    finally:
        cursor.close()
        db.close()


def get_trends_velocity():
    """GET /api/trends/velocity — risk level inflow/outflow between consecutive runs."""
    db = _db()
    cursor = db.conn.cursor()
    try:
        limit = min(max(request.args.get('limit', 10, type=int), 2), 20)
        conn_id = _connection_id()

        conn_filter = "AND cloud_connection_id IS NOT NULL AND cloud_connection_id > 0"
        params = [_org_id()]
        if conn_id:
            conn_filter += " AND cloud_connection_id = %s"
            params.append(conn_id)
        params.append(limit)

        cursor.execute(f"""
            SELECT * FROM (
                SELECT id, completed_at FROM discovery_runs
                WHERE status = 'completed' AND organization_id = %s
                  {conn_filter}
                ORDER BY id DESC LIMIT %s
            ) sub ORDER BY sub.id ASC
        """, tuple(params))
        runs = cursor.fetchmany(MAX_QUERY_ROWS)

        if len(runs) < 2:
            return jsonify({"transitions": [], "retention": {}})

        LEVELS = ['critical', 'high', 'medium', 'low']
        transitions = []

        for i in range(1, len(runs)):
            prev_run_id = runs[i - 1][0]
            curr_run_id = runs[i][0]
            curr_date = runs[i][1]

            cursor.execute("""
                SELECT
                    COALESCE(prev.risk_level, '__new__') as from_level,
                    COALESCE(curr.risk_level, '__removed__') as to_level,
                    COUNT(*) as cnt
                FROM (
                    SELECT identity_id, risk_level
                    FROM identities WHERE discovery_run_id = %s
                ) prev
                FULL OUTER JOIN (
                    SELECT identity_id, risk_level
                    FROM identities WHERE discovery_run_id = %s
                ) curr ON prev.identity_id = curr.identity_id
                WHERE COALESCE(prev.risk_level, '') != COALESCE(curr.risk_level, '')
                GROUP BY from_level, to_level
            """, (prev_run_id, curr_run_id))

            inflow = {l: 0 for l in LEVELS}
            outflow = {l: 0 for l in LEVELS}

            for from_lvl, to_lvl, cnt in cursor.fetchall():
                if to_lvl in LEVELS:
                    inflow[to_lvl] += cnt
                if from_lvl in LEVELS:
                    outflow[from_lvl] += cnt

            net = {l: inflow[l] - outflow[l] for l in LEVELS}

            transitions.append({
                "run_id": curr_run_id,
                "date": curr_date.isoformat() if curr_date else None,
                "prev_run_id": prev_run_id,
                "inflow": inflow,
                "outflow": outflow,
                "net": net,
            })

        # Retention rates for latest transition
        retention = {}
        if transitions:
            latest = transitions[-1]
            for level in ['critical', 'high']:
                cursor.execute("""
                    SELECT
                        COUNT(*) FILTER (WHERE curr.risk_level = %s) as retained,
                        COUNT(*) as total
                    FROM identities prev
                    JOIN identities curr
                        ON curr.identity_id = prev.identity_id
                        AND curr.discovery_run_id = %s
                    WHERE prev.discovery_run_id = %s
                      AND prev.risk_level = %s
                """, (level, latest["run_id"], latest["prev_run_id"], level))
                row = cursor.fetchone()
                total = row[1] or 0
                retained = row[0] or 0
                retention[level] = {
                    "retained": retained,
                    "total": total,
                    "rate": round(retained / total * 100, 1) if total > 0 else 0,
                }

        return jsonify({"transitions": transitions, "retention": retention})
    finally:
        cursor.close()
        db.close()


def get_identity_risk_history(identity_id):
    """GET /api/identities/<id>/risk-history — compact risk score trajectory for sparkline."""
    db = _db()
    cursor = db.conn.cursor()
    try:
        limit = min(max(request.args.get('limit', 20, type=int), 2), 50)
        conn_id = _connection_id()
        org_id = _org_id()

        conn_filter = "AND dr.cloud_connection_id IS NOT NULL AND dr.cloud_connection_id > 0"
        params = [identity_id, org_id, org_id]
        if conn_id:
            conn_filter += " AND dr.cloud_connection_id = %s"
            params.append(conn_id)
        params.append(limit)

        # Join through cloud_connections to enforce connector ownership
        cursor.execute(f"""
            SELECT * FROM (
                SELECT i.discovery_run_id, dr.completed_at,
                       COALESCE(i.risk_score, 0) AS risk_score, i.risk_level
                FROM identities i
                JOIN discovery_runs dr ON dr.id = i.discovery_run_id
                JOIN cloud_connections cc ON cc.id = dr.cloud_connection_id
                WHERE i.identity_id = %s AND dr.status = 'completed'
                  AND dr.organization_id = %s
                  AND cc.organization_id = %s
                  {conn_filter}
                ORDER BY dr.id DESC
                LIMIT %s
            ) sub ORDER BY sub.discovery_run_id ASC
        """, tuple(params))
        rows = cursor.fetchmany(MAX_QUERY_ROWS)

        if not rows:
            return jsonify({"identity_id": identity_id, "points": []})

        points = []
        for r in rows:
            points.append({
                "run_id": r[0],
                "date": r[1].isoformat() if r[1] else None,
                "risk_score": int(r[2]),
                "risk_level": r[3] or "info",
            })

        return jsonify({"identity_id": identity_id, "points": points})
    finally:
        cursor.close()
        db.close()


def get_batch_risk_history():
    """POST /api/identities/risk-history/batch — batch risk score histories for sparklines."""
    db = _db()
    cursor = db.conn.cursor()
    try:
        body = request.get_json(silent=True) or {}
        identity_ids = body.get("identity_ids", [])
        run_limit = min(body.get("limit", 10), 20)

        if not identity_ids or len(identity_ids) > 200:
            return jsonify({"error": "Provide 1-200 identity_ids"}), 400

        org_id = _org_id()
        conn_id = _connection_id()
        conn_filter = "AND dr.cloud_connection_id IS NOT NULL AND dr.cloud_connection_id > 0"
        params = [org_id]
        if conn_id:
            conn_filter += " AND dr.cloud_connection_id = %s"
            params.append(conn_id)
        params.append(run_limit)

        cursor.execute(f"""
            SELECT dr.id FROM discovery_runs dr
            JOIN cloud_connections cc ON cc.id = dr.cloud_connection_id
            WHERE dr.status = 'completed' AND dr.organization_id = %s
              AND cc.organization_id = dr.organization_id
              {conn_filter}
            ORDER BY dr.id DESC LIMIT %s
        """, tuple(params))
        run_ids = [r[0] for r in cursor.fetchall()]

        if not run_ids:
            return jsonify({"histories": {}})

        # Join through discovery_runs + cloud_connections to enforce
        # connector ownership — never return data from other orgs
        cursor.execute("""
            SELECT i.identity_id, i.discovery_run_id, COALESCE(i.risk_score, 0)
            FROM identities i
            JOIN discovery_runs dr ON dr.id = i.discovery_run_id
            JOIN cloud_connections cc ON cc.id = dr.cloud_connection_id
            WHERE i.identity_id = ANY(%s)
              AND i.discovery_run_id = ANY(%s)
              AND cc.organization_id = %s
            ORDER BY i.identity_id, i.discovery_run_id ASC
        """, (identity_ids, run_ids, org_id))

        histories = {}
        for iid, rid, score in cursor.fetchall():
            if iid not in histories:
                histories[iid] = []
            histories[iid].append(int(score))

        return jsonify({"histories": histories})
    finally:
        cursor.close()
        db.close()


