def trigger_discovery():
    """Trigger a manual discovery run in a background thread.
    Accepts optional JSON body: {connection_id: int} to scan a single connection.
    """
    guard = _demo_write_guard()
    if guard:
        return guard

    import threading
    from app.scheduler import trigger_manual_discovery

    tid = _org_id()
    tname = g.current_user.get('org_name') if hasattr(g, 'current_user') and g.current_user else None

    # Optional: scan only a specific connection
    conn_id = None
    data = request.get_json(silent=True)
    if data and data.get('connection_id'):
        try:
            conn_id = int(data['connection_id'])
        except (ValueError, TypeError):
            pass

    # Phase 3: Concurrency guard — reject if active job for this connection
    if conn_id:
        admin_db = Database(_admin_reason='trigger_discovery: check active job')
        try:
            active = admin_db.get_active_snapshot_job(conn_id)
            if active:
                return jsonify({
                    'error': 'Discovery already running for this connection',
                    'active_job': active,
                }), 409
        finally:
            admin_db.close()

    # Phase 13: Plan limit enforcement
    # Free plan: scanning allowed (identity cap enforced at save time).
    # Trial expired: scan blocked (data preserved, must upgrade).
    admin_db = Database(_admin_reason='trigger_discovery: plan limits')
    try:
        # Trial expiry check — blocks new scans but preserves existing data
        ok, err = _check_tier_limits(admin_db, tid)
        if not ok:
            return jsonify(err), 403
    finally:
        admin_db.close()

    # Validate org has at least one connected cloud connection
    if not conn_id:
        admin_db = Database(_admin_reason='trigger_discovery: check connections')
        try:
            connections = admin_db.get_cloud_connections(tid, include_secrets=False)
            connected = [c for c in connections if c.get('status') == 'connected']
            if not connected:
                return jsonify({
                    "error": "Discovery requires a valid cloud connection. "
                    "Add and test a cloud connection before triggering discovery."
                }), 400
        finally:
            admin_db.close()

    def _run():
        try:
            trigger_manual_discovery(db_org_id=tid, org_name=tname,
                                     connection_id=conn_id)
        except Exception as e:
            try: db.conn.rollback()
            except Exception: pass
            logging.getLogger(__name__).error(f"Manual discovery failed: {e}")

    thread = threading.Thread(target=_run, daemon=True)
    thread.start()

    db = _db()
    try:
        msg = 'Manual discovery run triggered'
        if conn_id:
            msg += f' for connection {conn_id}'
        _log(db, 'discovery_triggered', msg)
    finally:
        db.close()

    msg = "Discovery run triggered."
    if conn_id:
        msg = f"Discovery triggered for connection {conn_id}."
    msg += " Check /api/runs for progress."
    return jsonify({"status": "started", "message": msg}), 202


