def delete_notification_handler(notification_id):
    """DELETE /api/notifications/<id> — delete a notification."""
    db = _db()
    try:
        existing = db.get_notification(notification_id)
        if not existing:
            return jsonify({"error": "Notification not found"}), 404

        db.delete_notification(notification_id)
        return jsonify({"status": "deleted", "id": notification_id})
    finally:
        db.close()


def _normalize_category_key(raw_category: str) -> str:
    """
    Normalize category value to canonical snake_case key.
    Handles legacy display names from old database records.
    """
    if not raw_category:
        return 'unknown'

    c = raw_category.lower().strip()

    # Already canonical
    if c in ('service_principal', 'managed_identity_system', 'managed_identity_user',
             'human_user', 'guest', 'microsoft_internal', 'unknown'):
        return c

    # Legacy display name mappings
    if c in ('service principal', 'serviceprincipal'):
        return 'service_principal'
    if c in ('user', 'users', 'human user'):
        return 'human_user'
    if c in ('guest', 'guest user'):
        return 'guest'
    if 'user assigned' in c or 'user-assigned' in c or c == 'managed identity (user)':
        return 'managed_identity_user'
    if 'system assigned' in c or 'system-assigned' in c or c == 'managed identity (system)':
        return 'managed_identity_system'
    if 'microsoft' in c and 'internal' in c:
        return 'microsoft_internal'
    if 'managed identity' in c or 'managed_identity' in c:
        # Default managed identity to system if not specified
        return 'managed_identity_system'

    return 'unknown'


def _is_microsoft_internal_identity(display_name: str, identity_type: str) -> bool:
    """
    Detect if an identity is a Microsoft internal/first-party service.
    Uses display name patterns that reliably indicate Microsoft services.

    This is used at query time to properly categorize existing data that
    wasn't categorized during discovery.

    Args:
        display_name: The identity's display name
        identity_type: The identity type (user, service_principal, etc.)

    Returns:
        True if this is a Microsoft internal service, False otherwise
    """
    if not display_name:
        return False

    # Only apply to service principals
    if identity_type and identity_type.lower() not in ('service_principal', 'serviceprincipal'):
        return False

    name = display_name.lower().strip()

    # Microsoft product/service name patterns
    # These are reliable indicators of Microsoft first-party services
    microsoft_patterns = [
        # Explicit Microsoft branding
        'microsoft ',
        'ms-',
        'ms ',

        # Office 365 / M365
        'office 365',
        'office365',
        'o365',
        'm365 ',

        # Azure services
        'azure ',

        # Specific Microsoft products
        'sharepoint',
        'exchange ',
        'teams ',
        'intune',
        'dynamics ',
        'power bi',
        'powerbi',
        'powerapps',
        'power apps',
        'power platform',
        'onedrive',
        'onenote',
        'outlook',
        'skype',
        'yammer',
        'viva ',
        'cortana',
        'bing',
        'windows ',
        'graph ',

        # Azure AD / Entra
        'aad',
        'entra',
        'active directory',

        # Common Microsoft service patterns
        'substrate',
        'dataverse',
        'common data service',
    ]

    # Check if name starts with or contains Microsoft patterns
    for pattern in microsoft_patterns:
        if name.startswith(pattern) or f' {pattern}' in f' {name}':
            return True

    # Additional specific service names that are Microsoft internal
    microsoft_service_names = [
        'managed service identity',
        'device registration service',
        'billing rp',
        'signup',
        'conferencing virtual assistant',
        'conference auto attendant',
        'connectors',
        'pushchannel',
        'narada notification service',
        'idsproduction',
        'ids-prod',
        'safelinks',
        'sway',
        'ic3 ',
        'ocaas',
        'cap ',
        'cab',
        'oms',
        'pim',
        'spauthevent',
        'subscriptionrp',
        'weveengine',
        'signal b2',
        'privacy management',
        'policy administration',
        'request approvals',
        'group configuration',
        'people profile',
        'meeting migration',
        'media analysis',
        'messaging bot',
        'customer experience',
        'customer service',
        'compliance',
        'sales insights',
        'portfolios',
        'project work',
        'deployment scheduler',
        'deploymentscheduler',
        'configuration manager',
        'cloud licensing',
        'iam ',
        'ip substrate',
        'mcapi',
        'mro ',
        'ppe-',
        'aci api',
        'aciapi',
        # Additional Microsoft services that don't follow common patterns
        'azuresupportcenter',
        'support center',
        'capacitypolicyassignment',
        'capacity policy',
        'centralized deployment',
        'cloudlicensingsystem',
        'ipsubstrate',
        'microsoft.smit',
        '.smit',
        'office shredding',
        'shredding service',
        'officeclientservice',
        'officeservicesmanager',
        'oneprofile',
        'productslifecycle',
        'products lifecycle',
        'projectworkmanagement',
        'salesinsights',
        'virtual visits',
        'windowsupdate',
        'windows update',
        'tenantsearchprocessors',
        'tenant search',
    ]

    for service in microsoft_service_names:
        if service in name:
            return True

    return False


def get_overview_insights():
    """
    Aggregated insights for the Overview page:
    - Privilege tier distribution (T0-T3) with T0/T1 identity names
    - Action items: dormant privileged, expiring credentials, unowned SPNs
    - Lists of dormant privileged identities and unowned SPNs
    """
    db = _db()
    cursor = db.conn.cursor()
    try:
        run_ids = _latest_run_ids(cursor, _org_id(), _connection_id())
        if not run_ids:
            return jsonify({"error": "No completed discovery runs found"}), 404

        # Privilege tier for each identity
        cursor.execute(f"""
            SELECT
                i.identity_id,
                i.display_name,
                i.identity_category,
                i.risk_level,
                i.activity_status,
                COALESCE(i.owner_count, 0) as owner_count,
                i.credential_expiration,
                COALESCE(i.cloud, 'azure') as cloud,
                CASE
                    WHEN EXISTS (
                        SELECT 1 FROM entra_role_assignments era
                        WHERE era.identity_db_id = i.id
                        AND LOWER(era.role_name) IN (
                            'global administrator', 'privileged role administrator',
                            'privileged authentication administrator',
                            'partner tier2 support', 'security operator',
                            'application administrator', 'cloud application administrator',
                            'hybrid identity administrator',
                            'domain name administrator',
                            'external identity provider administrator'
                        )
                    ) THEN 0
                    WHEN EXISTS (
                        SELECT 1 FROM role_assignments ra
                        WHERE ra.identity_db_id = i.id
                        AND LOWER(ra.role_name) IN (
                            'owner', 'user access administrator'
                        )
                        AND (ra.scope IS NULL OR ra.scope = '/' OR ra.scope LIKE '/subscriptions/%%'
                             AND ra.scope NOT LIKE '/subscriptions/%%/resourceGroups/%%')
                    ) THEN 0
                    WHEN EXISTS (
                        SELECT 1 FROM entra_role_assignments era
                        WHERE era.identity_db_id = i.id
                        AND LOWER(era.role_name) IN (
                            'user administrator', 'exchange administrator',
                            'sharepoint administrator', 'teams administrator',
                            'intune administrator', 'conditional access administrator',
                            'authentication administrator',
                            'groups administrator', 'license administrator',
                            'password administrator', 'security administrator',
                            'compliance administrator', 'billing administrator',
                            'dynamics 365 administrator', 'power platform administrator',
                            'azure devops administrator', 'azure information protection administrator',
                            'helpdesk administrator'
                        )
                    ) THEN 1
                    WHEN EXISTS (
                        SELECT 1 FROM role_assignments ra
                        WHERE ra.identity_db_id = i.id
                        AND LOWER(ra.role_name) IN (
                            'owner', 'contributor', 'user access administrator'
                        )
                    ) THEN 1
                    WHEN EXISTS (
                        SELECT 1 FROM entra_role_assignments era
                        WHERE era.identity_db_id = i.id
                    ) THEN 2
                    WHEN EXISTS (
                        SELECT 1 FROM role_assignments ra
                        WHERE ra.identity_db_id = i.id
                    ) THEN 2
                    WHEN EXISTS (
                        SELECT 1 FROM graph_api_permissions gp
                        WHERE gp.identity_db_id = i.id
                        AND gp.risk_level IN ('critical', 'high')
                    ) THEN 2
                    ELSE 3
                END as privilege_tier
            FROM identities i
            WHERE i.discovery_run_id = ANY(%s)
            {HIDE_MICROSOFT_SQL}
        """, (run_ids,))

        rows = cursor.fetchall()

        tier_counts = {0: 0, 1: 0, 2: 0, 3: 0}
        tier_identities = {0: [], 1: []}  # Only list T0/T1 names
        dormant_privileged = []
        unowned_spns = []
        expiring_creds = 0

        now = datetime.now(timezone.utc)

        for r in rows:
            identity_id, display_name, category, risk_level, activity_status, owner_count, cred_exp, cloud, tier = r
            display_name = display_name or ''
            category = _normalize_category_key(category or '')
            tier = int(tier) if tier is not None else 3

            tier_counts[tier] = tier_counts.get(tier, 0) + 1

            identity_stub = {
                "identity_id": identity_id,
                "display_name": display_name,
                "risk_level": risk_level or "info",
                "category": category,
                "cloud": cloud or "azure",
            }

            # Collect T0/T1 names
            if tier <= 1:
                tier_identities[tier].append(identity_stub)

            # Dormant privileged (T0/T1 + stale)
            if tier <= 1 and activity_status in ('stale', 'never_used'):
                dormant_privileged.append({
                    **identity_stub,
                    "tier": tier,
                    "activity_status": activity_status,
                })

            # Expiring credentials (within 30 days)
            if cred_exp:
                try:
                    days_left = (cred_exp - now).days
                    if 0 <= days_left <= 30:
                        expiring_creds += 1
                except Exception:
                    pass

            # Unowned service principals (all risk levels)
            if category == 'service_principal' and (owner_count or 0) == 0:
                unowned_spns.append(identity_stub)

        # ── Risk Reduction Plan ────────────────────────────────────
        total_count = len(rows)
        plan = []

        # Credential rotation
        if expiring_creds > 0:
            est = round((expiring_creds / max(total_count, 1)) * 20, 1)  # 20% weight for P2
            plan.append({
                "priority": "critical" if expiring_creds > 5 else "high",
                "action": "credential_rotation",
                "description": f"Rotate {expiring_creds} expired/expiring credential{'s' if expiring_creds != 1 else ''} on privileged service principals",
                "affected_count": expiring_creds,
                "estimated_risk_reduction_pct": min(est, 20),
                "link": "/identities?credential_status=expiring_soon",
            })

        # Dormant privileged cleanup
        if len(dormant_privileged) > 0:
            est = round((len(dormant_privileged) / max(total_count, 1)) * 30, 1)  # 30% weight for P1
            plan.append({
                "priority": "critical",
                "action": "dormant_cleanup",
                "description": f"Disable or remove {len(dormant_privileged)} dormant T0/T1 identit{'ies' if len(dormant_privileged) != 1 else 'y'} with no recent activity",
                "affected_count": len(dormant_privileged),
                "estimated_risk_reduction_pct": min(est, 30),
                "link": "/identities?activity_status=dormant&privilege_tier=0,1",
            })

        # Unowned SPN assignment
        if len(unowned_spns) > 0:
            est = round((len(unowned_spns) / max(total_count, 1)) * 10, 1)  # 10% weight for P5
            plan.append({
                "priority": "high",
                "action": "ownership_assignment",
                "description": f"Assign owners to {len(unowned_spns)} unowned service principal{'s' if len(unowned_spns) != 1 else ''}",
                "affected_count": len(unowned_spns),
                "estimated_risk_reduction_pct": min(est, 10),
                "link": "/identities?identity_category=service_principal&owner_status=unowned",
            })

        # T0 footprint reduction
        if tier_counts[0] > 2:
            excess = tier_counts[0] - 2
            est = round((excess / max(total_count, 1)) * 30, 1)
            plan.append({
                "priority": "high",
                "action": "privilege_reduction",
                "description": f"Reduce T0 footprint by {excess} — only 2 Global Admin accounts recommended",
                "affected_count": excess,
                "estimated_risk_reduction_pct": min(est, 15),
                "link": "/identities?privilege_tier=0",
            })

        # Guest access review
        guest_privileged = [row for row in rows if _normalize_category_key(row[2] or '') == 'guest'
                           and (int(row[8]) if row[8] is not None else 3) <= 2]  # tier <= 2 means has roles
        if len(guest_privileged) > 0:
            est = round((len(guest_privileged) / max(total_count, 1)) * 20, 1)
            plan.append({
                "priority": "medium",
                "action": "guest_access_review",
                "description": f"Review {len(guest_privileged)} guest identit{'ies' if len(guest_privileged) != 1 else 'y'} with assigned roles",
                "affected_count": len(guest_privileged),
                "estimated_risk_reduction_pct": min(est, 10),
                "link": "/identities?identity_category=guest",
            })

        # Sort by estimated risk reduction descending
        plan.sort(key=lambda x: x['estimated_risk_reduction_pct'], reverse=True)

        return jsonify({
            "tier_distribution": {
                "t0": {"count": tier_counts[0], "identities": tier_identities[0]},
                "t1": {"count": tier_counts[1], "identities": tier_identities[1]},
                "t2": {"count": tier_counts[2]},
                "t3": {"count": tier_counts[3]},
            },
            "action_items": {
                "dormant_privileged": len(dormant_privileged),
                "expiring_credentials": expiring_creds,
                "unowned_spns": len(unowned_spns),
            },
            "dormant_privileged": dormant_privileged[:10],
            "unowned_spns": unowned_spns[:10],
            "risk_reduction_plan": plan[:6],
        })
    finally:
        cursor.close()
        db.close()


def get_attack_surface_score():
    """
    Compute the 6-pillar Identity Attack Surface Score (0-100).

    Pillars:
      P1 Effective Privilege (30%) — % of identities at T0/T1
      P2 Credential Risk     (20%) — % with expired/expiring creds
      P3 Trust & Federation  (20%) — % guest/external with privileged roles
      P4 Usage Dormancy      (10%) — % stale/never_used
      P5 Ownership Gov       (10%) — % SPNs without owners
      P6 External Exposure   (10%) — % with tenant-wide scope

    Higher score = worse posture (more exposed).
    """
    db = _db()
    cursor = db.conn.cursor()
    try:
        run_ids = _latest_run_ids(cursor, _org_id(), _connection_id())
        if not run_ids:
            return jsonify({"error": "No completed discovery runs found"}), 404

        cursor.execute(f"""
            SELECT
                -- totals
                COUNT(*) as total,
                COUNT(*) FILTER (WHERE COALESCE(identity_category, '') NOT IN ('microsoft_internal')) as total_excl_msft,

                -- P1: Privilege (T0/T1 via subquery)
                COUNT(*) FILTER (WHERE (
                    EXISTS (SELECT 1 FROM entra_role_assignments era WHERE era.identity_db_id = i.id
                        AND LOWER(era.role_name) IN (
                            'global administrator','privileged role administrator',
                            'privileged authentication administrator',
                            'application administrator','cloud application administrator',
                            'hybrid identity administrator','domain name administrator',
                            'external identity provider administrator'
                        ))
                    OR EXISTS (SELECT 1 FROM role_assignments ra WHERE ra.identity_db_id = i.id
                        AND LOWER(ra.role_name) IN ('owner','user access administrator')
                        AND (ra.scope IS NULL OR ra.scope = '/' OR (ra.scope LIKE '/subscriptions/%%'
                             AND ra.scope NOT LIKE '/subscriptions/%%/resourceGroups/%%')))
                )) as t0_count,

                COUNT(*) FILTER (WHERE (
                    EXISTS (SELECT 1 FROM entra_role_assignments era WHERE era.identity_db_id = i.id
                        AND LOWER(era.role_name) IN (
                            'user administrator','exchange administrator',
                            'sharepoint administrator','teams administrator',
                            'security administrator','conditional access administrator',
                            'authentication administrator','helpdesk administrator'
                        ))
                    OR EXISTS (SELECT 1 FROM role_assignments ra WHERE ra.identity_db_id = i.id
                        AND LOWER(ra.role_name) IN ('owner','contributor','user access administrator'))
                )) as t0t1_count,

                -- P1b: Dormant privileged (stale/never_used with T0/T1 role)
                COUNT(*) FILTER (WHERE activity_status IN ('stale', 'never_used')
                    AND (
                    EXISTS (SELECT 1 FROM entra_role_assignments era WHERE era.identity_db_id = i.id
                        AND LOWER(era.role_name) IN (
                            'global administrator','privileged role administrator',
                            'privileged authentication administrator',
                            'application administrator','cloud application administrator',
                            'user administrator','exchange administrator',
                            'sharepoint administrator','teams administrator',
                            'security administrator','conditional access administrator',
                            'authentication administrator','helpdesk administrator'
                        ))
                    OR EXISTS (SELECT 1 FROM role_assignments ra WHERE ra.identity_db_id = i.id
                        AND LOWER(ra.role_name) IN ('owner','contributor','user access administrator'))
                )) as dormant_privileged,

                -- P2: Credential risk
                COUNT(*) FILTER (WHERE credential_count > 0) as has_creds,
                COUNT(*) FILTER (WHERE credential_expiration IS NOT NULL
                    AND credential_expiration < NOW()) as expired_creds,
                COUNT(*) FILTER (WHERE credential_expiration IS NOT NULL
                    AND credential_expiration >= NOW()
                    AND credential_expiration < NOW() + INTERVAL '30 days') as expiring_creds,

                -- P3: Trust (guest/external with roles)
                COUNT(*) FILTER (WHERE COALESCE(identity_category, '') = 'guest') as guest_count,
                COUNT(*) FILTER (WHERE COALESCE(identity_category, '') = 'guest' AND (
                    EXISTS (SELECT 1 FROM entra_role_assignments era WHERE era.identity_db_id = i.id)
                    OR EXISTS (SELECT 1 FROM role_assignments ra WHERE ra.identity_db_id = i.id)
                )) as guest_with_roles,
                COUNT(*) FILTER (WHERE COALESCE(is_federated, false) = true) as federated_count,

                -- P4: Usage dormancy (exclude federated identities with no sign-in logs — they are "likely active")
                COUNT(*) FILTER (WHERE activity_status IN ('stale', 'never_used')
                    AND NOT (activity_status = 'never_used' AND federated_workload_type IS NOT NULL)) as dormant_count,
                COUNT(*) FILTER (WHERE activity_status IN ('stale', 'never_used', 'inactive')
                    AND NOT (activity_status = 'never_used' AND federated_workload_type IS NOT NULL)
                    AND COALESCE(identity_category, '') IN ('service_principal', 'managed_identity_system', 'managed_identity_user')) as dormant_nhi_count,

                -- P5: Ownership — SSOT uses recommended_action='ORPHANED' (set by lineage engine)
                COUNT(*) FILTER (WHERE i.recommended_action = 'ORPHANED'
                    AND i.deleted_at IS NULL
                    AND COALESCE(is_microsoft_system, FALSE) = FALSE) as unowned_spns,
                COUNT(*) FILTER (WHERE COALESCE(identity_category, '') IN ('service_principal', 'managed_identity_user')
                    AND COALESCE(is_microsoft_system, FALSE) = FALSE) as total_spns,

                -- P6: External exposure (tenant-wide scope)
                COUNT(*) FILTER (WHERE (
                    EXISTS (SELECT 1 FROM entra_role_assignments era WHERE era.identity_db_id = i.id
                        AND (era.directory_scope IS NULL OR era.directory_scope = '/'))
                    OR EXISTS (SELECT 1 FROM role_assignments ra WHERE ra.identity_db_id = i.id
                        AND ra.scope_type = 'tenant')
                )) as tenant_scope_count,

                -- NHI breakdown
                COUNT(*) FILTER (WHERE COALESCE(identity_category, '') = 'human_user') as human_count,
                COUNT(*) FILTER (WHERE COALESCE(identity_category, '') = 'service_principal') as sp_count,
                COUNT(*) FILTER (WHERE COALESCE(identity_category, '') = 'managed_identity_system') as mi_system_count,
                COUNT(*) FILTER (WHERE COALESCE(identity_category, '') = 'managed_identity_user') as mi_user_count,
                COUNT(*) FILTER (WHERE COALESCE(identity_category, '') = 'guest') as nhi_guest_count,

                -- NHI credential risk (SSOT: CredentialRiskSQL)
                COUNT(*) FILTER (WHERE {CredentialRiskSQL.NHI_CREDENTIAL_RISK_COUNT_FILTER}) as nhi_credential_risk_count,

                -- Credential health counts
                COUNT(*) FILTER (WHERE credential_count > 0
                    AND (credential_expiration IS NULL OR credential_expiration >= NOW() + INTERVAL '30 days')) as healthy_creds,

                -- Data completeness
                COUNT(*) FILTER (WHERE risk_score IS NOT NULL) as has_risk_score,

                -- Average risk score (source of truth for industry comparison)
                ROUND(COALESCE(AVG(i.risk_score), 0)::numeric, 1) as avg_risk_score

            FROM identities i
            WHERE i.discovery_run_id = ANY(%s)
            {HIDE_MICROSOFT_SQL}
        """, (run_ids,))

        r = cursor.fetchone()
        total = r[0] or 0
        total_excl = r[1] or 0
        t0_count = r[2] or 0
        t0t1_count = r[3] or 0
        dormant_privileged = r[4] or 0
        has_creds = r[5] or 0
        expired_creds = r[6] or 0
        expiring_creds = r[7] or 0
        guest_count = r[8] or 0
        guest_with_roles = r[9] or 0
        federated_count = r[10] or 0
        dormant_count = r[11] or 0
        dormant_nhi_count = r[12] or 0
        unowned_spns = r[13] or 0
        total_spns = r[14] or 0
        tenant_scope = r[15] or 0
        human_count = r[16] or 0
        sp_count = r[17] or 0
        mi_system_count = r[18] or 0
        mi_user_count = r[19] or 0
        nhi_guest_count = r[20] or 0
        nhi_credential_risk_count = r[21] or 0
        healthy_creds = r[22] or 0
        has_risk_score = r[23] or 0
        avg_risk_score = float(r[24] or 0)

        # P1: Effective Privilege — target < 1% at T0
        priv_pct = (t0t1_count / total_excl) * 100 if total_excl > 0 else 0.0
        p1 = min(priv_pct * 10, 100)  # 10% T0/T1 → score 100

        # P2: Credential Risk — expired + expiring as % of those with creds
        cred_risk_pct = ((expired_creds + expiring_creds) / has_creds) * 100 if has_creds > 0 else 0.0
        p2 = min(cred_risk_pct * 2, 100)  # 50% bad creds → score 100

        # P3: Trust & Federation — guest/external with roles
        trust_risk = 0
        if guest_count > 0:
            trust_risk = (guest_with_roles / max(guest_count, 1)) * 60
        trust_risk += min((federated_count / total_excl) * 200, 40) if total_excl > 0 else 0.0
        p3 = min(trust_risk, 100)

        # P4: Usage Dormancy — stale/never_used identities
        dormant_pct = (dormant_count / total_excl) * 100 if total_excl > 0 else 0.0
        p4 = min(dormant_pct * 2, 100)  # 50% dormant → score 100

        # P5: Ownership Governance — unowned SPNs
        unowned_pct = (unowned_spns / total_spns) * 100 if total_spns > 0 else 0.0
        p5 = min(unowned_pct * 1.5, 100)  # ~67% unowned → score 100

        # P6: External Exposure — tenant-wide scope
        scope_pct = (tenant_scope / total_excl) * 100 if total_excl > 0 else 0.0
        p6 = min(scope_pct * 5, 100)  # 20% tenant-wide → score 100

        # Weighted composite
        score = round(
            p1 * 0.30 + p2 * 0.20 + p3 * 0.20 +
            p4 * 0.10 + p5 * 0.10 + p6 * 0.10, 1
        )

        # Grade thresholds
        if score <= 20:
            grade, severity = 'A', 'low'
        elif score <= 40:
            grade, severity = 'B', 'moderate'
        elif score <= 60:
            grade, severity = 'C', 'high'
        elif score <= 80:
            grade, severity = 'D', 'very_high'
        else:
            grade, severity = 'F', 'critical'

        # ── NHI breakdown ──────────────────────────────────────────
        nhi_total = sp_count + mi_system_count + mi_user_count + nhi_guest_count
        nhi_pct = round((nhi_total / total_excl) * 100, 1) if total_excl > 0 else 0

        nhi_breakdown = {
            "human": human_count,
            "service_principal": sp_count,
            "managed_identity_system": mi_system_count,
            "managed_identity_user": mi_user_count,
            "guest": nhi_guest_count,
            "nhi_total": nhi_total,
            "nhi_pct": nhi_pct,
        }

        # ── Attack Opportunities ──────────────────────────────────
        # Top 5 riskiest
        cursor.execute(f"""
            SELECT i.identity_id, i.display_name, COALESCE(i.risk_score, 0) as risk_score,
                   COALESCE(i.identity_category, '') as identity_category, COALESCE(i.risk_level, 'info') as risk_level
            FROM identities i WHERE i.discovery_run_id = ANY(%s) {HIDE_MICROSOFT_SQL}
              AND i.risk_level IN ('critical','high')
            ORDER BY COALESCE(i.risk_score,0) DESC LIMIT 5
        """, (run_ids,))
        top_riskiest = [{"identity_id": row[0], "display_name": row[1] or '', "risk_score": row[2],
                         "identity_category": row[3], "risk_level": row[4]} for row in cursor.fetchall()]

        # Top 5 blast radius
        cursor.execute(f"""
            SELECT i.identity_id, i.display_name, COALESCE(i.identity_category, '') as identity_category,
                   COALESCE(i.additional_subscription_count, 0) as sub_count
            FROM identities i WHERE i.discovery_run_id = ANY(%s) {HIDE_MICROSOFT_SQL}
            ORDER BY COALESCE(i.additional_subscription_count, 0) DESC LIMIT 5
        """, (run_ids,))
        top_blast_radius = [{"identity_id": row[0], "display_name": row[1] or '', "identity_category": row[2],
                             "sub_count": row[3]} for row in cursor.fetchall()]

        # T0/T1 inline condition (privilege_tier is computed, not a real column)
        _T0T1_COND = """(
            EXISTS (SELECT 1 FROM entra_role_assignments era WHERE era.identity_db_id = i.id
                AND LOWER(era.role_name) IN (
                    'global administrator','privileged role administrator',
                    'privileged authentication administrator',
                    'application administrator','cloud application administrator',
                    'hybrid identity administrator','domain name administrator',
                    'external identity provider administrator',
                    'user administrator','exchange administrator',
                    'sharepoint administrator','teams administrator',
                    'security administrator','conditional access administrator',
                    'authentication administrator','helpdesk administrator'
                ))
            OR EXISTS (SELECT 1 FROM role_assignments ra WHERE ra.identity_db_id = i.id
                AND LOWER(ra.role_name) IN ('owner','contributor','user access administrator'))
        )"""

        # Stale privileged (dormant T0/T1)
        cursor.execute(f"""
            SELECT i.identity_id, i.display_name, COALESCE(i.identity_category, '') as identity_category,
                   COALESCE(i.activity_status, 'unknown') as activity_status
            FROM identities i WHERE i.discovery_run_id = ANY(%s) {HIDE_MICROSOFT_SQL}
              AND i.activity_status IN ('stale','never_used','inactive')
              AND {_T0T1_COND}
            LIMIT 5
        """, (run_ids,))
        stale_privileged = [{"identity_id": row[0], "display_name": row[1] or '', "identity_category": row[2],
                             "activity_status": row[3]} for row in cursor.fetchall()]

        # Privileged NHIs (T0/T1 that are SPN or MI)
        cursor.execute(f"""
            SELECT COUNT(*) FROM identities i
            WHERE i.discovery_run_id = ANY(%s) {HIDE_MICROSOFT_SQL}
            AND COALESCE(i.identity_category, '') IN ('service_principal','managed_identity_system','managed_identity_user')
            AND {_T0T1_COND}
        """, (run_ids,))
        privileged_nhi_count = _scalar(cursor, 0)

        # Multi-subscription identities (2+ subscriptions)
        cursor.execute(f"""
            SELECT COUNT(*) FROM identities i
            WHERE i.discovery_run_id = ANY(%s) {HIDE_MICROSOFT_SQL}
            AND COALESCE(i.additional_subscription_count, 0) >= 1
        """, (run_ids,))
        multi_sub_count = _scalar(cursor, 0)

        # RBAC modifiers (Owner or User Access Administrator)
        cursor.execute(f"""
            SELECT COUNT(DISTINCT i.id) FROM identities i
            JOIN role_assignments ra ON ra.identity_db_id = i.id
            WHERE i.discovery_run_id = ANY(%s) {HIDE_MICROSOFT_SQL}
            AND LOWER(ra.role_name) IN ('owner','user access administrator')
        """, (run_ids,))
        rbac_modifier_count = _scalar(cursor, 0)

        attack_opportunities = {
            "top_riskiest": top_riskiest,
            "top_blast_radius": top_blast_radius,
            "stale_privileged": stale_privileged,
            "privileged_nhi_count": privileged_nhi_count,
            "dormant_privileged_count": len(stale_privileged),
            "multi_sub_count": multi_sub_count,
            "rbac_modifier_count": rbac_modifier_count,
        }

        # ── Governance Maturity ───────────────────────────────────
        ownership_coverage_pct = round(((total_spns - unowned_spns) / total_spns) * 100, 1) if total_spns > 0 else 100
        credential_rotation_pct = round((healthy_creds / has_creds) * 100, 1) if has_creds > 0 else 100
        dormant_cleanup_pct = round(100 - (dormant_count / total_excl) * 100, 1) if total_excl > 0 else 100

        # PIM adoption: distinct identities with PIM eligible assignments vs T0/T1 count
        pim_adoption_pct = 0
        try:
            cursor.execute("SAVEPOINT gov_pim")
            cursor.execute("""
                SELECT COUNT(DISTINCT identity_db_id) FROM pim_eligible_assignments
            """)
            pim_count = _scalar(cursor, 0)
            pim_adoption_pct = round((pim_count / max(t0t1_count, 1)) * 100, 1) if t0t1_count > 0 else 0
            cursor.execute("RELEASE SAVEPOINT gov_pim")
        except Exception:
            try: cursor.connection.rollback()
            except Exception: pass
            try:
                cursor.execute("ROLLBACK TO SAVEPOINT gov_pim")
            except Exception as e:
                try: cursor.connection.rollback()
                except Exception: pass
                # Continue: read-only PIM analytics — no data mutation at risk.
                # Connection will be closed by handler teardown.
                logger.error(
                    "Savepoint rollback failed",
                    extra={"site": "handlers.py:4889", "savepoint": "gov_pim", "error": str(e)},
                    exc_info=True,
                )

        # Average remediation days
        avg_remediation_days = None
        try:
            cursor.execute("SAVEPOINT gov_rem")
            cursor.execute("""
                SELECT AVG(EXTRACT(EPOCH FROM (updated_at - created_at))/86400)
                FROM remediation_actions WHERE status = 'resolved'
            """)
            avg_val = _scalar(cursor, 0)
            avg_remediation_days = round(avg_val, 1) if avg_val is not None else None
            cursor.execute("RELEASE SAVEPOINT gov_rem")
        except Exception:
            try: cursor.connection.rollback()
            except Exception: pass
            try:
                cursor.execute("ROLLBACK TO SAVEPOINT gov_rem")
            except Exception as e:
                try: cursor.connection.rollback()
                except Exception: pass
                # Continue: read-only remediation avg — no data mutation at risk.
                # Connection will be closed by handler teardown.
                logger.error(
                    "Savepoint rollback failed",
                    extra={"site": "handlers.py:4904", "savepoint": "gov_rem", "error": str(e)},
                    exc_info=True,
                )

        # Privileged under review + access reviews done
        privileged_under_review_pct = 0
        access_reviews_done = 0
        try:
            cursor.execute("SAVEPOINT gov_rev")
            cursor.execute("SELECT COUNT(*) FROM access_reviews WHERE status = 'completed'")
            access_reviews_done = _scalar(cursor, 0)
            cursor.execute("""
                SELECT COUNT(DISTINCT ari.identity_id)
                FROM access_review_items ari
                JOIN access_reviews ar ON ar.id = ari.review_id
                WHERE ar.status = 'completed'
            """)
            reviewed = _scalar(cursor, 0)
            privileged_under_review_pct = round((reviewed / max(t0t1_count, 1)) * 100, 1)
            cursor.execute("RELEASE SAVEPOINT gov_rev")
        except Exception:
            try: cursor.connection.rollback()
            except Exception: pass
            try:
                cursor.execute("ROLLBACK TO SAVEPOINT gov_rev")
            except Exception as e:
                try: cursor.connection.rollback()
                except Exception: pass
                # Continue: read-only access-review analytics — no data mutation at risk.
                # Connection will be closed by handler teardown.
                logger.error(
                    "Savepoint rollback failed",
                    extra={"site": "handlers.py:4924", "savepoint": "gov_rev", "error": str(e)},
                    exc_info=True,
                )

        governance = {
            "ownership_coverage_pct": ownership_coverage_pct,
            "credential_rotation_pct": credential_rotation_pct,
            "pim_adoption_pct": min(pim_adoption_pct, 100),
            "dormant_cleanup_pct": dormant_cleanup_pct,
            "avg_remediation_days": avg_remediation_days,
            "privileged_under_review_pct": min(privileged_under_review_pct, 100),
            "access_reviews_done": access_reviews_done,
        }

        # ── Workload Exposure Aggregate ─────────────────────────────
        workload_agg = None
        try:
            cursor.execute("SAVEPOINT wl_agg")
            cursor.execute(f"""
                SELECT
                    COUNT(*) FILTER (WHERE COALESCE(i.exposure_score, 0) >= 80) as exp_critical,
                    COUNT(*) FILTER (WHERE COALESCE(i.exposure_score, 0) >= 60 AND COALESCE(i.exposure_score, 0) < 80) as exp_high,
                    COUNT(*) FILTER (WHERE COALESCE(i.exposure_score, 0) >= 35 AND COALESCE(i.exposure_score, 0) < 60) as exp_medium,
                    COUNT(*) FILTER (WHERE COALESCE(i.exposure_score, 0) < 35) as exp_low,
                    ROUND(COALESCE(AVG(i.privilege_score), 0), 1) as avg_privilege,
                    ROUND(COALESCE(AVG(i.credential_risk_score), 0), 1) as avg_cred,
                    ROUND(COALESCE(AVG(i.exposure_subscore), 0), 1) as avg_exposure,
                    ROUND(COALESCE(AVG(i.lifecycle_score), 0), 1) as avg_lifecycle,
                    ROUND(COALESCE(AVG(i.visibility_score), 0), 1) as avg_visibility,
                    ROUND(COALESCE(AVG(i.exposure_score), 0), 1) as avg_total,
                    COUNT(*) FILTER (WHERE COALESCE(i.lifecycle_state, '') = 'active') as lc_active,
                    COUNT(*) FILTER (WHERE COALESCE(i.lifecycle_state, '') = 'possibly_active') as lc_possibly,
                    COUNT(*) FILTER (WHERE COALESCE(i.lifecycle_state, '') = 'likely_dormant') as lc_likely_dormant,
                    COUNT(*) FILTER (WHERE COALESCE(i.lifecycle_state, '') = 'dormant') as lc_dormant,
                    COUNT(*) FILTER (WHERE COALESCE(i.lifecycle_state, 'blind') = 'blind') as lc_blind,
                    COUNT(*) FILTER (WHERE COALESCE(i.can_escalate, false)) as flag_can_escalate,
                    COUNT(*) FILTER (WHERE COALESCE(i.cross_subscription, false)) as flag_cross_sub,
                    COUNT(*) FILTER (WHERE i.recommended_action = 'ORPHANED'
                        AND i.deleted_at IS NULL
                        AND COALESCE(i.is_microsoft_system, FALSE) = FALSE) as flag_orphaned,
                    COUNT(*) FILTER (WHERE COALESCE(i.effective_scope_flag, '') = 'tenant') as scope_tenant,
                    COUNT(*) FILTER (WHERE COALESCE(i.effective_scope_flag, '') = 'management_group') as scope_mg,
                    COUNT(*) FILTER (WHERE COALESCE(i.effective_scope_flag, '') = 'subscription') as scope_sub,
                    COUNT(*) FILTER (WHERE COALESCE(i.lifecycle_state, '') IN ('likely_dormant', 'blind')
                        AND COALESCE(i.exposure_score, 0) >= 35) as zombie_count,
                    COUNT(*) as wl_total
                FROM identities i
                WHERE i.discovery_run_id = ANY(%s)
                  AND i.identity_category IN ('service_principal', 'managed_identity_system', 'managed_identity_user')
                  {HIDE_MICROSOFT_SQL}
            """, (run_ids,))
            wr = cursor.fetchone()
            cursor.execute("RELEASE SAVEPOINT wl_agg")
            workload_agg = {
                "total": wr[22] or 0,
                "exposure_distribution": {"critical": wr[0] or 0, "high": wr[1] or 0, "medium": wr[2] or 0, "low": wr[3] or 0},
                "component_averages": {
                    "privilege": float(wr[4] or 0), "credential_risk": float(wr[5] or 0),
                    "exposure": float(wr[6] or 0), "lifecycle": float(wr[7] or 0),
                    "visibility": float(wr[8] or 0), "total": float(wr[9] or 0),
                },
                "lifecycle_distribution": {
                    "active": wr[10] or 0, "possibly_active": wr[11] or 0,
                    "likely_dormant": wr[12] or 0, "dormant": wr[13] or 0, "blind": wr[14] or 0,
                },
                "flags": {"can_escalate": wr[15] or 0, "cross_subscription": wr[16] or 0, "orphaned": wr[17] or 0},
                "scope_distribution": {"tenant": wr[18] or 0, "management_group": wr[19] or 0, "subscription": wr[20] or 0},
                "zombie_count": wr[21] or 0,
            }
        except Exception:
            try:
                cursor.execute("ROLLBACK TO SAVEPOINT wl_agg")
            except Exception:
                try: cursor.connection.rollback()
                except Exception: pass
                pass

        # ── Data Integrity ────────────────────────────────────────
        data_completeness_pct = round((has_risk_score / total) * 100, 1) if total > 0 else 0.0
        last_scan = None
        scan_duration_seconds = None
        try:
            cursor.execute("""
                SELECT completed_at, started_at FROM discovery_runs
                WHERE status = 'completed' AND id = ANY(%s)
                ORDER BY completed_at DESC LIMIT 1
            """, (run_ids,))
            run_row = cursor.fetchone()
            if run_row and run_row[0]:
                last_scan = run_row[0].isoformat() if run_row[0] else None
                if run_row[1] and run_row[0]:
                    scan_duration_seconds = round((run_row[0] - run_row[1]).total_seconds(), 1)
        except Exception:
            try: db.conn.rollback()
            except Exception: pass

        confidence = 'High' if data_completeness_pct >= 90 else ('Medium' if data_completeness_pct >= 60 else 'Low')
        tid = _org_id()
        org_name = db.get_setting('org_name', organization_id=tid) if tid else None
        org_logo = db.get_setting('org_logo', organization_id=tid) if tid else None
        # Resolve org name from organizations table as fallback
        org_name = None
        if tid:
            try:
                cursor.execute("SELECT name FROM organizations WHERE id = %s", (tid,))
                tn_row = cursor.fetchone()
                if tn_row:
                    org_name = tn_row[0]
            except Exception:
                try: db.conn.rollback()
                except Exception: pass
        data_integrity = {
            "confidence": confidence,
            "last_scan": last_scan,
            "total_scanned": r[0] or 0,
            "data_completeness_pct": data_completeness_pct,
            "scan_duration_seconds": scan_duration_seconds,
            "organization_id": tid,
            "org_name": org_name,
            "organization_name": org_name or org_name,
            "organization_logo": org_logo,
        }

        # ── CISO Summary ─────────────────────────────────────────
        pillar_scores = {
            "effective_privilege": p1, "credential_risk": p2,
            "trust_federation": p3, "usage_dormancy": p4,
            "ownership_governance": p5, "external_exposure": p6,
        }
        pillar_labels = {
            "effective_privilege": "Effective Privilege",
            "credential_risk": "Credential Risk",
            "trust_federation": "Trust & Federation",
            "usage_dormancy": "Usage Dormancy",
            "ownership_governance": "Ownership Governance",
            "external_exposure": "External Exposure",
        }
        worst_key = max(pillar_scores, key=pillar_scores.get)
        worst_label = pillar_labels[worst_key]
        worst_score = round(pillar_scores[worst_key])
        parts = [f"Identity attack surface: Grade {grade} ({round(score)}/100)."]
        parts.append(f"Weakest area: {worst_label} ({worst_score}/100).")
        if worst_key == "effective_privilege":
            parts.append(f"{t0t1_count} identities hold T0/T1 privileges — reduce to under 1% of total.")
        elif worst_key == "credential_risk":
            parts.append(f"{expired_creds + expiring_creds} credentials expired or expiring — rotate immediately.")
        elif worst_key == "trust_federation":
            parts.append(f"{guest_with_roles} guest identities have privileged roles — review external access.")
        elif worst_key == "usage_dormancy":
            parts.append(f"{dormant_count} identities are dormant — disable or remove stale accounts.")
        elif worst_key == "ownership_governance":
            parts.append(f"{unowned_spns} service principals lack owners — assign accountability.")
        elif worst_key == "external_exposure":
            parts.append(f"{tenant_scope} identities have tenant-wide scope — apply least privilege.")
        ciso_summary = ' '.join(parts)

        # Compute industry_avg as posture equivalent of the org's mean identity risk score
        # avg_risk_score is 0-100 (higher = riskier), posture = 100 - attack_surface_score
        # Industry avg is the mean posture across all scored identities in this org
        industry_avg_posture = max(0, min(100, round(100 - avg_risk_score))) if avg_risk_score > 0 else None
        posture_target_setting = db.get_setting('posture_target', organization_id=tid) if tid else None

        # Ghost identities (disabled/deleted but retaining role assignments)
        ghost_count = 0
        try:
            cursor.execute("""
                SELECT COUNT(DISTINCT i.id)
                FROM identities i
                WHERE i.discovery_run_id = ANY(%s)
                  AND (i.deleted_at IS NOT NULL OR i.enabled = false
                       OR COALESCE(i.status, 'active') IN ('disabled', 'deleted'))
                  AND (EXISTS (SELECT 1 FROM role_assignments ra WHERE ra.identity_db_id = i.id)
                       OR EXISTS (SELECT 1 FROM entra_role_assignments era WHERE era.identity_db_id = i.id))
            """, (run_ids,))
            ghost_count = _scalar(cursor, 0)
        except Exception:
            try: db.conn.rollback()
            except Exception: pass

        return jsonify({
            "score": score,
            "grade": grade,
            "severity": severity,
            "industry_avg": industry_avg_posture,
            "posture_target": int(posture_target_setting) if posture_target_setting else None,
            "ghost_count": ghost_count,
            "pillars": {
                "effective_privilege": {"score": round(p1, 1), "weight": 30, "detail": {"t0": t0_count, "t0t1": t0t1_count, "total": total_excl, "dormant_privileged": dormant_privileged}},
                "credential_risk": {"score": round(p2, 1), "weight": 20, "detail": {"expired": expired_creds, "expiring": expiring_creds, "with_creds": has_creds, "healthy": healthy_creds, "nhi_credential_risk_count": nhi_credential_risk_count}},
                "trust_federation": {"score": round(p3, 1), "weight": 20, "detail": {"guests": guest_count, "guest_with_roles": guest_with_roles, "federated": federated_count}},
                "usage_dormancy": {"score": round(p4, 1), "weight": 10, "detail": {"dormant": dormant_count, "dormant_nhi": dormant_nhi_count, "total": total_excl}},
                "ownership_governance": {"score": round(p5, 1), "weight": 10, "detail": {"unowned_spns": unowned_spns, "total_spns": total_spns}},
                "external_exposure": {"score": round(p6, 1), "weight": 10, "detail": {"tenant_scope": tenant_scope, "total": total_excl}},
            },
            "total_identities": r[0] or 0,
            "nhi_breakdown": nhi_breakdown,
            "attack_opportunities": attack_opportunities,
            "governance": governance,
            "data_integrity": data_integrity,
            "ciso_summary": ciso_summary,
            "workload_exposure": workload_agg,
            "data_origin": "tenant_scan",
        })
    finally:
        cursor.close()
        db.close()


def get_risk_summary():
    """Canonical risk aggregation — reads ONLY from persisted risk_summary table.

    The RiskSummaryEngine computes all metrics at discovery time and persists
    them to the risk_summary table. No live computation is performed here.
    This guarantees all dashboards display identical, deterministic values.
    """
    db = _db()
    try:
        org_id = _org_id()
        conn_id = _connection_id()
        cursor = db.conn.cursor()
        run_ids = _latest_run_ids(cursor, org_id, conn_id)
        cursor.close()
        summary = db.get_latest_risk_summary(org_id, run_ids=run_ids or None)
        if not summary:
            return jsonify({
                "status": "analysis_pending",
                "message": "Risk summary not yet computed. Run a discovery scan first.",
                "agirs": None,
                "identity_risk_score": None,
                "ghost_accounts": 0,
                "orphaned_spns": 0,
                "over_privileged": 0,
                "dormant_privileged": 0,
                "high_blast_radius": 0,
                "attack_paths": 0,
                "identity_counts": {"total": 0, "customer": 0, "microsoft": 0},
                "source": "none",
            })

        agirs_data = None
        if summary.get('agirs_score') is not None:
            s = summary['agirs_score']
            agirs_data = {
                "score": s,
                "tier": summary.get('agirs_tier') or (
                    'A' if s >= 92 else 'B' if s >= 80 else 'C' if s >= 65 else 'D' if s >= 45 else 'F'
                ),
            }
        return jsonify({
            "agirs": agirs_data,
            "identity_risk_score": summary.get('identity_risk_score'),
            "ghost_accounts": summary.get('ghost_accounts', 0),
            "orphaned_spns": summary.get('orphaned_spns', 0),
            "over_privileged": summary.get('over_privileged', 0),
            "dormant_privileged": summary.get('dormant_privileged', 0),
            "high_blast_radius": summary.get('high_blast_radius', 0),
            "attack_paths": summary.get('attack_paths', 0),
            "identity_counts": {
                "total": summary.get('total_identities', 0),
                "customer": summary.get('customer_identities', 0),
                "microsoft": summary.get('microsoft_identities', 0),
            },
            "source": "persisted",
            "computed_at": summary.get('computed_at'),
            "discovery_run_id": summary.get('discovery_run_id'),
        })
    finally:
        db.close()


def get_exposure_summary():
    """Canonical exposure: total resources, subscriptions, key vaults, privileged roles."""
    db = _db()
    cursor = db.conn.cursor()
    try:
        run_ids = _latest_run_ids(cursor, _org_id(), _connection_id())
        if not run_ids:
            return jsonify({"error": "No completed runs"}), 404

        # Resource counts
        sa_count = kv_count = 0
        for table, var_name in [("azure_storage_accounts", "sa"), ("azure_key_vaults", "kv")]:
            try:
                cursor.execute(f"SAVEPOINT exp_{var_name}")
                cursor.execute(f"SELECT COUNT(*) FROM {table} WHERE discovery_run_id = ANY(%s)", (run_ids,))
                val = _scalar(cursor, 0)
                if var_name == "sa":
                    sa_count = val
                else:
                    kv_count = val
                cursor.execute(f"RELEASE SAVEPOINT exp_{var_name}")
            except Exception:
                try: cursor.connection.rollback()
                except Exception: pass
                try:
                    cursor.execute(f"ROLLBACK TO SAVEPOINT exp_{var_name}")
                except Exception:
                    try: cursor.connection.rollback()
                    except Exception: pass
                    pass

        # Subscription count from role_assignments scopes
        sub_count = 0
        try:
            cursor.execute("""
                SELECT COUNT(DISTINCT SPLIT_PART(ra.scope, '/', 3))
                FROM role_assignments ra
                JOIN identities i ON i.id = ra.identity_db_id
                WHERE i.discovery_run_id = ANY(%s) AND ra.scope LIKE '/subscriptions/%%'
            """, (run_ids,))
            sub_count = _scalar(cursor, 0)
        except Exception:
            try: db.conn.rollback()
            except Exception: pass

        # Privileged identity count (T0/T1 roles)
        priv_count = 0
        try:
            cursor.execute(f"""
                SELECT COUNT(*) FROM identities i
                WHERE i.discovery_run_id = ANY(%s)
                {HIDE_MICROSOFT_SQL}
                AND (
                    EXISTS (SELECT 1 FROM entra_role_assignments era WHERE era.identity_db_id = i.id
                        AND LOWER(era.role_name) IN ('global administrator',
                            'privileged role administrator','application administrator',
                            'cloud application administrator'))
                    OR EXISTS (SELECT 1 FROM role_assignments ra WHERE ra.identity_db_id = i.id
                        AND LOWER(ra.role_name) IN ('owner','user access administrator')
                        AND (ra.scope IS NULL OR ra.scope = '/'
                             OR (ra.scope LIKE '/subscriptions/%%'
                                 AND ra.scope NOT LIKE '/subscriptions/%%/resourceGroups/%%')))
                )
            """, (run_ids,))
            priv_count = _scalar(cursor, 0)
        except Exception:
            try: db.conn.rollback()
            except Exception: pass

        return jsonify({
            "total_resources": sa_count + kv_count,
            "storage_accounts": sa_count,
            "key_vaults": kv_count,
            "subscriptions": sub_count,
            "privileged_roles": priv_count,
        })
    finally:
        cursor.close()
        db.close()


def get_attack_path_count():
    """Unified attack path count — reads from attack_paths table (canonical source,
    same as RiskSummaryEngine) with graph_attack_findings as supplemental.
    Returns max() of both for consistent reporting across all screens."""
    db = _db()
    try:
        org_id = _org_id()
        conn_id = _connection_id()
        cursor = db.conn.cursor()
        run_ids = _latest_run_ids(cursor, org_id, conn_id)

        ap_total = ap_critical = ap_high = ap_medium = ap_low = ap_affected = 0
        gf_total = 0

        if run_ids:
            # Primary: attack_paths table (canonical, matches risk_summary)
            # Use org_id only — attack_paths may not be regenerated every run
            try:
                cursor.execute("""
                    SELECT
                        COUNT(*),
                        COUNT(*) FILTER (WHERE severity = 'critical'),
                        COUNT(*) FILTER (WHERE severity = 'high'),
                        COUNT(*) FILTER (WHERE severity = 'medium'),
                        COUNT(*) FILTER (WHERE severity = 'low'),
                        COUNT(DISTINCT source_entity_id)
                    FROM attack_paths
                    WHERE organization_id = %s
                """, (org_id,))
                row = cursor.fetchone()
                ap_total = row[0] or 0
                ap_critical = row[1] or 0
                ap_high = row[2] or 0
                ap_medium = row[3] or 0
                ap_low = row[4] or 0
                ap_affected = row[5] or 0
            except Exception:
                try: db.conn.rollback()
                except Exception: pass

            # Critical count: identities with risk_level='critical' that have attack paths
            # (path severity != identity risk_level — a critical identity with medium paths is critical)
            try:
                cursor.execute("""
                    SELECT COUNT(DISTINCT ap.source_entity_id)
                    FROM attack_paths ap
                    JOIN identities i ON i.identity_id = ap.source_entity_id
                        AND i.discovery_run_id = ANY(%s)
                    WHERE ap.organization_id = %s
                        AND i.risk_level = 'critical'
                """, (run_ids, org_id))
                _crit_identity_count = _scalar(cursor, 0)
                if _crit_identity_count > ap_critical:
                    ap_critical = _crit_identity_count
            except Exception:
                try: db.conn.rollback()
                except Exception: pass

            # Supplemental: graph_attack_findings (BFS analysis)
            try:
                cursor.execute("""
                    SELECT COUNT(*) FROM graph_attack_findings
                    WHERE organization_id = %s AND discovery_run_id = ANY(%s)
                """, (org_id, run_ids))
                gf_total = _scalar(cursor, 0)
            except Exception:
                try: db.conn.rollback()
                except Exception: pass

        cursor.close()
        total = max(ap_total, gf_total)
        return jsonify({
            "total": total,
            "open": total,  # all paths are open by default
            "critical": ap_critical,
            "high": ap_high,
            "medium": ap_medium,
            "low": ap_low,
            "affected_identities": ap_affected,
        })
    except Exception:
        try: db.conn.rollback()
        except Exception: pass
        return jsonify({"total": 0, "open": 0, "critical": 0, "high": 0,
                        "medium": 0, "low": 0, "affected_identities": 0})
    finally:
        db.close()


def _compute_compliance_metrics(cursor, run_ids):
    """Compute all compliance metrics from identity posture data."""
    if not isinstance(run_ids, list):
        run_ids = [run_ids]  # backward compat
    # T0 count
    cursor.execute(f"""
        SELECT COUNT(*) FROM identities i WHERE i.discovery_run_id = ANY(%s)
        {HIDE_MICROSOFT_SQL}
        AND (
            EXISTS (SELECT 1 FROM entra_role_assignments era WHERE era.identity_db_id = i.id
                AND LOWER(era.role_name) IN (
                    'global administrator', 'privileged role administrator',
                    'privileged authentication administrator',
                    'application administrator', 'cloud application administrator',
                    'hybrid identity administrator'
                ))
            OR EXISTS (SELECT 1 FROM role_assignments ra WHERE ra.identity_db_id = i.id
                AND LOWER(ra.role_name) IN ('owner', 'user access administrator')
                AND (ra.scope IS NULL OR ra.scope = '/' OR ra.scope LIKE '/subscriptions/%%'
                     AND ra.scope NOT LIKE '/subscriptions/%%/resourceGroups/%%'))
        )
    """, (run_ids,))
    t0_count = _scalar(cursor, 0)

    # Dormant privileged — SSOT: T0/T1 roles only (matches risk_summary_engine + AGIRS P1)
    _priv_entra = list(T0_ENTRA_ROLES_LOWER | T1_ENTRA_ROLES_LOWER)
    _priv_rbac = list(T2_RBAC_ROLES_LOWER)
    cursor.execute(f"""
        SELECT COUNT(*) FROM identities i WHERE i.discovery_run_id = ANY(%s)
        {HIDE_MICROSOFT_SQL}
        AND i.activity_status IN ('stale', 'never_used')
        AND (
            EXISTS (SELECT 1 FROM entra_role_assignments era WHERE era.identity_db_id = i.id
                AND LOWER(era.role_name) = ANY(%s))
            OR EXISTS (SELECT 1 FROM role_assignments ra WHERE ra.identity_db_id = i.id
                AND LOWER(ra.role_name) = ANY(%s))
        )
    """, (run_ids, _priv_entra, _priv_rbac))
    dormant_privileged = _scalar(cursor, 0)

    # Expired credentials
    cursor.execute(f"""
        SELECT COUNT(*) FROM identities i WHERE i.discovery_run_id = ANY(%s)
        {HIDE_MICROSOFT_SQL}
        AND i.credential_status = 'expired'
    """, (run_ids,))
    expired_credentials = _scalar(cursor, 0)

    # Expiring within 30 days
    cursor.execute(f"""
        SELECT COUNT(*) FROM identities i WHERE i.discovery_run_id = ANY(%s)
        {HIDE_MICROSOFT_SQL}
        AND i.credential_expiration IS NOT NULL
        AND i.credential_expiration > NOW()
        AND i.credential_expiration < NOW() + INTERVAL '30 days'
    """, (run_ids,))
    expiring_credentials_30d = _scalar(cursor, 0)

    # Unowned SPNs — SSOT uses recommended_action='ORPHANED'
    cursor.execute(f"""
        SELECT COUNT(*) FROM identities i WHERE i.discovery_run_id = ANY(%s)
        {HIDE_MICROSOFT_SQL}
        AND i.recommended_action = 'ORPHANED'
        AND i.deleted_at IS NULL
    """, (run_ids,))
    unowned_spns = _scalar(cursor, 0)

    # HIPAA violations
    cursor.execute(f"""
        SELECT COUNT(DISTINCT rhm.role_name)
        FROM role_hipaa_mappings rhm
        WHERE EXISTS (
            SELECT 1 FROM entra_role_assignments era
            JOIN identities i ON era.identity_db_id = i.id
            WHERE i.discovery_run_id = ANY(%s)
            {HIDE_MICROSOFT_SQL}
            AND era.role_name = rhm.role_name
        ) OR EXISTS (
            SELECT 1 FROM role_assignments ra
            JOIN identities i ON ra.identity_db_id = i.id
            WHERE i.discovery_run_id = ANY(%s)
            {HIDE_MICROSOFT_SQL}
            AND ra.role_name = rhm.role_name
        )
    """, (run_ids, run_ids))
    hipaa_violations = _scalar(cursor, 0)

    # MFA not enforced (identities not covered by any CA policy requiring MFA)
    cursor.execute(f"""
        SELECT COUNT(*) FROM identities i WHERE i.discovery_run_id = ANY(%s)
        {HIDE_MICROSOFT_SQL}
        AND COALESCE(i.ca_mfa_enforced, false) = false
        AND LOWER(COALESCE(i.identity_category, '')) IN ('human_user', 'guest')
    """, (run_ids,))
    mfa_not_enforced = _scalar(cursor, 0)

    # Excessive permissions (>5 role assignments)
    cursor.execute(f"""
        SELECT COUNT(*) FROM identities i WHERE i.discovery_run_id = ANY(%s)
        {HIDE_MICROSOFT_SQL}
        AND (
            (SELECT COUNT(*) FROM role_assignments ra WHERE ra.identity_db_id = i.id)
            + (SELECT COUNT(*) FROM entra_role_assignments era WHERE era.identity_db_id = i.id)
        ) > 5
    """, (run_ids,))
    excessive_permissions = _scalar(cursor, 0)

    # Stale accounts (inactive > 90 days)
    cursor.execute(f"""
        SELECT COUNT(*) FROM identities i WHERE i.discovery_run_id = ANY(%s)
        {HIDE_MICROSOFT_SQL}
        AND i.activity_status IN ('stale', 'never_used')
    """, (run_ids,))
    stale_accounts = _scalar(cursor, 0)

    # No credential rotation (credentials not rotated in 180+ days)
    cursor.execute(f"""
        SELECT COUNT(*) FROM identities i WHERE i.discovery_run_id = ANY(%s)
        {HIDE_MICROSOFT_SQL}
        AND EXISTS (
            SELECT 1 FROM credentials c WHERE c.identity_db_id = i.id
            AND c.start_datetime IS NOT NULL
            AND c.start_datetime < NOW() - INTERVAL '180 days'
        )
    """, (run_ids,))
    no_credential_rotation = _scalar(cursor, 0)

    # Shared/generic/test accounts (no_shared_accounts)
    cursor.execute(f"""
        SELECT COUNT(*) FROM identities i WHERE i.discovery_run_id = ANY(%s)
        {HIDE_MICROSOFT_SQL}
        AND LOWER(COALESCE(i.display_name, '')) ~* '(shared|generic|test|temp|svc[-_]?test)'
    """, (run_ids,))
    no_shared_accounts = _scalar(cursor, 0)

    # PIM coverage % (T0/T1 identities with PIM eligible assignments)
    cursor.execute(f"""
        SELECT COUNT(*) FROM identities i WHERE i.discovery_run_id = ANY(%s)
        {HIDE_MICROSOFT_SQL}
        AND (
            EXISTS (SELECT 1 FROM entra_role_assignments era WHERE era.identity_db_id = i.id
                AND LOWER(era.role_name) IN (
                    'global administrator', 'privileged role administrator',
                    'privileged authentication administrator',
                    'application administrator', 'cloud application administrator',
                    'hybrid identity administrator'
                ))
            OR EXISTS (SELECT 1 FROM role_assignments ra WHERE ra.identity_db_id = i.id
                AND LOWER(ra.role_name) IN ('owner', 'user access administrator')
                AND (ra.scope IS NULL OR ra.scope = '/' OR ra.scope LIKE '/subscriptions/%%'
                     AND ra.scope NOT LIKE '/subscriptions/%%/resourceGroups/%%'))
        )
        AND EXISTS (SELECT 1 FROM pim_eligible_assignments pea WHERE pea.identity_db_id = i.id)
    """, (run_ids,))
    pim_eligible_t0 = _scalar(cursor, 0)
    pim_coverage_pct = round(pim_eligible_t0 / max(t0_count, 1) * 100)

    # Access reviews completed (table may not exist)
    access_reviews_completed = 0
    try:
        cursor.execute("SAVEPOINT access_reviews_check")
        cursor.execute("SELECT COUNT(*) FROM access_reviews WHERE status = 'completed'")
        access_reviews_completed = _scalar(cursor, 0)
        cursor.execute("RELEASE SAVEPOINT access_reviews_check")
    except Exception:
        try: cursor.connection.rollback()
        except Exception: pass
        cursor.execute("ROLLBACK TO SAVEPOINT access_reviews_check")

    # Managed identity % (MI vs SPN among NHIs)
    cursor.execute(f"""
        SELECT
            COUNT(*) FILTER (WHERE LOWER(COALESCE(i.identity_category, '')) LIKE 'managed_identity%%') as mi_count,
            COUNT(*) FILTER (WHERE LOWER(COALESCE(i.identity_category, '')) IN ('service_principal', 'managed_identity_system', 'managed_identity_user')) as nhi_count
        FROM identities i WHERE i.discovery_run_id = ANY(%s)
        {HIDE_MICROSOFT_SQL}
    """, (run_ids,))
    row = cursor.fetchone()
    mi_count = row[0] if row else 0
    nhi_count = row[1] if row else 0
    managed_identity_pct = round(mi_count / max(nhi_count, 1) * 100)

    # Credential rotation compliance % (inverse of no_credential_rotation)
    cursor.execute(f"""
        SELECT COUNT(*) FROM identities i WHERE i.discovery_run_id = ANY(%s)
        {HIDE_MICROSOFT_SQL}
        AND EXISTS (SELECT 1 FROM credentials c WHERE c.identity_db_id = i.id)
    """, (run_ids,))
    total_with_creds = _scalar(cursor, 0)
    credential_rotation_compliance_pct = round(
        (max(total_with_creds - no_credential_rotation, 0) / max(total_with_creds, 1)) * 100
    )

    return {
        't0_count': t0_count,
        'dormant_privileged': dormant_privileged,
        'expired_credentials': expired_credentials,
        'expiring_credentials_30d': expiring_credentials_30d,
        'unowned_spns': unowned_spns,
        'hipaa_violations': hipaa_violations,
        'mfa_not_enforced': mfa_not_enforced,
        'excessive_permissions': excessive_permissions,
        'stale_accounts': stale_accounts,
        'no_credential_rotation': no_credential_rotation,
        'no_shared_accounts': no_shared_accounts,
        'pim_coverage_pct': pim_coverage_pct,
        'access_reviews_completed': access_reviews_completed,
        'managed_identity_pct': managed_identity_pct,
        'credential_rotation_compliance_pct': credential_rotation_compliance_pct,
    }


def _compute_compliance_evidence(cursor, run_ids, needed_metrics):
    """For each metric in needed_metrics, return up to 50 identities contributing to it."""
    if not isinstance(run_ids, list):
        run_ids = [run_ids]
    evidence = {}
    _COLS = "i.id, i.identity_id, i.display_name, i.risk_level, COALESCE(i.risk_score,0), COALESCE(i.identity_category,''), i.activity_status"

    def _rows(reason_text):
        return [
            {'id': r[0], 'identity_id': r[1], 'display_name': r[2] or r[1],
             'risk_level': r[3] or 'unknown', 'risk_score': r[4],
             'identity_category': r[5], 'reason': reason_text}
            for r in cursor.fetchall()
        ]

    if 't0_count' in needed_metrics:
        cursor.execute(f"""
            SELECT {_COLS} FROM identities i WHERE i.discovery_run_id = ANY(%s)
            AND (
                EXISTS (SELECT 1 FROM entra_role_assignments era WHERE era.identity_db_id = i.id
                    AND LOWER(era.role_name) IN (
                        'global administrator', 'privileged role administrator',
                        'privileged authentication administrator',
                        'application administrator', 'cloud application administrator',
                        'hybrid identity administrator'
                    ))
                OR EXISTS (SELECT 1 FROM role_assignments ra WHERE ra.identity_db_id = i.id
                    AND LOWER(ra.role_name) IN ('owner', 'user access administrator')
                    AND (ra.scope IS NULL OR ra.scope = '/' OR ra.scope LIKE '/subscriptions/%%'
                         AND ra.scope NOT LIKE '/subscriptions/%%/resourceGroups/%%'))
            )
            ORDER BY i.risk_score DESC LIMIT 50
        """, (run_ids,))
        evidence['t0_count'] = _rows("Control Plane (T0) privileged identity")

    if 'dormant_privileged' in needed_metrics:
        cursor.execute(f"""
            SELECT {_COLS} FROM identities i WHERE i.discovery_run_id = ANY(%s)
            AND i.activity_status IN ('stale', 'never_used')
            AND (
                EXISTS (SELECT 1 FROM entra_role_assignments era WHERE era.identity_db_id = i.id)
                OR EXISTS (SELECT 1 FROM role_assignments ra WHERE ra.identity_db_id = i.id)
            )
            ORDER BY i.risk_score DESC LIMIT 50
        """, (run_ids,))
        evidence['dormant_privileged'] = _rows("Dormant/stale identity with active role assignments")

    if 'expired_credentials' in needed_metrics:
        cursor.execute(f"""
            SELECT {_COLS} FROM identities i WHERE i.discovery_run_id = ANY(%s)
            AND i.credential_status = 'expired'
            ORDER BY i.risk_score DESC LIMIT 50
        """, (run_ids,))
        evidence['expired_credentials'] = _rows("Expired credentials")

    if 'expiring_credentials_30d' in needed_metrics:
        cursor.execute(f"""
            SELECT {_COLS} FROM identities i WHERE i.discovery_run_id = ANY(%s)
            AND i.credential_expiration IS NOT NULL
            AND i.credential_expiration > NOW()
            AND i.credential_expiration < NOW() + INTERVAL '30 days'
            ORDER BY i.credential_expiration ASC LIMIT 50
        """, (run_ids,))
        evidence['expiring_credentials_30d'] = _rows("Credential expires within 30 days")

    if 'unowned_spns' in needed_metrics:
        cursor.execute(f"""
            SELECT {_COLS} FROM identities i WHERE i.discovery_run_id = ANY(%s)
            AND LOWER(COALESCE(i.identity_category, '')) = 'service_principal'
            AND COALESCE(i.owner_count, 0) = 0
            ORDER BY i.risk_score DESC LIMIT 50
        """, (run_ids,))
        evidence['unowned_spns'] = _rows("Service principal without assigned owner")

    if 'hipaa_violations' in needed_metrics:
        cursor.execute(f"""
            SELECT {_COLS} FROM identities i
            WHERE i.discovery_run_id = ANY(%s)
            AND (
                EXISTS (
                    SELECT 1 FROM entra_role_assignments era
                    JOIN role_hipaa_mappings rhm ON era.role_name = rhm.role_name
                    WHERE era.identity_db_id = i.id
                )
                OR EXISTS (
                    SELECT 1 FROM role_assignments ra
                    JOIN role_hipaa_mappings rhm ON ra.role_name = rhm.role_name
                    WHERE ra.identity_db_id = i.id
                )
            )
            ORDER BY i.risk_score DESC LIMIT 50
        """, (run_ids,))
        evidence['hipaa_violations'] = _rows("Has roles with HIPAA violation mappings")

    if 'mfa_not_enforced' in needed_metrics:
        cursor.execute(f"""
            SELECT {_COLS} FROM identities i WHERE i.discovery_run_id = ANY(%s)
            AND COALESCE(i.ca_mfa_enforced, false) = false
            AND LOWER(COALESCE(i.identity_category, '')) IN ('human_user', 'guest')
            ORDER BY i.risk_score DESC LIMIT 50
        """, (run_ids,))
        evidence['mfa_not_enforced'] = _rows("Human user without MFA enforcement")

    if 'excessive_permissions' in needed_metrics:
        cursor.execute(f"""
            SELECT {_COLS} FROM identities i WHERE i.discovery_run_id = ANY(%s)
            AND (
                (SELECT COUNT(*) FROM role_assignments ra WHERE ra.identity_db_id = i.id)
                + (SELECT COUNT(*) FROM entra_role_assignments era WHERE era.identity_db_id = i.id)
            ) > 5
            ORDER BY i.risk_score DESC LIMIT 50
        """, (run_ids,))
        evidence['excessive_permissions'] = _rows("Has >5 role assignments")

    if 'stale_accounts' in needed_metrics:
        cursor.execute(f"""
            SELECT {_COLS} FROM identities i WHERE i.discovery_run_id = ANY(%s)
            AND i.activity_status IN ('stale', 'never_used')
            ORDER BY i.risk_score DESC LIMIT 50
        """, (run_ids,))
        evidence['stale_accounts'] = _rows("Stale or never-used account")

    if 'no_credential_rotation' in needed_metrics:
        cursor.execute(f"""
            SELECT {_COLS} FROM identities i WHERE i.discovery_run_id = ANY(%s)
            AND EXISTS (
                SELECT 1 FROM credentials c WHERE c.identity_db_id = i.id
                AND c.start_datetime IS NOT NULL
                AND c.start_datetime < NOW() - INTERVAL '180 days'
            )
            ORDER BY i.risk_score DESC LIMIT 50
        """, (run_ids,))
        evidence['no_credential_rotation'] = _rows("Credentials not rotated in 180+ days")

    return evidence


_FRAMEWORK_REF_PREFIX = {
    'soc2': 'SOC2', 'hipaa': 'HIPAA', 'pci_dss': 'PCI-DSS',
    'nist_800_53': 'NIST', 'cis_azure': 'CIS', 'iso_27001': 'ISO',
    'nist_csf': 'NIST-CSF', 'sox': 'SOX', 'hitrust': 'HITRUST',
    'gdpr': 'GDPR', 'ccpa': 'CCPA',
}


def _match_playbooks_to_control(all_playbooks, control_id, framework_key):
    """Filter pre-fetched playbooks whose compliance_refs match this control."""
    prefix = _FRAMEWORK_REF_PREFIX.get(framework_key, '')
    if not prefix:
        return []
    search = f"{prefix} {control_id}"
    matched = []
    for pb in all_playbooks:
        refs = pb.get('compliance_refs') or []
        if any(search in ref for ref in refs):
            matched.append({
                'id': pb['id'], 'title': pb['title'],
                'description': pb.get('description', ''),
                'impact': pb.get('impact', ''), 'effort': pb.get('effort', ''),
            })
    return matched


def _evaluate_control(control, metrics):
    """Evaluate a single control against computed metrics. Returns 'pass', 'warn', or 'fail'."""
    import operator
    ops = {
        '<=': operator.le, '>=': operator.ge, '==': operator.eq,
        '<': operator.lt, '>': operator.gt,
    }
    value = metrics.get(control['metric'], 0)
    pass_op = ops.get(control['pass_operator'])
    if pass_op and pass_op(value, control['pass_value']):
        return 'pass', value
    if control.get('warn_operator') and control.get('warn_value') is not None:
        warn_op = ops.get(control['warn_operator'])
        if warn_op and warn_op(value, control['warn_value']):
            return 'warn', value
    return 'fail', value


def _format_metric_label(metric):
    """Human-readable label for a metric key."""
    labels = {
        't0_count': 'Control Plane (T0) identities',
        'dormant_privileged': 'dormant privileged accounts',
        'expired_credentials': 'expired credentials',
        'expiring_credentials_30d': 'credentials expiring within 30 days',
        'unowned_spns': 'service principals without owners',
        'hipaa_violations': 'roles with HIPAA violation mappings',
        'mfa_not_enforced': 'users without MFA enforced',
        'excessive_permissions': 'identities with excessive permissions',
        'stale_accounts': 'stale/unused accounts',
        'no_credential_rotation': 'credentials not rotated in 180+ days',
        'no_shared_accounts': 'shared/generic/test accounts detected',
        'pim_coverage_pct': '% T0 identities with PIM coverage',
        'access_reviews_completed': 'completed access reviews',
        'managed_identity_pct': '% NHI workloads using managed identities',
        'credential_rotation_compliance_pct': '% credentials rotated within policy',
    }
    return labels.get(metric, metric)


def get_dashboard_compliance():
    """
    Data-driven compliance scorecard. Loads enabled frameworks and controls from DB,
    evaluates each control against computed identity posture metrics.
    """
    db = _db()
    cursor = db.conn.cursor()
    try:
        run_ids = _latest_run_ids(cursor, _org_id(), _connection_id())
        if not run_ids:
            return jsonify({"error": "No completed discovery runs found"}), 404

        metrics = _compute_compliance_metrics(cursor, run_ids)
        frameworks = db.get_compliance_frameworks(enabled_only=True)

        scorecard = {}
        for fw in frameworks:
            controls_out = []
            for ctrl in fw['controls']:
                status, value = _evaluate_control(ctrl, metrics)
                label = _format_metric_label(ctrl['metric'])
                if status == 'pass':
                    detail = f"{value} {label} — within limits"
                elif status == 'warn':
                    detail = f"{value} {label} — approaching threshold"
                else:
                    detail = f"{value} {label} — exceeds acceptable limit (target: {ctrl['pass_operator']}{int(ctrl['pass_value'])})"
                controls_out.append({
                    'id': ctrl['control_id'],
                    'name': ctrl['name'],
                    'status': status,
                    'detail': detail,
                    'metric': ctrl['metric'],
                    'value': value,
                    'pass_threshold': f"{ctrl['pass_operator']}{int(ctrl['pass_value'])}",
                    'drilldown_url': ctrl.get('drilldown_url'),
                })

            passes = sum(1 for c in controls_out if c['status'] == 'pass')
            scorecard[fw['key']] = {
                'name': fw['name'],
                'version': fw.get('version'),
                'description': fw.get('description'),
                'controls': controls_out,
                'score': round(passes / len(controls_out) * 100, 1) if controls_out else 0.0,
                'pass_count': passes,
                'warn_count': sum(1 for c in controls_out if c['status'] == 'warn'),
                'fail_count': sum(1 for c in controls_out if c['status'] == 'fail'),
                'total_controls': len(controls_out),
                'tier': fw.get('tier', 'core'),
                'category': fw.get('category', ''),
                'short_name': fw.get('short_name', fw['name']),
                'identity_controls_count': fw.get('identity_controls_count', len(controls_out)),
                'total_framework_controls': fw.get('total_framework_controls', 0),
                'scope_label': fw.get('scope_label', 'Identity, access, and privilege controls'),
            }

        return jsonify(scorecard)
    finally:
        cursor.close()
        db.close()


def get_compliance_frameworks_list():
    """GET /api/compliance/frameworks — list all frameworks (enabled and disabled)."""
    db = _db()
    try:
        frameworks = db.get_compliance_frameworks(enabled_only=False)
        return jsonify(frameworks)
    finally:
        db.close()


def toggle_compliance_framework_handler(framework_id):
    """PATCH /api/compliance/frameworks/<id> — toggle enabled state."""
    db = _db()
    try:
        data = request.get_json() or {}
        enabled = data.get('enabled')
        if enabled is None:
            return jsonify({'error': 'Missing "enabled" field'}), 400
        result = db.toggle_compliance_framework(framework_id, bool(enabled))
        if not result:
            return jsonify({'error': 'Framework not found'}), 404
        try:
            _log(db,
                'settings',
                f'Compliance framework "{result["name"]}" {"enabled" if enabled else "disabled"}',
                {'framework_id': framework_id, 'enabled': enabled}
            )
        except Exception:
            try: db.conn.rollback()
            except Exception: pass
        return jsonify(result)
    finally:
        db.close()


def get_compliance_trends_handler():
    """
    GET /api/compliance/trends
    Returns compliance score history per framework across discovery runs.
    Backfills snapshots from existing runs if table is empty.
    """
    fw_filter = request.args.get('framework')
    limit = _safe_query_int('limit', 20, 50)

    db = _db()
    try:
        # Backfill: if no snapshots exist, compute for the last N completed runs
        if db.get_compliance_snapshot_count() == 0:
            cursor = db.conn.cursor()
            cursor.execute("""
                SELECT id FROM discovery_runs
                WHERE status = 'completed' AND organization_id = %s
                ORDER BY id DESC LIMIT %s
            """, (_org_id(), limit))
            run_ids = [r[0] for r in cursor.fetchall()]
            cursor.close()

            if run_ids:
                frameworks = db.get_compliance_frameworks(enabled_only=True)
                for rid in run_ids:
                    cursor = db.conn.cursor()
                    try:
                        metrics = _compute_compliance_metrics(cursor, rid)
                    except Exception:
                        try: db.conn.rollback()
                        except Exception: pass
                        cursor.close()
                        continue
                    cursor.close()
                    for fw in frameworks:
                        pass_count = 0
                        warn_count = 0
                        for ctrl in fw['controls']:
                            status, _ = _evaluate_control(ctrl, metrics)
                            if status == 'pass':
                                pass_count += 1
                            elif status == 'warn':
                                warn_count += 1
                        total = len(fw['controls'])
                        fail_count = total - pass_count - warn_count
                        score = round(pass_count / total * 100, 1) if total > 0 else 0.0
                        db.save_compliance_snapshot(
                            rid, fw['key'], fw['name'], score,
                            pass_count, warn_count, fail_count, total, metrics
                        )

        runs = db.get_compliance_trends(limit=limit)

        if fw_filter:
            # Filter to single framework, flatten
            filtered = []
            for run in runs:
                fw_data = run['frameworks'].get(fw_filter)
                if fw_data:
                    filtered.append({
                        'run_id': run['run_id'],
                        'date': run['date'],
                        'score': fw_data['score'],
                        'pass_count': fw_data['pass_count'],
                        'warn_count': fw_data['warn_count'],
                        'fail_count': fw_data['fail_count'],
                        'total_controls': fw_data['total_controls'],
                    })
            return jsonify({'runs': filtered, 'count': len(filtered)})

        return jsonify({'runs': runs, 'count': len(runs)})
    finally:
        db.close()


def get_compliance_gap_analysis():
    """
    GET /api/compliance/gap-analysis
    Query params: framework (optional), format (json|csv)
    Returns per-control status with evidence identities and matched remediation playbooks.
    """
    import io as _io
    import csv as _csv

    fw_filter = request.args.get('framework')
    out_format = request.args.get('format', 'json')

    db = _db()
    cursor = db.conn.cursor()
    try:
        run_ids = _latest_run_ids(cursor, _org_id(), _connection_id())
        if not run_ids:
            return jsonify({"error": "No completed discovery runs found"}), 404

        metrics = _compute_compliance_metrics(cursor, run_ids)
        frameworks = db.get_compliance_frameworks(enabled_only=True)
        if fw_filter:
            frameworks = [fw for fw in frameworks if fw['key'] == fw_filter]

        # Evaluate all controls, collect needed metrics for evidence
        needed_metrics = set()
        fw_results = {}
        for fw in frameworks:
            controls_out = []
            for ctrl in fw['controls']:
                status, value = _evaluate_control(ctrl, metrics)
                label = _format_metric_label(ctrl['metric'])
                if status == 'pass':
                    detail = f"{value} {label} — within limits"
                elif status == 'warn':
                    detail = f"{value} {label} — approaching threshold"
                else:
                    detail = f"{value} {label} — exceeds acceptable limit (target: {ctrl['pass_operator']}{int(ctrl['pass_value'])})"
                if status != 'pass':
                    needed_metrics.add(ctrl['metric'])
                controls_out.append({
                    'control_id': ctrl['control_id'],
                    'name': ctrl['name'],
                    'status': status,
                    'metric': ctrl['metric'],
                    'value': value,
                    'pass_threshold': f"{ctrl['pass_operator']}{int(ctrl['pass_value'])}",
                    'detail': detail,
                    'drilldown_url': ctrl.get('drilldown_url'),
                })
            fw_results[fw['key']] = {'name': fw['name'], 'version': fw.get('version'), 'controls': controls_out}

        # Batch-fetch evidence for non-passing metrics
        evidence = _compute_compliance_evidence(cursor, run_ids, needed_metrics) if needed_metrics else {}

        # Fetch all remediation playbooks once
        cursor.execute("SELECT id, title, description, impact, effort, compliance_refs FROM remediation_playbooks ORDER BY priority_score DESC")
        all_playbooks = []
        for row in cursor.fetchall():
            refs = row[5] if isinstance(row[5], list) else []
            all_playbooks.append({'id': row[0], 'title': row[1], 'description': row[2], 'impact': row[3], 'effort': row[4], 'compliance_refs': refs})

        # Attach evidence + playbooks to non-passing controls, compute scores
        total_controls = 0
        total_passing = 0
        total_warnings = 0
        total_failing = 0
        for fw_key, fw_data in fw_results.items():
            pass_count = 0
            warn_count = 0
            fail_count = 0
            for ctrl in fw_data['controls']:
                total_controls += 1
                if ctrl['status'] == 'pass':
                    pass_count += 1
                    total_passing += 1
                    ctrl['evidence_identities'] = []
                    ctrl['evidence_count'] = 0
                    ctrl['remediation_playbooks'] = []
                else:
                    if ctrl['status'] == 'warn':
                        warn_count += 1
                        total_warnings += 1
                    else:
                        fail_count += 1
                        total_failing += 1
                    ctrl['evidence_identities'] = evidence.get(ctrl['metric'], [])
                    ctrl['evidence_count'] = ctrl['value']
                    ctrl['remediation_playbooks'] = _match_playbooks_to_control(all_playbooks, ctrl['control_id'], fw_key)
            n = len(fw_data['controls'])
            fw_data['score'] = round(pass_count / n * 100, 1) if n > 0 else 0.0
            fw_data['pass_count'] = pass_count
            fw_data['warn_count'] = warn_count
            fw_data['fail_count'] = fail_count
            fw_data['total_controls'] = n

        overall_score = round(total_passing / total_controls * 100, 1) if total_controls > 0 else 0.0

        result = {
            'generated_at': datetime.now(timezone.utc).isoformat(),
            'run_id': run_ids[0] if run_ids else None,
            'overall_score': overall_score,
            'total_controls': total_controls,
            'passing': total_passing,
            'warnings': total_warnings,
            'failing': total_failing,
            'frameworks': fw_results,
        }

        if out_format == 'csv':
            output = _io.StringIO()
            writer = _csv.writer(output)
            writer.writerow(['Framework', 'Control ID', 'Control Name', 'Status',
                             'Metric Value', 'Threshold', 'Evidence Count', 'Evidence Identities'])
            for fw_key, fw_data in fw_results.items():
                for ctrl in fw_data['controls']:
                    names = '; '.join(e['display_name'] for e in ctrl.get('evidence_identities', []))
                    writer.writerow([
                        fw_data['name'], ctrl['control_id'], ctrl['name'],
                        ctrl['status'], ctrl['value'], ctrl['pass_threshold'],
                        ctrl.get('evidence_count', 0), names,
                    ])
            from flask import Response
            return Response(
                output.getvalue(),
                mimetype='text/csv',
                headers={'Content-Disposition': f'attachment; filename=compliance-gap-analysis-{datetime.now().strftime("%Y%m%d")}.csv'}
            )

        return jsonify(result)
    finally:
        cursor.close()
        db.close()


def get_compliance_intelligence():
    """
    GET /api/compliance/intelligence
    Returns risk-weighted compliance scoring, root cause clustering,
    cloud failure counts, top risk drivers, and trend mini.
    """
    from psycopg2.extras import RealDictCursor

    SEVERITY_MULT = {'critical': 2.0, 'high': 1.5, 'medium': 1.0, 'low': 0.8}
    SEVERITY_RANK = {'critical': 0, 'high': 1, 'medium': 2, 'low': 3}

    db = _db()
    cursor = db.conn.cursor()
    rc_cursor = db.conn.cursor(cursor_factory=RealDictCursor)
    try:
        run_ids = _latest_run_ids(cursor, _org_id(), _connection_id())
        if not run_ids:
            return jsonify({"error": "No completed discovery runs found"}), 404

        metrics = _compute_compliance_metrics(cursor, run_ids)
        frameworks = db.get_compliance_frameworks(enabled_only=True)

        # Fetch root causes
        rc_cursor.execute("SELECT * FROM compliance_root_causes ORDER BY display_order")
        root_causes_rows = [dict(r) for r in rc_cursor.fetchall()]
        rc_by_id = {rc['id']: rc for rc in root_causes_rows}

        # Evaluate all controls
        total_controls = 0
        total_passing = 0
        total_warnings = 0
        total_failing = 0
        total_weighted_max = 0.0
        total_weighted_pass = 0.0
        cloud_failures = {}
        all_failing_controls = []
        needed_metrics = set()
        fw_results = {}

        for fw in frameworks:
            fw_pass = 0
            fw_warn = 0
            fw_fail = 0
            fw_weighted_max = 0.0
            fw_weighted_pass = 0.0
            controls_out = []

            for ctrl in fw['controls']:
                status, value = _evaluate_control(ctrl, metrics)
                label = _format_metric_label(ctrl['metric'])
                severity = ctrl.get('severity', 'medium')
                weight = ctrl.get('weight', 5)
                cloud = ctrl.get('cloud', 'azure')
                mult = SEVERITY_MULT.get(severity, 1.0)
                w_score = weight * mult

                fw_weighted_max += w_score
                total_weighted_max += w_score

                if status == 'pass':
                    detail = f"{value} {label} — within limits"
                    fw_pass += 1
                    total_passing += 1
                    fw_weighted_pass += w_score
                    total_weighted_pass += w_score
                elif status == 'warn':
                    detail = f"{value} {label} — approaching threshold"
                    fw_warn += 1
                    total_warnings += 1
                    needed_metrics.add(ctrl['metric'])
                else:
                    detail = f"{value} {label} — exceeds acceptable limit (target: {ctrl['pass_operator']}{int(ctrl['pass_value'])})"
                    fw_fail += 1
                    total_failing += 1
                    needed_metrics.add(ctrl['metric'])
                    # Cloud failure tracking
                    cloud_failures[cloud] = cloud_failures.get(cloud, 0) + 1
                    all_failing_controls.append({
                        'control_id': ctrl['control_id'],
                        'name': ctrl['name'],
                        'framework': fw['name'],
                        'framework_key': fw['key'],
                        'severity': severity,
                        'weight': weight,
                        'value': value,
                        'root_cause_id': ctrl.get('root_cause_id'),
                    })

                total_controls += 1
                controls_out.append({
                    'control_id': ctrl['control_id'],
                    'name': ctrl['name'],
                    'status': status,
                    'metric': ctrl['metric'],
                    'value': value,
                    'pass_threshold': f"{ctrl['pass_operator']}{int(ctrl['pass_value'])}",
                    'detail': detail,
                    'drilldown_url': ctrl.get('drilldown_url'),
                    'severity': severity,
                    'weight': weight,
                    'cloud': cloud,
                    'pillar': ctrl.get('pillar'),
                    'root_cause_id': ctrl.get('root_cause_id'),
                })

            n = len(fw['controls'])
            fw_score = round(fw_pass / n * 100, 1) if n > 0 else 0.0
            fw_rw_score = round(fw_weighted_pass / fw_weighted_max * 100, 1) if fw_weighted_max > 0 else 0.0
            fw_results[fw['key']] = {
                'name': fw['name'],
                'version': fw.get('version'),
                'score': fw_score,
                'risk_weighted_score': fw_rw_score,
                'pass_count': fw_pass,
                'warn_count': fw_warn,
                'fail_count': fw_fail,
                'total_controls': n,
                'controls': controls_out,
                'tier': fw.get('tier', 'core'),
                'category': fw.get('category', ''),
                'short_name': fw.get('short_name', fw['name']),
                'identity_controls_count': fw.get('identity_controls_count', n),
                'total_framework_controls': fw.get('total_framework_controls', 0),
                'scope_label': fw.get('scope_label', 'Identity, access, and privilege controls'),
            }

        overall_score = round(total_passing / total_controls * 100, 1) if total_controls > 0 else 0.0
        risk_weighted_score = round(total_weighted_pass / total_weighted_max * 100, 1) if total_weighted_max > 0 else 0.0

        # Top risk drivers — top 3 failing controls by severity rank then weight DESC
        all_failing_controls.sort(key=lambda c: (SEVERITY_RANK.get(c['severity'], 9), -c['weight']))
        top_risk_drivers = all_failing_controls[:3]

        # Root cause clusters
        rc_clusters = {}
        for ctrl in all_failing_controls:
            rc_id = ctrl.get('root_cause_id')
            if not rc_id or rc_id not in rc_by_id:
                continue
            if rc_id not in rc_clusters:
                rc = rc_by_id[rc_id]
                rc_clusters[rc_id] = {
                    'id': rc_id,
                    'code': rc['code'],
                    'title': rc['title'],
                    'description': rc.get('description'),
                    'category': rc.get('category'),
                    'recommendation': rc.get('recommendation'),
                    'linked_controls': [],
                    'frameworks_impacted': set(),
                    'total_weight': 0,
                    'affected_entities': 0,
                }
            cluster = rc_clusters[rc_id]
            cluster['linked_controls'].append({
                'control_id': ctrl['control_id'],
                'name': ctrl['name'],
                'framework': ctrl['framework'],
                'severity': ctrl['severity'],
            })
            cluster['frameworks_impacted'].add(ctrl['framework_key'])
            cluster['total_weight'] += ctrl['weight']
            cluster['affected_entities'] += ctrl.get('value', 0)

        # Compute impact scores and format
        max_raw = max((c['total_weight'] * len(c['frameworks_impacted']) * max(c['affected_entities'], 1) for c in rc_clusters.values()), default=1)
        root_causes_out = []
        for rc in rc_clusters.values():
            raw = rc['total_weight'] * len(rc['frameworks_impacted']) * max(rc['affected_entities'], 1)
            impact = round(raw / max_raw * 100, 1) if max_raw > 0 else 0.0
            root_causes_out.append({
                'id': rc['id'],
                'code': rc['code'],
                'title': rc['title'],
                'description': rc['description'],
                'category': rc['category'],
                'recommendation': rc['recommendation'],
                'impact_score': impact,
                'linked_controls': rc['linked_controls'],
                'frameworks_impacted': len(rc['frameworks_impacted']),
                'affected_entities': rc['affected_entities'],
            })
        root_causes_out.sort(key=lambda x: -x['impact_score'])

        # Trend mini — last 6 snapshots
        trend_mini = []
        try:
            cursor.execute("""
                SELECT DISTINCT ON (cs.run_id) cs.run_id,
                    dr.completed_at,
                    ROUND(AVG(cs.score) OVER (PARTITION BY cs.run_id)) as overall_score
                FROM compliance_snapshots cs
                JOIN discovery_runs dr ON dr.id = cs.run_id
                ORDER BY cs.run_id DESC
                LIMIT 6
            """)
            for row in cursor.fetchall():
                trend_mini.append({
                    'run_id': row[0],
                    'date': row[1].isoformat() if row[1] else None,
                    'overall_score': int(row[2]) if row[2] else 0,
                })
            trend_mini.reverse()
        except Exception:
            try: cursor.connection.rollback()
            except Exception: pass
            pass

        # Batch-fetch evidence for non-passing controls
        evidence = _compute_compliance_evidence(cursor, run_ids, needed_metrics) if needed_metrics else {}
        # Attach evidence to controls in fw_results
        for fw_key, fw_data in fw_results.items():
            for ctrl in fw_data['controls']:
                if ctrl['status'] == 'pass':
                    ctrl['evidence_identities'] = []
                    ctrl['evidence_count'] = 0
                else:
                    ctrl['evidence_identities'] = evidence.get(ctrl['metric'], [])
                    ctrl['evidence_count'] = ctrl['value']

        # Tier summary — aggregate scores by tier
        tier_summary = {}
        for fw_key, fw_data in fw_results.items():
            tier = fw_data.get('tier', 'core')
            if tier not in tier_summary:
                tier_summary[tier] = {'tier': tier, 'category': fw_data.get('category', ''), 'frameworks': 0, 'total_controls': 0, 'passing': 0, 'warnings': 0, 'failing': 0}
            ts = tier_summary[tier]
            ts['frameworks'] += 1
            ts['total_controls'] += fw_data['total_controls']
            ts['passing'] += fw_data['pass_count']
            ts['warnings'] += fw_data['warn_count']
            ts['failing'] += fw_data['fail_count']
        for ts in tier_summary.values():
            ts['score'] = round(ts['passing'] / ts['total_controls'] * 100, 1) if ts['total_controls'] > 0 else 0.0

        return jsonify({
            'overall_score': overall_score,
            'risk_weighted_score': risk_weighted_score,
            'total_controls': total_controls,
            'passing': total_passing,
            'warnings': total_warnings,
            'failing': total_failing,
            'cloud_failures': cloud_failures,
            'top_risk_drivers': top_risk_drivers,
            'frameworks': fw_results,
            'root_causes': root_causes_out,
            'trend_mini': trend_mini,
            'tier_summary': tier_summary,
            'generated_at': datetime.now(timezone.utc).isoformat(),
        })
    finally:
        rc_cursor.close()
        cursor.close()
        db.close()


def get_dashboard_posture():
    """
    Dashboard posture data: credential health, dormant counts, posture score,
    and previous run comparison for trend indicators.
    """
    db = _db()
    cursor = db.conn.cursor()

    try:
        run_ids = _latest_run_ids(cursor, _org_id(), _connection_id())
        if not run_ids:
            return jsonify({"error": "No completed discovery runs found"}), 404

        # Live filtered count across all connection runs (excluding Microsoft SPNs)
        cursor.execute(f"""
            SELECT COUNT(*),
                   SUM(CASE WHEN i.risk_level = 'critical' THEN 1 ELSE 0 END),
                   SUM(CASE WHEN i.risk_level = 'high' THEN 1 ELSE 0 END),
                   SUM(CASE WHEN i.risk_level = 'medium' THEN 1 ELSE 0 END)
            FROM identities i
            WHERE i.discovery_run_id = ANY(%s)
            {HIDE_MICROSOFT_SQL}
        """, (run_ids,))
        filt = cursor.fetchone()

        cursor.execute("SELECT MAX(completed_at) FROM discovery_runs WHERE id = ANY(%s)", (run_ids,))
        completed_at = _scalar(cursor)

        current_run = {
            "id": run_ids[0],
            "completed_at": completed_at.isoformat() if completed_at else None,
            "total_identities": filt[0] if filt else 0,
            "critical_count": filt[1] if filt else 0,
            "high_count": filt[2] if filt else 0,
            "medium_count": filt[3] if filt else 0,
        }

        # Previous run comparison — query second-most-recent completed runs
        prev_ids = _previous_run_ids(cursor, _org_id(), _connection_id())
        previous_run = None
        if prev_ids:
            cursor.execute("SELECT MAX(completed_at) FROM discovery_runs WHERE id = ANY(%s)", (prev_ids,))
            prev_completed = _scalar(cursor)
            cursor.execute(f"""
                SELECT COUNT(*),
                       SUM(CASE WHEN i.risk_level = 'critical' THEN 1 ELSE 0 END),
                       SUM(CASE WHEN i.risk_level = 'high' THEN 1 ELSE 0 END),
                       SUM(CASE WHEN i.risk_level = 'medium' THEN 1 ELSE 0 END),
                       ROUND(COALESCE(AVG(i.risk_score), 0), 1)
                FROM identities i
                WHERE i.discovery_run_id = ANY(%s)
                {HIDE_MICROSOFT_SQL}
            """, (prev_ids,))
            ppf = cursor.fetchone()
            previous_run = {
                "id": prev_ids[0],
                "completed_at": prev_completed.isoformat() if prev_completed else None,
                "total_identities": ppf[0] if ppf else 0,
                "critical_count": ppf[1] if ppf else 0,
                "high_count": ppf[2] if ppf else 0,
                "medium_count": ppf[3] if ppf else 0,
                "avg_risk_score": float(ppf[4]) if ppf and ppf[4] else 0,
            }

        # FIX1B: Credential health, dormant, no-owner — use canonical metric queries
        from app.api.metric_queries import get_metric_count_sql
        _mparams = {'run_ids': run_ids}

        cursor.execute(get_metric_count_sql('credential_expired'), _mparams)
        expired = _scalar(cursor, 0)
        cursor.execute(get_metric_count_sql('credential_expiring'), _mparams)
        expiring_soon = _scalar(cursor, 0)
        cursor.execute(get_metric_count_sql('credential_healthy'), _mparams)
        healthy = _scalar(cursor, 0)
        cursor.execute(get_metric_count_sql('no_credentials'), _mparams)
        no_credentials = _scalar(cursor, 0)

        credential_health = {
            "expired": expired,
            "expiring_soon": expiring_soon,
            "healthy": healthy,
            "no_credentials": no_credentials,
        }

        cursor.execute(get_metric_count_sql('dormant'), _mparams)
        dormant_count = _scalar(cursor, 0)

        cursor.execute(get_metric_count_sql('unowned_nhi'), _mparams)
        no_owner_count = _scalar(cursor, 0)

        # Posture score: % of identities at low/info risk
        total = current_run["total_identities"] or 0
        high_risk = (current_run["critical_count"] + current_run["high_count"]
                     + current_run["medium_count"])
        posture_score = round(((total - high_risk) / total) * 100, 1) if total > 0 else 0.0

        previous_posture_score = None
        if previous_run:
            prev_total = previous_run["total_identities"] or 0
            prev_high_risk = (previous_run["critical_count"] + previous_run["high_count"]
                              + previous_run["medium_count"])
            previous_posture_score = round(((prev_total - prev_high_risk) / prev_total) * 100, 1) if prev_total > 0 else 0.0

        # ── v3.1 fields required by usePostureDashboard ──
        org_id = _org_id()

        if posture_score >= 90:
            posture_status = "STRONG"
        elif posture_score >= 70:
            posture_status = "MODERATE"
        elif posture_score >= 50:
            posture_status = "ELEVATED_RISK"
        else:
            posture_status = "WEAK"

        cursor.execute(
            "SELECT COUNT(*) FROM cloud_subscriptions WHERE organization_id = %s AND monitored = true AND deleted = false",
            (org_id,),
        )
        sub_count = _scalar(cursor, 0)

        identity_count = total  # already computed above (customer identities from current run)

        narrative_text = (
            f"AuditGraph is monitoring {identity_count} identities across "
            f"{sub_count} subscription{'s' if sub_count != 1 else ''} "
            f"with an overall posture score of {posture_score}."
        )

        coverage = {
            "subscriptions": sub_count,
            "identities_scoped": identity_count,
            "label": f"{sub_count} subscription{'s' if sub_count != 1 else ''} \u00b7 {identity_count} identities monitored",
            "active_sources": 1 if sub_count > 0 else 0,
            "total_sources": 1,
            "sub_count": sub_count,
            "cloud_label": "Azure",
            "confidence_level": "high" if posture_score >= 90 else ("medium" if posture_score >= 70 else "low"),
            "coverage_pct": 100 if sub_count > 0 else 0,
        }

        cursor.execute(
            "SELECT completed_at, status FROM discovery_runs WHERE organization_id = %s AND status = 'completed' ORDER BY completed_at DESC LIMIT 1",
            (org_id,),
        )
        dr_row = cursor.fetchone()
        _last_scan_ts = dr_row[0] if dr_row and dr_row[0] else None
        _last_scan_ago = None
        if _last_scan_ts:
            from datetime import datetime, timezone
            _now = datetime.now(timezone.utc)
            _diff = _now - _last_scan_ts
            _mins = int(_diff.total_seconds() / 60)
            if _mins < 60:
                _last_scan_ago = f"{_mins}m ago"
            elif _mins < 1440:
                _last_scan_ago = f"{_mins // 60}h ago"
            else:
                _last_scan_ago = f"{_mins // 1440}d ago"
        scan_metadata = {
            "last_scan": _last_scan_ts.isoformat() if _last_scan_ts else None,
            "last_scan_at": _last_scan_ts.isoformat() if _last_scan_ts else None,
            "last_scan_ago": _last_scan_ago,
            "status": dr_row[1] if dr_row else "unknown",
        }

        # v3.1 identity_risk: dormant / ghost / unowned_nhi / machine_pct
        cursor.execute(get_metric_count_sql('ghost'), _mparams)
        ghost_count = _scalar(cursor, 0)
        cursor.execute(get_metric_count_sql('dormant_privileged'), _mparams)
        dormant_priv_count = _scalar(cursor, 0)

        # B3: Provisioned unowned — never authenticated, no owner assigned
        # Excludes disabled accounts (those are Ghost Identities, not Provisioned Never Used)
        cursor.execute(f"""
            SELECT COUNT(*)
            FROM identities i
            WHERE i.discovery_run_id = ANY(%(run_ids)s)
              AND i.activity_status = 'never_used'
              AND COALESCE(i.owner_count, 0) = 0
              AND i.enabled IS NOT FALSE
              AND i.deleted_at IS NULL
              {HIDE_MICROSOFT_SQL}
        """, _mparams)
        provisioned_unowned_count = _scalar(cursor, 0)

        # A4: Excess privilege — T0/T1 with critical/high risk (excludes Ghost)
        cursor.execute(f"""
            SELECT COUNT(*)
            FROM identities i
            WHERE i.discovery_run_id = ANY(%(run_ids)s)
              AND COALESCE(i.privilege_tier, 'T3') IN ('T0', 'T1')
              AND i.risk_level IN ('critical', 'high')
              AND i.enabled IS NOT FALSE
              AND i.deleted_at IS NULL
              {HIDE_MICROSOFT_SQL}
        """, _mparams)
        excess_privilege_count = _scalar(cursor, 0)

        cursor.execute(f"""
            SELECT COUNT(*) FILTER (
                WHERE i.identity_category IN ('service_principal','managed_identity_system','managed_identity_user')
            )
            FROM identities i
            WHERE i.discovery_run_id = ANY(%(run_ids)s)
            {HIDE_MICROSOFT_SQL}
        """, _mparams)
        machine_count = _scalar(cursor, 0)
        machine_pct = round((machine_count / total) * 100) if total > 0 else 0

        identity_risk = {
            "critical": current_run["critical_count"],
            "high": current_run["high_count"],
            "medium": current_run["medium_count"],
            "total": total,
            "dormant": dormant_priv_count,
            "ghost": ghost_count,
            "unowned_nhi": no_owner_count,
            "machine_pct": machine_pct,
            "dormant_privileged": dormant_priv_count,
            "provisioned_unowned": provisioned_unowned_count,
        }

        # v3.1 blast_radius: single highest-risk identity object
        blast_radius = None
        try:
            cursor.execute(f"""
                SELECT
                    i.id,
                    i.display_name,
                    i.identity_id,
                    i.identity_category,
                    COALESCE(i.risk_score, 0) AS risk_score,
                    i.risk_level,
                    (SELECT COUNT(*) FROM attack_paths ap
                     WHERE ap.source_entity_id = i.identity_id
                       AND ap.organization_id = %(org_id)s) AS path_count,
                    (SELECT string_agg(DISTINCT ra.role_name, ', ' ORDER BY ra.role_name)
                     FROM role_assignments ra WHERE ra.identity_db_id = i.id) AS roles,
                    (SELECT COUNT(DISTINCT ra.scope)
                     FROM role_assignments ra WHERE ra.identity_db_id = i.id
                       AND ra.scope ~ '^/subscriptions/[^/]+$') AS sub_count
                FROM identities i
                WHERE i.discovery_run_id = ANY(%(run_ids)s)
                  AND i.risk_level IN ('critical', 'high')
                  {HIDE_MICROSOFT_SQL}
                ORDER BY COALESCE(i.risk_score, 0) DESC, path_count DESC
                LIMIT 1
            """, {'run_ids': run_ids, 'org_id': org_id})
            br_row = cursor.fetchone()
            if br_row and br_row[0]:
                _br_name = br_row[1] or ''
                _br_uuid = br_row[2] or ''
                _br_cat = br_row[3] or ''
                _br_score = br_row[4] or 0
                _br_level = br_row[5] or ''
                _br_paths = br_row[6] or 0
                _br_roles = br_row[7] or ''
                _br_subs = br_row[8] or 0

                # Derive role tier from highest privilege role
                _roles_lower = _br_roles.lower() if _br_roles else ''
                if 'owner' in _roles_lower or 'user access administrator' in _roles_lower:
                    _tier = 'T0'
                elif 'contributor' in _roles_lower:
                    _tier = 'T1'
                elif _br_roles:
                    _tier = 'T2'
                else:
                    _tier = 'T3'

                # Build scope string
                if _br_subs > 1:
                    _scope = f"Full control of {_br_subs} subscriptions"
                elif _br_subs == 1:
                    _scope = "Full control of the entire subscription"
                else:
                    _scope = "Access to tenant-level resources"

                # Build exploitation text
                _actor = 'Service account' if 'service_principal' in _br_cat or 'managed_identity' in _br_cat else 'User'
                _exploitation = (
                    f"{_actor} with {_br_roles} — "
                    f"{_br_paths} attack path{'s' if _br_paths != 1 else ''} detected"
                ) if _br_paths > 0 else f"{_actor} with {_br_roles}"

                blast_radius = {
                    "identity_id": br_row[0],
                    "identity_name": _br_name,
                    "identity_string_id": _br_uuid,
                    "scope_string": _scope,
                    "role_tier": _tier,
                    "exploitation_text": _exploitation,
                    "impact_label": _derive_blast_impact(_roles_lower, _br_subs, _tier),
                }
        except Exception:
            try:
                cursor.connection.rollback()
            except Exception:
                pass

        # v3.1 blast_radius_count: total critical/high identities for "+N more" badge
        try:
            cursor.execute(f"""
                SELECT COUNT(*)
                FROM identities i
                WHERE i.discovery_run_id = ANY(%(run_ids)s)
                  AND i.risk_level IN ('critical', 'high')
                  {HIDE_MICROSOFT_SQL}
            """, _mparams)
            _br_total = _scalar(cursor, 0)
            if blast_radius and _br_total > 1:
                blast_radius['more_count'] = _br_total - 1
        except Exception:
            try:
                cursor.connection.rollback()
            except Exception:
                pass

        # A3: Microsoft system anomalies — unexpected privilege (MITRE T1078.004)
        microsoft_anomalies = []
        try:
            cursor.execute("""
                SELECT i.display_name, i.risk_level, ra.role_name, ra.scope
                FROM identities i
                JOIN role_assignments ra ON ra.identity_db_id = i.id
                WHERE i.discovery_run_id = ANY(%(run_ids)s)
                  AND COALESCE(i.is_microsoft_system, false) = true
                  AND i.risk_level IN ('critical', 'high')
                  AND ra.role_name IN ('Owner', 'User Access Administrator', 'Contributor')
                  AND ra.scope ~ '^/subscriptions/[^/]+$'
                ORDER BY i.display_name
            """, {'run_ids': run_ids})
            for ma_row in cursor.fetchall():
                microsoft_anomalies.append({
                    "display_name": ma_row[0],
                    "risk_level": ma_row[1],
                    "anomaly_type": "unexpected_privilege",
                    "role": ma_row[2],
                    "scope": ma_row[3],
                    "mitre_technique": "T1078.004",
                })
        except Exception:
            try:
                cursor.connection.rollback()
            except Exception:
                pass

        # v3.1 attack_paths: top paths for Privilege Exposure tile
        _attack_paths_list = []
        _attack_path_total = 0
        _attack_path_source_count = 0
        try:
            cursor.execute("""
                SELECT ap.id, ap.source_entity_id, ap.source_entity_name,
                       ap.source_entity_type, ap.path_type, ap.severity,
                       ap.risk_score, ap.description, ap.narrative,
                       ap.affected_resource_count
                FROM attack_paths ap
                WHERE ap.organization_id = %(org_id)s
                  AND ap.discovery_run_id = ANY(%(run_ids)s)
                ORDER BY
                    CASE ap.severity
                        WHEN 'critical' THEN 1
                        WHEN 'high' THEN 2
                        WHEN 'medium' THEN 3
                        ELSE 4
                    END,
                    ap.risk_score DESC
                LIMIT 5
            """, {'org_id': org_id, 'run_ids': run_ids})
            for ap_row in cursor.fetchall():
                _attack_paths_list.append({
                    "id": ap_row[0],
                    "identity_string_id": ap_row[1],
                    "identity_name": ap_row[2] or 'Unknown',
                    "actor": ap_row[3] or 'Identity',
                    "path_type": ap_row[4],
                    "severity": ap_row[5],
                    "risk_score": ap_row[6] or 0,
                    "description": ap_row[7] or '',
                    "narrative": ap_row[8],
                    "affected_resource_count": ap_row[9] or 0,
                })
            # Total count and distinct source count
            cursor.execute("""
                SELECT COUNT(*), COUNT(DISTINCT source_entity_id)
                FROM attack_paths
                WHERE organization_id = %(org_id)s
                  AND discovery_run_id = ANY(%(run_ids)s)
            """, {'org_id': org_id, 'run_ids': run_ids})
            _ap_counts = cursor.fetchone()
            _attack_path_total = _ap_counts[0] or 0
            _attack_path_source_count = _ap_counts[1] or 0
        except Exception:
            try:
                cursor.connection.rollback()
            except Exception:
                pass

        # Recent executed fixes with positive score delta
        recent_fixes = []
        try:
            cursor.execute("""
                SELECT ar.identity_id, ar.identity_display_name,
                       ar.score_delta, ar.pre_fix_score,
                       ar.attack_paths_before, ar.attack_paths_after,
                       ar.execution_completed_at
                FROM approval_requests ar
                WHERE ar.organization_id = %s
                  AND ar.score_delta IS NOT NULL
                  AND ar.score_delta > 0
                ORDER BY ar.execution_completed_at DESC
                LIMIT 10
            """, (org_id,))
            for fix_row in cursor.fetchall():
                pre = float(fix_row[3]) if fix_row[3] else 0
                delta = float(fix_row[2]) if fix_row[2] else 0
                paths_before = int(fix_row[4]) if fix_row[4] else 0
                paths_after = int(fix_row[5]) if fix_row[5] else 0
                recent_fixes.append({
                    "identity_name": fix_row[1] or fix_row[0],
                    "score_delta": delta,
                    "score_delta_pct": round((delta / pre) * 100, 1) if pre > 0 else 0.0,
                    "paths_eliminated": paths_before - paths_after,
                    "executed_at": fix_row[6].isoformat() if fix_row[6] else None,
                })
        except Exception:
            try:
                cursor.connection.rollback()
            except Exception:
                pass

        # ── v3.1 priority_actions: top 3 remediations computed live ──
        # Computed directly from risk tables (identities, role_assignments,
        # attack_paths) so the CISO dashboard never depends on the
        # Remediation Center having been visited first.

        # Guard: ensure cursor is in a clean transaction state before running
        # priority_actions queries.  Upstream try/except blocks (blast_radius,
        # microsoft_anomalies, recent_fixes) may have called
        # cursor.connection.rollback() which leaves the connection usable but
        # could clear transaction-local state.  A quick SELECT 1 validates it.
        try:
            cursor.execute("SELECT 1")
            cursor.fetchone()
        except Exception:
            try:
                cursor.connection.rollback()
            except Exception:
                pass
        logger.debug(
            "priority_actions: org=%s run_ids=%s total_identities=%s",
            org_id, run_ids, total,
        )

        _VERB_MAP = {
            'reduce_privilege': 'REVOKE',
            'break_attack_path': 'MITIGATE',
            'remove_identity': 'REMOVE',
            'disable_identity': 'DISABLE',
            'assign_owner': 'ASSIGN',
            'scope_reduction': 'REDUCE',
        }
        _COMPLIANCE_MAP = {
            'reduce_privilege': ['CIS 6.8', 'NIST'],
            'break_attack_path': ['CIS 6.1', 'NIST'],
            'remove_identity': ['CIS 5.3', 'NIST'],
            'disable_identity': ['CIS 5.3', 'CIS 5.1'],
            'scope_reduction': ['CIS 5.3', 'NIST'],
            'assign_owner': ['CIS 5.1', 'NIST'],
        }
        _ROUTE_MAP = {
            'reduce_privilege': '/identities?risk=critical,high',
            'break_attack_path': '/attack-paths',
            'remove_identity': '/identities?filter=unowned_nhi',
            'disable_identity': '/identities?activity_status=dormant_strict',
            'scope_reduction': '/identities?activity_status=never_used',
            'assign_owner': '/identities?risk=critical,high&filter=unowned',
        }
        _DESC_MAP = {
            'reduce_privilege': 'with excessive privileges',
            'break_attack_path': 'with active lateral-movement paths',
            'remove_identity': 'ownerless service principal(s) — unattested risk',
            'disable_identity': 'dormant privileged account(s) — standing risk',
            'scope_reduction': 'provisioned but never used — unnecessary attack surface',
            'assign_owner': 'high-risk identities without an assigned owner',
        }
        priority_actions = []
        _pa_candidates = []
        try:
            # 1. Excessive privileges (reduce_privilege) — excludes Ghost
            cursor.execute("""
                SELECT COUNT(DISTINCT i.id)
                FROM identities i
                JOIN role_assignments ra ON ra.identity_db_id = i.id
                WHERE i.discovery_run_id = ANY(%(run_ids)s)
                  AND NOT COALESCE(i.is_microsoft_system, FALSE)
                  AND i.enabled IS NOT FALSE
                  AND i.deleted_at IS NULL
                  AND ra.role_name IN %(priv_roles)s
            """, {'run_ids': run_ids, 'priv_roles': PRIVILEGED_ROLES})
            _priv_count = cursor.fetchone()[0] or 0
            if _priv_count > 0:
                _pa_candidates.append({
                    'action_type': 'reduce_privilege',
                    'title': 'Downgrade Excessive Privileges',
                    'risk_reduction': 90,
                    'priority': 'critical',
                    'blast_radius': 'high',
                    'identity_count': _priv_count,
                })
        except Exception as _e1:
            logger.warning("priority_actions query 1 (reduce_privilege) failed: %s", _e1)
            try:
                cursor.connection.rollback()
            except Exception:
                pass

        try:
            # 2. Attack paths (break_attack_path)
            cursor.execute("""
                SELECT COUNT(*)
                FROM attack_paths
                WHERE organization_id = %(org_id)s
                  AND discovery_run_id = ANY(%(run_ids)s)
                  AND severity IN ('critical', 'high')
            """, {'org_id': org_id, 'run_ids': run_ids})
            _ap_count = cursor.fetchone()[0] or 0
            if _ap_count > 0:
                _pa_candidates.append({
                    'action_type': 'break_attack_path',
                    'title': 'Lateral Movement',
                    'risk_reduction': 70,
                    'priority': 'critical',
                    'blast_radius': 'high',
                    'identity_count': _ap_count,
                })
        except Exception as _e2:
            logger.warning("priority_actions query 2 (attack_paths) failed: %s", _e2)
            try:
                cursor.connection.rollback()
            except Exception:
                pass

        try:
            # 3. Unowned NHIs (remove_identity) — broadened to all non-human types
            # Excludes Ghost (disabled/deleted) — Ghost is its own category
            cursor.execute("""
                SELECT COUNT(*)
                FROM identities i
                WHERE i.discovery_run_id = ANY(%(run_ids)s)
                  AND i.identity_category IN ('service_principal', 'managed_identity_system', 'managed_identity_user')
                  AND COALESCE(i.owner_count, 0) = 0
                  AND i.enabled IS NOT FALSE
                  AND i.deleted_at IS NULL
                  AND NOT COALESCE(i.is_microsoft_system, FALSE)
            """, {'run_ids': run_ids})
            _orphan_count = cursor.fetchone()[0] or 0
            if _orphan_count > 0:
                _pa_candidates.append({
                    'action_type': 'remove_identity',
                    'title': 'Orphaned Service Principal',
                    'risk_reduction': 65,
                    'priority': 'high',
                    'blast_radius': 'medium',
                    'identity_count': _orphan_count,
                })
        except Exception as _e3:
            logger.warning("priority_actions query 3 (unowned NHIs) failed: %s", _e3)
            try:
                cursor.connection.rollback()
            except Exception:
                pass

        try:
            # 4. Stale privileged accounts (disable_identity) — excludes Ghost
            cursor.execute("""
                SELECT COUNT(DISTINCT i.id)
                FROM identities i
                JOIN role_assignments ra ON ra.identity_db_id = i.id
                WHERE i.discovery_run_id = ANY(%(run_ids)s)
                  AND NOT COALESCE(i.is_microsoft_system, FALSE)
                  AND i.activity_status IN ('stale', 'inactive', 'never_used')
                  AND i.enabled IS NOT FALSE
                  AND i.deleted_at IS NULL
                  AND ra.role_name IN %(priv_roles)s
            """, {'run_ids': run_ids, 'priv_roles': PRIVILEGED_ROLES})
            _stale_count = cursor.fetchone()[0] or 0
            if _stale_count > 0:
                _pa_candidates.append({
                    'action_type': 'disable_identity',
                    'title': 'Dormant Privileged Access',
                    'risk_reduction': 60,
                    'priority': 'high',
                    'blast_radius': 'medium',
                    'identity_count': _stale_count,
                })
        except Exception as _e4:
            logger.warning("priority_actions query 4 (stale privileged) failed: %s", _e4)
            try:
                cursor.connection.rollback()
            except Exception:
                pass

        try:
            # 5. Never-used identities with elevated risk (scope_reduction) — excludes Ghost
            cursor.execute("""
                SELECT COUNT(*)
                FROM identities i
                WHERE i.discovery_run_id = ANY(%(run_ids)s)
                  AND NOT COALESCE(i.is_microsoft_system, FALSE)
                  AND i.activity_status = 'never_used'
                  AND i.enabled IS NOT FALSE
                  AND i.deleted_at IS NULL
                  AND i.risk_level IN ('critical', 'high', 'medium')
            """, {'run_ids': run_ids})
            _never_count = cursor.fetchone()[0] or 0
            if _never_count > 0:
                _pa_candidates.append({
                    'action_type': 'scope_reduction',
                    'title': 'Never-Used Identities',
                    'risk_reduction': 55,
                    'priority': 'high',
                    'blast_radius': 'medium',
                    'identity_count': _never_count,
                })
        except Exception as _e5:
            logger.warning("priority_actions query 5 (never-used) failed: %s", _e5)
            try:
                cursor.connection.rollback()
            except Exception:
                pass

        try:
            # 6. High/Critical risk identities needing owner assignment (assign_owner) — excludes Ghost
            cursor.execute("""
                SELECT COUNT(*)
                FROM identities i
                WHERE i.discovery_run_id = ANY(%(run_ids)s)
                  AND NOT COALESCE(i.is_microsoft_system, FALSE)
                  AND i.risk_level IN ('critical', 'high')
                  AND COALESCE(i.owner_count, 0) = 0
                  AND i.enabled IS NOT FALSE
                  AND i.deleted_at IS NULL
            """, {'run_ids': run_ids})
            _unowned_risky = cursor.fetchone()[0] or 0
            if _unowned_risky > 0:
                _pa_candidates.append({
                    'action_type': 'assign_owner',
                    'title': 'Unowned High-Risk Identities',
                    'risk_reduction': 50,
                    'priority': 'high',
                    'blast_radius': 'medium',
                    'identity_count': _unowned_risky,
                })
        except Exception as _e6:
            logger.warning("priority_actions query 6 (unowned risky) failed: %s", _e6)
            try:
                cursor.connection.rollback()
            except Exception:
                pass

        # Sort by risk_reduction desc, take top 3
        _pa_candidates.sort(key=lambda c: -c['risk_reduction'])
        for idx, _c in enumerate(_pa_candidates[:3], 1):
            _at = _c['action_type']
            _verb = _VERB_MAP.get(_at, _at.split('_')[0].upper())
            _ic = _c['identity_count']
            _rr = _c['risk_reduction']
            _desc = (
                f"{_ic} identit{'ies' if _ic != 1 else 'y'} "
                f"{_DESC_MAP.get(_at, '')} \u2014 {_rr}% risk reduction"
            )
            priority_actions.append({
                "rank": idx,
                "action": f"{_verb} {_c['title']}",
                "title": _c['title'],
                "description": _desc,
                "risk_reduction_pct": _rr,
                "affected_count": _ic,
                "compliance_tags": _COMPLIANCE_MAP.get(_at, []),
                "impact_level": "HIGH" if _c['priority'] == 'critical' or _c['blast_radius'] == 'high' else "MEDIUM",
                "is_quick_win": _ic <= 3 and _rr >= 50,
                "action_type": _at,
                "route": _ROUTE_MAP.get(_at, '/identities'),
            })

        # ── v3.1 immediate_risks: reuse already-computed metric counts ──
        _risk_items = [
            {
                "type": "dormant_privileged",
                "label": "Dormant Privileged Accounts",
                "count": dormant_priv_count,
                "severity": "high",
            },
            {
                "type": "ghost_accounts",
                "label": "Ghost Identities (access not revoked)",
                "count": ghost_count,
                "severity": "critical",
            },
            {
                "type": "unowned_nhi",
                "label": "Unowned Service Principals",
                "count": no_owner_count,
                "severity": "high",
            },
        ]
        # B4: Provisioned — Never Used card
        if provisioned_unowned_count > 0:
            _prov_pct = round((provisioned_unowned_count / total) * 100, 1) if total > 0 else 0
            _prov_noun = 'identity' if provisioned_unowned_count == 1 else 'identities'
            _risk_items.append({
                "type": "provisioned_unowned",
                "label": "Provisioned \u2014 Never Used",
                "count": provisioned_unowned_count,
                "severity": "high",
                "narrative": (
                    f"{provisioned_unowned_count} {_prov_noun} ({_prov_pct}%) "
                    f"exist with roles assigned but have never signed in \u2014 "
                    f"access was provisioned but never justified"
                ),
                "pct": _prov_pct,
            })
        immediate_risks = [r for r in _risk_items if r["count"] > 0]
        immediate_risks.sort(key=lambda r: r["count"], reverse=True)

        # Top risk narrative + highest type
        if_unaddressed_count = sum(r["count"] for r in immediate_risks)
        highest_risk_type = immediate_risks[0]["type"] if immediate_risks else None
        _NARRATIVE_MAP = {
            "dormant_privileged": lambda c, p: (
                f"{c} account{'s' if c != 1 else ''} ({p}% of all identities) with admin "
                f"access have been dormant \u2014 removing them eliminates most misuse risk"
            ),
            "ghost_accounts": lambda c, p: (
                f"{c} disabled or deleted identit{'ies' if c != 1 else 'y'} ({p}%) still "
                f"hold active RBAC roles \u2014 access not revoked"
            ),
            "unowned_nhi": lambda c, p: (
                f"{c} service principal{'s' if c != 1 else ''} ({p}%) operate without "
                f"an owner \u2014 creates blind spots for attackers"
            ),
            "provisioned_unowned": lambda c, p: (
                f"{c} {'identity' if c == 1 else 'identities'} ({p}%) exist with roles "
                f"assigned but have never signed in \u2014 access was provisioned but never justified"
            ),
        }
        top_risk_narrative = None
        if highest_risk_type:
            _hr = next((r for r in immediate_risks if r["type"] == highest_risk_type), None)
            if _hr:
                _pct = round((_hr["count"] / total) * 100, 1) if total > 0 else 0
                _fn = _NARRATIVE_MAP.get(highest_risk_type)
                top_risk_narrative = _fn(_hr["count"], _pct) if _fn else None

        # Check for overlapping identities across risk categories
        has_overlapping = (dormant_priv_count + ghost_count + no_owner_count) > if_unaddressed_count if if_unaddressed_count > 0 else False

        # ── v3.1 drift: mini-widget data from latest drift report ──
        posture_anomalies = []
        drift = None
        try:
            cursor.execute("""
                SELECT events, total_changes, created_at
                FROM drift_reports
                WHERE organization_id = %s
                ORDER BY created_at DESC LIMIT 1
            """, (org_id,))
            dr_drift = cursor.fetchone()
            if dr_drift and dr_drift[0]:
                _drift_events = dr_drift[0] if isinstance(dr_drift[0], list) else []
                _total = dr_drift[1] or len(_drift_events)
                # Map backend event_types → frontend widget categories
                _DRIFT_TYPE_MAP = {
                    'role_assigned': 'ROLE_ADDED',
                    'role_removed': 'ROLE_REMOVED',
                    'privilege_escalated': 'PRIVILEGE_CHANGE',
                    'privilege_deescalated': 'PRIVILEGE_CHANGE',
                    'risk_escalated': 'PRIVILEGE_CHANGE',
                    'risk_deescalated': 'PRIVILEGE_CHANGE',
                    'identity_added': 'NEW_IDENTITY',
                    'identity_removed': 'STATE_CHANGE',
                    'identity_disabled': 'STATE_CHANGE',
                    'identity_reactivated': 'STATE_CHANGE',
                    'identity_resurrection': 'STATE_CHANGE',
                    'spn_credential_expired': 'CREDENTIAL_CHANGE',
                    'spn_credential_added': 'CREDENTIAL_CHANGE',
                    'mfa_disabled': 'CREDENTIAL_CHANGE',
                    'owner_changed': 'STATE_CHANGE',
                    'microsoft_spn_modified': 'STATE_CHANGE',
                    'classification_added': 'STATE_CHANGE',
                    'classification_removed': 'STATE_CHANGE',
                    'classification_changed': 'STATE_CHANGE',
                    'attack_path_created': 'PRIVILEGE_CHANGE',
                }
                from collections import Counter
                _type_counts = Counter()
                for ev in _drift_events:
                    _et = ev.get('event_type') or ev.get('type', '')
                    _mapped = _DRIFT_TYPE_MAP.get(_et, 'STATE_CHANGE')
                    _type_counts[_mapped] += 1
                drift = {
                    "has_drift": _total > 0,
                    "total_changes": _total,
                    "changes": [
                        {"type": t, "count": c}
                        for t, c in _type_counts.most_common()
                    ],
                    "report_date": dr_drift[2].isoformat() if dr_drift[2] else None,
                }
                # FIX F: Build anomalies from drift events for Anomalies tile
                _ANOMALY_EVENT_MAP = {
                    'risk_escalated': 'risk_score_spike',
                    'privilege_escalated': 'permission_escalation',
                    'identity_resurrection': 'dormant_reactivation',
                    'identity_reactivated': 'dormant_reactivation',
                    'spn_credential_expired': 'credential_surge',
                    'spn_credential_added': 'credential_surge',
                    'mfa_disabled': 'credential_surge',
                    'attack_path_created': 'permission_escalation',
                }
                _HIGH_EVENTS = {'risk_escalated', 'privilege_escalated', 'mfa_disabled', 'attack_path_created'}
                _anom_id = 0
                for ev in _drift_events:
                    _et = ev.get('event_type') or ev.get('type', '')
                    _anom_type = _ANOMALY_EVENT_MAP.get(_et)
                    if _anom_type:
                        _anom_id += 1
                        posture_anomalies.append({
                            "id": _anom_id,
                            "type": _anom_type,
                            "severity": 'high' if _et in _HIGH_EVENTS else 'medium',
                            "identity_name": ev.get('identity_name') or ev.get('display_name', 'Unknown'),
                            "identity_id": ev.get('identity_id'),
                            "created_at": dr_drift[2].isoformat() if dr_drift[2] else None,
                        })
            elif dr_drift:
                # Drift report exists but no events → stable
                drift = {"has_drift": False, "total_changes": 0, "changes": []}
        except Exception:
            try:
                cursor.connection.rollback()
            except Exception:
                pass

        # A3: Score trend delta
        score_trend = None
        if previous_posture_score and previous_posture_score > 0:
            _delta = round(posture_score - previous_posture_score, 1)
            if _delta > 0:
                _direction = "up"
            elif _delta < 0:
                _direction = "down"
            else:
                _direction = "stable"
            score_trend = {
                "current": posture_score,
                "previous": previous_posture_score,
                "delta": _delta,
                "direction": _direction,
                "delta_pct": round(abs(_delta / previous_posture_score * 100), 1),
            }

        # A4: Business impact findings
        # v3.1 business_impact: object with named count fields
        # (BusinessImpactWidgetV31 reads .inactive_admin_count, .disabled_live_rbac_count)
        business_impact = {
            "inactive_admin_count": dormant_priv_count,
            "disabled_live_rbac_count": ghost_count,
        }

        return jsonify({
            "current_run": current_run,
            "previous_run": previous_run,
            "posture_score": posture_score,
            "posture_status": posture_status,
            "narrative_text": narrative_text,
            "identity_risk": identity_risk,
            "coverage": coverage,
            "scan_metadata": scan_metadata,
            "previous_posture_score": previous_posture_score,
            "credential_health": credential_health,
            "dormant_count": dormant_count,
            "no_owner_count": no_owner_count,
            "expiring_credentials_count": credential_health["expiring_soon"],
            "blast_radius": blast_radius,
            "recent_fixes": recent_fixes,
            "priority_actions": priority_actions,
            "immediate_risks": immediate_risks,
            "top_risk_narrative": top_risk_narrative,
            "highest_risk_type": highest_risk_type,
            "if_unaddressed_count": if_unaddressed_count,
            "has_overlapping_identities": has_overlapping,
            "score_trend": score_trend,
            "business_impact": business_impact,
            "has_business_risk": (business_impact["inactive_admin_count"] + business_impact["disabled_live_rbac_count"]) > 0,
            "microsoft_anomalies": microsoft_anomalies,
            "attack_paths": _attack_paths_list,
            "attack_path_total": _attack_path_total,
            "attack_path_source_count": _attack_path_source_count,
            "anomalies": posture_anomalies,
            "drift": drift,
            "p2_enabled": db.get_setting('p2_telemetry_enabled', 'false', organization_id=org_id) == 'true',
            # AG-43/44: flat aliases for frontend trend rendering
            "score_delta": score_trend["delta"] if score_trend else None,
            "previous_score": previous_posture_score,
            "score_direction": score_trend["direction"] if score_trend else None,
            "posture_change_pct": score_trend["delta_pct"] if score_trend else None,
        })

    finally:
        cursor.close()
        db.close()


def get_trust_dashboard():
    """
    Trust & Federation data for the Dashboard Trust tab.
    Returns: external identity breakdown, trust path summary, cross-org access.
    """
    db = _db()
    cursor = db.conn.cursor()
    try:
        run_ids = _latest_run_ids(cursor, _org_id(), _connection_id())
        if not run_ids:
            return jsonify({"error": "No completed discovery runs found"}), 404

        # External identity breakdown
        cursor.execute(f"""
            SELECT
                COUNT(*) as total,
                COUNT(*) FILTER (WHERE COALESCE(identity_category, '') = 'guest') as guests,
                COUNT(*) FILTER (WHERE COALESCE(is_federated, false) = true) as federated,
                COUNT(*) FILTER (WHERE COALESCE(identity_category, '') = 'guest'
                    AND (EXISTS (SELECT 1 FROM entra_role_assignments era WHERE era.identity_db_id = i.id)
                         OR EXISTS (SELECT 1 FROM role_assignments ra WHERE ra.identity_db_id = i.id))
                ) as guests_with_roles,
                COUNT(*) FILTER (WHERE COALESCE(identity_category, '') = 'guest'
                    AND EXISTS (SELECT 1 FROM entra_role_assignments era WHERE era.identity_db_id = i.id
                        AND LOWER(era.role_name) IN (
                            'global administrator','privileged role administrator',
                            'application administrator','user administrator','security administrator'
                        ))
                ) as guest_admins,
                COUNT(*) FILTER (WHERE COALESCE(identity_category, '') = 'service_principal'
                    AND COALESCE(service_principal_type, '') = 'Application'
                    AND app_owner_organization_id IS NOT NULL
                    AND app_owner_organization_id != ''
                ) as multi_tenant_apps,
                COUNT(*) FILTER (WHERE tenant_or_org_id IS NOT NULL AND tenant_or_org_id != '') as cross_tenant
            FROM identities i
            WHERE i.discovery_run_id = ANY(%s)
            {HIDE_MICROSOFT_SQL}
        """, (run_ids,))
        r = cursor.fetchone()
        external = {
            "total_identities": r[0] or 0,
            "guests": r[1] or 0,
            "federated": r[2] or 0,
            "guests_with_roles": r[3] or 0,
            "guest_admins": r[4] or 0,
            "multi_tenant_apps": r[5] or 0,
            "cross_tenant": r[6] or 0,
        }

        # Top external organizations (by tenant_or_org_id)
        cursor.execute(f"""
            SELECT i.tenant_or_org_id, COUNT(*) as cnt,
                   COUNT(*) FILTER (WHERE i.risk_level IN ('critical', 'high')) as high_risk
            FROM identities i
            WHERE i.discovery_run_id = ANY(%s)
              AND i.tenant_or_org_id IS NOT NULL AND i.tenant_or_org_id != ''
            {HIDE_MICROSOFT_SQL}
            GROUP BY i.tenant_or_org_id
            ORDER BY cnt DESC
            LIMIT 10
        """, (run_ids,))
        orgs = [{"org_id": row[0], "identity_count": row[1], "high_risk_count": row[2]} for row in cursor.fetchall()]

        # Guest identities list (top 10 by risk)
        cursor.execute(f"""
            SELECT i.identity_id, i.display_name, i.risk_level, COALESCE(i.risk_score, 0),
                   i.activity_status, i.tenant_or_org_id
            FROM identities i
            WHERE i.discovery_run_id = ANY(%s) AND COALESCE(i.identity_category, '') = 'guest'
            {HIDE_MICROSOFT_SQL}
            ORDER BY COALESCE(i.risk_score, 0) DESC
            LIMIT 10
        """, (run_ids,))
        top_guests = [{
            "identity_id": row[0], "display_name": row[1], "risk_level": row[2],
            "risk_score": row[3], "activity_status": row[4], "org_id": row[5],
        } for row in cursor.fetchall()]

        return jsonify({
            "external_summary": external,
            "top_organizations": orgs,
            "top_risk_guests": top_guests,
        })
    finally:
        cursor.close()
        db.close()


def get_credential_intelligence():
    """
    Credential Intelligence data for the Dashboard Credential tab.
    Returns: secret age distribution, auth method breakdown, rotation compliance.
    """
    db = _db()
    cursor = db.conn.cursor()
    try:
        run_ids = _latest_run_ids(cursor, _org_id(), _connection_id())
        if not run_ids:
            return jsonify({"error": "No completed discovery runs found"}), 404

        # Secret age distribution — buckets by age of oldest credential
        cursor.execute(f"""
            SELECT
                COUNT(*) FILTER (WHERE c.age_days IS NOT NULL AND c.age_days < 30) as age_lt_30,
                COUNT(*) FILTER (WHERE c.age_days >= 30 AND c.age_days < 90) as age_30_90,
                COUNT(*) FILTER (WHERE c.age_days >= 90 AND c.age_days < 180) as age_90_180,
                COUNT(*) FILTER (WHERE c.age_days >= 180 AND c.age_days < 365) as age_180_365,
                COUNT(*) FILTER (WHERE c.age_days >= 365) as age_gt_365
            FROM (
                SELECT i.id,
                    EXTRACT(EPOCH FROM (NOW() - MIN(cr.start_datetime))) / 86400 as age_days
                FROM identities i
                JOIN credentials cr ON cr.identity_db_id = i.id
                WHERE i.discovery_run_id = ANY(%s)
                {HIDE_MICROSOFT_SQL}
                GROUP BY i.id
            ) c
        """, (run_ids,))
        age_row = cursor.fetchone()
        secret_age = {
            "<30d": age_row[0] or 0,
            "30-90d": age_row[1] or 0,
            "90-180d": age_row[2] or 0,
            "180-365d": age_row[3] or 0,
            ">365d": age_row[4] or 0,
        }

        # Auth method breakdown — credential types
        cursor.execute(f"""
            SELECT
                COALESCE(cr.credential_type, 'unknown') as ctype,
                COUNT(DISTINCT cr.identity_db_id) as identity_count
            FROM credentials cr
            JOIN identities i ON i.id = cr.identity_db_id
            WHERE i.discovery_run_id = ANY(%s)
            {HIDE_MICROSOFT_SQL}
            GROUP BY ctype
            ORDER BY identity_count DESC
        """, (run_ids,))
        auth_methods = {}
        for row in cursor.fetchall():
            auth_methods[row[0]] = row[1]

        # Rotation compliance — identities with creds needing rotation
        cursor.execute(f"""
            SELECT
                COUNT(DISTINCT i.id) FILTER (WHERE cr.end_datetime IS NOT NULL AND cr.end_datetime < NOW()) as rotation_overdue,
                COUNT(DISTINCT i.id) FILTER (WHERE cr.end_datetime IS NOT NULL
                    AND cr.end_datetime >= NOW()
                    AND cr.end_datetime < NOW() + INTERVAL '30 days') as rotation_soon,
                COUNT(DISTINCT i.id) FILTER (WHERE cr.end_datetime IS NOT NULL
                    AND cr.end_datetime >= NOW() + INTERVAL '30 days') as rotation_ok,
                COUNT(DISTINCT i.id) as total_with_creds,
                COUNT(DISTINCT i.id) FILTER (WHERE cr.credential_type = 'password'
                    AND EXTRACT(EPOCH FROM (NOW() - cr.start_datetime)) / 86400 > 90) as stale_passwords,
                COUNT(DISTINCT i.id) FILTER (WHERE (
                    SELECT COUNT(*) FROM credentials c2
                    WHERE c2.identity_db_id = i.id AND (c2.end_datetime IS NULL OR c2.end_datetime > NOW())
                ) > 1) as multi_active
            FROM identities i
            JOIN credentials cr ON cr.identity_db_id = i.id
            WHERE i.discovery_run_id = ANY(%s)
            {HIDE_MICROSOFT_SQL}
        """, (run_ids,))
        rot_row = cursor.fetchone()
        rotation = {
            "overdue": rot_row[0] or 0,
            "due_soon": rot_row[1] or 0,
            "compliant": rot_row[2] or 0,
            "total_with_creds": rot_row[3] or 0,
            "stale_passwords": rot_row[4] or 0,
            "multi_active_secrets": rot_row[5] or 0,
        }

        return jsonify({
            "secret_age_distribution": secret_age,
            "auth_method_breakdown": auth_methods,
            "rotation_compliance": rotation,
        })
    finally:
        cursor.close()
        db.close()


def get_identity_summary():
    """
    Get identity counts grouped by category for the dashboard.

    Returns:
        JSON with category breakdown including risk counts per category
    """
    db = _db()
    cursor = db.conn.cursor()

    try:
        run_ids = _latest_run_ids(cursor, _org_id(), _connection_id())
        if not run_ids:
            return jsonify({
                "run_id": None,
                "completed_at": None,
                "categories": {}
            })

        cursor.execute("SELECT MAX(completed_at) FROM discovery_runs WHERE id = ANY(%s)", (run_ids,))
        completed_at = _scalar(cursor)

        # Get individual identities to properly categorize each one
        # This ensures Microsoft internal detection works correctly
        summary_sql = f"""
            SELECT
                i.display_name,
                i.identity_type,
                COALESCE(i.identity_category, 'unknown') as category,
                COALESCE(i.risk_level, 'unknown') as risk
            FROM identities i
            WHERE i.discovery_run_id = ANY(%s)
            {HIDE_MICROSOFT_SQL}
        """
        summary_params = [run_ids]
        summary_sql, summary_params = _apply_sub_filter(summary_sql, summary_params, cursor, _org_id(), _connection_id())
        cursor.execute(summary_sql, tuple(summary_params))
        rows = cursor.fetchall()

        # Build category structure with proper Microsoft internal detection
        categories = {}
        for display_name, identity_type, raw_cat, risk in rows:
            # Normalize category key
            cat = _normalize_category_key(raw_cat)

            if cat not in categories:
                categories[cat] = {
                    "total": 0,
                    "critical": 0,
                    "high": 0,
                    "medium": 0,
                    "low": 0,
                    "info": 0,
                    "unknown": 0,
                }
            categories[cat]["total"] += 1
            if risk in categories[cat]:
                categories[cat][risk] += 1

        # Count monitored resources per cloud (subscriptions, accounts, projects)
        # Azure: distinct subscription IDs from role_assignments scopes
        cursor.execute("""
            SELECT COUNT(DISTINCT
                CASE
                    WHEN ra.scope LIKE '/subscriptions/%%'
                    THEN SPLIT_PART(ra.scope, '/', 3)
                END
            )
            FROM role_assignments ra
            JOIN identities i ON i.id = ra.identity_db_id
            WHERE i.discovery_run_id = ANY(%s)
              AND ra.scope LIKE '/subscriptions/%%'
        """, (run_ids,))
        arm_sub_count = _scalar(cursor, 0)

        # Also get the distinct subscription names/IDs for the detail view
        cursor.execute("""
            SELECT DISTINCT SPLIT_PART(ra.scope, '/', 3) as sub_id
            FROM role_assignments ra
            JOIN identities i ON i.id = ra.identity_db_id
            WHERE i.discovery_run_id = ANY(%s)
              AND ra.scope LIKE '/subscriptions/%%'
            ORDER BY sub_id
        """, (run_ids,))
        azure_subs = [r[0] for r in cursor.fetchall() if r[0]]

        # Also check cloud_subscriptions table for accurate count
        # Only include subscriptions whose cloud_connection still exists
        tid = _org_id()
        conn_id = _connection_id()
        if tid:
            if conn_id:
                cursor.execute("""
                    SELECT COUNT(DISTINCT cs.account_id)
                    FROM cloud_subscriptions cs
                    JOIN cloud_connections cc ON cc.id = cs.cloud_connection_id
                    WHERE cs.organization_id = %s AND cs.cloud = 'azure'
                      AND cs.cloud_connection_id = %s
                      AND cs.status IN ('active', 'discovered')
                """, (tid, conn_id))
            else:
                cursor.execute("""
                    SELECT COUNT(DISTINCT cs.account_id)
                    FROM cloud_subscriptions cs
                    JOIN cloud_connections cc ON cc.id = cs.cloud_connection_id
                    WHERE cs.organization_id = %s AND cs.cloud = 'azure'
                      AND cs.status IN ('active', 'discovered')
                """, (tid,))
            cs_count = _scalar(cursor, 0)
            # Also get sub IDs from cloud_subscriptions
            if conn_id:
                cursor.execute("""
                    SELECT DISTINCT cs.account_id
                    FROM cloud_subscriptions cs
                    JOIN cloud_connections cc ON cc.id = cs.cloud_connection_id
                    WHERE cs.organization_id = %s AND cs.cloud = 'azure'
                      AND cs.cloud_connection_id = %s
                      AND cs.status IN ('active', 'discovered')
                    ORDER BY cs.account_id
                """, (tid, conn_id))
            else:
                cursor.execute("""
                    SELECT DISTINCT cs.account_id
                    FROM cloud_subscriptions cs
                    JOIN cloud_connections cc ON cc.id = cs.cloud_connection_id
                    WHERE cs.organization_id = %s AND cs.cloud = 'azure'
                      AND cs.status IN ('active', 'discovered')
                    ORDER BY cs.account_id
                """, (tid,))
            cs_subs = [r[0] for r in cursor.fetchall() if r[0]]
        else:
            cs_count = 0
            cs_subs = []

        # Use the higher count (cloud_subscriptions is more accurate for multi-connection)
        azure_sub_count = max(arm_sub_count, cs_count)
        # Merge subscription IDs from both sources
        all_sub_ids = list(set(azure_subs + cs_subs))
        all_sub_ids.sort()

        # Count distinct Azure tenants for multi-tenant display
        azure_tenant_count = 1
        try:
            cursor.execute("""
                SELECT COUNT(DISTINCT cc.azure_directory_id)
                FROM cloud_connections cc
                WHERE cc.organization_id = %s AND cc.cloud = 'azure'
                  AND cc.azure_directory_id IS NOT NULL
            """, (tid,))
            azure_tenant_count = _scalar(cursor, 1)
        except Exception:
            try: cursor.connection.rollback()
            except Exception: pass
            pass

        # ── Read cloud_connections table per provider ──
        provider_connections = {'azure': [], 'aws': [], 'gcp': []}
        try:
            cursor.execute("""
                SELECT cc.id, cc.cloud, cc.label, cc.status, cc.connection_type,
                       cc.last_test_status, cc.last_discovery_at,
                       COALESCE(cc.discovered_count, 0) as discovered_count,
                       (SELECT COUNT(DISTINCT cs.account_id)
                        FROM cloud_subscriptions cs
                        WHERE cs.cloud_connection_id = cc.id
                          AND cs.status IN ('active', 'discovered')
                          AND COALESCE(cs.deleted, false) = false
                       ) as sub_count
                FROM cloud_connections cc
                WHERE cc.organization_id = %s
                ORDER BY cc.cloud, cc.display_order, cc.created_at
            """, (tid,))
            for row in cursor.fetchall():
                cloud = row[1]
                if cloud in provider_connections:
                    provider_connections[cloud].append({
                        'id': row[0],
                        'label': row[2],
                        'status': row[3],
                        'connection_type': row[4],
                        'last_test_status': row[5],
                        'last_discovery_at': row[6].isoformat() if row[6] else None,
                        'discovered_count': row[7],
                        'sub_count': row[8],
                    })
        except Exception:
            try: cursor.connection.rollback()
            except Exception: pass
            pass

        # AWS/GCP subscription counts from cloud_subscriptions
        aws_account_count = 0
        gcp_project_count = 0
        aws_account_ids = []
        gcp_project_ids = []
        if tid:
            for cloud_key, count_var, ids_var in [
                ('aws', 'aws_account_count', 'aws_account_ids'),
                ('gcp', 'gcp_project_count', 'gcp_project_ids'),
            ]:
                try:
                    cursor.execute("""
                        SELECT DISTINCT cs.account_id
                        FROM cloud_subscriptions cs
                        JOIN cloud_connections cc ON cc.id = cs.cloud_connection_id
                        WHERE cs.organization_id = %s AND cs.cloud = %s
                          AND cs.status IN ('active', 'discovered')
                          AND COALESCE(cs.deleted, false) = false
                        ORDER BY cs.account_id
                    """, (tid, cloud_key))
                    ids = [r[0] for r in cursor.fetchall() if r[0]]
                    if cloud_key == 'aws':
                        aws_account_ids = ids
                        aws_account_count = len(ids)
                    else:
                        gcp_project_ids = ids
                        gcp_project_count = len(ids)
                except Exception:
                    try: cursor.connection.rollback()
                    except Exception: pass
                    pass

        # Determine connected status per provider
        def _provider_connected(cloud_key):
            conns = provider_connections.get(cloud_key, [])
            return any(c['status'] in ('connected', 'active') or c['sub_count'] > 0 for c in conns)

        return jsonify({
            "run_id": run_ids[0] if run_ids else None,
            "completed_at": completed_at.isoformat() if completed_at else None,
            "categories": categories,
            "monitored_resources": {
                "azure": {
                    "subscriptions": azure_sub_count,
                    "subscription_ids": all_sub_ids,
                    "tenant_count": azure_tenant_count,
                    "connected": _provider_connected('azure') or azure_sub_count > 0,
                    "connections": provider_connections.get('azure', []),
                },
                "aws": {
                    "accounts": aws_account_count,
                    "account_ids": aws_account_ids,
                    "connected": _provider_connected('aws') or aws_account_count > 0,
                    "connections": provider_connections.get('aws', []),
                },
                "gcp": {
                    "projects": gcp_project_count,
                    "project_ids": gcp_project_ids,
                    "connected": _provider_connected('gcp') or gcp_project_count > 0,
                    "connections": provider_connections.get('gcp', []),
                },
            }
        })

    finally:
        cursor.close()
        db.close()


# =====================================================================
# Access Graph: Trust, Scope, Secret Exposure, Graph Visualization
# =====================================================================

_ISSUER_LABELS = {
    "token.actions.githubusercontent.com": "GitHub Actions",
    "login.microsoftonline.com": "Azure AD",
    "sts.windows.net": "Azure AD",
    "accounts.google.com": "Google Cloud",
    "oidc.eks.": "AWS EKS",
    "vstoken.dev.azure.com": "Azure DevOps",
}

_RISK_ORDER_GRAPH = {"critical": 5, "high": 4, "medium": 3, "low": 2, "info": 1, "unknown": 0}


def _issuer_label(issuer):
    if not issuer:
        return "Unknown"
    for fragment, label in _ISSUER_LABELS.items():
        if fragment in issuer:
            return label
    parts = issuer.replace("https://", "").replace("http://", "").split("/")
    return parts[0] if parts else issuer


def _max_risk(a, b):
    return a if _RISK_ORDER_GRAPH.get(a, 0) >= _RISK_ORDER_GRAPH.get(b, 0) else b


def _parse_arm_scope(scope):
    parts = scope.strip("/").split("/") if scope else []
    sub_id = rg_name = res_type = res_name = None
    lower_parts = [p.lower() for p in parts]
    if "subscriptions" in lower_parts:
        idx = lower_parts.index("subscriptions")
        if idx + 1 < len(parts):
            sub_id = parts[idx + 1]
    if "resourcegroups" in lower_parts:
        idx = lower_parts.index("resourcegroups")
        if idx + 1 < len(parts):
            rg_name = parts[idx + 1]
    if "providers" in lower_parts:
        idx = lower_parts.index("providers")
        if idx + 2 < len(parts):
            res_type = f"{parts[idx+1]}/{parts[idx+2]}"
            if idx + 3 < len(parts):
                res_name = parts[-1]
    return sub_id, rg_name, res_type, res_name


def _build_scope_label(scope):
    """Build a human-readable label from an ARM scope path."""
    sub_id, rg_name, res_type, res_name = _parse_arm_scope(scope)
    if not sub_id:
        return "Entire Directory" if not scope or scope == "/" else scope
    parts = []
    # Short sub ID (first 8 chars)
    parts.append(f"Sub: {sub_id[:8]}...")
    if rg_name:
        parts.append(f"RG: {rg_name}")
    if res_name:
        # Extract short resource type (e.g. "storageAccounts" from "Microsoft.Storage/storageAccounts")
        short_type = res_type.split("/")[-1] if res_type else ""
        parts.append(f"{short_type}: {res_name}")
    return " / ".join(parts)


def get_identity_graph_data(identity_id):
    """
    Return trust relationships, effective scope, secret exposure analysis,
    and pre-computed graph nodes/edges for dual-mode visualization.
    """
    db = _db()
    cursor = db.conn.cursor()

    try:
        run_ids = _latest_run_ids(cursor, _org_id(), _connection_id())
        graph_sql = """
            SELECT i.id, i.identity_id, i.display_name, i.identity_category, i.risk_level,
                   COALESCE(i.risk_score, 0), i.activity_status,
                   COALESCE(i.cloud, 'azure'), COALESCE(i.owner_count, 0),
                   COALESCE(i.credential_count, 0)
            FROM identities i
            WHERE i.identity_id = %s AND i.discovery_run_id = ANY(%s)
        """
        graph_params = [identity_id, run_ids]
        graph_sql, graph_params = _apply_sub_filter(graph_sql, graph_params, cursor, _org_id(), _connection_id())
        graph_sql += " LIMIT 1"
        cursor.execute(graph_sql, tuple(graph_params))
        row = cursor.fetchone()

        # Fallback: check app_registrations if identity not found
        if not row:
            cursor.execute("""
                SELECT linked_spn_id, app_object_id, app_id, display_name,
                       risk_level, COALESCE(risk_score, 0), owner_count
                FROM app_registrations
                WHERE (app_object_id = %s OR app_id = %s)
                  AND discovery_run_id = ANY(%s)
                LIMIT 1
            """, (identity_id, identity_id, run_ids))
            ar_row = cursor.fetchone()
            if ar_row and ar_row[0]:
                # Has linked SPN — use the SPN's identity for graph data
                cursor.execute("""
                    SELECT id, identity_id, display_name, identity_category, risk_level,
                           COALESCE(risk_score, 0), activity_status,
                           COALESCE(cloud, 'azure'), COALESCE(owner_count, 0),
                           COALESCE(credential_count, 0)
                    FROM identities WHERE id = %s LIMIT 1
                """, (ar_row[0],))
                row = cursor.fetchone()
            elif ar_row:
                # App registration with no linked SPN — return empty graph
                cursor.close()
                return jsonify({
                    "identity_id": ar_row[1] or ar_row[2],
                    "display_name": ar_row[3] or "",
                    "identity_category": "application",
                    "risk_level": ar_row[4] or "info",
                    "risk_score": int(ar_row[5]),
                    "activity_status": "unknown",
                    "cloud": "azure",
                    "trust": {"federated_trusts": [], "ownership_edges": [], "role_edges": []},
                    "effective_scope": {
                        "subscription_count": 0, "resource_group_count": 0,
                        "resource_count": 0, "scope_hierarchy": [],
                        "entra_scopes": [], "blast_radius_label": "No scoped access",
                        "cli_commands": [],
                    },
                    "secret_exposure": [],
                    "graph": {"executive_nodes": [], "executive_edges": [],
                              "technical_nodes": [], "technical_edges": []},
                })

        if not row:
            return jsonify({"error": "Identity not found"}), 404

        db_id = row[0]
        ident = {
            "identity_id": row[1],
            "display_name": row[2] or "",
            "identity_category": _normalize_category_key(row[3] or ""),
            "risk_level": row[4] or "info",
            "risk_score": int(row[5]),
            "activity_status": row[6] or "unknown",
            "cloud": row[7],
            "owner_count": int(row[8]),
            "credential_count": int(row[9]),
        }

        roles = db.get_identity_roles_enriched(db_id)
        credentials = db.get_identity_credentials(db_id)
        owners = db.get_ownership(db_id)
        graph_perms = db.get_graph_permissions(db_id)
        app_roles = db.get_app_roles(db_id)

        # Fetch group memberships for human_user/guest identities
        identity_groups = []
        if ident["identity_category"] in ("human_user", "guest"):
            try:
                identity_groups = db.get_identity_entra_groups(
                    ident["identity_id"], run_ids
                )
            except Exception:
                try: cursor.connection.rollback()
                except Exception: pass

        is_dormant = ident["activity_status"] in ("stale", "never_used")
        has_priv_roles = any(r.get("risk_level") in ("critical", "high") for r in roles)

        # Phase 3: Check AI agent classification for graph node type
        agent_graph_info = None
        try:
            from app.config import FEATURE_AI_AGENT_GOVERNANCE
            if FEATURE_AI_AGENT_GOVERNANCE:
                cursor.execute("""
                    SELECT ac.agent_identity_type, ac.detected_platform,
                           ac.classification_confidence,
                           COALESCE(ac.agent_penalty_score, 0),
                           i.last_sign_in, i.risk_score
                    FROM agent_classifications ac
                    JOIN identities i ON i.id = ac.identity_db_id
                    WHERE ac.identity_db_id = %s
                      AND ac.agent_identity_type IN ('ai_agent', 'possible_ai_agent')
                    ORDER BY ac.updated_at DESC LIMIT 1
                """, (db_id,))
                ac_row = cursor.fetchone()
                if ac_row:
                    from datetime import datetime, timezone
                    days_inactive = None
                    if ac_row[4]:
                        days_inactive = (datetime.now(timezone.utc) - ac_row[4]).days
                    has_orphan = ac_row[3] > 0
                    agent_graph_info = {
                        'detected_platform': ac_row[1],
                        'classification_confidence': float(ac_row[2] or 0),
                        'days_inactive': days_inactive,
                        'agirs_score': int(ac_row[5] or 0) + int(ac_row[3]),
                        'has_orphan_finding': has_orphan,
                    }
        except Exception:
            try: cursor.connection.rollback()
            except Exception: pass
            pass  # Non-blocking — fall back to regular identity node

        # ── TRUST RELATIONSHIPS ──────────────────────────────────
        federated_trusts = []
        for c in credentials:
            if c.get("credential_type") == "federated":
                issuer = c.get("issuer") or ""
                label = _issuer_label(issuer)
                risk = "high" if has_priv_roles else "medium"
                reason = f"External identity from {label} can authenticate as this identity"
                if has_priv_roles:
                    reason += " (privileged roles present)"
                federated_trusts.append({
                    "credential_id": c.get("id"),
                    "issuer": issuer,
                    "subject": c.get("subject") or "",
                    "issuer_label": label,
                    "trust_risk": risk,
                    "trust_reason": reason,
                })

        ownership_edges = [{
            "owner_object_id": o.get("owner_object_id"),
            "owner_display_name": o.get("owner_display_name") or "Unknown",
            "owner_upn": o.get("owner_upn"),
            "owner_type": o.get("owner_type", "user"),
            "is_primary_owner": o.get("is_primary_owner", False),
        } for o in owners]

        from datetime import datetime, timezone
        _now_graph = datetime.now(timezone.utc)
        role_edges = []
        for r in roles:
            us = r.get("usage_status") or "unknown"
            lu = r.get("last_used_at")
            if lu and hasattr(lu, 'date'):
                delta = (_now_graph - lu).days
                if delta == 0: lud = "Today"
                elif delta == 1: lud = "Yesterday"
                elif delta < 30: lud = f"{delta} days ago"
                elif delta < 365:
                    months = delta // 30
                    lud = f"{months} month{'s' if months > 1 else ''} ago"
                else: lud = f"{delta // 365}+ years ago"
            elif lu:
                lud = "Unknown"
            else:
                lud = "Never used"
            role_edges.append({
                "role_name": r.get("role_name"),
                "role_type": r.get("role_type", "azure"),
                "scope": r.get("scope") or "",
                "scope_type": r.get("scope_type") or "directory",
                "risk_level": r.get("risk_level") or "low",
                "usage_status": us,
                "last_used_display": lud,
                "is_removable": us in ("stale", "dormant", "never_used"),
            })

        trust = {
            "federated_trusts": federated_trusts,
            "ownership_edges": ownership_edges,
            "role_edges": role_edges,
        }

        # ── EFFECTIVE SCOPE ──────────────────────────────────────
        subs = {}
        for r in roles:
            if r.get("role_type") != "azure":
                continue
            scope = r.get("scope") or ""
            sub_id, rg_name, res_type, res_name = _parse_arm_scope(scope)
            if not sub_id:
                continue
            if sub_id not in subs:
                subs[sub_id] = {"subscription_id": sub_id, "resource_groups": {}, "subscription_level_roles": []}
            s = subs[sub_id]
            if rg_name:
                if rg_name not in s["resource_groups"]:
                    s["resource_groups"][rg_name] = {"name": rg_name, "rg_level_roles": [], "resources": {}}
                rg = s["resource_groups"][rg_name]
                if res_type and res_name:
                    # Resource-level role
                    res_key = f"{res_type}:{res_name}"
                    if res_key not in rg["resources"]:
                        rg["resources"][res_key] = {"type": res_type, "name": res_name, "roles": []}
                    if r["role_name"] not in rg["resources"][res_key]["roles"]:
                        rg["resources"][res_key]["roles"].append(r["role_name"])
                else:
                    # RG-level role (no specific resource)
                    if r["role_name"] not in rg["rg_level_roles"]:
                        rg["rg_level_roles"].append(r["role_name"])
            else:
                if r["role_name"] not in s["subscription_level_roles"]:
                    s["subscription_level_roles"].append(r["role_name"])

        scope_hierarchy = []
        total_rgs = 0
        total_resources = 0
        for s in subs.values():
            rgs_out = []
            for rg in s["resource_groups"].values():
                res_list = list(rg["resources"].values())
                total_resources += len(res_list)
                rgs_out.append({
                    "name": rg["name"],
                    "roles": rg["rg_level_roles"],
                    "resources": res_list,
                })
            total_rgs += len(rgs_out)
            scope_hierarchy.append({
                "subscription_id": s["subscription_id"],
                "resource_groups": rgs_out,
                "subscription_level_roles": s["subscription_level_roles"],
            })

        entra_scopes = []
        for r in roles:
            if r.get("role_type") != "entra":
                continue
            ds = r.get("scope") or "/"
            label = "Entire Directory" if ds == "/" else f"Scoped: {ds}"
            us = r.get("usage_status") or "unknown"
            # Compute last_used_display for entra scopes (same logic as role_edges)
            lu = r.get("last_used_at")
            if lu and hasattr(lu, 'date'):
                delta = (_now_graph - lu).days
                if delta == 0: e_lud = "Today"
                elif delta == 1: e_lud = "Yesterday"
                elif delta < 30: e_lud = f"{delta} days ago"
                elif delta < 365:
                    months = delta // 30
                    e_lud = f"{months} month{'s' if months > 1 else ''} ago"
                else: e_lud = f"{delta // 365}+ years ago"
            elif lu:
                e_lud = "Unknown"
            else:
                e_lud = "Never used"
            entra_scopes.append({
                "role_name": r.get("role_name"),
                "directory_scope": ds,
                "scope_label": label,
                "risk_level": r.get("risk_level") or "low",
                "usage_status": us,
                "last_used_display": e_lud,
                "is_removable": us in ("stale", "dormant", "never_used"),
            })

        sub_count = len(subs)
        blast_parts = []
        if sub_count:
            blast_parts.append(f"{sub_count} subscription{'s' if sub_count != 1 else ''}")
        if total_rgs:
            blast_parts.append(f"{total_rgs} resource group{'s' if total_rgs != 1 else ''}")
        if total_resources:
            blast_parts.append(f"{total_resources} resource{'s' if total_resources != 1 else ''}")
        if entra_scopes:
            blast_parts.append(f"{len(entra_scopes)} Entra role{'s' if len(entra_scopes) != 1 else ''}")
        blast_label = ", ".join(blast_parts) if blast_parts else "No scoped access"

        # ── CLI REMEDIATION COMMANDS ──────────────────────────────
        cli_commands = []
        principal_id = ident["identity_id"]
        for r in roles:
            if r.get("role_type") != "azure":
                continue
            scope = r.get("scope") or ""
            role_name = r.get("role_name") or ""
            if not scope:
                continue
            cli_commands.append({
                "action": "remove_role",
                "role": role_name,
                "scope": scope,
                "command": f'az role assignment delete --assignee "{principal_id}" --role "{role_name}" --scope "{scope}"',
                "description": f"Remove {role_name} from {scope}",
            })
        # Also provide create commands for least-privilege replacements
        for r in roles:
            if r.get("role_type") != "azure":
                continue
            role_name = r.get("role_name") or ""
            scope = r.get("scope") or ""
            risk = r.get("risk_level") or "low"
            if risk in ("critical", "high") and role_name in ("Owner", "Contributor", "User Access Administrator"):
                replacement = "Reader" if role_name == "Owner" else "Reader"
                cli_commands.append({
                    "action": "replace_role",
                    "current_role": role_name,
                    "replacement_role": replacement,
                    "scope": scope,
                    "commands": [
                        f'az role assignment delete --assignee "{principal_id}" --role "{role_name}" --scope "{scope}"',
                        f'az role assignment create --assignee "{principal_id}" --role "{replacement}" --scope "{scope}"',
                    ],
                    "description": f"Downgrade {role_name} to {replacement} on {scope}",
                })

        effective_scope = {
            "subscription_count": sub_count,
            "resource_group_count": total_rgs,
            "resource_count": total_resources,
            "scope_hierarchy": scope_hierarchy,
            "entra_scopes": entra_scopes,
            "blast_radius_label": blast_label,
            "cli_commands": cli_commands,
        }

        # ── SECRET EXPOSURE ──────────────────────────────────────
        now = datetime.now(timezone.utc)
        secret_exposure = []
        for c in credentials:
            flags = []
            risk = "low"
            ctype = c.get("credential_type", "")
            start = c.get("start_datetime")
            end = c.get("end_datetime")
            age_days = None
            days_to_expiry = int(c["days_to_expiry"]) if c.get("days_to_expiry") is not None else None

            if start:
                try:
                    age_days = (now - start).days
                except Exception:
                    pass

            if age_days is not None and age_days > 365:
                flags.append(f"Secret age {age_days} days - never rotated")
                risk = _max_risk(risk, "high")
            elif age_days is not None and age_days > 180:
                flags.append(f"Secret age {age_days} days - rotation recommended")
                risk = _max_risk(risk, "medium")

            if days_to_expiry is not None and days_to_expiry < 0:
                flags.append("Expired credential still present")
                risk = _max_risk(risk, "high")
            elif days_to_expiry is not None and days_to_expiry <= 30:
                flags.append(f"Expires in {days_to_expiry} days")
                risk = _max_risk(risk, "medium")

            if is_dormant and ctype == "secret":
                if not end or (end and end > now):
                    flags.append("Active secret on dormant identity - takeover risk")
                    risk = _max_risk(risk, "critical")

            if has_priv_roles and ctype == "secret":
                flags.append("Secret credential on privileged identity")
                risk = _max_risk(risk, "high")

            if ctype == "federated":
                issuer = c.get("issuer") or ""
                flags.append(f"Federated trust to {_issuer_label(issuer)}")
                if has_priv_roles:
                    flags.append("Identity has privileged roles - lateral movement risk")
                    risk = _max_risk(risk, "high")

            status = c.get("status") or "unknown"
            if ctype == "federated":
                status = "active"

            secret_exposure.append({
                "credential_id": c.get("id"),
                "credential_type": ctype,
                "display_name": c.get("display_name"),
                "age_days": age_days,
                "days_to_expiry": days_to_expiry,
                "status": status,
                "issuer": c.get("issuer"),
                "subject": c.get("subject"),
                "issuer_label": _issuer_label(c.get("issuer") or "") if ctype == "federated" else None,
                "exposure_flags": flags,
                "exposure_risk": risk,
            })

        secret_exposure.sort(key=lambda x: _RISK_ORDER_GRAPH.get(x["exposure_risk"], 0), reverse=True)

        # ── GRAPH PRE-COMPUTATION ────────────────────────────────
        cx, cy = 400, 250

        # Phase 3: Use ai_agent node type for classified agents
        _center_node_type = "identity"
        _center_node_data = {
            "label": ident["display_name"], "risk_level": ident["risk_level"],
            "risk_score": ident["risk_score"], "category": ident["identity_category"],
        }
        if agent_graph_info:
            _center_node_type = "ai_agent"
            _center_node_data.update(agent_graph_info)

        # Executive mode (3-5 nodes)
        exec_nodes = [{"id": "identity", "type": _center_node_type, "position": {"x": cx, "y": cy},
            "data": _center_node_data}]
        exec_edges = []

        risk_lines = []
        if has_priv_roles:
            crit_roles = [r["role_name"] for r in roles if r.get("risk_level") == "critical"]
            if crit_roles:
                risk_lines.append(f"Critical roles: {', '.join(crit_roles[:3])}")
        crit_secrets = [s for s in secret_exposure if s["exposure_risk"] in ("critical", "high")]
        if crit_secrets:
            risk_lines.append(f"{len(crit_secrets)} credential exposure{'s' if len(crit_secrets) != 1 else ''}")
        if is_dormant and ident["credential_count"] > 0:
            risk_lines.append("Dormant identity with active credentials")
        high_perms = [p for p in graph_perms if p.get("risk_level") in ("critical", "high")]
        if high_perms:
            risk_lines.append(f"{len(high_perms)} high-risk API permission{'s' if len(high_perms) != 1 else ''}")

        if risk_lines:
            exec_nodes.append({"id": "risk", "type": "risk_summary",
                "position": {"x": cx + 300, "y": cy - 100},
                "data": {"label": risk_lines[0],
                         "detail": "; ".join(risk_lines[1:]) if len(risk_lines) > 1 else "",
                         "risk_level": ident["risk_level"]}})
            exec_edges.append({"id": "e-id-risk", "source": "identity", "target": "risk",
                "label": "top risk", "animated": True, "style": {"stroke": "#ef4444"}})

        if blast_label != "No scoped access":
            exec_nodes.append({"id": "blast", "type": "blast_radius",
                "position": {"x": cx + 300, "y": cy + 100},
                "data": {"label": blast_label}})
            exec_edges.append({"id": "e-id-blast", "source": "identity", "target": "blast",
                "label": "blast radius"})

        if federated_trusts:
            ft = federated_trusts[0]
            fl = ft["issuer_label"]
            if len(federated_trusts) > 1:
                fl += f" (+{len(federated_trusts) - 1} more)"
            exec_nodes.append({"id": "fed", "type": "federated_trust",
                "position": {"x": cx - 300, "y": cy - 100},
                "data": {"label": fl, "subject": ft["subject"], "trust_risk": ft["trust_risk"]}})
            exec_edges.append({"id": "e-fed-id", "source": "fed", "target": "identity",
                "label": "can act as", "animated": True, "style": {"stroke": "#f59e0b"}})

        if ownership_edges:
            primary = next((o for o in ownership_edges if o.get("is_primary_owner")), ownership_edges[0])
            ol = primary["owner_display_name"]
            if len(ownership_edges) > 1:
                ol += f" (+{len(ownership_edges) - 1})"
            exec_nodes.append({"id": "owner", "type": "owner",
                "position": {"x": cx - 300, "y": cy + 100},
                "data": {"label": ol, "owner_type": primary["owner_type"], "upn": primary.get("owner_upn")}})
            exec_edges.append({"id": "e-owner-id", "source": "owner", "target": "identity", "label": "manages"})

        # Technical mode — hierarchical ARM tree layout
        tech_nodes = [{"id": "identity", "type": _center_node_type, "position": {"x": cx, "y": cy},
            "data": dict(_center_node_data)}]
        tech_edges = []

        # Role risk lookup for badge coloring in the tree
        role_risk_map = {}
        for r in role_edges:
            role_risk_map[r["role_name"]] = r.get("risk_level", "low")

        # ── Left column: owners + federated trusts ──
        left_y = 80
        for i, o in enumerate(ownership_edges):
            nid = f"owner-{i}"
            tech_nodes.append({"id": nid, "type": "owner",
                "position": {"x": cx - 350, "y": left_y},
                "data": {"label": o["owner_display_name"], "owner_type": o["owner_type"], "upn": o.get("owner_upn")}})
            tech_edges.append({"id": f"e-{nid}-id", "source": nid, "target": "identity", "label": "manages"})
            left_y += 80

        for i, ft in enumerate(federated_trusts):
            nid = f"fed-{i}"
            tech_nodes.append({"id": nid, "type": "federated_trust",
                "position": {"x": cx - 350, "y": left_y},
                "data": {"label": ft["issuer_label"], "subject": ft["subject"], "trust_risk": ft["trust_risk"]}})
            tech_edges.append({"id": f"e-{nid}-id", "source": nid, "target": "identity",
                "label": "can act as", "animated": True, "style": {"stroke": "#f59e0b"}})
            left_y += 80

        # ── Entra Directory branch (upper-right) ──
        # Roles embedded as data inside the entra_directory node
        right_y = 30
        if entra_scopes:
            entra_roles_data = []
            for es in entra_scopes:
                entra_roles_data.append({
                    "name": es["role_name"],
                    "risk_level": es.get("risk_level", "low"),
                })
            entra_nid = "entra-dir"
            # Height scales with role count
            entra_height = 55 + len(entra_scopes) * 28
            tech_nodes.append({"id": entra_nid, "type": "entra_directory",
                "position": {"x": cx + 280, "y": right_y},
                "data": {"label": "Entra Directory", "count": len(entra_scopes),
                         "roles": entra_roles_data}})
            tech_edges.append({"id": "e-id-entra", "source": "identity", "target": entra_nid,
                "label": "directory roles", "style": {"stroke": "#6366f1"}})
            right_y += entra_height + 20

        # ── Security group membership branch (human_user/guest only) ──
        # Shows: Identity → [member of] → Security Group → [has role] → Sub
        # Only groups with RBAC roles get rendered (access-relevant groups).
        group_sub_links = {}  # group_nid → list of subscription_ids
        if identity_groups:
            grp_y = max(right_y, 40)
            grp_count = 0
            for gi, grp in enumerate(identity_groups):
                rbac_roles_data = grp.get('rbac_roles') or []
                if isinstance(rbac_roles_data, str):
                    import json as _json2
                    try: rbac_roles_data = _json2.loads(rbac_roles_data)
                    except Exception: rbac_roles_data = []
                if not rbac_roles_data:
                    continue  # skip groups with no RBAC roles
                grp_nid = f"grp-{gi}"
                member_count = grp.get('member_count', 0)
                is_nested = grp.get('is_nested', False)
                grp_roles_display = [
                    {"name": r.get("role_name", ""), "risk_level": role_risk_map.get(r.get("role_name", ""), "low")}
                    for r in rbac_roles_data
                ]
                grp_height = 55 + len(grp_roles_display) * 24
                tech_nodes.append({"id": grp_nid, "type": "security_group",
                    "position": {"x": cx - 100, "y": grp_y},
                    "data": {"label": grp.get('display_name', 'Security Group'),
                             "member_count": member_count,
                             "is_nested": is_nested,
                             "is_privileged": grp.get('is_privileged', False),
                             "roles": grp_roles_display}})
                edge_label = "nested member" if is_nested else "member of"
                tech_edges.append({"id": f"e-id-{grp_nid}", "source": "identity",
                    "target": grp_nid, "label": edge_label,
                    "style": {"stroke": "#8b5cf6", "strokeDasharray": "5 3"}})
                # Track which subscriptions this group grants access to
                for r in rbac_roles_data:
                    scope = r.get('scope', '')
                    if '/subscriptions/' in scope:
                        sub_id = scope.split('/subscriptions/')[1].split('/')[0]
                        group_sub_links.setdefault(grp_nid, set()).add(sub_id)
                grp_y += grp_height + 15
                grp_count += 1
            if grp_count > 0:
                right_y = max(right_y, grp_y)

        # ── ARM hierarchy tree (roles embedded inside each node) ──
        arm_y = max(right_y, 40)

        # Index subscription node IDs for group→sub linking
        sub_node_index = {}  # subscription_id → node_id
        for si, sub_entry in enumerate(scope_hierarchy):
            sub_nid = f"sub-{si}"
            sub_label = sub_entry["subscription_id"][:12] + "..."
            sub_roles = sub_entry.get("subscription_level_roles", [])
            sub_roles_data = [{"name": rn, "risk_level": role_risk_map.get(rn, "low")} for rn in sub_roles]
            sub_height = 55 + len(sub_roles) * 24
            tech_nodes.append({"id": sub_nid, "type": "subscription",
                "position": {"x": cx + 280, "y": arm_y},
                "data": {"label": sub_label, "full_id": sub_entry["subscription_id"],
                         "roles": sub_roles_data}})
            tech_edges.append({"id": f"e-id-{sub_nid}", "source": "identity", "target": sub_nid,
                "label": "", "style": {"stroke": "#3b82f6"}})
            sub_node_index[sub_entry["subscription_id"]] = sub_nid
            arm_y += sub_height + 10

            # Resource groups under this subscription
            for rgi, rg in enumerate(sub_entry.get("resource_groups", [])):
                rg_nid = f"sub-{si}-rg-{rgi}"
                rg_roles = rg.get("roles", [])
                rg_roles_data = [{"name": rn, "risk_level": role_risk_map.get(rn, "low")} for rn in rg_roles]
                rg_height = 45 + len(rg_roles) * 24
                tech_nodes.append({"id": rg_nid, "type": "resource_group",
                    "position": {"x": cx + 530, "y": arm_y},
                    "data": {"label": rg["name"], "roles": rg_roles_data}})
                tech_edges.append({"id": f"e-{sub_nid}-{rg_nid}", "source": sub_nid, "target": rg_nid})
                arm_y += rg_height + 10

                # Resources under this RG
                for resi, res in enumerate(rg.get("resources", [])):
                    res_nid = f"sub-{si}-rg-{rgi}-res-{resi}"
                    short_type = res["type"].split("/")[-1] if "/" in res["type"] else res["type"]
                    res_roles = res.get("roles", [])
                    res_roles_data = [{"name": rn, "risk_level": role_risk_map.get(rn, "low")} for rn in res_roles]
                    res_height = 40 + len(res_roles) * 24
                    tech_nodes.append({"id": res_nid, "type": "resource",
                        "position": {"x": cx + 780, "y": arm_y},
                        "data": {"label": res["name"], "resource_type": short_type,
                                 "full_type": res["type"], "roles": res_roles_data}})
                    tech_edges.append({"id": f"e-{rg_nid}-{res_nid}", "source": rg_nid, "target": res_nid})
                    arm_y += res_height + 10

                arm_y += 10  # spacing between RGs

            arm_y += 15  # spacing between subscriptions

        # ── Group → Subscription edges (inherited access paths) ──
        for grp_nid, sub_ids in group_sub_links.items():
            for sub_id in sub_ids:
                sub_nid = sub_node_index.get(sub_id)
                if sub_nid:
                    tech_edges.append({
                        "id": f"e-{grp_nid}-{sub_nid}",
                        "source": grp_nid, "target": sub_nid,
                        "label": "has role",
                        "style": {"stroke": "#8b5cf6", "strokeDasharray": "5 3"},
                    })

        # ── Permissions (Graph API + App Roles) ──
        perm_y = arm_y + 20
        for i, p in enumerate(graph_perms):
            nid = f"perm-{i}"
            tech_nodes.append({"id": nid, "type": "permission",
                "position": {"x": cx + 280, "y": perm_y},
                "data": {"label": p["permission_name"], "permission_type": "graph_api",
                         "resource": p.get("resource_name", "Microsoft Graph"),
                         "risk_level": p.get("risk_level", "info")}})
            tech_edges.append({"id": f"e-id-{nid}", "source": "identity", "target": nid, "label": "has permission"})
            perm_y += 55

        for i, ar in enumerate(app_roles):
            nid = f"approle-{i}"
            tech_nodes.append({"id": nid, "type": "permission",
                "position": {"x": cx + 280, "y": perm_y},
                "data": {"label": ar.get("role_display_name") or ar.get("app_role_id", "App Role"),
                         "permission_type": "app_role",
                         "resource": ar.get("resource_display_name", "Application"),
                         "risk_level": ar.get("risk_level", "info")}})
            tech_edges.append({"id": f"e-id-{nid}", "source": "identity", "target": nid, "label": "app role"})
            perm_y += 55

        # ── Credentials at bottom ──
        bottom_y = max(perm_y, left_y, cy + 200) + 40
        cred_start_x = cx - min(len(secret_exposure), 6) * 65
        for i, c in enumerate(secret_exposure):
            nid = f"cred-{i}"
            tech_nodes.append({"id": nid, "type": "credential",
                "position": {"x": cred_start_x + i * 130, "y": bottom_y},
                "data": {"label": c["display_name"] or c["credential_type"],
                         "credential_type": c["credential_type"], "exposure_risk": c["exposure_risk"],
                         "status": c["status"], "age_days": c.get("age_days"), "days_to_expiry": c.get("days_to_expiry")}})
            tech_edges.append({"id": f"e-id-{nid}", "source": "identity", "target": nid,
                "sourceHandle": "bottom", "label": "holds"})

        graph = {
            "executive_nodes": exec_nodes, "executive_edges": exec_edges,
            "technical_nodes": tech_nodes, "technical_edges": tech_edges,
        }

        result = {
            "identity_id": ident["identity_id"],
            "display_name": ident["display_name"],
            "risk_level": ident["risk_level"],
            "risk_score": ident["risk_score"],
            "trust_relationships": trust,
            "effective_scope": effective_scope,
            "secret_exposure": secret_exposure,
            "graph": graph,
        }
        # Phase 3: Include agent classification data for panel display
        if agent_graph_info:
            result["agent_info"] = agent_graph_info
        return jsonify(result)

    finally:
        cursor.close()
        db.close()


def get_identity_keyvault_access(identity_id):
    """
    Return Key Vault metadata for an identity's KV-scoped role assignments.
    Groups items by vault with expiry status for graph visualization.
    """
    db = _db()
    cursor = db.conn.cursor()

    try:
        run_ids = _latest_run_ids(cursor, _org_id(), _connection_id())
        # Fetch role_assignments JSON for this identity
        ra_sql = """
            SELECT i.role_assignments
            FROM identities i
            WHERE i.identity_id = %s AND i.discovery_run_id = ANY(%s)
        """
        ra_params = [identity_id, run_ids]
        ra_sql, ra_params = _apply_sub_filter(ra_sql, ra_params, cursor, _org_id(), _connection_id())
        ra_sql += " LIMIT 1"
        cursor.execute(ra_sql, tuple(ra_params))
        row = cursor.fetchone()
        if not row or not row[0]:
            return jsonify({'vaults': []})

        role_assignments = row[0] if isinstance(row[0], list) else json.loads(row[0]) if row[0] else []

        # Extract unique vault resource IDs from scopes
        vault_map = {}  # vault_resource_id -> role_name
        for ra in role_assignments:
            scope = (ra.get('scope') or '').lower()
            kv_idx = scope.find('microsoft.keyvault/vaults/')
            if kv_idx == -1:
                continue
            # Rebuild the vault ARM path up to the vault name
            parts = (ra.get('scope') or '').split('/')
            vault_parts = []
            for p in parts:
                vault_parts.append(p)
                if p.lower() == 'vaults' and len(vault_parts) > 1:
                    # Next part is the vault name — grab one more
                    break
            # vault_parts ends at 'vaults', need to include vault name
            vault_idx = len(vault_parts)
            if vault_idx < len(parts):
                vault_parts.append(parts[vault_idx])
            vault_id = '/'.join(vault_parts)
            role = ra.get('role_definition_name', 'Unknown')
            if vault_id not in vault_map:
                vault_map[vault_id] = set()
            vault_map[vault_id].add(role)

        if not vault_map:
            return jsonify({'vaults': []})

        # Fetch KV metadata items per vault
        vaults = []
        for vault_resource_id, roles in vault_map.items():
            items = db.get_keyvault_items_for_vault(vault_resource_id)
            # Extract vault name from ARM path (last segment)
            vault_name = vault_resource_id.rsplit('/', 1)[-1] if '/' in vault_resource_id else vault_resource_id
            # Serialize dates
            for item in items:
                for key in ('expires_on', 'created_on', 'last_updated'):
                    if item.get(key) and hasattr(item[key], 'isoformat'):
                        item[key] = item[key].isoformat()
            vaults.append({
                'vault_name': vault_name,
                'vault_resource_id': vault_resource_id,
                'roles': sorted(roles),
                'items': items,
            })

        return jsonify({'vaults': vaults})

    finally:
        cursor.close()
        db.close()


def get_identity_pim_data(identity_id):
    """
    Get PIM (Privileged Identity Management) data for an identity.
    Returns eligible assignments, activation history, and overuse metrics.
    """
    db = _db()
    cursor = db.conn.cursor()

    try:
        # Resolve identity_db_id from identity_id (org-scoped)
        run_ids = _latest_run_ids(cursor, _org_id(), _connection_id())
        cursor.execute("""
            SELECT i.id FROM identities i
            WHERE i.identity_id = %s AND i.discovery_run_id = ANY(%s)
            LIMIT 1
        """, (identity_id, run_ids))
        row = cursor.fetchone()
        if not row:
            return jsonify({"eligible_assignments": [], "activations": [], "overuse_metrics": {
                "activation_frequency_30d": 0, "always_active_pattern": False, "total_active_hours_30d": 0
            }})

        identity_db_id = row[0]
        pim_data = db.get_pim_data(identity_db_id)

        # Serialize datetimes
        for item in pim_data["eligible_assignments"]:
            for key in ("start_datetime", "end_datetime"):
                if item.get(key) and hasattr(item[key], "isoformat"):
                    item[key] = item[key].isoformat()

        for item in pim_data["activations"]:
            for key in ("activation_start", "activation_end", "created_datetime"):
                if item.get(key) and hasattr(item[key], "isoformat"):
                    item[key] = item[key].isoformat()

        return jsonify(pim_data)

    finally:
        cursor.close()
        db.close()


