def get_remediation_status(identity_id: str):
    """Get remediation action statuses for all playbooks for a specific identity."""
    db = _db()
    try:
        # Block remediation status lookup for Microsoft/system identities
        cursor = db.conn.cursor()
        run_ids = _latest_run_ids(cursor, _org_id(), _connection_id())
        cursor.execute("""
            SELECT COALESCE(i.is_microsoft_system, FALSE)
            FROM identities i
            WHERE i.identity_id = %s AND i.discovery_run_id = ANY(%s)
            LIMIT 1
        """, (identity_id, run_ids))
        ms_row = cursor.fetchone()
        cursor.close()
        if ms_row and ms_row[0]:
            return jsonify({'identity_id': identity_id, 'actions': {}, 'microsoft_system': True})

        actions = db.get_remediation_actions(identity_id)
        return jsonify({
            'identity_id': identity_id,
            'actions': actions,
        })
    finally:
        db.close()


def post_remediation_action(identity_id: str):
    """Create or update a remediation action for an identity."""
    db = _db()
    try:
        # Block creating remediation actions for Microsoft/system identities
        cursor = db.conn.cursor()
        run_ids = _latest_run_ids(cursor, _org_id(), _connection_id())
        cursor.execute("""
            SELECT COALESCE(i.is_microsoft_system, FALSE)
            FROM identities i
            WHERE i.identity_id = %s AND i.discovery_run_id = ANY(%s)
            LIMIT 1
        """, (identity_id, run_ids))
        ms_row = cursor.fetchone()
        cursor.close()
        if ms_row and ms_row[0]:
            return jsonify({'error': 'Cannot create remediation actions for Microsoft/system-managed identities'}), 403

        body = request.get_json()
        if not body:
            return jsonify({'error': 'Request body required'}), 400

        playbook_id = body.get('playbook_id')
        status = body.get('status')
        notes = body.get('notes')

        if not playbook_id or not status:
            return jsonify({'error': 'playbook_id and status are required'}), 400

        valid_statuses = ('open', 'acknowledged', 'completed', 'skipped')
        if status not in valid_statuses:
            return jsonify({'error': f'status must be one of: {", ".join(valid_statuses)}'}), 400

        result = db.upsert_remediation_action(
            identity_id=identity_id,
            playbook_id=_safe_int(playbook_id, 'playbook_id'),
            status=status,
            notes=notes,
        )

        # Serialize timestamps
        for key in ('created_at', 'updated_at'):
            if result.get(key) and hasattr(result[key], 'isoformat'):
                result[key] = result[key].isoformat()

        _log(db,'remediation_updated', f'Remediation status changed to {status}', {
            'identity_id': identity_id,
            'playbook_id': playbook_id,
            'status': status,
        })

        return jsonify(result)
    finally:
        db.close()


def post_bulk_remediation():
    """Apply a remediation status to all matched playbooks for multiple identities."""
    db = _db()
    try:
        body = request.get_json()
        if not body:
            return jsonify({'error': 'Request body required'}), 400

        identity_ids = body.get('identity_ids', [])
        status = body.get('status')
        notes = body.get('notes')

        if not identity_ids or not isinstance(identity_ids, list):
            return jsonify({'error': 'identity_ids must be a non-empty list'}), 400

        if len(identity_ids) > 50:
            return jsonify({'error': 'Maximum 50 identities per bulk action'}), 400

        valid_statuses = ('acknowledged', 'completed', 'skipped')
        if status not in valid_statuses:
            return jsonify({'error': f'status must be one of: {", ".join(valid_statuses)}'}), 400

        # Validate all identity_ids belong to the caller's tenant
        cursor = db.conn.cursor()
        run_ids = _latest_run_ids(cursor, _org_id(), _connection_id())
        if run_ids:
            cursor.execute("""
                SELECT identity_id FROM identities
                WHERE identity_id = ANY(%s)
                  AND discovery_run_id = ANY(%s)
            """, (identity_ids, run_ids))
            validated_ids = [row[0] for row in cursor.fetchall()]
        else:
            validated_ids = []
        cursor.close()

        rejected = len(identity_ids) - len(validated_ids)
        if rejected > 0:
            logger.warning(
                "Bulk remediation: %d identity_ids rejected (not in caller's tenant)",
                rejected,
            )

        if not validated_ids:
            return jsonify({'error': 'No valid identity_ids for this tenant'}), 400

        result = db.bulk_upsert_remediation_actions(validated_ids, status, notes)

        _log(db,'remediation_updated', f'Bulk {status} applied to {result["identity_count"]} identities ({result["updated_count"]} actions)', {
            'bulk': True,
            'status': status,
            'identity_count': result['identity_count'],
            'updated_count': result['updated_count'],
        })

        return jsonify(result)
    finally:
        db.close()


