def auth_refresh():
    """POST /api/auth/refresh — exchange refresh token for new tokens."""
    from app.api.auth import _derive_portal, _cookie_name
    data = request.get_json(silent=True) or {}
    raw_refresh = data.get('refresh_token', '')

    # Phase S1: Fall back to httpOnly cookie if no refresh token in body
    if not raw_refresh:
        _portal = _derive_portal()
        raw_refresh = request.cookies.get(_cookie_name(_portal, 'refresh'), '')

    if not raw_refresh:
        return jsonify({'error': 'Refresh token required'}), 400

    # Phase 68 fix: Close DB connection BEFORE token generation to avoid deadlock
    # (same pattern as auth_login fix)
    # Refresh is pre-auth (public path), so use admin DB to bypass RLS.
    db = Database(_admin_reason='auth_refresh: pre-auth token exchange')
    try:
        token_hash = hash_refresh_token(raw_refresh)
        token_record = db.get_refresh_token(token_hash)

        if not token_record:
            return jsonify({'error': 'Invalid refresh token'}), 401

        # Phase 1C: Detect token reuse — if revoked token is presented,
        # an attacker may have stolen it. Revoke ALL tokens for this user.
        if token_record.get('revoked'):
            try:
                db.revoke_all_user_tokens(token_record['user_id'])
                logger.warning(f"Refresh token reuse detected for user_id={token_record['user_id']} — all tokens revoked")
            except Exception as e:
                try: db.conn.rollback()
                except Exception: pass
                logger.error(f"Failed to revoke all tokens for user_id={token_record['user_id']}: {e}")
            return jsonify({'error': 'Token reuse detected — all sessions invalidated'}), 401

        expires_at = token_record['expires_at']
        if expires_at.tzinfo is None:
            expires_at = expires_at.replace(tzinfo=timezone.utc)
        if expires_at < datetime.now(timezone.utc):
            return jsonify({'error': 'Refresh token expired'}), 401

        user = db.get_user_by_id(token_record['user_id'])
        if not user or not user.get('enabled'):
            return jsonify({'error': 'User disabled'}), 401

        db.revoke_refresh_token(token_hash)

        # Phase 1B: Preserve portal context from stored refresh token
        portal = token_record.get('portal', 'client')

        # Look up org slug for audience claim if client portal
        slug = None
        if portal == 'client' and user.get('organization_id'):
            try:
                org = db.get_organization_by_id(user['organization_id'])
                if org:
                    slug = org.get('slug')
            except Exception:
                try: db.conn.rollback()
                except Exception: pass
                pass
    finally:
        db.close()

    # Generate tokens AFTER closing connection 1
    # Phase 1B: Pass portal + org_slug for portal-scoped tokens
    access_token = generate_access_token(user, portal=portal, org_slug=slug)
    new_refresh = generate_refresh_token(user, portal=portal)

    from flask import make_response as _mkr
    from app.api.auth import set_auth_cookies
    resp = _mkr(jsonify({
        'access_token': access_token,
        'refresh_token': new_refresh,
        'user': {
            'id': user['id'],
            'username': user['username'],
            'display_name': user['display_name'],
            'role': user['role'],
            'organization_id': user.get('organization_id'),
            'org_name': user.get('org_name'),
            'is_superadmin': user.get('is_superadmin', False),
            'portal_role': user.get('portal_role'),
            'force_password_change': user.get('force_password_change', False),
        }
    }))
    set_auth_cookies(resp, access_token, new_refresh, portal)
    return resp


def auth_logout():
    """POST /api/auth/logout — revoke refresh token + clear httpOnly cookies."""
    from app.api.auth import _derive_portal, _cookie_name, clear_auth_cookies
    data = request.get_json(silent=True) or {}
    raw_refresh = data.get('refresh_token', '')
    portal = _derive_portal()

    # Phase S1: Also try revoking the refresh token from cookie
    if not raw_refresh:
        raw_refresh = request.cookies.get(_cookie_name(portal, 'refresh'), '')

    db = _db()
    try:
        if raw_refresh:
            db.revoke_refresh_token(hash_refresh_token(raw_refresh))

        user = getattr(g, 'current_user', None)
        if user:
            try:
                action_type = 'admin_logout' if portal == 'admin' else 'auth_logout'
                _log(db, action_type, f'User "{user["username"]}" logged out ({portal} portal)',
                                {'user_id': user['id'], 'portal': portal})
            except Exception:
                try: db.conn.rollback()
                except Exception: pass
                pass

        from flask import make_response as _mkr
        resp = _mkr(jsonify({'message': 'Logged out'}))
        clear_auth_cookies(resp, portal)
        return resp
    finally:
        db.close()


def auth_me():
    """GET /api/auth/me — return current authenticated user profile."""
    user = g.current_user
    db = _db()
    try:
        full_user = db.get_user_by_id(user['id'])
        if not full_user:
            return jsonify({'error': 'User not found'}), 404
        # Phase S1: Include impersonation state so frontend can derive it from /me
        if user.get('impersonating'):
            full_user['impersonating'] = True
            full_user['impersonator_username'] = user.get('impersonator_username')
        return jsonify({'user': full_user})
    finally:
        db.close()


def change_password():
    """PUT /api/auth/password — change own password."""
    user = g.current_user
    data = request.get_json(silent=True) or {}
    current_password = str(data.get('current_password', ''))
    new_password = str(data.get('new_password', ''))

    if not current_password or not new_password:
        return jsonify({'error': 'Current password and new password are required'}), 400
    valid, err = validate_password(new_password)
    if not valid:
        return jsonify({'error': err}), 400

    db = _db()
    try:
        full_user = db.get_user_by_username(user['username'])
        if not full_user:
            return jsonify({'error': 'User not found'}), 404

        if not bcrypt.checkpw(current_password.encode('utf-8'), full_user['password_hash'].encode('utf-8')):
            return jsonify({'error': 'Current password is incorrect'}), 401

        new_hash = bcrypt.hashpw(new_password.encode('utf-8'), bcrypt.gensalt()).decode('utf-8')
        db.update_user(user['id'], password_hash=new_hash)
        # Phase 78: Clear force_password_change after successful password change
        db.set_force_password_change(user['id'], False)

        try:
            _log(db,'password_changed', f'User "{user["username"]}" changed their password',
                            {'user_id': user['id']})
        except Exception:
            try: db.conn.rollback()
            except Exception: pass
            pass

        return jsonify({'message': 'Password changed successfully'})
    finally:
        db.close()


def forgot_password_handler():
    """POST /api/auth/forgot-password — initiate password reset (public)."""
    data = request.get_json(silent=True) or {}
    email = str(data.get('email', '')).strip().lower()
    org_slug = str(data.get('org_slug', '')).strip() or None

    # Always return success to prevent email enumeration
    success_msg = 'If an account exists with this email, a password reset link has been sent.'

    if not email:
        return jsonify({'error': 'Email is required'}), 400

    db = Database()  # Bypass RLS — pre-auth public endpoint
    try:
        # Resolve organization_id from slug if provided
        organization_id = None
        if org_slug:
            org = db.get_organization_by_slug(org_slug)
            if org:
                organization_id = org['id']

        user = db.get_user_by_email(email, organization_id=organization_id)
        if not user:
            return jsonify({'message': success_msg})

        # Rate limit: max 3 reset requests per email per hour
        recent = db.count_recent_reset_requests(email)
        if recent >= 3:
            return jsonify({'message': success_msg})

        # Generate token
        raw_token = secrets.token_urlsafe(48)
        token_hash = hashlib.sha256(raw_token.encode()).hexdigest()
        expires = datetime.now(timezone.utc) + timedelta(hours=1)

        db.set_password_reset_token(user['id'], token_hash, expires)

        # Build reset URL (email delivery uses existing EmailService if configured)
        reset_url = f"/reset-password?token={raw_token}"
        logger.info(f"[Password Reset] Token generated for user: {email}")

        try:
            _log(db, 'password_reset_requested',
                 f'Password reset requested for "{email}"',
                 {'user_id': user['id'], 'ip': request.remote_addr})
        except Exception:
            try: db.conn.rollback()
            except Exception: pass
            pass

        return jsonify({'message': success_msg})
    finally:
        db.close()


def validate_reset_token_handler():
    """GET /api/auth/validate-reset-token — check if a reset token is valid (public)."""
    token = request.args.get('token', '').strip()
    if not token:
        return jsonify({'valid': False}), 400

    token_hash = hashlib.sha256(token.encode()).hexdigest()
    db = Database()  # Bypass RLS — pre-auth public endpoint
    try:
        user = db.get_user_by_reset_token(token_hash)
        if not user:
            return jsonify({'valid': False})

        # Mask email: show first 2 chars + *** + domain
        email = user.get('email', '') or ''
        if '@' in email:
            local, domain = email.split('@', 1)
            masked = local[:2] + '***@' + domain
        else:
            masked = '***'

        return jsonify({'valid': True, 'email': masked})
    finally:
        db.close()


def reset_password_handler():
    """POST /api/auth/reset-password — reset password with token (public)."""
    data = request.get_json(silent=True) or {}
    token = str(data.get('token', '')).strip()
    new_password = str(data.get('new_password', ''))

    if not token:
        return jsonify({'error': 'Reset token is required'}), 400
    if not new_password:
        return jsonify({'error': 'New password is required'}), 400
    valid, err = validate_password(new_password)
    if not valid:
        return jsonify({'error': err}), 400

    token_hash = hashlib.sha256(token.encode()).hexdigest()
    db = Database()  # Bypass RLS — pre-auth public endpoint
    try:
        user = db.get_user_by_reset_token(token_hash)
        if not user:
            return jsonify({'error': 'Invalid or expired reset token'}), 400

        new_hash = bcrypt.hashpw(new_password.encode('utf-8'), bcrypt.gensalt()).decode('utf-8')
        db.update_user(user['id'], password_hash=new_hash)
        db.clear_password_reset_token(user['id'])
        db.reset_failed_login(user['id'])
        db.set_force_password_change(user['id'], False)

        try:
            _log(db, 'password_reset_completed',
                 f'Password reset completed for user "{user["username"]}"',
                 {'user_id': user['id'], 'ip': request.remote_addr})
        except Exception:
            try: db.conn.rollback()
            except Exception: pass
            pass

        return jsonify({'message': 'Password reset successfully. You can now log in with your new password.'})
    finally:
        db.close()


def admin_reset_user_password(user_id):
    """POST /api/users/<id>/reset-password — admin resets a user's password."""
    current_user = getattr(g, 'current_user', None)
    if not current_user:
        return jsonify({'error': 'Authentication required'}), 401

    db = _db()
    try:
        target = db.get_user_by_id(user_id)
        if not target:
            return jsonify({'error': 'User not found'}), 404

        # Generate temporary password
        temp_password = secrets.token_urlsafe(16)
        new_hash = bcrypt.hashpw(temp_password.encode('utf-8'), bcrypt.gensalt()).decode('utf-8')

        db.update_user(user_id, password_hash=new_hash)
        db.set_force_password_change(user_id, True)
        db.reset_failed_login(user_id)
        db.clear_password_reset_token(user_id)

        try:
            db.log_admin_audit(current_user['id'], 'admin_password_reset',
                               target_user_id=user_id,
                               target_organization_id=target.get('organization_id'),
                               details={'target_username': target['username']},
                               ip_address=request.remote_addr)
        except Exception:
            try: db.conn.rollback()
            except Exception: pass
            pass

        try:
            _log(db, 'admin_password_reset',
                 f'Admin "{current_user["username"]}" reset password for user "{target["username"]}"',
                 {'admin_user_id': current_user['id'], 'target_user_id': user_id})
        except Exception:
            try: db.conn.rollback()
            except Exception: pass
            pass

        return jsonify({
            'message': f'Password reset for "{target["username"]}". User will be required to change it on next login.',
            'temp_password': temp_password,
        })
    finally:
        db.close()


