# ── Phase 33: Export Pipeline ─────────────────────────────────────

def _resolve_export_run_ids(cursor, tid, conn_id):
    """Resolve run IDs for export, optionally filtered by date range.
    Reads ?from=YYYY-MM-DD&to=YYYY-MM-DD query params.
    Returns (run_ids, date_range_text).
    """
    from_date = request.args.get('from')
    to_date = request.args.get('to')

    if from_date and to_date:
        try:
            from_dt = datetime.strptime(from_date, '%Y-%m-%d')
            to_dt = datetime.strptime(to_date, '%Y-%m-%d').replace(hour=23, minute=59, second=59)

            query = """
                SELECT id FROM discovery_runs
                WHERE organization_id = %s AND status = 'completed'
                  AND completed_at >= %s AND completed_at <= %s
            """
            params = [tid, from_dt, to_dt]
            if conn_id:
                query += " AND cloud_connection_id = %s"
                params.append(conn_id)
            query += " ORDER BY completed_at DESC"
            cursor.execute(query, params)
            range_run_ids = [r[0] for r in cursor.fetchall()]
            if range_run_ids:
                return range_run_ids[:1], f'{from_date} to {to_date}'
        except ValueError:
            pass

    run_ids = _latest_run_ids(cursor, tid, conn_id)
    return run_ids, 'latest'


def export_data(export_type):
    """
    GET /api/export/<type>
    Returns structured JSON for client-side CSV/JSON file generation.
    Supported types: identities, compliance, drift, risk-summary
    """
    VALID_TYPES = {'identities', 'compliance', 'drift', 'risk-summary', 'evidence-package', 'sensitive-data', 'evidence-json'}
    if export_type not in VALID_TYPES:
        return jsonify({'error': f'Invalid export type. Valid: {", ".join(sorted(VALID_TYPES))}'}), 400

    if export_type == 'identities':
        return _export_identities()
    elif export_type == 'compliance':
        return _export_compliance()
    elif export_type == 'drift':
        return _export_drift()
    elif export_type == 'risk-summary':
        return _export_risk_summary()
    elif export_type == 'evidence-package':
        return _export_evidence_package()
    elif export_type == 'sensitive-data':
        return _export_sensitive_data()
    elif export_type == 'evidence-json':
        return _export_evidence_json()


def _export_identities():
    """Export all identities (no pagination) with optional filters."""
    db = _db()
    cursor = db.conn.cursor()
    try:
        risk_filter = request.args.get('risk_level')
        category_filter = request.args.get('identity_category')

        run_ids, date_range = _resolve_export_run_ids(cursor, _org_id(), _connection_id())
        if not run_ids:
            return jsonify({'error': 'No completed discovery runs found'}), 404

        query = """
            SELECT
                i.identity_id, i.display_name, i.identity_type,
                COALESCE(i.identity_category, '') as identity_category,
                i.risk_level, i.credential_count, i.credential_status,
                i.credential_expiration, i.created_datetime, i.activity_status,
                (SELECT COUNT(*) FROM role_assignments ra WHERE ra.identity_db_id = i.id) as rbac_role_count,
                (SELECT COUNT(*) FROM entra_role_assignments era WHERE era.identity_db_id = i.id) as entra_role_count,
                COALESCE(i.cloud, 'azure') as cloud,
                COALESCE(i.status, 'active') as status,
                i.last_seen_auth,
                i.owner_display_name,
                COALESCE(i.owner_count, 0) as owner_count,
                COALESCE(i.risk_score, 0) as risk_score,
                COALESCE(i.api_permission_count, 0) as api_permission_count,
                COALESCE(i.app_role_count, 0) as app_role_count,
                i.enabled,
                CASE
                    WHEN EXISTS (
                        SELECT 1 FROM entra_role_assignments era WHERE era.identity_db_id = i.id
                        AND LOWER(era.role_name) IN (
                            'global administrator', 'privileged role administrator',
                            'privileged authentication administrator',
                            'application administrator', 'cloud application administrator',
                            'hybrid identity administrator'
                        )
                    ) THEN 0
                    WHEN EXISTS (
                        SELECT 1 FROM role_assignments ra WHERE ra.identity_db_id = i.id
                        AND LOWER(ra.role_name) IN ('owner', 'user access administrator')
                        AND (ra.scope IS NULL OR ra.scope = '/' OR ra.scope LIKE '/subscriptions/%%'
                             AND ra.scope NOT LIKE '/subscriptions/%%/resourceGroups/%%')
                    ) THEN 0
                    WHEN EXISTS (
                        SELECT 1 FROM entra_role_assignments era WHERE era.identity_db_id = i.id
                        AND LOWER(era.role_name) IN (
                            'user administrator', 'exchange administrator',
                            'sharepoint administrator', 'teams administrator',
                            'security administrator', 'compliance administrator',
                            'conditional access administrator', 'helpdesk administrator'
                        )
                    ) THEN 1
                    WHEN EXISTS (
                        SELECT 1 FROM role_assignments ra WHERE ra.identity_db_id = i.id
                        AND LOWER(ra.role_name) IN ('owner', 'contributor', 'user access administrator')
                    ) THEN 1
                    WHEN EXISTS (SELECT 1 FROM entra_role_assignments era WHERE era.identity_db_id = i.id) THEN 2
                    WHEN EXISTS (SELECT 1 FROM role_assignments ra WHERE ra.identity_db_id = i.id) THEN 2
                    ELSE 3
                END as privilege_tier,
                i.ca_coverage_status,
                COALESCE(i.ca_mfa_enforced, false) as ca_mfa_enforced,
                i.risk_reasons
            FROM identities i
            WHERE i.discovery_run_id = ANY(%s)
        """
        params = [run_ids]

        if risk_filter:
            query += " AND i.risk_level = %s"
            params.append(risk_filter)
        if category_filter:
            query += " AND COALESCE(i.identity_category, '') = %s"
            params.append(category_filter)

        query += """
            ORDER BY
                CASE i.risk_level
                    WHEN 'critical' THEN 1 WHEN 'high' THEN 2
                    WHEN 'medium' THEN 3 WHEN 'low' THEN 4 ELSE 5
                END, i.display_name
        """

        cursor.execute(query, params)
        rows = cursor.fetchall()

        identities = []
        for row in rows:
            identities.append({
                'identity_id': row[0],
                'display_name': row[1] or '',
                'identity_type': row[2] or '',
                'identity_category': _normalize_category_key(row[3] or ''),
                'risk_level': row[4] or 'info',
                'credential_count': int(row[5] or 0),
                'credential_status': row[6] or 'unknown',
                'credential_expiration': row[7].isoformat() if row[7] else None,
                'created_datetime': row[8].isoformat() if row[8] else None,
                'activity_status': row[9] or 'unknown',
                'rbac_role_count': int(row[10] or 0),
                'entra_role_count': int(row[11] or 0),
                'cloud': row[12] or 'azure',
                'status': row[13] or 'active',
                'last_seen_auth': row[14].isoformat() if row[14] else None,
                'owner_display_name': row[15],
                'owner_count': int(row[16] or 0),
                'risk_score': int(row[17] or 0),
                'api_permission_count': int(row[18] or 0),
                'app_role_count': int(row[19] or 0),
                'enabled': row[20] if row[20] is not None else True,
                'privilege_tier': f'T{row[21]}' if row[21] is not None else 'T3',
                'ca_coverage_status': row[22] or None,
                'ca_mfa_enforced': bool(row[23]) if row[23] is not None else False,
                'risk_reasons': row[24] if row[24] else [],
            })

        try:
            _log(db,'export', f'Identities export generated ({len(identities)} records)',
                            {'export_type': 'identities', 'count': len(identities)})
        except Exception:
            pass

        return jsonify({
            'export_type': 'identities',
            'generated_at': datetime.now(timezone.utc).isoformat(),
            'run_id': run_ids[0] if run_ids else None,
            'date_range': date_range,
            'total_count': len(identities),
            'filters': {'risk_level': risk_filter, 'identity_category': category_filter},
            'identities': identities,
        })
    finally:
        cursor.close()
        db.close()


def _export_compliance():
    """Export compliance framework evaluations with gap analysis."""
    db = _db()
    cursor = db.conn.cursor()
    try:
        run_ids = _latest_run_ids(cursor, _org_id(), _connection_id())
        if not run_ids:
            return jsonify({'error': 'No completed discovery runs found'}), 404

        metrics = _compute_compliance_metrics(cursor, run_ids)
        frameworks = db.get_compliance_frameworks(enabled_only=True)

        scorecard = {}
        all_controls = []
        gap_analysis = []

        for fw in frameworks:
            controls_out = []
            for ctrl in fw['controls']:
                status, value = _evaluate_control(ctrl, metrics)
                label = _format_metric_label(ctrl['metric'])
                if status == 'pass':
                    detail = f"{value} {label} — within limits"
                elif status == 'warn':
                    detail = f"{value} {label} — approaching threshold"
                else:
                    detail = f"{value} {label} — exceeds acceptable limit (target: {ctrl['pass_operator']}{int(ctrl['pass_value'])})"

                ctrl_data = {
                    'id': ctrl['control_id'],
                    'name': ctrl['name'],
                    'status': status,
                    'detail': detail,
                    'metric': ctrl['metric'],
                    'value': value,
                    'pass_threshold': f"{ctrl['pass_operator']}{int(ctrl['pass_value'])}",
                }
                controls_out.append(ctrl_data)

                # Flat record for all_controls and gap_analysis
                flat = {
                    'framework': fw['name'],
                    'framework_key': fw['key'],
                    'control_id': ctrl['control_id'],
                    'control_name': ctrl['name'],
                    'status': status,
                    'current_value': value,
                    'threshold': f"{ctrl['pass_operator']}{int(ctrl['pass_value'])}",
                    'detail': detail,
                }
                all_controls.append(flat)
                if status != 'pass':
                    gap_analysis.append(flat)

            passes = sum(1 for c in controls_out if c['status'] == 'pass')
            scorecard[fw['key']] = {
                'name': fw['name'],
                'version': fw.get('version'),
                'score': round(passes / len(controls_out) * 100, 1) if controls_out else 0.0,
                'pass_count': passes,
                'warn_count': sum(1 for c in controls_out if c['status'] == 'warn'),
                'fail_count': sum(1 for c in controls_out if c['status'] == 'fail'),
                'total_controls': len(controls_out),
                'controls': controls_out,
            }

        total_controls = sum(fw['total_controls'] for fw in scorecard.values())
        total_passing = sum(fw['pass_count'] for fw in scorecard.values())
        overall_score = round((total_passing / total_controls) * 100, 1) if total_controls > 0 else 0.0

        try:
            _log(db,'export', f'Compliance export generated ({len(frameworks)} frameworks)',
                            {'export_type': 'compliance', 'frameworks': len(frameworks)})
        except Exception:
            pass

        return jsonify({
            'export_type': 'compliance',
            'generated_at': datetime.now(timezone.utc).isoformat(),
            'run_id': run_ids[0] if run_ids else None,
            'overall_score': overall_score,
            'raw_metrics': metrics,
            'frameworks': scorecard,
            'all_controls': all_controls,
            'gap_analysis': gap_analysis,
        })
    finally:
        cursor.close()
        db.close()


def _export_drift():
    """Export latest drift report with flattened changes."""
    db = _db()
    try:
        cursor = db.conn.cursor()
        cursor.execute("""
            SELECT id FROM discovery_runs WHERE status = 'completed' AND organization_id = %s
            ORDER BY id DESC LIMIT 1
        """, (_org_id(),))
        row = cursor.fetchone()
        cursor.close()
        if not row:
            return jsonify({'error': 'No completed discovery runs found'}), 404

        run_id = row[0]
        report = db.get_drift_report(run_id)
        if not report:
            return jsonify({
                'export_type': 'drift',
                'generated_at': datetime.now(timezone.utc).isoformat(),
                'has_data': False,
                'total_changes': 0,
                'changes': [],
            })

        # Flatten all change types into a single list
        flat_changes = []
        changes = report.get('changes') or {}
        if isinstance(changes, str):
            changes = json.loads(changes)

        for item in (changes.get('new_identities') or []):
            flat_changes.append({
                'change_type': 'new_identity',
                'identity_id': item.get('identity_id', ''),
                'display_name': item.get('display_name', ''),
                'detail': f"New {item.get('identity_category', 'identity')} discovered",
                'risk_level': item.get('risk_level', ''),
            })
        for item in (changes.get('removed_identities') or []):
            flat_changes.append({
                'change_type': 'removed_identity',
                'identity_id': item.get('identity_id', ''),
                'display_name': item.get('display_name', ''),
                'detail': 'Identity removed from environment',
                'risk_level': item.get('risk_level', ''),
            })
        for item in (changes.get('permission_changes') or []):
            detail_parts = []
            if item.get('added_roles'):
                detail_parts.append(f"Added: {', '.join(item['added_roles'])}")
            if item.get('removed_roles'):
                detail_parts.append(f"Removed: {', '.join(item['removed_roles'])}")
            flat_changes.append({
                'change_type': 'permission_change',
                'identity_id': item.get('identity_id', ''),
                'display_name': item.get('display_name', ''),
                'detail': '; '.join(detail_parts) if detail_parts else 'Permission change detected',
                'risk_level': item.get('risk_level', ''),
            })
        for item in (changes.get('risk_changes') or []):
            flat_changes.append({
                'change_type': 'risk_change',
                'identity_id': item.get('identity_id', ''),
                'display_name': item.get('display_name', ''),
                'detail': f"{item.get('old_risk', '?')} -> {item.get('new_risk', '?')}",
                'risk_level': item.get('new_risk', ''),
            })
        for item in (changes.get('credential_changes') or []):
            flat_changes.append({
                'change_type': 'credential_change',
                'identity_id': item.get('identity_id', ''),
                'display_name': item.get('display_name', ''),
                'detail': f"{item.get('old_status', '?')} -> {item.get('new_status', '?')}",
                'risk_level': item.get('risk_level', ''),
            })

        try:
            _log(db,'export', f'Drift export generated ({len(flat_changes)} changes)',
                            {'export_type': 'drift', 'run_id': run_id})
        except Exception:
            pass

        return jsonify({
            'export_type': 'drift',
            'generated_at': datetime.now(timezone.utc).isoformat(),
            'run_id': run_id,
            'previous_run_id': report.get('previous_run_id'),
            'total_changes': report.get('total_changes', 0),
            'has_data': True,
            'summary': {
                'new_identities': report.get('new_identities_count', 0),
                'removed_identities': report.get('removed_identities_count', 0),
                'permission_changes': report.get('permission_changes_count', 0),
                'risk_changes': report.get('risk_changes_count', 0),
                'credential_changes': report.get('credential_changes_count', 0),
            },
            'changes': flat_changes,
        })
    finally:
        db.close()


def _export_risk_summary():
    """Export executive risk summary for SIEM/GRC integration."""
    db = _db()
    try:
        data = db.get_report_data()
        if data is None:
            return jsonify({'error': 'No completed discovery runs found'}), 404

        top_risks = []
        for tr in data.get('top_risks', []):
            top_risks.append({
                'identity_id': tr.get('identity_id'),
                'display_name': tr.get('display_name'),
                'identity_category': tr.get('identity_category'),
                'risk_level': tr.get('risk_level'),
                'risk_score': tr.get('risk_score'),
                'risk_reasons': tr.get('risk_reasons', []),
                'top_remediation': tr['remediations'][0]['title'] if tr.get('remediations') else None,
            })

        try:
            _log(db,'export', 'Risk summary export generated',
                            {'export_type': 'risk-summary'})
        except Exception:
            pass

        return jsonify({
            'export_type': 'risk-summary',
            'generated_at': datetime.now(timezone.utc).isoformat(),
            'run_id': data.get('run_id'),
            'collected_at': data.get('collected_at'),
            'risk_distribution': data.get('stats'),
            'credential_health': data.get('credential_health'),
            'conditional_access': data.get('conditional_access'),
            'top_risks': top_risks,
            'remediation_priorities': data.get('remediation_summary', {}).get('top_priorities', []),
        })
    finally:
        db.close()


def _export_evidence_package():
    """Export comprehensive HIPAA-aligned evidence package bundling all audit data."""
    db = _db()
    try:
        data = db.get_report_data()
        if data is None:
            return jsonify({'error': 'No completed discovery runs found'}), 404

        # Get organization name
        tid = _org_id()
        org_name = db.get_setting('org_name', organization_id=tid) if tid else 'Organization'

        # Privileged access: identities with critical/high risk
        privileged = []
        for tr in data.get('top_risks', []):
            privileged.append({
                'identity_id': tr.get('identity_id'),
                'display_name': tr.get('display_name'),
                'identity_category': tr.get('identity_category'),
                'risk_level': tr.get('risk_level'),
                'risk_score': tr.get('risk_score'),
                'risk_reasons': tr.get('risk_reasons', []),
                'remediations': [r.get('title') for r in tr.get('remediations', [])],
            })

        # HIPAA compliance gaps
        hipaa_gaps = []
        try:
            cursor = db.conn.cursor()
            run_ids = _latest_run_ids(cursor, tid, _connection_id())
            if run_ids:
                # Get compliance intelligence for HIPAA
                from app.engines.compliance import COMPLIANCE_FRAMEWORKS
                for fw in COMPLIANCE_FRAMEWORKS:
                    if 'hipaa' in fw.get('key', '').lower():
                        for ctrl in fw.get('controls', []):
                            hipaa_gaps.append({
                                'control_id': ctrl['control_id'],
                                'name': ctrl['name'],
                                'metric': ctrl['metric'],
                                'framework': fw['name'],
                            })
            cursor.close()
        except Exception:
            try: db.conn.rollback()
            except Exception: pass
            pass

        try:
            _log(db, 'export', 'HIPAA evidence package export generated',
                            {'export_type': 'evidence-package'})
        except Exception:
            pass

        # Sensitive data access section
        sensitive_data_section = {}
        try:
            cursor2 = db.conn.cursor(cursor_factory=RealDictCursor)
            run_ids2 = _latest_run_ids(cursor2, tid, _connection_id())
            if run_ids2:
                classified_resources = []
                for table, rtype in [('azure_storage_accounts', 'storage_account'), ('azure_key_vaults', 'key_vault')]:
                    cursor2.execute(f"""
                        SELECT name, resource_id, data_classification, classification_source, risk_level, risk_score
                        FROM {table}
                        WHERE discovery_run_id = ANY(%s) AND data_classification IS NOT NULL
                    """, (run_ids2,))
                    for row in cursor2.fetchall():
                        classified_resources.append({
                            'name': row['name'], 'resource_path': row['resource_id'],
                            'classification': row['data_classification'], 'source': row.get('classification_source'),
                            'resource_type': rtype, 'risk_level': row.get('risk_level', 'info'),
                        })
                sensitive_data_section = {
                    'classified_resource_count': len(classified_resources),
                    'classified_resources': classified_resources,
                    'by_classification': {},
                }
                for cr in classified_resources:
                    c = cr['classification']
                    sensitive_data_section['by_classification'][c] = sensitive_data_section['by_classification'].get(c, 0) + 1
            cursor2.close()
        except Exception:
            pass

        return jsonify({
            'export_type': 'evidence-package',
            'metadata': {
                'organization': org_name or 'Organization',
                'generated_at': datetime.now(timezone.utc).isoformat(),
                'framework': 'HIPAA',
                'run_id': data.get('run_id'),
                'identity_count': data.get('stats', {}).get('total_identities', 0),
                'collected_at': data.get('collected_at'),
            },
            'risk_distribution': data.get('stats'),
            'credential_health': data.get('credential_health'),
            'conditional_access': data.get('conditional_access'),
            'privileged_access': privileged,
            'hipaa_controls': hipaa_gaps,
            'remediation_priorities': data.get('remediation_summary', {}).get('top_priorities', []),
            'evidence_sources': data.get('evidence', {}).get('sources', {}),
            'sensitive_data_access': sensitive_data_section,
        })
    finally:
        db.close()


def _export_sensitive_data():
    """Export sensitive data classification + access mapping for compliance evidence."""
    db = _db()
    try:

        tid = _org_id()
        org_name = db.get_setting('org_name', organization_id=tid) if tid else 'Organization'
        cursor = db.conn.cursor(cursor_factory=RealDictCursor)
        run_ids = _latest_run_ids(cursor, tid, _connection_id())
        if not run_ids:
            cursor.close()
            return jsonify({'error': 'No discovery runs found'}), 404

        # Get classified resources
        classified = []
        for table, rtype in [('azure_storage_accounts', 'storage_account'), ('azure_key_vaults', 'key_vault')]:
            cursor.execute(f"""
                SELECT name, resource_id, data_classification, classification_source,
                       classification_confidence, classified_by, classified_at,
                       risk_level, risk_score, resource_group, subscription_name
                FROM {table}
                WHERE discovery_run_id = ANY(%s) AND data_classification IS NOT NULL
            """, (run_ids,))
            for row in cursor.fetchall():
                r = dict(row)
                r['resource_type'] = rtype
                r['classified_at'] = r['classified_at'].isoformat() if r.get('classified_at') else None
                classified.append(r)

        # Get blast radius data
        # Get all identities and their role assignments to compute access
        cursor.execute("""
            SELECT i.id, i.identity_id, i.display_name, i.identity_type, i.identity_category,
                   i.risk_level, i.risk_score
            FROM identities i
            WHERE i.discovery_run_id = ANY(%s)
              AND NOT COALESCE(i.is_microsoft_system, false)
        """, (run_ids,))
        identities = cursor.fetchall()

        id_list = [i['id'] for i in identities]
        identity_roles = {}
        if id_list:
            cursor.execute("""
                SELECT identity_db_id, role_name, scope
                FROM role_assignments WHERE identity_db_id = ANY(%s)
            """, (id_list,))
            for ra in cursor.fetchall():
                db_id = ra['identity_db_id']
                if db_id not in identity_roles:
                    identity_roles[db_id] = []
                identity_roles[db_id].append(ra)

        # Compute access map
        access_map = []
        for ident in identities:
            roles = identity_roles.get(ident['id'], [])
            if not roles:
                continue
            for res in classified:
                res_id_full = (res.get('resource_id') or '').lower()
                res_rg = (res.get('resource_group') or '').lower()
                res_sub = (res.get('subscription_name') or '').lower()
                for ra in roles:
                    scope = (ra.get('scope') or '').lower()
                    matched = False
                    if res_id_full and scope == res_id_full:
                        matched = True
                    elif res_rg and f'/resourcegroups/{res_rg}' in scope and '/providers/' not in scope.split(f'/resourcegroups/{res_rg}')[-1]:
                        matched = True
                    elif scope == '/':
                        matched = True
                    if matched:
                        access_map.append({
                            'identity_name': ident['display_name'],
                            'identity_id': ident['identity_id'],
                            'identity_category': ident.get('identity_category', ''),
                            'resource_name': res['name'],
                            'resource_type': res['resource_type'],
                            'classification': res['data_classification'],
                            'role_name': ra['role_name'],
                            'identity_risk': ident.get('risk_level', 'info'),
                        })
                        break

        cursor.close()

        try:
            _log(db, 'export', 'Sensitive data access export generated', {'export_type': 'sensitive-data'})
        except Exception:
            pass

        return jsonify({
            'export_type': 'sensitive-data',
            'metadata': {
                'organization': org_name or 'Organization',
                'generated_at': datetime.now(timezone.utc).isoformat(),
                'total_classified_resources': len(classified),
                'total_access_mappings': len(access_map),
            },
            'classified_resources': classified,
            'access_map': access_map,
        })
    finally:
        db.close()


# ─── GRC Evidence JSON (Gate 32) ──────────────────────────────────────────

def _export_evidence_json():
    """
    GET /api/export/evidence-json
    Comprehensive JSON evidence package for GRC/SIEM integration.
    Bundles identity inventory, compliance posture, risk summary,
    drift changes, remediation status, and sensitive data into a
    single structured document with OSCAL-aligned metadata.
    """
    db = _db()
    try:
        tid = _org_id()
        conn_id = _connection_id()
        org_name = db.get_setting('org_name', organization_id=tid) if tid else 'Organization'
        cursor = db.conn.cursor(cursor_factory=RealDictCursor)
        run_ids = _latest_run_ids(cursor, tid, conn_id)
        if not run_ids:
            cursor.close()
            return jsonify({'error': 'No completed discovery runs found'}), 404

        now = datetime.now(timezone.utc).isoformat()

        # --- 1. Run metadata ---
        cursor.execute("""
            SELECT id, started_at, completed_at, status,
                   total_identities, critical_count, high_count, medium_count, low_count, info_count,
                   cloud_connection_id
            FROM discovery_runs WHERE id = ANY(%s) ORDER BY completed_at DESC
        """, (run_ids,))
        runs = []
        for r in cursor.fetchall():
            rd = dict(r)
            for k in ('started_at', 'completed_at'):
                if rd.get(k):
                    rd[k] = rd[k].isoformat()
            runs.append(rd)

        # --- 2. Identity inventory summary ---
        cursor.execute("""
            SELECT risk_level, COUNT(*) as cnt
            FROM identities WHERE discovery_run_id = ANY(%s)
              AND NOT COALESCE(is_microsoft_system, false)
            GROUP BY risk_level
        """, (run_ids,))
        risk_dist = {row['risk_level']: row['cnt'] for row in cursor.fetchall()}
        total_identities = sum(risk_dist.values())

        cursor.execute("""
            SELECT identity_category, COUNT(*) as cnt
            FROM identities WHERE discovery_run_id = ANY(%s)
              AND NOT COALESCE(is_microsoft_system, false)
            GROUP BY identity_category
        """, (run_ids,))
        category_dist = {row['identity_category']: row['cnt'] for row in cursor.fetchall()}

        # Top 25 critical/high risk identities
        cursor.execute("""
            SELECT identity_id, display_name, identity_category, risk_level, risk_score,
                   status, credential_count, has_expired_credentials
            FROM identities WHERE discovery_run_id = ANY(%s)
              AND risk_level IN ('critical','high')
              AND NOT COALESCE(is_microsoft_system, false)
            ORDER BY risk_score DESC LIMIT 25
        """, (run_ids,))
        top_risks = [dict(row) for row in cursor.fetchall()]

        # --- 3. Compliance posture ---
        compliance_section = []
        try:
            from app.engines.compliance import COMPLIANCE_FRAMEWORKS, evaluate_framework
            for fw in COMPLIANCE_FRAMEWORKS:
                result = evaluate_framework(cursor, fw, run_ids, tid)
                if result:
                    compliance_section.append(result)
        except Exception:
            try: cursor.connection.rollback()
            except Exception: pass
            pass

        # --- 4. Drift summary (latest) ---
        drift_section = None
        try:
            cursor.execute("""
                SELECT id, run_id, created_at, summary
                FROM drift_reports
                WHERE organization_id = %s ORDER BY created_at DESC LIMIT 1
            """, (tid,))
            drift_row = cursor.fetchone()
            if drift_row:
                drift_section = {
                    'report_id': drift_row['id'],
                    'run_id': drift_row['run_id'],
                    'created_at': drift_row['created_at'].isoformat() if drift_row.get('created_at') else None,
                    'summary': drift_row.get('summary') or {},
                }
        except Exception:
            try: cursor.connection.rollback()
            except Exception: pass
            pass

        # --- 5. Remediation status ---
        remediation_section = {}
        try:
            cursor.execute("""
                SELECT status, COUNT(*) as cnt
                FROM remediation_actions
                WHERE organization_id = %s
                GROUP BY status
            """, (tid,))
            remediation_section = {row['status']: row['cnt'] for row in cursor.fetchall()}
        except Exception:
            try: cursor.connection.rollback()
            except Exception: pass
            pass

        # --- 6. Credential health ---
        cred_section = {}
        try:
            cursor.execute("""
                SELECT
                    COUNT(*) FILTER (WHERE credential_count > 0) as with_credentials,
                    COUNT(*) FILTER (WHERE has_expired_credentials = true) as expired,
                    COUNT(*) FILTER (WHERE credential_count = 0) as no_credentials,
                    COUNT(*) as total
                FROM identities WHERE discovery_run_id = ANY(%s)
                  AND NOT COALESCE(is_microsoft_system, false)
            """, (run_ids,))
            cred_row = cursor.fetchone()
            if cred_row:
                cred_section = dict(cred_row)
        except Exception:
            try: cursor.connection.rollback()
            except Exception: pass
            pass

        # --- 7. Sensitive data classifications ---
        sensitive_section = {}
        try:
    
            classified_counts = {}
            for table in ['azure_storage_accounts', 'azure_key_vaults']:
                cursor.execute(f"""
                    SELECT data_classification, COUNT(*) as cnt
                    FROM {table}
                    WHERE discovery_run_id = ANY(%s) AND data_classification IS NOT NULL
                    GROUP BY data_classification
                """, (run_ids,))
                for row in cursor.fetchall():
                    c = row['data_classification']
                    classified_counts[c] = classified_counts.get(c, 0) + row['cnt']
            sensitive_section = {
                'total_classified': sum(classified_counts.values()),
                'by_classification': classified_counts,
            }
        except Exception:
            try: cursor.connection.rollback()
            except Exception: pass
            pass

        cursor.close()

        try:
            _log(db, 'export', 'GRC evidence JSON export generated',
                 {'export_type': 'evidence-json'})
        except Exception:
            try: cursor.connection.rollback()
            except Exception: pass
            pass

        return jsonify({
            'schema': 'auditgraph-grc-evidence-v1',
            'export_type': 'evidence-json',
            'metadata': {
                'organization': org_name or 'Organization',
                'generated_at': now,
                'generator': 'AuditGraph Identity Risk Platform',
                'version': '3.4.0',
                'organization_id': tid,
                'connection_id': conn_id,
                'discovery_runs': len(runs),
            },
            'discovery_runs': runs,
            'identity_inventory': {
                'total': total_identities,
                'risk_distribution': risk_dist,
                'category_distribution': category_dist,
                'top_risks': top_risks,
            },
            'compliance_posture': compliance_section,
            'drift_summary': drift_section,
            'remediation_status': remediation_section,
            'credential_health': cred_section,
            'sensitive_data': sensitive_section,
        })
    finally:
        db.close()


# ─── Evidence ZIP Package (Phase 3 — Audit Evidence) ──────────────────────

def export_evidence_zip():
    """
    GET /api/export/evidence-zip[?from=YYYY-MM-DD&to=YYYY-MM-DD]
    Generate a ZIP file containing 8 CSV evidence files + MANIFEST.md.
    Optional date range filters; defaults to latest run data.
    """
    import zipfile
    import csv
    import io

    from_date = request.args.get('from')
    to_date = request.args.get('to')

    db = _db()
    cursor = db.conn.cursor(cursor_factory=RealDictCursor)
    try:
        tid = _org_id()
        conn_id = _connection_id()
        run_ids = _latest_run_ids(cursor, tid, conn_id)
        if not run_ids:
            cursor.close()
            db.close()
            return jsonify({'error': 'No completed discovery runs found'}), 404

        org_name = db.get_setting('org_name', organization_id=tid) if tid else 'Organization'
        generated_at = datetime.now(timezone.utc)

        # Determine date range text
        date_range_text = 'Latest discovery run'
        run_filter_clause = 'discovery_run_id = ANY(%s)'
        run_params = (run_ids,)

        if from_date and to_date:
            try:
                from_dt = datetime.strptime(from_date, '%Y-%m-%d')
                to_dt = datetime.strptime(to_date, '%Y-%m-%d').replace(hour=23, minute=59, second=59)
                date_range_text = f'{from_date} to {to_date}'
                # Get all runs in date range
                cursor.execute("""
                    SELECT id FROM discovery_runs
                    WHERE organization_id = %s AND status = 'completed'
                      AND completed_at >= %s AND completed_at <= %s
                    ORDER BY completed_at DESC
                """, (tid, from_dt, to_dt))
                range_run_ids = [r['id'] for r in cursor.fetchall()]
                if range_run_ids:
                    # Use the latest run in the range for identity data
                    run_ids = [range_run_ids[0]]
                    run_params = (run_ids,)
            except ValueError:
                pass

        def _make_csv(rows, columns):
            """Convert list of dicts to CSV string."""
            output = io.StringIO()
            writer = csv.DictWriter(output, fieldnames=columns, extrasaction='ignore')
            writer.writeheader()
            for row in rows:
                writer.writerow(row)
            return output.getvalue()

        files = {}
        file_descriptions = {}
        total_rows = {}

        # 1. Identity Inventory
        cursor.execute("""
            SELECT identity_id, display_name, identity_type,
                   COALESCE(identity_category, '') as identity_category,
                   risk_level, COALESCE(risk_score, 0) as risk_score,
                   credential_count, credential_status, credential_risk,
                   activity_status, COALESCE(status, 'active') as status,
                   created_datetime, last_sign_in, COALESCE(cloud, 'azure') as cloud,
                   enabled
            FROM identities WHERE discovery_run_id = ANY(%s)
            ORDER BY risk_score DESC
        """, run_params)
        identity_rows = cursor.fetchall()
        id_cols = ['identity_id', 'display_name', 'identity_type', 'identity_category',
                   'risk_level', 'risk_score', 'credential_count', 'credential_status',
                   'credential_risk', 'activity_status', 'status', 'created_datetime',
                   'last_sign_in', 'cloud', 'enabled']
        rows_for_csv = []
        for r in identity_rows:
            row = dict(r)
            row['created_datetime'] = row['created_datetime'].isoformat() if row.get('created_datetime') else ''
            row['last_sign_in'] = row['last_sign_in'].isoformat() if row.get('last_sign_in') else ''
            rows_for_csv.append(row)
        files['01_identity_inventory.csv'] = _make_csv(rows_for_csv, id_cols)
        file_descriptions['01_identity_inventory.csv'] = 'Complete identity inventory with risk scores, credentials, and status'
        total_rows['01_identity_inventory.csv'] = len(rows_for_csv)

        # 2. Privileged Access
        cursor.execute("""
            SELECT i.identity_id, i.display_name, i.identity_category, i.risk_level, i.risk_score,
                   ra.role_name, ra.scope, ra.scope_type, ra.risk_level as role_risk
            FROM identities i
            JOIN role_assignments ra ON ra.identity_db_id = i.id
            WHERE i.discovery_run_id = ANY(%s)
              AND (ra.risk_level IN ('critical', 'high') OR LOWER(ra.role_name) IN ('owner', 'contributor', 'user access administrator'))
            ORDER BY i.risk_score DESC
        """, run_params)
        priv_rows = cursor.fetchall()
        priv_cols = ['identity_id', 'display_name', 'identity_category', 'risk_level',
                     'risk_score', 'role_name', 'scope', 'scope_type', 'role_risk']
        priv_csv = []
        for r in priv_rows:
            priv_csv.append(dict(r))
        files['02_privileged_access.csv'] = _make_csv(priv_csv, priv_cols)
        file_descriptions['02_privileged_access.csv'] = 'Identities with privileged RBAC roles (Owner, Contributor, UAA) and high-risk assignments'
        total_rows['02_privileged_access.csv'] = len(priv_csv)

        # 3. Entra Role Assignments
        cursor.execute("""
            SELECT i.identity_id, i.display_name, i.identity_category,
                   era.role_name, era.role_definition_id,
                   era.directory_scope, era.risk_level as role_risk,
                   era.role_type
            FROM identities i
            JOIN entra_role_assignments era ON era.identity_db_id = i.id
            WHERE i.discovery_run_id = ANY(%s)
            ORDER BY i.display_name
        """, run_params)
        entra_rows = cursor.fetchall()
        entra_cols = ['identity_id', 'display_name', 'identity_category',
                      'role_name', 'role_definition_id', 'directory_scope', 'role_risk', 'role_type']
        files['03_entra_roles.csv'] = _make_csv([dict(r) for r in entra_rows], entra_cols)
        file_descriptions['03_entra_roles.csv'] = 'Entra ID directory role assignments'
        total_rows['03_entra_roles.csv'] = len(entra_rows)

        # 4. Credential Health
        cursor.execute("""
            SELECT identity_id, display_name, identity_type, identity_category,
                   credential_count, credential_status, credential_risk,
                   credential_expiration, next_expiry
            FROM identities WHERE discovery_run_id = ANY(%s)
              AND credential_count > 0
            ORDER BY credential_risk DESC, next_expiry ASC
        """, run_params)
        cred_rows = cursor.fetchall()
        cred_cols = ['identity_id', 'display_name', 'identity_type', 'identity_category',
                     'credential_count', 'credential_status', 'credential_risk',
                     'credential_expiration', 'next_expiry']
        cred_csv = []
        for r in cred_rows:
            row = dict(r)
            row['credential_expiration'] = row['credential_expiration'].isoformat() if row.get('credential_expiration') else ''
            row['next_expiry'] = row['next_expiry'].isoformat() if row.get('next_expiry') else ''
            cred_csv.append(row)
        files['04_credential_health.csv'] = _make_csv(cred_csv, cred_cols)
        file_descriptions['04_credential_health.csv'] = 'Credential inventory with expiry dates and risk status'
        total_rows['04_credential_health.csv'] = len(cred_csv)

        # 5. Compliance Controls
        compliance_csv = []
        try:
            from app.engines.compliance import COMPLIANCE_FRAMEWORKS
            for fw in COMPLIANCE_FRAMEWORKS:
                for ctrl in fw.get('controls', []):
                    compliance_csv.append({
                        'framework': fw['name'],
                        'framework_key': fw['key'],
                        'control_id': ctrl['control_id'],
                        'control_name': ctrl['name'],
                        'metric': ctrl.get('metric', ''),
                    })
        except Exception:
            pass
        comp_cols = ['framework', 'framework_key', 'control_id', 'control_name', 'metric']
        files['05_compliance_controls.csv'] = _make_csv(compliance_csv, comp_cols)
        file_descriptions['05_compliance_controls.csv'] = 'Compliance framework controls and evaluation criteria'
        total_rows['05_compliance_controls.csv'] = len(compliance_csv)

        # 6. Sensitive Data Classification
        classified_csv = []
        for table, rtype in [('azure_storage_accounts', 'storage_account'), ('azure_key_vaults', 'key_vault')]:
            cursor.execute(f"""
                SELECT name, resource_id, data_classification, classification_source,
                       classification_confidence, classified_by, classified_at,
                       risk_level, resource_group, subscription_name
                FROM {table}
                WHERE discovery_run_id = ANY(%s) AND data_classification IS NOT NULL
            """, run_params)
            for row in cursor.fetchall():
                r = dict(row)
                r['resource_type'] = rtype
                r['classified_at'] = r['classified_at'].isoformat() if r.get('classified_at') else ''
                classified_csv.append(r)
        class_cols = ['name', 'resource_id', 'resource_type', 'data_classification',
                      'classification_source', 'classification_confidence', 'classified_by',
                      'classified_at', 'risk_level', 'resource_group', 'subscription_name']
        files['06_data_classifications.csv'] = _make_csv(classified_csv, class_cols)
        file_descriptions['06_data_classifications.csv'] = 'Sensitive data classification inventory (PHI/PCI/PII)'
        total_rows['06_data_classifications.csv'] = len(classified_csv)

        # 7. Drift / Changes (latest drift report)
        drift_csv = []
        try:
            cursor.execute("""
                SELECT changes, created_at, current_run_id, previous_run_id
                FROM drift_reports
                WHERE current_run_id = ANY(%s)
                ORDER BY created_at DESC LIMIT 1
            """, run_params)
            drift_row = cursor.fetchone()
            if drift_row and drift_row.get('changes'):
                changes = drift_row['changes'] if isinstance(drift_row['changes'], dict) else {}
                for change_type, items in changes.items():
                    if isinstance(items, list):
                        for item in items:
                            drift_csv.append({
                                'change_type': change_type,
                                'identity_id': item.get('identity_id', ''),
                                'display_name': item.get('display_name', item.get('name', '')),
                                'detail': str(item.get('detail', item.get('change', ''))),
                            })
        except Exception:
            try: cursor.connection.rollback()
            except Exception: pass
            pass
        drift_cols = ['change_type', 'identity_id', 'display_name', 'detail']
        files['07_drift_changes.csv'] = _make_csv(drift_csv, drift_cols)
        file_descriptions['07_drift_changes.csv'] = 'Latest drift detection results (new/removed identities, permission/risk changes)'
        total_rows['07_drift_changes.csv'] = len(drift_csv)

        # 8. Activity Log (last 30 days)
        activity_csv = []
        try:
            cursor.execute("""
                SELECT action_type, description, created_at,
                       u.display_name as user_name
                FROM activity_log al
                LEFT JOIN users u ON u.id = al.user_id
                WHERE al.organization_id = %s
                  AND al.created_at >= NOW() - INTERVAL '30 days'
                ORDER BY al.created_at DESC
                LIMIT 1000
            """, (tid,))
            for row in cursor.fetchall():
                activity_csv.append({
                    'timestamp': row['created_at'].isoformat() if row.get('created_at') else '',
                    'action_type': row.get('action_type', ''),
                    'description': row.get('description', ''),
                    'user': row.get('user_name', ''),
                })
        except Exception:
            try: cursor.connection.rollback()
            except Exception: pass
            pass
        act_cols = ['timestamp', 'action_type', 'description', 'user']
        files['08_activity_log.csv'] = _make_csv(activity_csv, act_cols)
        file_descriptions['08_activity_log.csv'] = 'Audit activity log (last 30 days)'
        total_rows['08_activity_log.csv'] = len(activity_csv)

        # Build MANIFEST.md
        manifest_lines = [
            f'# Evidence Package — {org_name or "Organization"}',
            f'',
            f'**Generated**: {generated_at.strftime("%Y-%m-%d %H:%M:%S UTC")}',
            f'**Date Range**: {date_range_text}',
            f'**Discovery Run ID(s)**: {", ".join(str(r) for r in run_ids)}',
            f'**Tenant**: {org_name or "N/A"}',
            f'',
            f'## Contents',
            f'',
            f'| File | Description | Rows |',
            f'|------|-------------|------|',
        ]
        for fname in sorted(files.keys()):
            manifest_lines.append(f'| {fname} | {file_descriptions.get(fname, "")} | {total_rows.get(fname, 0)} |')

        manifest_lines.extend([
            f'',
            f'## Summary',
            f'',
            f'- **Total Identities**: {len(identity_rows)}',
            f'- **Privileged Access Entries**: {len(priv_csv)}',
            f'- **Entra Role Assignments**: {len(entra_rows)}',
            f'- **Credentials Tracked**: {len(cred_csv)}',
            f'- **Compliance Controls**: {len(compliance_csv)}',
            f'- **Classified Resources**: {len(classified_csv)}',
            f'- **Drift Events**: {len(drift_csv)}',
            f'- **Activity Log Entries**: {len(activity_csv)}',
            f'',
            f'## Integrity',
            f'',
            f'This package was generated by AuditGraph and contains point-in-time evidence',
            f'from automated identity discovery. Data reflects the state at the time of the',
            f'discovery run(s) listed above.',
            f'',
            f'---',
            f'*AuditGraph — Identity Risk Operating System*',
        ])

        manifest_content = '\n'.join(manifest_lines)

        # Build ZIP
        zip_buffer = io.BytesIO()
        with zipfile.ZipFile(zip_buffer, 'w', zipfile.ZIP_DEFLATED) as zf:
            zf.writestr('MANIFEST.md', manifest_content)
            for fname, content in sorted(files.items()):
                zf.writestr(fname, content)
        zip_buffer.seek(0)

        _log(db, 'export', 'Evidence ZIP package exported', {
            'export_type': 'evidence-zip',
            'file_count': len(files) + 1,
            'date_range': date_range_text,
            'total_identities': len(identity_rows),
        })

        cursor.close()
        db.close()

        from flask import send_file
        filename = f'auditgraph_evidence_{generated_at.strftime("%Y%m%d_%H%M%S")}.zip'
        return send_file(
            zip_buffer,
            mimetype='application/zip',
            as_attachment=True,
            download_name=filename,
        )
    except Exception as e:
        try: db.conn.rollback()
        except Exception: pass
        cursor.close()
        db.close()
        logger.error(f"Export failed: {e}", exc_info=True)
        return jsonify({'error': 'Export failed'}), 500


