def get_groups_list():
    db = _db()
    try:
        groups = db.get_groups()

        # Recompute auto-group member counts with Microsoft filter + multi-run
        cursor = db.conn.cursor()
        run_ids = _latest_run_ids(cursor, _org_id(), _connection_id())
        if run_ids:
            for grp in groups:
                if grp.get('group_type') == 'auto' and grp.get('auto_criteria'):
                    criteria = grp['auto_criteria']
                    if isinstance(criteria, str):
                        import json as _json
                        criteria = _json.loads(criteria)
                    where_parts, where_params = db._build_auto_criteria_where(criteria)
                    where_clause = (" AND " + " AND ".join(where_parts)) if where_parts else ""
                    cursor.execute(f"""
                        SELECT COUNT(*) FROM identities i
                        WHERE i.discovery_run_id = ANY(%s)
                          {where_clause} {HIDE_MICROSOFT_SQL}
                    """, [run_ids] + where_params)
                    grp['member_count'] = _scalar(cursor, 0)

            # Append Entra security groups from latest discovery run
            try:
                db._ensure_entra_group_tables()
                cursor.execute("""
                    SELECT id, display_name, member_count, is_privileged,
                           is_role_assignable, group_id as azure_object_id
                    FROM entra_groups
                    WHERE discovery_run_id = ANY(%s)
                      AND rbac_roles IS NOT NULL
                      AND rbac_roles != '[]'::jsonb
                    ORDER BY display_name ASC
                """, (run_ids,))
                for row in cursor.fetchall():
                    groups.append({
                        'id': f"entra-{row[5]}",
                        'name': row[1],
                        'display_name': row[1],
                        'member_count': row[2] or 0,
                        'group_type': 'entra',
                        'source': 'entra',
                        'color': '#7C3AED',
                        'is_privileged': row[3],
                        'is_role_assignable': row[4],
                        'azure_object_id': row[5],
                    })
            except Exception as e:
                logger.warning("Failed to load Entra groups for filter: %s", e)
                try:
                    db.conn.rollback()
                except Exception:
                    pass

        cursor.close()

        return jsonify({'groups': groups})
    finally:
        db.close()


