def get_organizations_list():
    """GET /api/organizations — list all organizations (superadmin/portal access).

    Uses admin DB connection (bypasses RLS) because organizations table has
    no tenant_id column — it IS the tenant registry.  All portal-role users
    need to see the full list.
    """
    db = Database(_admin_reason='admin_portal_org_list')
    try:
        organizations = db.get_organizations()
        # Return both keys: 'organizations' (TopBar, Settings) + 'tenants' (AdminTenants compat)
        return jsonify({'organizations': organizations, 'tenants': organizations})
    except Exception as e:
        try: db.conn.rollback()
        except Exception: pass
        logger.exception("Failed to list organizations: %s", e)
        return jsonify({'error': 'Internal server error', 'organizations': [], 'tenants': []}), 500
    finally:
        db.close()


def create_organization_handler():
    """POST /api/organizations — create a new organization (admin portal).

    Admin portal enrollment defaults to 'pro' plan (no identity limits,
    no trial expiry). Self-signup via /api/auth/signup uses 'trial'.
    """
    data = request.get_json(silent=True) or {}
    name = str(data.get('name', '')).strip()
    slug = str(data.get('slug', '')).strip().lower()
    plan = str(data.get('plan', 'pro')).strip().lower()  # admin portal default = pro

    if not name:
        return jsonify({'error': 'name is required'}), 400
    if len(name) > 255:
        return jsonify({'error': 'name must be 255 characters or less'}), 400
    if not slug:
        return jsonify({'error': 'slug is required'}), 400
    if not slug.replace('-', '').replace('_', '').isalnum():
        return jsonify({'error': 'slug must be alphanumeric (hyphens and underscores allowed)'}), 400
    if len(slug) > 100:
        return jsonify({'error': 'slug must be 100 characters or less'}), 400
    if plan not in ('free', 'trial', 'pro', 'enterprise'):
        return jsonify({'error': 'plan must be free, trial, pro, or enterprise'}), 400

    # Phase 85: Optional onboarding fields
    primary_cloud = str(data.get('primary_cloud', '')).strip().lower() or None
    industry = str(data.get('industry', '')).strip() or None
    compliance_framework = str(data.get('compliance_framework', '')).strip() or None
    if primary_cloud and primary_cloud not in ('azure', 'aws', 'gcp'):
        return jsonify({'error': 'primary_cloud must be azure, aws, or gcp'}), 400

    # Use admin DB (no RLS) — creates user in a different org than caller's context
    db = Database(_admin_reason='admin_portal_org_create')
    try:
        existing = db.get_organization_by_slug(slug)
        if existing:
            return jsonify({'error': f'Tenant slug "{slug}" already exists'}), 409

        org = db.create_organization(name, slug, plan,
                                  primary_cloud=primary_cloud,
                                  industry=industry,
                                  compliance_framework=compliance_framework)

        # Set subscription term + auto-compute dates if provided
        term = _safe_int(data.get('subscription_term', 0), 'subscription_term')
        if term in (1, 3, 5):
            now = datetime.now(timezone.utc)
            db.update_organization(org['id'],
                             subscription_term=term,
                             license_activated_at=now.isoformat(),
                             license_expires_at=now.replace(year=now.year + term).isoformat())
            org = db.get_organization_by_id(org['id'])

        try:
            _log(db,'org_created',
                f'Tenant "{name}" created (slug: {slug}, plan: {plan})',
                {'organization_id': org['id'], 'slug': slug, 'plan': plan})
        except Exception:
            try: db.conn.rollback()
            except Exception: pass
            pass

        # Phase 84: Optional root user creation during org onboarding
        root_username = str(data.get('root_username', '')).strip().lower()
        root_email = str(data.get('root_email', '')).strip().lower()
        root_password = str(data.get('root_password', ''))
        root_user = None

        if root_username and root_password:
            if len(root_username) < 3:
                return jsonify({'error': 'root_username must be at least 3 characters'}), 400
            if len(root_password) < 8:
                return jsonify({'error': 'root_password must be at least 8 characters'}), 400

            existing_user = db.get_user_by_username(root_username)
            if existing_user:
                return jsonify({'error': f'Username "{root_username}" already exists'}), 409

            hashed = bcrypt.hashpw(root_password.encode('utf-8'), bcrypt.gensalt()).decode('utf-8')
            current_user = getattr(g, 'current_user', None)
            created_by = current_user['id'] if current_user else None

            root_user = db.create_user(
                root_username, hashed, root_username,
                role='admin', created_by=created_by,
                organization_id=org['id'], is_root_user=True,
                force_password_change=True,
                email=root_email or None
            )

            # Mark org as provisioned + set onboarding stage + auto-enable primary cloud
            settings = org.get('settings') or {}
            if isinstance(settings, str):
                try:
                    settings = json.loads(settings)
                except Exception:
                    try: db.conn.rollback()
                    except Exception: pass
                    settings = {}
            settings['provisioned'] = True
            settings['provisioned_at'] = datetime.now(timezone.utc).isoformat()
            settings['onboarding_stage'] = 'password_change'
            # Auto-enable primary cloud in cloud_providers
            if primary_cloud:
                cp = settings.get('cloud_providers', {})
                cp[primary_cloud] = {'enabled': True, 'plan': 'pro' if plan == 'pro' else 'pro'}
                settings['cloud_providers'] = cp
            db.update_organization(org['id'], settings=settings)
            org = db.get_organization_by_id(org['id'])

            try:
                admin_id = current_user['id'] if current_user else None
                db.log_admin_audit(admin_id, 'org_root_user_created',
                                   target_user_id=root_user['id'], target_organization_id=org['id'],
                                   details={'root_username': root_username},
                                   ip_address=request.remote_addr)
            except Exception:
                try: db.conn.rollback()
                except Exception: pass
                pass

        # Send welcome email to root user
        if root_user and root_email:
            try:
                from app.services.email_service import EmailService
                email_svc = EmailService()
                portal_url = f"https://{slug}.auditgraph.ai"
                email_svc.send_welcome_email(root_email, name, portal_url, root_username)
            except Exception as e:
                try: db.conn.rollback()
                except Exception: pass
                logger.warning(f"Failed to send welcome email: {e}")

        result = {'organization': org, 'message': 'Organization created'}
        if root_user:
            result['root_user'] = {k: v for k, v in root_user.items() if k != 'password_hash'}
        return jsonify(result), 201
    except Exception as e:
        logger.exception("Client onboarding failed: %s", e)
        return jsonify({'error': 'Internal server error'}), 500
    finally:
        db.close()


def update_organization_handler(organization_id):
    """PUT /api/organizations/<id> — update organization details (superadmin only)."""
    data = request.get_json(silent=True) or {}
    db = Database(_admin_reason='admin_portal_org_update')
    try:
        existing = db.get_organization_by_id(organization_id)
        if not existing:
            return jsonify({'error': 'Tenant not found'}), 404

        updates = {}
        if 'name' in data:
            name = str(data['name']).strip()
            if not name or len(name) > 255:
                return jsonify({'error': 'name must be 1-255 characters'}), 400
            updates['name'] = name
        if 'plan' in data:
            plan = str(data['plan']).strip().lower()
            if plan not in ('free', 'trial', 'pro'):
                return jsonify({'error': 'plan must be free, trial, or pro'}), 400
            updates['plan'] = plan
        if 'enabled' in data:
            updates['enabled'] = bool(data['enabled'])
        if 'settings' in data and isinstance(data['settings'], dict):
            updates['settings'] = data['settings']
        if 'license_activated_at' in data:
            updates['license_activated_at'] = data['license_activated_at']
        if 'license_expires_at' in data:
            updates['license_expires_at'] = data['license_expires_at']
        if 'subscription_term' in data:
            term = _safe_int(data['subscription_term'], 'subscription_term')
            if term not in (0, 1, 3, 5):
                return jsonify({'error': 'subscription_term must be 0 (monthly), 1, 3, or 5 years'}), 400
            updates['subscription_term'] = term
            # Auto-compute expiry from activation date + term
            if term > 0:
                activated = data.get('license_activated_at') or existing.get('license_activated_at')
                if activated:
                    act_dt = datetime.fromisoformat(str(activated).replace('Z', '+00:00')) if isinstance(activated, str) else activated
                    updates['license_expires_at'] = act_dt.replace(year=act_dt.year + term).isoformat()
            elif term == 0:
                # Monthly — no fixed expiry
                updates['license_expires_at'] = None
        # Phase 85: Additional org metadata fields
        if 'primary_cloud' in data:
            pc = str(data['primary_cloud']).strip().lower()
            if pc and pc not in ('azure', 'aws', 'gcp'):
                return jsonify({'error': 'primary_cloud must be azure, aws, or gcp'}), 400
            updates['primary_cloud'] = pc or None
        if 'industry' in data:
            updates['industry'] = str(data['industry']).strip() or None
        if 'compliance_framework' in data:
            updates['compliance_framework'] = str(data['compliance_framework']).strip() or None
        if 'status' in data:
            st = str(data['status']).strip().lower()
            if st not in ('active', 'trial', 'suspended', 'cancelled'):
                return jsonify({'error': 'status must be active, trial, suspended, or cancelled'}), 400
            updates['status'] = st

        if not updates:
            return jsonify({'organization': existing, 'message': 'No changes'})

        org = db.update_organization(organization_id, **updates)
        try:
            _log(db,'org_updated',
                f'Tenant "{existing["name"]}" updated: {", ".join(updates.keys())}',
                {'organization_id': organization_id, 'updates': list(updates.keys())})
        except Exception:
            try: db.conn.rollback()
            except Exception: pass
            pass
        try:
            user = getattr(g, 'current_user', None)
            user_id = user.get('id') if user else None
            db.log_admin_audit(user_id, 'org_updated', target_organization_id=organization_id,
                               details={'fields_changed': list(updates.keys())},
                               ip_address=request.remote_addr)
        except Exception:
            try: db.conn.rollback()
            except Exception: pass
            pass
        return jsonify({'organization': org, 'message': 'Organization updated'})
    finally:
        db.close()


def delete_organization_handler(organization_id):
    """DELETE /api/organizations/<id> — delete an organization (superadmin only)."""
    # Use admin DB (no RLS) so cascade can delete across org boundaries
    db = Database(_admin_reason='admin_portal_org_delete')
    try:
        existing = db.get_organization_by_id(organization_id)
        if not existing:
            return jsonify({'error': 'Tenant not found'}), 404
        if existing.get('slug') == 'default':
            return jsonify({'error': 'Cannot delete the default organization'}), 400

        try:
            db.delete_organization(organization_id)
        except Exception as e:
            try: db.conn.rollback()
            except Exception: pass
            logger.error(f"Failed to delete organization {organization_id}: {e}", exc_info=True)
            detail = str(e)
            # Surface the actual constraint name for debugging
            if 'foreign key' in detail.lower() or 'violates' in detail.lower():
                return jsonify({'error': f'Failed to delete organization: {detail}'}), 500
            return jsonify({'error': f'Failed to delete organization: {detail}'}), 500

        try:
            _log(db,'org_deleted',
                f'Tenant "{existing["name"]}" deleted',
                {'organization_id': organization_id, 'slug': existing.get('slug')})
        except Exception:
            try: db.conn.rollback()
            except Exception: pass
            pass
        return jsonify({'message': f'Tenant "{existing["name"]}" deleted'})
    finally:
        db.close()


def bulk_delete_organizations_handler():
    """POST /api/admin/organizations/bulk-delete — delete orgs matching a name pattern.

    Request body:
      {
        "pattern":    "Benchmark%",   (required) SQL LIKE pattern
        "dry_run":    true,           (default true) preview only, no DB changes
        "confirm":    false,          (default false) must be true to execute
        "max_delete": 10              (default 10) safety cap, 400 if exceeded
      }

    Response:
      {
        "dry_run": true/false,
        "pattern": "...",
        "matched_count": 4,
        "deleted_count": 0/4,
        "matched": [...],             (always present — orgs that match)
        "deleted": [...],             (only when dry_run=false)
        "skipped": [...],             (orgs skipped due to errors)
        "errors":  [...]              (error details per org)
      }
    """
    data = request.get_json(silent=True) or {}
    pattern = data.get('pattern', '').strip()
    if not pattern:
        return jsonify({'error': 'pattern is required (e.g. "Benchmark%")'}), 400

    dry_run = data.get('dry_run', True)
    confirm = data.get('confirm', False)
    max_delete = data.get('max_delete', 10)

    db = Database(_admin_reason='admin_portal_bulk_delete')
    try:
        # Always find matching orgs first
        matched = db.find_organizations_by_pattern(pattern)
        matched_count = len(matched)

        # Dry-run: return preview only
        if dry_run:
            return jsonify({
                'dry_run': True,
                'pattern': pattern,
                'matched_count': matched_count,
                'deleted_count': 0,
                'matched': matched,
                'deleted': [],
                'skipped': [],
                'errors': [],
            })

        # Safety: require explicit confirm=true for destructive operation
        if not confirm:
            return jsonify({
                'error': 'confirm must be true to execute deletion',
                'matched_count': matched_count,
                'matched': matched,
            }), 400

        # Safety: cap on number of deletions
        if matched_count > max_delete:
            return jsonify({
                'error': (f'Matched {matched_count} organizations, exceeds '
                          f'max_delete={max_delete}. Increase max_delete or '
                          f'narrow the pattern.'),
                'matched_count': matched_count,
                'matched': matched,
            }), 400

        # Execute deletion
        deleted, errors = db.delete_organizations_by_pattern(pattern)
        skipped = [e for e in errors]
        deleted_names = [o['name'] for o in deleted]
        logger.info("Bulk deleted %d organizations matching '%s': %s",
                     len(deleted), pattern, deleted_names)
        if errors:
            logger.warning("Bulk delete errors for pattern '%s': %s",
                            pattern, errors)

        return jsonify({
            'dry_run': False,
            'pattern': pattern,
            'matched_count': matched_count,
            'deleted_count': len(deleted),
            'matched': matched,
            'deleted': deleted,
            'skipped': skipped,
            'errors': errors,
        })
    except Exception as e:
        logger.error(f"Bulk delete failed for pattern '{pattern}': {e}",
                     exc_info=True)
        return jsonify({'error': f'Bulk delete failed: {str(e)}'}), 500
    finally:
        db.close()


