# ── Phase 47: Cross-Tenant Analytics ─────────────────────────────

def get_cross_org_analytics():
    """GET /api/analytics/organizations — per-org metrics + global aggregates (superadmin only).

    Uses admin DB (no RLS) — organizations table has no tenant_id.
    Gracefully degrades when discovery_runs table doesn't exist (fresh DB).
    """
    db = Database(_admin_reason='admin_cross_org_analytics')
    try:
        cursor = db.conn.cursor(cursor_factory=RealDictCursor)

        # Check if discovery_runs table exists (fresh DB may not have it)
        cursor.execute("""
            SELECT EXISTS (
                SELECT 1 FROM information_schema.tables
                WHERE table_schema = 'public' AND table_name = 'discovery_runs'
            )
        """)
        has_discovery_runs = cursor.fetchone()['exists']

        if has_discovery_runs:
            cursor.execute("""
                WITH latest_runs AS (
                    SELECT DISTINCT ON (organization_id)
                        id, organization_id, completed_at, total_identities,
                        critical_count, high_count, medium_count, low_count
                    FROM discovery_runs
                    WHERE status = 'completed'
                    ORDER BY organization_id, id DESC
                ),
                prev_runs AS (
                    SELECT DISTINCT ON (organization_id)
                        organization_id, total_identities AS prev_total,
                        critical_count AS prev_critical, high_count AS prev_high
                    FROM discovery_runs
                    WHERE status = 'completed' AND id NOT IN (SELECT id FROM latest_runs)
                    ORDER BY organization_id, id DESC
                ),
                run_counts AS (
                    SELECT organization_id, COUNT(*) AS total_runs
                    FROM discovery_runs GROUP BY organization_id
                ),
                user_counts AS (
                    SELECT organization_id, COUNT(*) AS user_count
                    FROM users WHERE organization_id IS NOT NULL GROUP BY organization_id
                )
                SELECT
                    o.id, o.name, o.slug, o.plan, o.enabled,
                    o.settings, o.license_activated_at, o.license_expires_at, o.subscription_term,
                    COALESCE(uc.user_count, 0) AS user_count,
                    COALESCE(rc.total_runs, 0) AS total_runs,
                    lr.completed_at AS last_discovery,
                    COALESCE(lr.total_identities, 0) AS total_identities,
                    COALESCE(lr.critical_count, 0) AS critical_count,
                    COALESCE(lr.high_count, 0) AS high_count,
                    COALESCE(lr.medium_count, 0) AS medium_count,
                    COALESCE(lr.low_count, 0) AS low_count,
                    pr.prev_total, pr.prev_critical, pr.prev_high
                FROM organizations o
                LEFT JOIN latest_runs lr ON lr.organization_id = o.id
                LEFT JOIN prev_runs pr ON pr.organization_id = o.id
                LEFT JOIN run_counts rc ON rc.organization_id = o.id
                LEFT JOIN user_counts uc ON uc.organization_id = o.id
                ORDER BY o.id
            """)
        else:
            # Fallback: org + user counts only (no discovery data)
            cursor.execute("""
                SELECT o.id, o.name, o.slug, o.plan, o.enabled,
                       o.settings, o.license_activated_at, o.license_expires_at, o.subscription_term,
                       COALESCE((SELECT COUNT(*) FROM users u WHERE u.organization_id = o.id), 0) AS user_count,
                       0 AS total_runs, NULL AS last_discovery,
                       0 AS total_identities, 0 AS critical_count, 0 AS high_count,
                       0 AS medium_count, 0 AS low_count,
                       NULL AS prev_total, NULL AS prev_critical, NULL AS prev_high
                FROM organizations o ORDER BY o.id
            """)

        rows = [dict(r) for r in cursor.fetchall()]
        cursor.close()

        # Compute risk score per org + serialize timestamps + extract clouds
        for row in rows:
            c = row.get('critical_count') or 0
            h = row.get('high_count') or 0
            m = row.get('medium_count') or 0
            row['risk_score'] = max(0, min(100, 100 - (c * 15 + h * 5 + m * 1)))
            if row.get('last_discovery'):
                row['last_discovery'] = row['last_discovery'].isoformat()
            for ts in ('license_activated_at', 'license_expires_at'):
                if row.get(ts):
                    row[ts] = row[ts].isoformat()
            # Extract enabled clouds from org settings JSON
            settings = row.pop('settings', None) or {}
            cp = settings.get('cloud_providers', {})
            row['clouds_enabled'] = [k for k in ('azure', 'aws', 'gcp') if cp.get(k, {}).get('enabled')]

        # Global aggregates
        total_orgs = len(rows)
        active_orgs = sum(1 for r in rows if r.get('total_runs', 0) > 0)
        total_identities = sum(r.get('total_identities', 0) for r in rows)
        total_critical = sum(r.get('critical_count', 0) for r in rows)
        total_high = sum(r.get('high_count', 0) for r in rows)
        scores = [r['risk_score'] for r in rows if r.get('total_runs', 0) > 0]
        avg_risk_score = round(sum(scores) / len(scores), 1) if scores else 0.0

        global_metrics = {
            'total_orgs': total_orgs,
            'active_orgs': active_orgs,
            # AdminOverview.tsx reads total_tenants/active_tenants
            'total_tenants': total_orgs,
            'active_tenants': active_orgs,
            'total_identities': total_identities,
            'total_critical': total_critical,
            'total_high': total_high,
            'avg_risk_score': avg_risk_score,
        }

        return jsonify({
            'organizations': rows,
            'tenants': rows,  # AdminOverview compat
            'global': global_metrics,
        })
    except Exception as e:
        logger.exception("Failed to load cross-org analytics: %s", e)
        return jsonify({
            'organizations': [], 'tenants': [],
            'global': {'total_orgs': 0, 'active_orgs': 0,
                       'total_tenants': 0, 'active_tenants': 0,
                       'total_identities': 0, 'total_critical': 0,
                       'total_high': 0, 'avg_risk_score': 0},
        }), 500
    finally:
        db.close()


def get_cross_org_trends():
    """GET /api/analytics/organizations/trends — recent runs per org for timeline (superadmin only)."""
    db = Database(_admin_reason='admin_cross_org_trends')
    cursor = db.conn.cursor(cursor_factory=RealDictCursor)
    try:
        # Check if discovery_runs table exists
        cursor.execute("""
            SELECT EXISTS (
                SELECT 1 FROM information_schema.tables
                WHERE table_schema = 'public' AND table_name = 'discovery_runs'
            )
        """)
        has_runs = cursor.fetchone()['exists']

        if not has_runs:
            return jsonify({'trends': {}})

        cursor.execute("""
            SELECT dr.organization_id, o.name AS org_name,
                   dr.id, dr.completed_at, dr.total_identities,
                   dr.critical_count, dr.high_count
            FROM discovery_runs dr
            JOIN organizations o ON o.id = dr.organization_id
            WHERE dr.status = 'completed'
            ORDER BY dr.organization_id, dr.completed_at DESC
            LIMIT 100
        """)
        rows = [dict(r) for r in cursor.fetchall()]

        # Group by organization
        trends: dict = {}
        for row in rows:
            tid = str(row['organization_id'])
            if tid not in trends:
                trends[tid] = {'org_name': row['org_name'], 'runs': []}
            if row.get('completed_at'):
                row['completed_at'] = row['completed_at'].isoformat()
            trends[tid]['runs'].append({
                'id': row['id'],
                'completed_at': row['completed_at'],
                'total_identities': row['total_identities'] or 0,
                'critical_count': row['critical_count'] or 0,
                'high_count': row['high_count'] or 0,
            })

        return jsonify({'trends': trends})
    except Exception as e:
        logger.exception("Failed to load cross-org trends: %s", e)
        return jsonify({'trends': {}}), 500
    finally:
        cursor.close()
        db.close()


def get_login_sessions():
    """GET /api/analytics/login-sessions — paired login/logout events for governance.
    ?portal=admin|client — filter by portal context (default: all)
    """
    db = Database(_admin_reason='admin_login_sessions')
    cursor = db.conn.cursor(cursor_factory=RealDictCursor)
    try:
        limit = request.args.get('limit', 50, type=int)
        limit = min(limit, 200)
        portal_filter = request.args.get('portal', '')  # 'admin', 'client', or '' (all)

        # Determine which action types to include based on portal filter
        if portal_filter == 'admin':
            login_types = ('admin_login',)
            logout_types = ('admin_logout',)
        elif portal_filter == 'client':
            login_types = ('auth_login',)
            logout_types = ('auth_logout',)
        else:
            login_types = ('auth_login', 'admin_login')
            logout_types = ('auth_logout', 'admin_logout')

        all_types = login_types + logout_types
        organization_id_filter = request.args.get('organization_id', type=int)

        # Fetch recent login + logout events with user details
        where_clause = "WHERE a.action_type = ANY(%s)"
        query_params: list = [list(all_types)]
        if organization_id_filter:
            where_clause += " AND a.organization_id = %s"
            query_params.append(organization_id_filter)
        query_params.append(limit * 3)
        cursor.execute(f"""
            SELECT a.id, a.action_type, a.description, a.metadata, a.created_at,
                   a.user_id, a.organization_id,
                   u.username, u.display_name, u.role,
                   o.name AS org_name
            FROM activity_log a
            LEFT JOIN users u ON u.id = a.user_id
            LEFT JOIN organizations o ON o.id = a.organization_id
            {where_clause}
            ORDER BY a.created_at DESC
            LIMIT %s
        """, query_params)  # fetch extra to pair logouts with logins
        rows = [dict(r) for r in cursor.fetchall()]

        # Serialize timestamps
        for row in rows:
            if row.get('created_at'):
                row['created_at'] = row['created_at'].isoformat()

        # Build sessions: for each login, find the next logout by the same user
        logins = [r for r in rows if r['action_type'] in login_types]
        logouts = [r for r in rows if r['action_type'] in logout_types]

        # Index logouts by user_id (list, most recent first — already sorted desc)
        logout_map: dict = {}
        for lo in logouts:
            uid = lo.get('user_id')
            if uid not in logout_map:
                logout_map[uid] = []
            logout_map[uid].append(lo)

        sessions = []
        for login in logins[:limit]:
            uid = login.get('user_id')
            meta = login.get('metadata') or {}
            login_time = login['created_at']

            # Find matching logout: first logout by same user AFTER this login
            logout_time = None
            duration_min = None
            if uid in logout_map:
                for lo in reversed(logout_map[uid]):  # oldest first
                    if lo['created_at'] and login_time and lo['created_at'] > login_time:
                        logout_time = lo['created_at']
                        # Calculate duration
                        try:
                            lt = datetime.fromisoformat(login_time.replace('Z', '+00:00'))
                            lot = datetime.fromisoformat(logout_time.replace('Z', '+00:00'))
                            duration_min = round((lot - lt).total_seconds() / 60, 1)
                        except Exception:
                            pass
                        # Remove this logout so it isn't reused
                        logout_map[uid].remove(lo)
                        break

            session_portal = 'admin' if login['action_type'] == 'admin_login' else 'client'
            sessions.append({
                'user_id': uid,
                'username': login.get('username') or '',
                'display_name': login.get('display_name') or login.get('username') or '',
                'role': login.get('role') or meta.get('role', ''),
                'org_name': login.get('org_name') or meta.get('org_name', ''),
                'organization_id': login.get('organization_id'),
                'login_at': login_time,
                'logout_at': logout_time,
                'duration_minutes': duration_min,
                'ip_address': meta.get('ip', ''),
                'user_agent': meta.get('user_agent', ''),
                'status': 'ended' if logout_time else 'active',
                'portal': session_portal,
            })

        return jsonify({
            'sessions': sessions,
            'count': len(sessions),
        })
    except Exception as e:
        logger.exception("Failed to load login sessions: %s", e)
        return jsonify({'sessions': [], 'count': 0}), 500
    finally:
        cursor.close()
        db.close()


# ── Phase 48: Onboarding Wizard ─────────────────────────────────

def get_onboarding_status():
    """Check if the current org has completed onboarding. Returns checklist progress."""
    db = _db()
    try:
        tid = _org_id()
        settings = db.get_settings(organization_id=tid)
        completed_flag = settings.get('onboarding_completed', 'false') == 'true'

        # Check cloud_connections table for verified connections (not stale settings keys)
        azure_configured = False
        cloud_connections_count = 0
        try:
            cursor = db.conn.cursor()
            cursor.execute("""
                SELECT COUNT(*) FROM cloud_connections
                WHERE organization_id = %s AND status = 'connected'
            """, (tid,))
            row = cursor.fetchone()
            cloud_connections_count = (row[0] if row else 0)
            azure_configured = cloud_connections_count > 0
            cursor.close()
        except Exception:
            try: db.conn.rollback()
            except Exception: pass

        # FIX: Never report onboarding as complete if no cloud connection
        # actually exists. The settings flag alone is not sufficient — the
        # user must have successfully tested a connection during the wizard.
        completed = completed_flag and (azure_configured or cloud_connections_count > 0)

        # Pre-fetch org name (needed for checklist + response)
        org_name = ''
        try:
            org = db.get_organization_by_id(tid)
            org_name = (org or {}).get('name', '') or ''
        except Exception:
            pass

        # Check for active subscriptions
        subs_activated = False
        try:
            cursor = db.conn.cursor()
            cursor.execute("""
                SELECT COUNT(*) FROM cloud_subscriptions
                WHERE organization_id = %s AND monitored = true
                  AND (deleted IS NULL OR deleted = false)
            """, (tid,))
            row = cursor.fetchone()
            subs_activated = row and row[0] > 0
            cursor.close()
        except Exception:
            try: db.conn.rollback()
            except Exception: pass
            pass

        # Build onboarding checklist
        # org_name: check both settings key and organization name
        # (signup sets org name on the organizations table, not settings)
        has_org_name = bool(settings.get('org_name') or org_name)
        checklist = [
            {
                'key': 'org_name',
                'label': 'Set organization name',
                'done': has_org_name,
            },
            {
                'key': 'cloud_connected',
                'label': 'Connect a cloud provider',
                'done': azure_configured,
            },
            {
                'key': 'subscriptions_activated',
                'label': 'Activate a subscription',
                'done': subs_activated,
            },
            {
                'key': 'first_scan',
                'label': 'Run first discovery scan',
                'done': False,
            },
            {
                'key': 'review_identities',
                'label': 'Review discovered identities',
                'done': False,
            },
            {
                'key': 'notifications',
                'label': 'Configure notifications',
                'done': settings.get('email_enabled') == 'true' or settings.get('slack_webhook_url') or settings.get('teams_webhook_url'),
            },
        ]

        # Check if first scan completed
        cursor = db.conn.cursor()
        try:
            run_ids = _latest_run_ids(cursor, tid, None)
            if run_ids:
                checklist[3]['done'] = True  # first_scan (index 3 after subscriptions_activated)
                # Check if any identity was viewed (proxy for "reviewed")
                cursor.execute("""
                    SELECT COUNT(*) FROM activity_log
                    WHERE organization_id = %s AND action = 'identity_viewed'
                    LIMIT 1
                """, (tid,))
                row = cursor.fetchone()
                if row and row[0] > 0:
                    checklist[4]['done'] = True  # review_identities (index 4)
        except Exception:
            try: db.conn.rollback()
            except Exception: pass
            pass
        finally:
            cursor.close()

        done_count = sum(1 for c in checklist if c['done'])

        snapshot_completed = checklist[3]['done'] if len(checklist) > 3 else False

        return jsonify({
            'onboarding_completed': completed,
            'azure_configured': azure_configured,
            'cloud_connections_count': cloud_connections_count,
            'snapshot_completed': snapshot_completed,
            'has_settings': bool(settings),
            'checklist': checklist,
            'checklist_progress': done_count,
            'checklist_total': len(checklist),
            'org_name': org_name,
        })
    finally:
        db.close()


def test_azure_connection():
    """Test Azure credentials without saving. Returns subscription list on success."""
    data = request.get_json()
    if not data:
        return jsonify({'error': 'Expected JSON body'}), 400

    azure_directory_id = (data.get('azure_directory_id') or data.get('tenant_id') or '').strip()
    azure_client_id = (data.get('azure_client_id') or data.get('client_id') or '').strip()
    azure_client_secret = (data.get('azure_client_secret') or data.get('client_secret') or '').strip()

    if not all([azure_directory_id, azure_client_id, azure_client_secret]):
        return jsonify({'error': 'All three Azure credential fields are required'}), 400

    try:
        from azure.identity import ClientSecretCredential
        from azure.mgmt.resource import SubscriptionClient

        credential = ClientSecretCredential(
            tenant_id=azure_directory_id,
            client_id=azure_client_id,
            client_secret=azure_client_secret,
        )
        sub_client = SubscriptionClient(credential)
        subs = []
        all_states = []
        for sub in sub_client.subscriptions.list():
            state_str = str(sub.state).lower() if sub.state else 'unknown'
            all_states.append(state_str)
            if state_str in ('enabled', 'warned'):
                subs.append({
                    'id': sub.subscription_id,
                    'name': sub.display_name or sub.subscription_id,
                })

        if all_states:
            logger.info("Azure subscriptions found: %d total, %d enabled — states: %s",
                         len(all_states), len(subs), all_states)
        else:
            logger.warning("Azure auth succeeded but 0 subscriptions visible — "
                           "SPN likely needs Reader RBAC on at least one subscription")

        # Auto-advance onboarding stage to 'active' and insert discovered subs
        tid = _org_id()
        if tid:
            from app.database import Database
            admin_db = Database(_admin_reason='test_azure: advance stage + insert subs')
            try:
                admin_db.update_organization(tid, onboarding_stage='active')

                # Ensure a cloud_connection exists for this directory (needed as FK for subscriptions)
                # Always persist encrypted credentials so discovery can use them later
                from app.encryption import encrypt_field
                encrypted_meta = json.dumps({'client_secret': encrypt_field(azure_client_secret)})
                cursor = admin_db.conn.cursor()
                cursor.execute("""
                    SELECT id FROM cloud_connections
                    WHERE organization_id = %s AND cloud = 'azure'
                      AND azure_directory_id = %s
                    ORDER BY id LIMIT 1
                """, (tid, azure_directory_id))
                row = cursor.fetchone()
                if row:
                    conn_id = row[0]
                    # Update credentials + status on existing connection
                    cursor.execute("""
                        UPDATE cloud_connections
                        SET metadata = %s, client_id = %s, status = 'connected',
                            credential_last_rotated = NOW(), updated_at = NOW()
                        WHERE id = %s
                    """, (encrypted_meta, azure_client_id, conn_id))
                else:
                    cursor.execute("""
                        INSERT INTO cloud_connections
                            (organization_id, cloud, connection_type, label,
                             azure_directory_id, client_id, status, metadata,
                             credential_last_rotated)
                        VALUES (%s, 'azure', 'entra', 'Primary',
                                %s, %s, 'connected', %s, NOW())
                        RETURNING id
                    """, (tid, azure_directory_id, azure_client_id, encrypted_meta))
                    conn_id = cursor.fetchone()[0]

                admin_db._ensure_cloud_subscriptions_table()
                for s in subs:
                    cursor.execute("""
                        INSERT INTO cloud_subscriptions
                            (organization_id, cloud, account_id, account_name,
                             status, cloud_connection_id)
                        VALUES (%s, 'azure', %s, %s, 'discovered', %s)
                        ON CONFLICT (organization_id, cloud, account_id)
                        DO UPDATE SET cloud_connection_id = EXCLUDED.cloud_connection_id,
                                      account_name = COALESCE(EXCLUDED.account_name, cloud_subscriptions.account_name)
                    """, (tid, s['id'], s['name'], conn_id))
                # Auto-enable P2 telemetry if connection already has P2 license
                cursor.execute(
                    "SELECT has_p2_license FROM cloud_connections WHERE id = %s",
                    (conn_id,)
                )
                p2_row = cursor.fetchone()
                if p2_row and p2_row[0]:
                    cursor.execute("""
                        INSERT INTO settings (key, value, organization_id, updated_at)
                        VALUES ('p2_telemetry_enabled', 'true', %s, NOW())
                        ON CONFLICT (organization_id, key) DO UPDATE SET value = 'true', updated_at = NOW()
                    """, (tid,))
                    logger.info("P2 auto-enabled for org %s at connection time", tid)

                admin_db._commit()
                cursor.close()
                # Seed auto identity groups for this org
                admin_db.seed_auto_groups_for_organization(tid)
            finally:
                admin_db.close()

        msg = f'Connected successfully. Found {len(subs)} subscription(s).'
        if not subs:
            msg += (' The Service Principal authenticated but has no RBAC access to any subscription. '
                     'Assign at least Reader role on the target subscription(s) in Azure IAM.')

        return jsonify({
            'status': 'success',
            'subscriptions': subs,
            'message': msg,
        })
    except Exception as e:
        logger.error(f"Azure connection test failed: {e}", exc_info=True)
        err_str = str(e)
        if 'AADSTS7000215' in err_str:
            hint = 'Invalid client secret. Ensure you are using the secret Value (not the Secret ID).'
        elif 'AADSTS700016' in err_str:
            hint = 'Application not found. Verify the Client ID matches your App Registration.'
        elif 'AADSTS90002' in err_str:
            hint = 'Tenant not found. Verify the Directory (Tenant) ID.'
        else:
            hint = 'Failed to connect. Check your credentials and network access.'
        return jsonify({
            'status': 'error',
            'error': 'Connection test failed',
            'message': hint,
        }), 400


# ── Cloud Connections (multi-directory / multi-cloud) ───────────

def get_client_connections():
    """List all cloud connections for the current organization.
    Auto-creates a 'Primary' connection from settings if none exist yet.
    Returns {connected: false, requires_setup: true} when no connections exist.
    """
    tid = _org_id()
    if not tid or tid == -1:
        return jsonify({'error': 'Tenant context required'}), 403
    cloud = request.args.get('cloud')
    db = _db()
    try:
        connections = db.get_cloud_connections(tid, cloud=cloud)

        # Auto-create primary connection from existing settings if none exist
        if not connections and not cloud:
            try:
                settings = db.get_settings(organization_id=tid)
                azure_tid = (settings.get('azure_directory_id') or '').strip()
                azure_cid = (settings.get('azure_client_id') or '').strip()
                azure_secret = (settings.get('azure_client_secret') or '').strip()
                if azure_tid:
                    meta = {'migrated_from_settings': True}
                    if azure_secret:
                        meta['client_secret'] = azure_secret
                    conn = db.create_cloud_connection(
                        organization_id=tid, cloud='azure', label='Primary',
                        azure_directory_id=azure_tid, client_id=azure_cid,
                        connection_type='entra',
                        metadata=meta,
                    )
                    # Mark as connected since it was already working
                    db.update_cloud_connection(conn['id'], status='connected',
                                               last_test_status='success')
                    # Link existing subscriptions to this primary connection
                    db._ensure_cloud_subscriptions_table()
                    cursor = db.conn.cursor()
                    cursor.execute("""
                        UPDATE cloud_subscriptions
                        SET cloud_connection_id = %s
                        WHERE organization_id = %s AND cloud_connection_id IS NULL
                    """, (conn['id'], tid))
                    db._commit()
                    cursor.close()
                    connections = db.get_cloud_connections(tid)
            except Exception:
                try: db.conn.rollback()
                except Exception: pass
                pass

        if not connections:
            return jsonify({
                'connected': False,
                'connections': [],
                'requires_setup': True,
            })
        return jsonify({
            'connected': True,
            'connections': connections,
            'requires_setup': False,
        })
    except Exception as e:
        try: db.conn.rollback()
        except Exception: pass
        logger.exception("Failed to list cloud connections: %s", e)
        return jsonify({
            'connected': False,
            'connections': [],
            'requires_setup': True,
            'error': 'Internal server error',
        }), 500
    finally:
        db.close()


def create_client_connection():
    """Create a new cloud connection for the current organization.
    Stores credentials in metadata and auto-discovers subscriptions.
    """
    guard = _demo_write_guard()
    if guard:
        return guard
    tid = _org_id()
    if not tid or tid == -1:
        return jsonify({'error': 'Tenant context required'}), 403

    # Enforce subscription limit before creating connection
    from app.entitlements.service import enforce_subscription_limit
    admin_db = Database(_admin_reason='create_connection: enforce subscription limit')
    try:
        allowed, err_msg = enforce_subscription_limit(admin_db, tid)
        if not allowed:
            return jsonify({'error': err_msg, 'upgrade_required': True}), 403
    finally:
        admin_db.close()

    data = request.get_json()
    if not data:
        return jsonify({'error': 'Expected JSON body'}), 400

    cloud = (data.get('cloud') or 'azure').strip().lower()
    label = (data.get('label') or '').strip()
    azure_directory_id = (data.get('azure_directory_id') or data.get('tenant_id') or '').strip()
    client_id = (data.get('client_id') or data.get('azure_client_id') or '').strip()
    client_secret = (data.get('client_secret') or data.get('azure_client_secret') or '').strip()
    connection_type = (data.get('connection_type') or 'entra').strip()
    status = (data.get('status') or 'pending').strip()

    if not label:
        return jsonify({'error': 'Connection label is required'}), 400
    if cloud == 'azure' and not azure_directory_id:
        return jsonify({'error': 'Entra Directory ID is required for Azure connections'}), 400

    # FIX1C: Cross-org uniqueness check — prevent same cloud account reused by another org
    if azure_directory_id:
        from app.connectors import validate_connector_unique
        check_db = Database(_admin_reason='create_connection: cross-org uniqueness check')
        try:
            existing_org = validate_connector_unique(check_db, cloud, azure_directory_id)
            if existing_org and existing_org != tid:
                return jsonify({
                    'error': f'This {cloud} directory is already connected by another organization.',
                    'code': 'DUPLICATE_CONNECTOR'
                }), 409
        finally:
            check_db.close()

    # Build metadata — store credentials encrypted in JSONB
    from app.encryption import encrypt_field
    metadata = data.get('metadata') or {}
    if client_secret:
        metadata['client_secret'] = encrypt_field(client_secret)

    db = _db()
    try:
        conn = db.create_cloud_connection(
            organization_id=tid, cloud=cloud, label=label,
            azure_directory_id=azure_directory_id or None,
            client_id=client_id or None,
            connection_type=connection_type,
            metadata=metadata,
        )
        # If already verified (test passed), mark connected
        if status == 'connected':
            conn = db.update_cloud_connection(conn['id'], status='connected',
                                               last_test_status='success') or conn

        # Auto-discover subscriptions/accounts for verified connections
        discovered_count = 0
        discovered_subs = []
        if cloud == 'azure' and status == 'connected' and client_secret and azure_directory_id and client_id:
            try:
                from azure.identity import ClientSecretCredential
                from azure.mgmt.resource import SubscriptionClient
                credential = ClientSecretCredential(
                    tenant_id=azure_directory_id,
                    client_id=client_id,
                    client_secret=client_secret,
                )
                sub_client = SubscriptionClient(credential)
                subs_list = []
                for sub in sub_client.subscriptions.list():
                    if sub.state and sub.state.lower() in ('enabled', 'warned'):
                        subs_list.append({
                            'id': sub.subscription_id,
                            'name': sub.display_name or sub.subscription_id,
                            'tenant_id': sub.tenant_id or azure_directory_id,
                        })
                # Partition own-tenant vs foreign-tenant subscriptions
                own_subs = [s for s in subs_list if s['tenant_id'] == azure_directory_id]
                foreign_subs = [s for s in subs_list if s['tenant_id'] != azure_directory_id]
                # Insert own-tenant subs under this connection
                discovered_count = db.insert_discovered_subscriptions(
                    tid, cloud, conn['id'], own_subs)
                discovered_subs = own_subs
                # Insert foreign-tenant subs under auto-created connections
                import itertools
                for foreign_tenant, group in itertools.groupby(
                        sorted(foreign_subs, key=lambda s: s['tenant_id']),
                        key=lambda s: s['tenant_id']):
                    group_list = list(group)
                    foreign_conn = db.find_or_create_cloud_connection(
                        tid, foreign_tenant,
                        label=f'Azure Tenant {foreign_tenant[:8]}...',
                        source_azure_directory_id=azure_directory_id,
                        source_connection_label=label)
                    db.insert_discovered_subscriptions(
                        tid, cloud, foreign_conn['id'], group_list)
                    discovered_count += len(group_list)
                    discovered_subs.extend(group_list)
            except Exception as e:
                try: db.conn.rollback()
                except Exception: pass
                logger.warning("Azure subscription re-discovery failed for connection %s: %s", conn['id'], e)
        elif cloud == 'aws' and status == 'connected':
            access_key_id = metadata.get('access_key_id') or client_id
            secret_access_key = metadata.get('secret_access_key') or client_secret
            if access_key_id and secret_access_key:
                try:
                    import boto3
                    sts = boto3.client(
                        'sts',
                        aws_access_key_id=access_key_id,
                        aws_secret_access_key=secret_access_key,
                        region_name=metadata.get('region', 'us-east-1'),
                    )
                    caller = sts.get_caller_identity()
                    account_id = caller.get('Account', '')
                    if account_id:
                        subs_list = [{'id': account_id, 'name': f'AWS Account {account_id}'}]
                        discovered_count = db.insert_discovered_subscriptions(
                            tid, cloud, conn['id'], subs_list)
                        discovered_subs = subs_list
                        # Store account_id as azure_directory_id for UNIQUE constraint compatibility
                        db.update_cloud_connection(conn['id'], azure_directory_id=account_id)
                except Exception:
                    try: db.conn.rollback()
                    except Exception: pass
                    pass  # Non-fatal

        # Fallback: if re-discovery yielded nothing, count subs already linked
        # (e.g. inserted during the test-connection step)
        if discovered_count == 0:
            try:
                existing = db.get_cloud_subscriptions(tid, cloud=cloud, connection_id=conn['id'])
                if existing:
                    discovered_count = len(existing)
                    discovered_subs = [{'id': s.get('account_id', ''), 'name': s.get('account_name', '')} for s in existing]
            except Exception:
                try: db.conn.rollback()
                except Exception: pass

        _log(db, 'connection_created', f'Created {cloud} connection: {label}',
             {'connection_id': conn['id'], 'cloud': cloud, 'discovered_subs': discovered_count})

        # Track usage
        from app.entitlements.service import track_usage
        track_usage(db, tid, 'connection', str(conn['id']), 'added', {'cloud': cloud})

        # Advance org stage to 'active' for verified connections (no auto-discovery)
        if status == 'connected':
            try:
                adm = Database(_admin_reason='create_connection: advance onboarding stage')
                try:
                    o = adm.get_organization_by_id(tid)
                    if o and o.get('onboarding_stage') in ('locked', 'authenticating', 'password_change'):
                        adm.update_organization(tid, onboarding_stage='active')
                finally:
                    adm.close()
            except Exception:
                pass

        # Security event: connector created
        from app.security_events import SecurityEventLogger
        user_id = g.current_user.get('id') if hasattr(g, 'current_user') and g.current_user else None
        evt = SecurityEventLogger.connector_created(tid, conn['id'], cloud, label, user_id)
        SecurityEventLogger.persist(evt, db)

        result = dict(conn)
        result['discovered_count'] = discovered_count
        result['discovered_subscriptions'] = discovered_subs
        # Strip secret from response
        meta = result.get('metadata') or {}
        if isinstance(meta, dict):
            meta.pop('client_secret', None)
            result['metadata'] = meta
        return jsonify({'connection': result}), 201
    finally:
        db.close()


def update_client_connection(connection_id):
    """Update a cloud connection."""
    tid = _org_id()
    if not tid or tid == -1:
        return jsonify({'error': 'Tenant context required'}), 403
    data = request.get_json()
    if not data:
        return jsonify({'error': 'Expected JSON body'}), 400

    db = _db()
    try:
        # Verify ownership
        existing = db.get_cloud_connection_by_id(connection_id)
        if not existing or existing['organization_id'] != tid:
            return jsonify({'error': 'Connection not found'}), 404

        allowed_fields = {}
        for key in ('label', 'status', 'display_order', 'azure_directory_id', 'client_id'):
            if key in data:
                allowed_fields[key] = data[key]

        updated = db.update_cloud_connection(connection_id, **allowed_fields)
        _log(db, 'connection_updated', f'Updated connection: {existing["label"]}',
             {'connection_id': connection_id, 'changes': list(allowed_fields.keys())})
        return jsonify({'connection': updated})
    finally:
        db.close()


def delete_client_connection(connection_id):
    """Delete a cloud connection and ALL associated data.

    Uses ConnectionLifecycleService to cascade-delete:
    - discovery_runs (→ cascades to identities, role_assignments,
      risk_summary, anomalies, app_registrations, resources, etc.)
    - snapshot_jobs, cloud_subscriptions
    - cloud_connections row itself
    """
    tid = _org_id()
    if not tid or tid == -1:
        return jsonify({'error': 'Tenant context required'}), 403

    db = _db()
    try:
        existing = db.get_cloud_connection_by_id(connection_id)
        if not existing or existing['organization_id'] != tid:
            return jsonify({'error': 'Connection not found'}), 404

        connection_label = existing.get('label', '')
        connection_cloud = existing.get('cloud', '')

        # Full lifecycle cleanup — deletes all data, then the connection row
        from app.services.connection_lifecycle import ConnectionLifecycleService
        service = ConnectionLifecycleService(db)
        result = service.remove_connection_data(tid, connection_id)

        _log(db, 'connection_deleted',
             f'Deleted connection: {connection_label} — {result.get("total_deleted", 0)} data rows removed',
             {'connection_id': connection_id, 'cloud': connection_cloud,
              'runs_removed': result.get('runs_removed', 0),
              'total_deleted': result.get('total_deleted', 0)})

        # Track usage on connection removal
        from app.entitlements.service import track_usage
        track_usage(db, tid, 'connection', str(connection_id), 'removed', {'cloud': connection_cloud})

        return jsonify({
            'deleted': True,
            'connection_name': connection_label,
            'data_removed': {
                'runs_removed': result.get('runs_removed', 0),
                'total_deleted': result.get('total_deleted', 0),
                'details': result.get('rows_deleted', {}),
            },
        })
    finally:
        db.close()


def purge_client_connection_data(connection_id):
    """POST /api/client/connections/<id>/purge-data

    Clear all discovery data (identities, runs, resources) for an auth_failed
    connection but keep the connection row so the user can re-authenticate.
    """
    tid = _org_id()
    if not tid or tid == -1:
        return jsonify({'error': 'Tenant context required'}), 403

    db = _db()
    try:
        existing = db.get_cloud_connection_by_id(connection_id)
        if not existing or existing['organization_id'] != tid:
            return jsonify({'error': 'Connection not found'}), 404

        if existing['status'] != 'auth_failed':
            return jsonify({'error': 'Only auth_failed connections can be purged. Use Remove for connected connections.'}), 400

        from app.services.connection_lifecycle import ConnectionLifecycleService
        service = ConnectionLifecycleService(db)
        result = service.purge_connection_data(tid, connection_id)

        if not result.get('purged'):
            return jsonify({'error': result.get('error', 'Purge failed')}), 500

        _log(db, 'connection_data_purged',
             f'Cleared stale data for auth_failed connection: {existing.get("label", "")} — '
             f'{result.get("total_deleted", 0)} rows removed',
             {'connection_id': connection_id, 'cloud': existing.get('cloud', ''),
              'runs_removed': result.get('runs_removed', 0),
              'total_deleted': result.get('total_deleted', 0)})

        return jsonify({
            'purged': True,
            'connection_id': connection_id,
            'connection_name': existing.get('label', ''),
            'data_removed': {
                'runs_removed': result.get('runs_removed', 0),
                'total_deleted': result.get('total_deleted', 0),
            },
        })
    finally:
        db.close()


def cleanup_inactive_connections_handler():
    """POST /api/admin/cleanup-inactive-connections

    One-time cleanup: removes all data from connections that no longer
    exist in cloud_connections table (deleted) or are marked 'removed'.
    """
    tid = _org_id()
    if not tid or tid == -1:
        return jsonify({'error': 'Tenant context required'}), 403

    db = _db()
    try:
        from app.services.connection_lifecycle import ConnectionLifecycleService
        service = ConnectionLifecycleService(db)
        result = service.cleanup_orphaned_data(tid)

        _log(db, 'admin_cleanup',
             f'Inactive connection cleanup: {result.get("cleaned", 0)} connections, '
             f'{result.get("total_rows_deleted", 0)} rows',
             result)

        return jsonify(result)
    except Exception as e:
        logger.exception("Cleanup failed: %s", e)
        return jsonify({'error': str(e)}), 500
    finally:
        db.close()


def rotate_connector_credentials(connection_id):
    """POST /api/connectors/<id>/rotate-credentials — update credentials and reset rotation timestamps."""
    tid = _org_id()
    if not tid or tid == -1:
        return jsonify({'error': 'Tenant context required'}), 403

    data = request.get_json()
    if not data:
        return jsonify({'error': 'Expected JSON body'}), 400

    client_secret = (data.get('client_secret') or '').strip()
    if not client_secret:
        return jsonify({'error': 'client_secret is required'}), 400

    db = _db()
    try:
        existing = db.get_cloud_connection_by_id(connection_id)
        if not existing or existing.get('organization_id') != tid:
            return jsonify({'error': 'Connection not found'}), 404

        # Update metadata with new secret (encrypted)
        from app.encryption import encrypt_field
        metadata = existing.get('metadata') or {}
        if isinstance(metadata, str):
            import json as _json
            metadata = _json.loads(metadata)
        metadata['client_secret'] = encrypt_field(client_secret)

        # Parse credential_expires_at if provided
        credential_expires_at = None
        if data.get('credential_expires_at'):
            try:
                from datetime import datetime
                credential_expires_at = datetime.fromisoformat(data['credential_expires_at'].replace('Z', '+00:00'))
            except (ValueError, AttributeError):
                return jsonify({'error': 'Invalid credential_expires_at format (use ISO 8601)'}), 400

        from datetime import datetime, timezone
        update_kwargs = {
            'metadata': metadata,
            'credential_last_rotated': datetime.now(timezone.utc),
        }
        if credential_expires_at:
            update_kwargs['credential_expires_at'] = credential_expires_at

        updated = db.update_cloud_connection(connection_id, **update_kwargs)

        _log(db, 'credential_rotated',
             f'Credentials rotated for connector: {existing["label"]}',
             {'connection_id': connection_id, 'cloud': existing.get('cloud'),
              'expires_at': data.get('credential_expires_at')})

        # Security event: credential rotated
        from app.security_events import SecurityEventLogger
        user_id = g.current_user.get('id') if hasattr(g, 'current_user') and g.current_user else None
        evt = SecurityEventLogger.credential_rotated(tid, connection_id, existing['label'], user_id)
        SecurityEventLogger.persist(evt, db)

        # Strip secret from response
        if updated and updated.get('metadata'):
            meta = updated['metadata']
            if isinstance(meta, dict):
                meta.pop('client_secret', None)
                updated['metadata'] = meta

        return jsonify({'connection': updated, 'rotated': True})
    finally:
        db.close()


def check_connector_credential_expiry_handler():
    """GET /api/connectors/expiring-credentials — list connectors with credentials expiring soon."""
    tid = _org_id()
    if not tid or tid == -1:
        return jsonify({'error': 'Tenant context required'}), 403

    warning_days = request.args.get('days', 30, type=int)
    warning_days = min(max(warning_days, 1), 365)

    db = _db()
    try:
        expiring = db.check_connector_credential_expiry(warning_days=warning_days)
        # Filter to current org
        org_expiring = [c for c in expiring if c.get('organization_id') == tid]
        for c in org_expiring:
            logger.warning("Connector credential expiring soon: id=%s, label=%s, days=%s",
                           c['id'], c['label'], c.get('days_until_expiry'))
        return jsonify({'expiring': org_expiring, 'warning_days': warning_days})
    finally:
        db.close()


def test_client_connection():
    """Test cloud connection credentials without saving."""
    tid = _org_id()
    if not tid or tid == -1:
        return jsonify({'error': 'Tenant context required'}), 403

    data = request.get_json()
    if not data:
        return jsonify({'error': 'Expected JSON body'}), 400

    cloud = (data.get('cloud') or 'azure').strip().lower()

    if cloud == 'azure':
        azure_directory_id = (data.get('azure_directory_id') or data.get('tenant_id') or '').strip()
        azure_client_id = (data.get('client_id') or data.get('azure_client_id') or '').strip()
        azure_client_secret = (data.get('client_secret') or data.get('azure_client_secret') or '').strip()

        if not all([azure_directory_id, azure_client_id, azure_client_secret]):
            return jsonify({'error': 'Entra Directory ID, Client ID, and Client Secret are required'}), 400

        try:
            from azure.identity import ClientSecretCredential
            from azure.mgmt.resource import SubscriptionClient

            credential = ClientSecretCredential(
                tenant_id=azure_directory_id,
                client_id=azure_client_id,
                client_secret=azure_client_secret,
            )
            sub_client = SubscriptionClient(credential)
            subs = []
            all_states = []
            for sub in sub_client.subscriptions.list():
                state_str = str(sub.state).lower() if sub.state else 'unknown'
                all_states.append(state_str)
                if state_str in ('enabled', 'warned'):
                    subs.append({
                        'id': sub.subscription_id,
                        'name': sub.display_name or sub.subscription_id,
                    })

            if all_states:
                logger.info("Azure subscriptions found: %d total, %d enabled — states: %s",
                             len(all_states), len(subs), all_states)
            else:
                logger.warning("Azure auth succeeded but 0 subscriptions visible — "
                               "SPN likely needs Reader RBAC on at least one subscription")

            # If connection_id provided, update its test status and persist subscriptions
            connection_id = data.get('connection_id')
            if connection_id:
                db = _db()
                try:
                    db.update_cloud_connection(connection_id,
                                               last_test_at=datetime.now(timezone.utc).isoformat(),
                                               last_test_status='success',
                                               status='connected')

                    # Insert discovered subscriptions into cloud_subscriptions
                    cursor = db.conn.cursor()
                    for s in subs:
                        cursor.execute("""
                            INSERT INTO cloud_subscriptions
                                (organization_id, cloud, account_id, account_name,
                                 status, cloud_connection_id)
                            VALUES (%s, 'azure', %s, %s, 'discovered', %s)
                            ON CONFLICT (organization_id, cloud, account_id) DO UPDATE
                                SET account_name = EXCLUDED.account_name,
                                    cloud_connection_id = EXCLUDED.cloud_connection_id,
                                    deleted = false
                        """, (tid, s['id'], s['name'], connection_id))
                    cursor.close()
                    db._commit()
                    logger.info("Inserted %d Azure subscription(s) into cloud_subscriptions for org %s", len(subs), tid)
                finally:
                    db.close()

            # Advance onboarding stage on successful connection test
            try:
                adm = Database(_admin_reason='test_connection: advance onboarding stage')
                try:
                    o = adm.get_organization_by_id(tid)
                    if o and o.get('onboarding_stage') in ('connections', 'locked', 'authenticating', 'password_change'):
                        adm.update_organization(tid, onboarding_stage='active')
                finally:
                    adm.close()
            except Exception:
                try: db.conn.rollback()
                except Exception: pass
                pass

            msg = f'Connected successfully. Found {len(subs)} subscription(s).'
            if not subs:
                msg += (' The Service Principal authenticated but has no RBAC access to any subscription. '
                         'Assign at least Reader role on the target subscription(s) in Azure IAM.')

            return jsonify({
                'status': 'success',
                'subscriptions': subs,
                'message': msg,
            })
        except Exception as e:
            # Update test status on failure
            connection_id = data.get('connection_id')
            if connection_id:
                db = _db()
                try:
                    db.update_cloud_connection(connection_id,
                                               last_test_at=datetime.now(timezone.utc).isoformat(),
                                               last_test_status='failed')
                finally:
                    db.close()
            logger.error(f"Cloud connection test failed: {e}", exc_info=True)
            return jsonify({
                'status': 'error',
                'error': 'Connection test failed',
                'message': 'Failed to connect. Check your credentials.',
            }), 400
    elif cloud == 'aws':
        access_key_id = (data.get('access_key_id') or data.get('client_id') or '').strip()
        secret_access_key = (data.get('secret_access_key') or data.get('client_secret') or '').strip()
        region = (data.get('region') or 'us-east-1').strip()

        if not all([access_key_id, secret_access_key]):
            return jsonify({'error': 'Access Key ID and Secret Access Key are required'}), 400

        try:
            import boto3
            sts = boto3.client(
                'sts',
                aws_access_key_id=access_key_id,
                aws_secret_access_key=secret_access_key,
                region_name=region,
            )
            caller = sts.get_caller_identity()
            account_id = caller.get('Account', '')

            # Update connection test status if connection_id provided
            connection_id_param = data.get('connection_id')
            if connection_id_param:
                db = _db()
                try:
                    db.update_cloud_connection(connection_id_param,
                                               last_test_at=datetime.now(timezone.utc).isoformat(),
                                               last_test_status='success',
                                               status='connected')
                finally:
                    db.close()

            return jsonify({
                'status': 'success',
                'subscriptions': [{'id': account_id, 'name': f'AWS Account {account_id}'}],
                'message': f'Connected successfully. AWS Account: {account_id}',
            })
        except Exception as e:
            try: db.conn.rollback()
            except Exception: pass
            connection_id_param = data.get('connection_id')
            if connection_id_param:
                db = _db()
                try:
                    db.update_cloud_connection(connection_id_param,
                                               last_test_at=datetime.now(timezone.utc).isoformat(),
                                               last_test_status='failed')
                finally:
                    db.close()
            logger.error(f"AWS connection test failed: {e}", exc_info=True)
            return jsonify({
                'status': 'error',
                'error': 'Connection test failed',
                'message': 'Failed to connect to AWS. Check your credentials.',
            }), 400
    else:
        return jsonify({'error': f'Cloud provider "{cloud}" test not yet supported'}), 400


def discover_client_connection(connection_id):
    """Trigger discovery for a specific cloud connection.

    Auto-activates all discovered (unmonitored) subscriptions for this
    connection before triggering discovery, so identities are captured
    for every subscription found during the connection test.
    """
    import threading
    from app.scheduler import trigger_manual_discovery

    tid = _org_id()
    if not tid or tid == -1:
        return jsonify({'error': 'Tenant context required'}), 403

    db = _db()
    try:
        existing = db.get_cloud_connection_by_id(connection_id)
        if not existing or existing['organization_id'] != tid:
            return jsonify({'error': 'Connection not found'}), 404

        if existing['status'] == 'auth_failed':
            return jsonify({'error': 'Credential expired or invalid. Re-authenticate this connection before scanning.'}), 400
        if existing['status'] != 'connected':
            return jsonify({'error': 'Connection must be tested and connected before discovery'}), 400

        # Auto-activate all unmonitored subscriptions for this connection
        user = getattr(g, 'current_user', None)
        user_id = user.get('id') if user else None
        cursor = db.conn.cursor()
        cursor.execute("""
            UPDATE cloud_subscriptions
            SET monitored = true, status = 'active',
                activated_at = NOW(), activated_by = %s
            WHERE organization_id = %s
              AND cloud_connection_id = %s
              AND monitored = false
              AND deleted = false
            RETURNING id, account_id
        """, (user_id, tid, connection_id))
        activated = cursor.fetchall()
        cursor.close()
        db._commit()
        if activated:
            logger.info("Auto-activated %d subscription(s) for connection %d: %s",
                         len(activated), connection_id,
                         [row[1] for row in activated])

        _log(db, 'connection_discovery', f'Discovery triggered for connection: {existing["label"]}',
             {'connection_id': connection_id, 'auto_activated': len(activated)})
    finally:
        db.close()

    # Advance onboarding stage to 'active' immediately (don't rely on background thread)
    try:
        adm = Database(_admin_reason='discover_connection: advance onboarding stage')
        try:
            o = adm.get_organization_by_id(tid)
            if o and o.get('onboarding_stage') in ('connections', 'locked', 'authenticating', 'password_change'):
                adm.update_organization(tid, onboarding_stage='active')
                logger.info("Onboarding stage advanced to 'active' for org %s", tid)
        finally:
            adm.close()
    except Exception:
        try: db.conn.rollback()
        except Exception: pass
        pass

    # Run discovery in background thread (after DB closed to avoid holding connection)
    _org_name = g.current_user.get('org_name') if hasattr(g, 'current_user') and g.current_user else None
    def _run():
        try:
            trigger_manual_discovery(
                scan_mode='deep', db_org_id=tid,
                org_name=_org_name, connection_id=connection_id,
            )
        except Exception as e:
            logging.getLogger(__name__).error(f"Connection discovery failed for {connection_id}: {e}")
    thread = threading.Thread(target=_run, daemon=True)
    thread.start()

    return jsonify({
        'status': 'started',
        'message': f'Discovery started for connection: {existing["label"]}',
        'connection_id': connection_id,
        'subscriptions_activated': len(activated),
    }), 202


# ── Phase 49: Identity Risk Simulation ──────────────────────────

def _compute_risk_score(azure_roles, entra_roles, permissions, app_roles, credentials,
                        identity_category=None):
    """Pure-function risk scoring — no DB access. Returns (score, level, reasons)."""
    risk_score = 0
    risk_reasons = []

    # 1. Entra ID directory roles
    for er in entra_roles:
        rn = (er.get('role_name') or '').lower()
        if 'global administrator' in rn:
            risk_score += 100
            risk_reasons.append('Global Administrator: Full tenant control - violates SOC2 least privilege, HIPAA §164.312, PCI-DSS 7')
        elif 'privileged role administrator' in rn:
            risk_score += 90
            risk_reasons.append('Privileged Role Admin: Can assign any role - privilege escalation risk, SOC2 separation of duties')
        elif 'application administrator' in rn or 'cloud application administrator' in rn:
            risk_score += 80
            risk_reasons.append(f"{er.get('role_name','App Admin')}: Can manage all apps/SPNs - HIPAA BAA concerns")
        elif 'user administrator' in rn:
            risk_score += 60
            risk_reasons.append('User Administrator: Can reset passwords, create users - SOC2 access control, PCI-DSS 8.1')
        elif 'security administrator' in rn:
            risk_score += 60
            risk_reasons.append('Security Administrator: Can modify security policies - SOC2 change management')
        elif 'exchange administrator' in rn:
            risk_score += 50
            risk_reasons.append('Exchange Administrator: Full mailbox access - HIPAA ePHI exposure')
        elif 'sharepoint administrator' in rn:
            risk_score += 50
            risk_reasons.append('SharePoint Administrator: Full document access - GDPR Art. 32')

    # 2. Azure RBAC roles
    for role in azure_roles:
        rn = (role.get('role_name') or '').lower()
        st = role.get('scope_type', '')
        if 'owner' in rn:
            if st == 'subscription':
                risk_score += 100
                risk_reasons.append('Owner on Subscription: Full control including IAM - SOC2, PCI-DSS 7.1, HIPAA §164.312(a)(1)')
            elif st == 'resource_group':
                risk_score += 60
                risk_reasons.append('Owner on Resource Group: Can delete all resources, modify access - SOC2 availability')
            else:
                risk_score += 30
                risk_reasons.append(f"Owner role on {st}")
        elif 'contributor' in rn:
            if st == 'subscription':
                risk_score += 80
                risk_reasons.append('Contributor on Subscription: Can create/modify/delete all resources - SOC2, PCI-DSS 7.2')
            elif st == 'resource_group':
                risk_score += 40
                risk_reasons.append('Contributor on Resource Group: Broad resource modification - SOC2 least privilege')
        elif 'user access administrator' in rn:
            risk_score += 70
            risk_reasons.append('User Access Administrator: Can grant any role - privilege escalation, SOC2/PCI-DSS 7.1')
        elif 'key vault' in rn and ('administrator' in rn or 'officer' in rn):
            risk_score += 50
            risk_reasons.append('Key Vault Admin/Officer: Access to secrets/keys - HIPAA §164.312(a)(2)(iv), PCI-DSS 3.5')

    # 3. Graph API permissions
    write_perms = [p for p in permissions
                   if '.write' in (p.get('permission_name') or '').lower()
                   or '.readwrite' in (p.get('permission_name') or '').lower()]
    read_all_perms = [p for p in permissions
                      if ('.read.all' in (p.get('permission_name') or '').lower()
                          or 'readall' in (p.get('permission_name') or '').lower())
                      and p not in write_perms]

    if write_perms:
        risk_score += 60
        risk_reasons.append(f"Graph API Write Access: {len(write_perms)} write permission(s) - SOC2 change management, HIPAA §164.312(c)")
    if read_all_perms and not write_perms:
        risk_score += 40
        risk_reasons.append(f"Graph API Read-All: {len(read_all_perms)} permission(s) - PII/PHI exposure, GDPR Art. 32")

    # 4. Orphaned permissions
    has_roles = len(azure_roles) > 0 or len(entra_roles) > 0
    has_permissions = len(permissions) > 0
    if not has_roles and has_permissions:
        risk_score += 30
        risk_reasons.append('API permissions without role justification (orphaned)')

    # 5. App roles
    admin_app_roles = [ar for ar in app_roles
                       if any(kw in (ar.get('app_role_value') or ar.get('resource_display_name') or '').lower()
                              for kw in ['admin', 'owner', 'full', 'write', 'manage'])]
    if admin_app_roles:
        risk_score += 50
        risk_reasons.append(f"Has {len(admin_app_roles)} administrative app role(s)")
    elif app_roles:
        risk_score += 20
        risk_reasons.append(f"Has {len(app_roles)} app role assignment(s)")

    # 6. Credentials
    has_expired = False
    has_expiring_soon = False
    for cred in credentials:
        end_date = cred.get('end_datetime')
        if end_date:
            try:
                if isinstance(end_date, str):
                    end_dt = datetime.fromisoformat(end_date.replace('Z', '+00:00'))
                else:
                    end_dt = end_date
                now = datetime.now(timezone.utc)
                if end_dt < now:
                    has_expired = True
                elif (end_dt - now).days < 30:
                    has_expiring_soon = True
            except Exception:
                pass
    if has_expired:
        risk_score += 35
        risk_reasons.append('Has expired credentials')
    elif has_expiring_soon:
        risk_score += 15
        risk_reasons.append('Has credentials expiring within 30 days')

    # 7. Orphaned identity (no roles, no perms, no app roles — non-user)
    if not has_roles and not has_permissions and not app_roles:
        if identity_category and identity_category not in ('human_user', 'guest'):
            risk_score += 25
            risk_reasons.append('No role assignments (potentially orphaned identity)')

    # Convert to level
    if risk_score >= 120:
        risk_level = 'critical'
    elif risk_score >= 70:
        risk_level = 'high'
    elif risk_score >= 40:
        risk_level = 'medium'
    elif risk_score > 0:
        risk_level = 'low'
    else:
        risk_level = 'info'
        risk_reasons = ['No elevated privileges detected']

    return risk_score, risk_level, risk_reasons


def simulate_risk(identity_id):
    """POST /api/identities/<id>/simulate — what-if risk simulation."""
    db = _db()
    try:
        data = request.get_json(silent=True) or {}
        remove_roles = set(r.lower() for r in (data.get('remove_roles') or []))
        add_roles = data.get('add_roles') or []
        remove_perms = set(p.lower() for p in (data.get('remove_permissions') or []))
        add_perms = data.get('add_permissions') or []

        # Fetch identity — scoped to latest runs for selected connection
        cursor = db.conn.cursor(cursor_factory=RealDictCursor)
        conn_id = _connection_id()
        run_ids = _latest_run_ids(cursor, _org_id(), conn_id)
        if run_ids:
            cursor.execute("""
                SELECT id, identity_id, identity_category, risk_score, risk_level, risk_reasons,
                       credential_status
                FROM identities WHERE identity_id = %s AND discovery_run_id = ANY(%s)
                ORDER BY discovery_run_id DESC LIMIT 1
            """, (identity_id, run_ids))
        else:
            cursor.execute("""
                SELECT id, identity_id, identity_category, risk_score, risk_level, risk_reasons,
                       credential_status
                FROM identities WHERE identity_id = %s
                ORDER BY discovery_run_id DESC LIMIT 1
            """, (identity_id,))
        row = cursor.fetchone()
        if not row:
            cursor.close()
            return jsonify({'error': 'Identity not found'}), 404

        db_id = row['id']
        current_score = row['risk_score'] or 0
        current_level = row['risk_level'] or 'info'
        current_reasons = row['risk_reasons'] if isinstance(row['risk_reasons'], list) else []
        identity_category = row['identity_category']

        # Fetch current data
        roles = db.get_identity_roles_enriched(db_id)
        azure_roles = [r for r in roles if r.get('role_type') == 'azure']
        entra_roles_list = [r for r in roles if r.get('role_type') == 'entra']
        perms = db.get_graph_permissions(db_id)
        app_roles = db.get_app_roles(db_id)

        # Fetch credentials
        cursor.execute("""
            SELECT credential_type, end_datetime FROM credentials WHERE identity_db_id = %s
        """, (db_id,))
        creds = [dict(c) for c in cursor.fetchall()]
        cursor.close()

        # Apply modifications: remove
        sim_azure = [r for r in azure_roles if r.get('role_name', '').lower() not in remove_roles]
        sim_entra = [r for r in entra_roles_list if r.get('role_name', '').lower() not in remove_roles]
        sim_perms = [p for p in perms if (p.get('permission_name') or '').lower() not in remove_perms]
        sim_app_roles = list(app_roles)  # app roles not modified in simulation

        # Apply modifications: add
        for ar in add_roles:
            entry = {'role_name': ar.get('role_name', ''), 'scope_type': ar.get('scope_type', 'subscription')}
            if ar.get('role_type') == 'entra':
                sim_entra.append(entry)
            else:
                sim_azure.append(entry)

        for ap in add_perms:
            sim_perms.append({
                'permission_name': ap.get('permission_name', ''),
                'risk_level': ap.get('risk_level', 'medium'),
            })

        # Compute simulated risk
        sim_score, sim_level, sim_reasons = _compute_risk_score(
            sim_azure, sim_entra, sim_perms, sim_app_roles, creds, identity_category
        )

        delta = sim_score - current_score
        level_change = f"{current_level} \u2192 {sim_level}" if current_level != sim_level else current_level

        # Determine removed and added reasons
        current_set = set(current_reasons)
        sim_set = set(sim_reasons)
        removed_reasons = sorted(current_set - sim_set)
        added_reasons = sorted(sim_set - current_set)

        return jsonify({
            'current': {
                'risk_score': current_score,
                'risk_level': current_level,
                'risk_reasons': current_reasons,
            },
            'simulated': {
                'risk_score': sim_score,
                'risk_level': sim_level,
                'risk_reasons': sim_reasons,
            },
            'delta': delta,
            'level_change': level_change,
            'removed_reasons': removed_reasons,
            'added_reasons': added_reasons,
        })
    finally:
        db.close()


def get_sensitive_access_for_identity(identity_id):
    """GET /api/identities/<id>/sensitive-access — which sensitive resources can this identity access."""
    db = _db()
    try:

        organization_id = _org_id()
        cursor = db.conn.cursor(cursor_factory=RealDictCursor)
        run_ids = _latest_run_ids(cursor, organization_id, _connection_id())
        if not run_ids:
            cursor.close()
            return jsonify({'identity_id': identity_id, 'sensitive_resources': [], 'blast_radius': {}})

        # Resolve identity
        cursor.execute("SELECT id, display_name FROM identities WHERE identity_id = %s AND discovery_run_id = ANY(%s)", (identity_id, run_ids))
        ident = cursor.fetchone()
        if not ident:
            # Try by integer id
            try:
                cursor.execute("SELECT id, display_name FROM identities WHERE id = %s", (int(identity_id),))
                ident = cursor.fetchone()
            except (ValueError, TypeError):
                pass
        if not ident:
            cursor.close()
            return jsonify({'error': 'Identity not found'}), 404

        db_id = ident['id']
        display_name = ident['display_name']

        # Get role assignments for this identity
        cursor.execute("""
            SELECT role_name, scope, scope_type, risk_level
            FROM role_assignments
            WHERE identity_db_id = %s
        """, (db_id,))
        role_assignments = cursor.fetchall()

        # Get classified resources
        classified_resources = []
        for table, rtype in [('azure_storage_accounts', 'storage_account'), ('azure_key_vaults', 'key_vault')]:
            cursor.execute(f"""
                SELECT id, name, resource_id, resource_group, subscription_id,
                       data_classification, risk_level, risk_score
                FROM {table}
                WHERE discovery_run_id = ANY(%s)
                AND data_classification IS NOT NULL
            """, (run_ids,))
            for row in cursor.fetchall():
                row['_type'] = rtype
                classified_resources.append(row)

        # Match: identity role assignments → classified resources via scope hierarchy
        sensitive = []
        for res in classified_resources:
            res_id_full = res['resource_id'] or ''
            res_rg = res.get('resource_group', '') or ''
            res_sub = res.get('subscription_id', '') or ''

            for ra in role_assignments:
                scope = (ra.get('scope') or '').lower()
                # Direct resource match
                if res_id_full and res_id_full.lower() == scope:
                    access_source = 'direct'
                # Resource group match
                elif res_rg and f'/resourcegroups/{res_rg.lower()}' in scope and '/providers/' not in scope.split(f'/resourcegroups/{res_rg.lower()}')[-1]:
                    access_source = 'resource_group'
                # Subscription match
                elif res_sub and scope == f'/subscriptions/{res_sub.lower()}':
                    access_source = 'subscription'
                elif scope == '/':
                    access_source = 'root'
                else:
                    continue

                # Determine access level from role
                role_name = (ra.get('role_name') or '').lower()
                if role_name in ('owner', 'user access administrator'):
                    access_level = 'Admin'
                elif role_name in ('contributor', 'storage account contributor', 'storage blob data contributor', 'key vault administrator', 'key vault secrets officer', 'key vault crypto officer'):
                    access_level = 'Write'
                else:
                    access_level = 'Read'

                sensitive.append({
                    'resource_db_id': res['id'],
                    'resource_name': res['name'],
                    'resource_type': res['_type'],
                    'resource_path': res_id_full,
                    'classification': res['data_classification'],
                    'access_level': access_level,
                    'role_name': ra['role_name'],
                    'access_source': access_source,
                    'resource_risk_level': res.get('risk_level', 'info'),
                    'resource_risk_score': res.get('risk_score', 0),
                })
                break  # One match per resource is enough

        # Compute blast radius
        by_classification = {}
        by_access_level = {}
        for s in sensitive:
            by_classification[s['classification']] = by_classification.get(s['classification'], 0) + 1
            by_access_level[s['access_level']] = by_access_level.get(s['access_level'], 0) + 1

        cursor.close()
        return jsonify({
            'identity_id': identity_id,
            'display_name': display_name,
            'sensitive_resources': sensitive,
            'blast_radius': {
                'total_sensitive': len(sensitive),
                'by_classification': by_classification,
                'by_access_level': by_access_level,
            },
        })
    finally:
        db.close()


def get_blast_radius_summary():
    """GET /api/blast-radius/summary — identities with access to sensitive resources."""
    db = _db()
    try:

        organization_id = _org_id()
        cursor = db.conn.cursor(cursor_factory=RealDictCursor)
        run_ids = _latest_run_ids(cursor, organization_id, _connection_id())
        if not run_ids:
            cursor.close()
            return jsonify({
                'identities_with_sensitive_access': [],
                'summary': {
                    'total_identities_with_phi_access': 0,
                    'total_identities_with_pci_access': 0,
                    'total_identities_with_pii_access': 0,
                },
            })

        # Get all classified resources
        classified = []
        for table, rtype in [('azure_storage_accounts', 'storage_account'), ('azure_key_vaults', 'key_vault')]:
            cursor.execute(f"""
                SELECT id, name, resource_id, resource_group, subscription_id, data_classification
                FROM {table}
                WHERE discovery_run_id = ANY(%s) AND data_classification IS NOT NULL
            """, (run_ids,))
            for row in cursor.fetchall():
                row['_type'] = rtype
                classified.append(row)

        if not classified:
            cursor.close()
            return jsonify({
                'identities_with_sensitive_access': [],
                'summary': {
                    'total_identities_with_phi_access': 0,
                    'total_identities_with_pci_access': 0,
                    'total_identities_with_pii_access': 0,
                },
            })

        # Get all identities
        cursor.execute("""
            SELECT i.id, i.identity_id, i.display_name, i.identity_type, i.identity_category,
                   i.risk_level, i.risk_score
            FROM identities i
            WHERE i.discovery_run_id = ANY(%s)
              AND NOT COALESCE(i.is_microsoft_system, false)
        """, (run_ids,))
        identities = cursor.fetchall()

        # Get all role assignments for these identities
        id_list = [i['id'] for i in identities]
        if not id_list:
            cursor.close()
            return jsonify({
                'identities_with_sensitive_access': [],
                'summary': {
                    'total_identities_with_phi_access': 0,
                    'total_identities_with_pci_access': 0,
                    'total_identities_with_pii_access': 0,
                },
            })

        cursor.execute("""
            SELECT identity_db_id, role_name, scope
            FROM role_assignments
            WHERE identity_db_id = ANY(%s)
        """, (id_list,))
        # Build identity → roles map
        identity_roles = {}
        for ra in cursor.fetchall():
            db_id = ra['identity_db_id']
            if db_id not in identity_roles:
                identity_roles[db_id] = []
            identity_roles[db_id].append(ra)

        # For each identity, check which classified resources they can access
        results = []
        phi_ids = set()
        pci_ids = set()
        pii_ids = set()

        for ident in identities:
            roles = identity_roles.get(ident['id'], [])
            if not roles:
                continue

            phi_count = 0
            pci_count = 0
            pii_count = 0
            highest_access = 'Read'

            for res in classified:
                res_id_full = (res.get('resource_id') or '').lower()
                res_rg = (res.get('resource_group') or '').lower()
                res_sub = (res.get('subscription_id') or '').lower()
                cls = res['data_classification']

                for ra in roles:
                    scope = (ra.get('scope') or '').lower()
                    matched = False
                    if res_id_full and scope == res_id_full:
                        matched = True
                    elif res_rg and f'/resourcegroups/{res_rg}' in scope and '/providers/' not in scope.split(f'/resourcegroups/{res_rg}')[-1]:
                        matched = True
                    elif res_sub and scope == f'/subscriptions/{res_sub}':
                        matched = True
                    elif scope == '/':
                        matched = True

                    if matched:
                        role_name = (ra.get('role_name') or '').lower()
                        if role_name in ('owner', 'user access administrator'):
                            al = 'Admin'
                        elif 'contributor' in role_name or 'officer' in role_name or 'administrator' in role_name:
                            al = 'Write'
                        else:
                            al = 'Read'

                        if al == 'Admin' or (al == 'Write' and highest_access != 'Admin'):
                            highest_access = al
                        elif highest_access == 'Read':
                            highest_access = al

                        if cls == 'PHI':
                            phi_count += 1
                            phi_ids.add(ident['id'])
                        elif cls == 'PCI':
                            pci_count += 1
                            pci_ids.add(ident['id'])
                        elif cls == 'PII':
                            pii_count += 1
                            pii_ids.add(ident['id'])
                        break

            total_sensitive = phi_count + pci_count + pii_count
            if total_sensitive > 0:
                results.append({
                    'identity_db_id': ident['id'],
                    'identity_id': ident['identity_id'],
                    'display_name': ident['display_name'],
                    'identity_type': ident.get('identity_type', ''),
                    'identity_category': ident.get('identity_category', ''),
                    'risk_level': ident.get('risk_level', 'info'),
                    'risk_score': ident.get('risk_score', 0),
                    'sensitive_resources_count': total_sensitive,
                    'phi_count': phi_count,
                    'pci_count': pci_count,
                    'pii_count': pii_count,
                    'highest_access': highest_access,
                })

        results.sort(key=lambda x: x['sensitive_resources_count'], reverse=True)

        cursor.close()
        return jsonify({
            'identities_with_sensitive_access': results,
            'summary': {
                'total_identities_with_phi_access': len(phi_ids),
                'total_identities_with_pci_access': len(pci_ids),
                'total_identities_with_pii_access': len(pii_ids),
                'total_classified_resources': len(classified),
                'highest_risk_identity': results[0]['display_name'] if results else None,
            },
        })
    finally:
        db.close()


