def validate_organization_slug():
    """POST /api/tenants/validate-slug — Public, rate-limited.
    Validates a slug maps to an active tenant without leaking internal details.
    Used by TenantContext on cold load to block rendering until the tenant is confirmed.
    """
    data = request.get_json(silent=True) or {}
    slug = str(data.get('slug', '')).strip().lower()
    if not slug or len(slug) > 63:
        return jsonify({'valid': False}), 200

    db = Database(_admin_reason='public endpoint — slug validation')
    try:
        cursor = db.conn.cursor(cursor_factory=RealDictCursor)
        cursor.execute(
            "SELECT id, name, slug, plan, enabled FROM organizations WHERE slug = %s AND enabled = true",
            (slug,),
        )
        row = cursor.fetchone()
        cursor.close()
        if not row:
            return jsonify({'valid': False}), 200
        return jsonify({
            'valid': True,
            'org': {
                'id': row['id'],
                'name': row['name'],
                'slug': row['slug'],
                'plan': row.get('plan', 'free'),
                'enabled': True,
            },
        })
    finally:
        db.close()


def provision_organization_handler(organization_id):
    """POST /api/organizations/<id>/provision — Create admin user for an organization. Superadmin only."""
    data = request.get_json(silent=True) or {}
    admin_username = str(data.get('admin_username', '')).strip().lower()
    admin_display_name = str(data.get('admin_display_name', '')).strip()
    admin_password = str(data.get('admin_password', ''))

    if not admin_username or len(admin_username) < 3:
        return jsonify({'error': 'admin_username must be at least 3 characters'}), 400
    if not admin_display_name:
        return jsonify({'error': 'admin_display_name is required'}), 400
    if not admin_password or len(admin_password) < 12:
        return jsonify({'error': 'admin_password must be at least 12 characters'}), 400

    db = _db()
    try:
        org = db.get_organization_by_id(organization_id)
        if not org:
            return jsonify({'error': 'Tenant not found'}), 404

        existing = db.get_user_by_username(admin_username)
        if existing:
            return jsonify({'error': f'Username "{admin_username}" already exists'}), 409

        hashed = bcrypt.hashpw(admin_password.encode('utf-8'), bcrypt.gensalt()).decode('utf-8')
        current_user = getattr(g, 'current_user', None)
        created_by = current_user['id'] if current_user else None

        user = db.create_user(admin_username, hashed, admin_display_name, 'admin', created_by, organization_id=organization_id, force_password_change=True)

        # Mark org as provisioned
        settings = org.get('settings') or {}
        if isinstance(settings, str):
            try:
                settings = json.loads(settings)
            except Exception:
                try: db.conn.rollback()
                except Exception: pass
                settings = {}
        settings['provisioned'] = True
        settings['provisioned_at'] = datetime.now(timezone.utc).isoformat()
        db.update_organization(organization_id, settings=settings)

        _log(db, 'org_provisioned',
             f'Organization provisioned with admin user "{admin_username}"',
             {'organization_id': organization_id, 'admin_user_id': user['id']})

        return jsonify({
            'organization': db.get_organization_by_id(organization_id),
            'admin_user': {k: v for k, v in user.items() if k != 'password_hash'},
            'message': f'Tenant provisioned with admin user "{admin_username}"',
        }), 201
    finally:
        db.close()


def reset_client_root_user(organization_id):
    """POST /api/admin/clients/<id>/reset-root-user — Reset root admin credentials for a tenant."""
    data = request.get_json(silent=True) or {}
    new_username = str(data.get('new_username', '')).strip().lower() or None

    if new_username and len(new_username) < 3:
        return jsonify({'error': 'new_username must be at least 3 characters'}), 400

    db = Database(_admin_reason='admin_root_user_reset')
    try:
        org = db.get_organization_by_id(organization_id)
        if not org:
            return jsonify({'error': 'Tenant not found'}), 404

        # Find root admin user for this org
        cursor = db.conn.cursor(cursor_factory=RealDictCursor)
        cursor.execute("""
            SELECT id, username FROM users
            WHERE organization_id = %s AND role = 'admin'
            ORDER BY id LIMIT 1
        """, (organization_id,))
        root_user = cursor.fetchone()
        cursor.close()

        if not root_user:
            return jsonify({'error': 'No admin user found for this tenant'}), 404

        old_username = root_user['username']
        root_id = root_user['id']

        # Check username uniqueness if changing
        if new_username and new_username != old_username:
            existing = db.get_user_by_username(new_username)
            if existing:
                return jsonify({'error': f'Username "{new_username}" already exists'}), 409

        # Generate temp password
        temp_password = secrets.token_urlsafe(16)
        new_hash = bcrypt.hashpw(temp_password.encode('utf-8'), bcrypt.gensalt()).decode('utf-8')

        update_kwargs = {'password_hash': new_hash}
        if new_username and new_username != old_username:
            update_kwargs['username'] = new_username

        db.update_user(root_id, **update_kwargs)
        db.set_force_password_change(root_id, True)
        db.reset_failed_login(root_id)
        db.clear_password_reset_token(root_id)
        db.conn.commit()

        final_username = new_username if new_username else old_username

        # Audit log
        current_user = getattr(g, 'current_user', None)
        user_id = current_user.get('id') if current_user else None
        try:
            db.log_admin_audit(user_id, 'admin_root_user_reset',
                               target_organization_id=organization_id,
                               target_user_id=root_id,
                               details={
                                   'old_username': old_username,
                                   'new_username': final_username,
                                   'username_changed': new_username is not None and new_username != old_username,
                               },
                               ip_address=request.remote_addr)
        except Exception:
            try: db.conn.rollback()
            except Exception: pass
            pass

        try:
            _log(db, 'admin_root_user_reset',
                 f'Root user credentials reset for tenant "{org.get("name")}"',
                 {'organization_id': organization_id, 'old_username': old_username, 'new_username': final_username})
        except Exception:
            pass

        return jsonify({
            'user_id': root_id,
            'old_username': old_username,
            'username': final_username,
            'temp_password': temp_password,
            'message': f'Root user credentials reset. New username: {final_username}',
        })
    finally:
        db.close()


def get_user_organizations_handler():
    """GET /api/auth/organizations — Return organizations accessible to the current user."""
    user = getattr(g, 'current_user', None)
    if not user:
        return jsonify({'error': 'Authentication required'}), 401

    db = _db()
    try:
        if user.get('is_superadmin'):
            all_organizations = db.get_organizations()
            organizations = [
                {'id': t['id'], 'name': t['name'], 'slug': t['slug'], 'plan': t.get('plan', 'free')}
                for t in all_orgs if t.get('enabled', True)
            ]
        else:
            tid = user.get('organization_id')
            if tid:
                t = db.get_organization_by_id(tid)
                organizations = [{'id': t['id'], 'name': t['name'], 'slug': t['slug'], 'plan': t.get('plan', 'free')}] if t else []
            else:
                organizations = []
        return jsonify({'organizations': organizations})
    finally:
        db.close()


