# Phase 68: Real-Time Monitoring & Health
# ---------------------------------------------------------------------------

def health_check():
    """GET /api/health — Enhanced health check with DB, scheduler, system diagnostics."""
    from app.metrics import MetricsCollector
    checks = {}
    overall = 'healthy'

    # DB connectivity check
    try:
        db = _db()
        t0 = time.time()
        cursor = db.conn.cursor()
        cursor.execute("SELECT 1")
        cursor.fetchone()
        db_latency = round((time.time() - t0) * 1000, 1)
        cursor.close()
        db.close()
        checks['database'] = {'status': 'healthy', 'latency_ms': db_latency}
    except Exception as e:
        try: db.conn.rollback()
        except Exception: pass
        logger.error(f"Health check DB probe failed: {e}", exc_info=True)
        checks['database'] = {'status': 'unhealthy', 'error': 'Database connection failed'}
        overall = 'degraded'

    # Scheduler check
    try:
        from app.scheduler import scheduler as _sched, get_next_run_time
        sched_running = _sched is not None
        next_run = get_next_run_time()
        checks['scheduler'] = {
            'status': 'running' if sched_running else 'stopped',
            'next_run': next_run.isoformat() if next_run else None,
        }
        if not sched_running:
            overall = 'degraded'
    except Exception:
        checks['scheduler'] = {'status': 'unknown'}

    # System metrics
    checks['system'] = {
        'pid': os.getpid(),
        'uptime_seconds': round(time.time() - MetricsCollector.get().start_time),
    }
    try:
        import psutil
        proc = psutil.Process()
        checks['system']['memory_mb'] = round(proc.memory_info().rss / 1024 / 1024, 1)
        checks['system']['cpu_percent'] = proc.cpu_percent()
    except ImportError:
        pass

    # Connection pool
    from app.database import _PoolManager
    checks['connection_pool'] = _PoolManager.stats()

    # External API reachability
    external_apis = {}
    import requests as _req
    for name, url in [
        ('microsoft_graph', 'https://graph.microsoft.com/v1.0/$metadata'),
        ('azure_login', 'https://login.microsoftonline.com/common/v2.0/.well-known/openid-configuration'),
    ]:
        try:
            t0 = time.time()
            r = _req.get(url, timeout=5)
            latency = round((time.time() - t0) * 1000, 1)
            external_apis[name] = {
                'status': 'reachable' if r.status_code < 500 else 'degraded',
                'latency_ms': latency,
                'http_status': r.status_code,
            }
        except Exception:
            external_apis[name] = {'status': 'unreachable'}
            overall = 'degraded'
    checks['external_apis'] = external_apis

    # Encryption status
    from app.encryption import encryption_available
    checks['encryption'] = 'configured' if encryption_available() else 'not_configured'

    # Circuit breaker status
    try:
        from app.resilience import get_all_breaker_stats
        checks['circuit_breakers'] = get_all_breaker_stats()
    except Exception:
        pass

    return jsonify({
        'service': 'AuditGraph API',
        'status': overall,
        'timestamp': datetime.now(timezone.utc).isoformat(),
        'checks': checks,
    })


def health_live():
    """GET /health/live — Kubernetes liveness probe. Always returns 200."""
    return jsonify({
        'status': 'alive',
        'timestamp': datetime.now(timezone.utc).isoformat(),
    })


def health_ready():
    """GET /health/ready — Kubernetes readiness probe. Checks DB + scheduler.

    Returns 503 (not ready) during:
      - Database connectivity failure
      - Scheduler not running
      - Active schema migration (MIGRATION_IN_PROGRESS flag)
      - Startup not yet complete (_startup_complete flag)
    """
    checks = {}
    ready = True

    # Migration gate — return not_ready during migrations so the load
    # balancer stops routing traffic to this instance
    from app.database import Database as _DbClass
    if getattr(_DbClass, '_migration_in_progress', False):
        checks['migration'] = 'in_progress'
        ready = False
    else:
        checks['migration'] = 'idle'

    # Startup complete gate
    if not getattr(_DbClass, '_startup_complete', False):
        checks['startup'] = 'initializing'
        ready = False
    else:
        checks['startup'] = 'complete'

    # DB connectivity
    try:
        db = _db()
        cursor = db.conn.cursor()
        cursor.execute("SELECT 1")
        cursor.fetchone()
        cursor.close()
        db.close()
        checks['database'] = 'ok'
    except Exception:
        try: db.conn.rollback()
        except Exception: pass
        checks['database'] = 'failed'
        ready = False

    # Scheduler running
    try:
        from app.scheduler import scheduler as _sched
        sched_ok = _sched is not None
        checks['scheduler'] = 'ok' if sched_ok else 'stopped'
        if not sched_ok:
            ready = False
    except Exception:
        try: db.conn.rollback()
        except Exception: pass
        checks['scheduler'] = 'unknown'

    status_code = 200 if ready else 503
    return jsonify({
        'status': 'ready' if ready else 'not_ready',
        'timestamp': datetime.now(timezone.utc).isoformat(),
        'checks': checks,
    }), status_code


