import re as _re

_ARM_SUB_RE = _re.compile(r'^/subscriptions/([^/]+)', _re.IGNORECASE)


def _extract_subscription_id(resource_id: str) -> str:
    """Extract the Azure subscription ID from an ARM resource_id path.

    ARM paths follow the pattern:
        /subscriptions/{subId}/resourceGroups/{rg}/providers/...
    Returns the subscription UUID, or empty string if not parseable.
    """
    m = _ARM_SUB_RE.match(resource_id or '')
    return m.group(1) if m else ''


def _build_federated_mapping(row: dict) -> dict:
    """Convert a credentials-table row into the FederatedMapping shape expected
    by the frontend (FederatedMappingsPanel.tsx).

    Uses the canonical classifier from AzureDiscoveryEngine to determine
    workload type, then builds the frontend-compatible evidence dict.
    """
    from app.engines.discovery.azure_discovery import AzureDiscoveryEngine

    issuer = row.get('issuer') or ''
    subject = row.get('subject') or ''
    cls = AzureDiscoveryEngine._classify_federated_credential(issuer, subject)
    wtype = cls['federated_workload_type']

    # ── type-specific evidence ──
    _TYPE_TO_RESOURCE = {
        'github_actions': 'FederatedGitHub',
        'aks_workload': 'FederatedAKS',
        'external_federation': 'FederatedExternal',
    }
    _TYPE_TO_CONFIDENCE = {
        'github_actions': 95,
        'aks_workload': 90,
        'external_federation': 80,
    }

    if wtype == 'github_actions':
        org, repo, branch, env = '', '', None, None
        if subject.startswith('repo:'):
            parts = subject[5:]
            colon_idx = parts.find(':')
            org_repo = parts[:colon_idx] if colon_idx > 0 else parts
            remainder = parts[colon_idx + 1:] if colon_idx > 0 else ''
            slash = org_repo.find('/')
            org = org_repo[:slash] if slash > 0 else org_repo
            repo = org_repo[slash + 1:] if slash > 0 else ''
            if remainder.startswith('ref:'):
                branch = remainder[4:]
            elif remainder.startswith('environment:'):
                env = remainder[12:]
        evidence = {'org': org, 'repo': repo, 'branch': branch, 'environment': env}
        resource_name = f'{org}/{repo}' if repo else org or issuer
    elif wtype == 'aks_workload':
        namespace, sa = '', ''
        if 'system:serviceaccount:' in subject:
            sa_parts = subject.split('system:serviceaccount:')[-1].split(':')
            namespace = sa_parts[0] if len(sa_parts) > 0 else ''
            sa = sa_parts[1] if len(sa_parts) > 1 else ''
        evidence = {'namespace': namespace, 'serviceAccount': sa}
        resource_name = f'{namespace}/{sa}' if sa else subject
    else:
        evidence = {'issuer': issuer, 'subject': subject}
        resource_name = row.get('display_name') or issuer

    return {
        'resource_type': _TYPE_TO_RESOURCE.get(wtype, 'FederatedExternal'),
        'resource_name': resource_name,
        'binding_method': 'FederatedCredential',
        'confidence_score': _TYPE_TO_CONFIDENCE.get(wtype, 80),
        'binding_evidence': evidence,
    }


def get_identity_lineage(identity_id):
    """GET /api/identities/<identity_id>/lineage — Unified lineage endpoint.

    Single source of truth for ALL identity lineage data.
    Used by LineageTab, LineageDetailPanel, and any future consumer.
    Data sourced from: identities table, identity_lineage_bindings,
    credentials (federated), role_assignments.
    """
    db = _db()
    try:
        organization_id = _org_id()
        cursor = db.conn.cursor(cursor_factory=RealDictCursor)
        run_ids = _latest_run_ids(cursor, organization_id, _connection_id())
        if not run_ids:
            cursor.close()
            return jsonify({'error': 'No discovery run found'}), 404

        cursor.execute("""
            SELECT id, identity_id, display_name, identity_category, object_id,
                   app_id, created_datetime, owner_count,
                   COALESCE(cloud, 'azure') AS cloud,
                   last_sign_in,
                   app_registration_object_id, app_registration_name, is_external_app,
                   app_reg_publisher_domain, app_reg_sign_in_audience,
                   app_reg_owner_display_name, app_reg_owner_id,
                   app_reg_reply_url_hostnames, app_reg_likely_service,
                   app_reg_likely_service_type, app_reg_identifier_uris,
                   app_reg_notes, app_reg_required_apis,
                   workload_type, workload_confidence, role_pattern_matched, workload_risk_flags,
                   signin_pattern, last_delegated_signin, last_noninteractive_signin,
                   days_since_last_signin,
                   verdict_confidence, verdict_score,
                   workload_origin, workload_origin_source,
                   recommended_action, verdict_action_text,
                   verdict_signals, verdict_risk_summary,
                   is_discovery_connector,
                   federated_workload_type, federated_workload_name,
                   dependency_impact, dependency_impact_resources,
                   lineage_signals, lineage_narrative,
                   observed_last_used,
                   api_usage_pattern, oauth2_resource_apis,
                   app_reg_required_permission_ids, app_reg_high_risk_manifest_perms,
                   audit_created_by, audit_creation_method, audit_creation_date,
                   audit_recent_modifications, audit_modification_count_90d,
                   signin_ips, signin_resources_accessed, signin_locations,
                   signin_client_apps, signin_failure_count_30d,
                   signin_success_count_30d, signin_total_events_30d,
                   owned_objects, created_objects,
                   owned_object_count, created_object_count,
                   is_platform_spn, platform_spn_evidence
            FROM identities
            WHERE discovery_run_id = ANY(%s) AND identity_id = %s
        """, (run_ids, identity_id))
        identity = cursor.fetchone()
        if not identity:
            cursor.close()
            return jsonify({'error': 'Identity not found'}), 404

        db_id = identity['id']

        # ── Role assignments ──────────────────────────────────────────
        role_assignments = []
        try:
            cursor.execute("SAVEPOINT lin_roles")
            cursor.execute("""
                SELECT role_name, scope, scope_type, resource_type, resource_name
                FROM role_assignments WHERE identity_db_id = %s ORDER BY role_name
            """, (db_id,))
            role_assignments = [dict(r) for r in cursor.fetchall()]
            cursor.execute("RELEASE SAVEPOINT lin_roles")
        except Exception:
            try: cursor.connection.rollback()
            except Exception: pass
            try:
                cursor.execute("ROLLBACK TO SAVEPOINT lin_roles")
            except Exception:
                try: cursor.connection.rollback()
                except Exception: pass
                pass

        # Active role count: excludes read-only roles (Reader/Viewer)
        # which don't indicate meaningful access for orphan classification.
        active_role_count = sum(
            1 for r in role_assignments
            if not any(ro in (r.get('role_name') or '').lower() for ro in ('reader', 'viewer'))
        )

        # ── Enrichment tier ───────────────────────────────────────────
        # Tiers: STATIC < ENRICHED < FULL (P2_AUDIT stays separate for P2 license)
        enrichment_tier = 'STATIC'
        has_static_intel = (
            identity.get('audit_created_by')
            or identity.get('api_usage_pattern')
            or identity.get('owned_object_count', 0) > 0
            or identity.get('signin_ips')
            or identity.get('is_platform_spn')
        )
        try:
            cursor.execute("SAVEPOINT lin_p2")
            cursor.execute("""
                SELECT 1 FROM workload_signin_events
                WHERE identity_db_id = %s LIMIT 1
            """, (db_id,))
            has_p2 = cursor.fetchone() is not None
            cursor.execute("RELEASE SAVEPOINT lin_p2")
            if has_p2:
                enrichment_tier = 'P2_AUDIT'
            elif ((identity.get('signin_pattern') and identity.get('signin_pattern') not in ('never_used', 'unknown'))
                  or identity.get('last_sign_in')
                  or identity.get('signin_total_events_30d')):
                enrichment_tier = 'FULL'
            elif has_static_intel:
                enrichment_tier = 'ENRICHED'
        except Exception:
            try: cursor.connection.rollback()
            except Exception: pass
            try:
                cursor.execute("ROLLBACK TO SAVEPOINT lin_p2")
            except Exception:
                try: cursor.connection.rollback()
                except Exception: pass
                pass
            if ((identity.get('signin_pattern') and identity.get('signin_pattern') not in ('never_used', 'unknown'))
                    or identity.get('last_sign_in')
                    or identity.get('signin_total_events_30d')):
                enrichment_tier = 'FULL'
            elif has_static_intel:
                enrichment_tier = 'ENRICHED'

        # ── Resource bindings (split ARM vs managed identity) ─────────
        arm_associations = []
        managed_identity_bindings = []
        try:
            cursor.execute("SAVEPOINT lin_rb")
            cursor.execute("""
                SELECT resource_id, resource_type, resource_name,
                       resource_group, subscription_id, region,
                       binding_method, confidence_score,
                       binding_evidence, last_verified_at
                FROM identity_lineage_bindings
                WHERE spn_id = %s
                ORDER BY confidence_score DESC
            """, (db_id,))
            for row in cursor.fetchall():
                ev = row.get('binding_evidence')
                if isinstance(ev, str):
                    try:
                        ev = json.loads(ev)
                    except Exception:
                        try: cursor.connection.rollback()
                        except Exception: pass
                        ev = {}
                binding = {
                    'resource_id': row['resource_id'],
                    'resource_type': row['resource_type'],
                    'resource_name': row.get('resource_name') or '',
                    'resource_group': row.get('resource_group') or '',
                    'subscription_id': row.get('subscription_id') or '',
                    'region': row.get('region') or '',
                    'binding_method': row.get('binding_method') or '',
                    'confidence_score': row.get('confidence_score') or 0,
                    'binding_evidence': ev if isinstance(ev, dict) else {},
                    'last_verified_at': row['last_verified_at'].isoformat() if row.get('last_verified_at') and hasattr(row['last_verified_at'], 'isoformat') else row.get('last_verified_at'),
                }
                method = (binding['binding_method'] or '').lower()
                if 'managedidentity' in method:
                    managed_identity_bindings.append(binding)
                else:
                    arm_associations.append(binding)
            cursor.execute("RELEASE SAVEPOINT lin_rb")
        except Exception:
            try: cursor.connection.rollback()
            except Exception: pass
            try:
                cursor.execute("ROLLBACK TO SAVEPOINT lin_rb")
            except Exception:
                try: cursor.connection.rollback()
                except Exception: pass
                pass

        # ── Federated credentials ─────────────────────────────────────
        federated_credentials = []
        try:
            cursor.execute("SAVEPOINT lin_fed")
            cursor.execute("""
                SELECT key_id, display_name, issuer, subject
                FROM credentials
                WHERE identity_db_id = %s AND credential_type = 'federated'
                ORDER BY display_name
            """, (db_id,))
            for row in cursor.fetchall():
                federated_credentials.append(
                    _build_federated_mapping(row)
                )
            cursor.execute("RELEASE SAVEPOINT lin_fed")
        except Exception:
            try: cursor.connection.rollback()
            except Exception: pass
            try:
                cursor.execute("ROLLBACK TO SAVEPOINT lin_fed")
            except Exception:
                try: cursor.connection.rollback()
                except Exception: pass
                pass

        # ── Dependency impact ─────────────────────────────────────────
        dep_impact_raw = identity.get('dependency_impact') or 'none_detected'
        dep_resources_raw = identity.get('dependency_impact_resources')
        if isinstance(dep_resources_raw, str):
            try:
                dep_resources_raw = json.loads(dep_resources_raw)
            except Exception:
                try: cursor.connection.rollback()
                except Exception: pass
                dep_resources_raw = []
        dep_resources = dep_resources_raw if isinstance(dep_resources_raw, list) else []

        if dep_impact_raw == 'high':
            high_names = [r.get('resource_name', '?') for r in dep_resources if r.get('impact_level') == 'high']
            impact_stmt = 'If deleted, this will impact:\n' + '\n'.join(
                f'  - {n}' for n in high_names[:5]
            )
            remaining = len(dep_resources) - len(high_names[:5])
            if remaining > 0:
                impact_stmt += f'\n  + {remaining} more resource(s)'
        elif dep_impact_raw == 'medium':
            impact_stmt = f'If deleted, {len(dep_resources)} resource(s) may be affected.'
        elif dep_resources:
            impact_stmt = f'{len(dep_resources)} low-impact resource(s) bound.'
        else:
            impact_stmt = 'No direct resource bindings detected.'

        # ── Verdict signals ───────────────────────────────────────────
        signals_raw = identity.get('verdict_signals')
        if isinstance(signals_raw, str):
            try:
                signals_raw = json.loads(signals_raw)
            except Exception:
                signals_raw = []
        signals = signals_raw if isinstance(signals_raw, list) else []

        risk_summary_raw = identity.get('verdict_risk_summary')
        if isinstance(risk_summary_raw, str):
            try:
                risk_summary_raw = json.loads(risk_summary_raw)
            except Exception:
                risk_summary_raw = []
        risk_summary = risk_summary_raw if isinstance(risk_summary_raw, list) else []

        # ── Sign-in data ──────────────────────────────────────────────
        sign_in = None
        sp = identity.get('signin_pattern')
        observed_raw = identity.get('observed_last_used')
        observed_iso = observed_raw.isoformat() if observed_raw and hasattr(observed_raw, 'isoformat') else observed_raw

        if sp or identity.get('last_sign_in') or identity.get('days_since_last_signin') is not None:
            sign_in = {
                'pattern': sp or 'never_used',
                'dormancy_days': identity.get('days_since_last_signin') if identity.get('days_since_last_signin') is not None else -1,
                'last_sign_in': identity['last_sign_in'].isoformat() if identity.get('last_sign_in') and hasattr(identity['last_sign_in'], 'isoformat') else identity.get('last_sign_in'),
                'last_delegated': identity['last_delegated_signin'].isoformat() if identity.get('last_delegated_signin') and hasattr(identity['last_delegated_signin'], 'isoformat') else identity.get('last_delegated_signin'),
                'last_noninteractive': identity['last_noninteractive_signin'].isoformat() if identity.get('last_noninteractive_signin') and hasattr(identity['last_noninteractive_signin'], 'isoformat') else identity.get('last_noninteractive_signin'),
                'observed_last_used': observed_iso,
            }

        # ── Effective last used: MAX(observed, Azure sign-in) ────────
        from datetime import datetime as _dt
        def _try_parse(v):
            if not v:
                return None
            if hasattr(v, 'timestamp'):
                return v
            try:
                return _dt.fromisoformat(str(v).replace('Z', '+00:00').replace('+00:00', ''))
            except (ValueError, TypeError):
                return None

        eff_candidates = [
            (_try_parse(observed_raw), 'auditgraph'),
            (_try_parse(identity.get('last_noninteractive_signin')), 'azure_signin'),
            (_try_parse(identity.get('last_sign_in')), 'azure_signin'),
        ]
        eff_last_used = None
        eff_source = None
        for dt, src in eff_candidates:
            if dt and (eff_last_used is None or dt > eff_last_used):
                eff_last_used = dt
                eff_source = src

        # Federated inference: infer usage from created_datetime when no sign-in data
        if identity.get('federated_workload_type') and eff_last_used is None:
            created_dt = _try_parse(identity.get('created_datetime'))
            if created_dt:
                eff_last_used = created_dt
                eff_source = 'inferred_federated'

        # ── App registration ──────────────────────────────────────────
        app_registration = None
        if identity.get('app_registration_name') or identity.get('app_registration_object_id'):
            owners = []
            if identity.get('app_reg_owner_display_name'):
                owners.append({
                    'display_name': identity['app_reg_owner_display_name'],
                    'id': identity.get('app_reg_owner_id', ''),
                })
            hostnames = identity.get('app_reg_reply_url_hostnames')
            inferred_urls = hostnames if isinstance(hostnames, list) else (
                [hostnames] if hostnames else []
            )
            app_registration = {
                'object_id': identity.get('app_registration_object_id'),
                'display_name': identity.get('app_registration_name') or identity.get('display_name', ''),
                'is_external': identity.get('is_external_app', False),
                'publisher_domain': identity.get('app_reg_publisher_domain'),
                'sign_in_audience': identity.get('app_reg_sign_in_audience'),
                'owners': owners,
                'likely_service': identity.get('app_reg_likely_service'),
                'reply_url_hostnames': inferred_urls,
                'identifier_uris': identity.get('app_reg_identifier_uris'),
                'notes': identity.get('app_reg_notes') or '',
                'required_apis': identity.get('app_reg_required_apis'),
                'created_at': identity.get('created_datetime'),
            }

        # ── Role topology ─────────────────────────────────────────────
        role_topology = None
        wt = identity.get('workload_type')
        if wt and wt != 'unknown':
            role_topology = {
                'workload_type': wt,
                'workload_confidence': identity.get('workload_confidence') or 0,
                'role_pattern_matched': identity.get('role_pattern_matched'),
                'role_assignments': [
                    {'role_name': r['role_name'], 'scope': r['scope'],
                     'scope_type': r.get('scope_type', ''), 'resource_type': r.get('resource_type', '')}
                    for r in role_assignments
                ],
            }

        # ── Orphan status mapping ─────────────────────────────────────
        _VERDICT_TO_ORPHAN = {
            'ORPHANED': 'SAFE_TO_RETIRE',
            'UNUSED': 'SAFE_TO_RETIRE',
            'AT_RISK': 'CAUTION',
            'STALE': 'CAUTION',
            'NEEDS_REVIEW': 'UNKNOWN',
            'HEALTHY': 'NOT_ORPHANED',
        }
        rec_action = (identity.get('recommended_action') or '').upper()
        orphan_badge = _VERDICT_TO_ORPHAN.get(rec_action, 'UNKNOWN')
        if orphan_badge == 'SAFE_TO_RETIRE' and active_role_count > 0:
            orphan_badge = 'CAUTION'

        # ── Human-readable lineage_signals (enriched with ROLE) ─────
        lin_signals_raw = identity.get('lineage_signals')
        if isinstance(lin_signals_raw, str):
            try:
                lin_signals_raw = json.loads(lin_signals_raw)
            except Exception:
                lin_signals_raw = []
        lineage_signals = lin_signals_raw if isinstance(lin_signals_raw, list) else []

        # Add ROLE signal from actual role_assignments (not available during discovery verdict)
        if role_assignments:
            top_roles = role_assignments[:3]
            role_summaries = []
            for r in top_roles:
                rn = r.get('role_name', 'Unknown Role')
                rt = r.get('resource_type') or r.get('scope_type', '')
                rname = r.get('resource_name', '')
                if rname:
                    role_summaries.append(f'{rn} on {rname}')
                elif rt:
                    role_summaries.append(f'{rn} ({rt})')
                else:
                    role_summaries.append(rn)
            extra = len(role_assignments) - len(top_roles)
            value = '; '.join(role_summaries)
            if extra > 0:
                value += f' +{extra} more'
            lineage_signals.append({
                'type': 'ROLE',
                'label': 'Roles',
                'value': value,
                'confidence': 'medium' if len(role_assignments) > 0 else 'low',
            })

        # Add warning badges
        lineage_warnings = []
        days_since_raw = identity.get('days_since_last_signin')
        if days_since_raw is not None and days_since_raw > 365:
            lineage_warnings.append('No recent usage')
        if not identity.get('app_reg_owner_display_name') and identity.get('app_registration_object_id'):
            lineage_warnings.append('Owner inactive')
        if dep_impact_raw in ('high', 'medium'):
            lineage_warnings.append('Still has active access')

        # Narrative (from DB, enriched with role context)
        lineage_narrative_raw = identity.get('lineage_narrative') or ''
        # Append role detail if roles exist and narrative doesn't mention them
        if role_assignments and 'role' not in lineage_narrative_raw.lower():
            top = role_assignments[0]
            rn = top.get('role_name', 'Unknown Role')
            rname = top.get('resource_name', '')
            if rname:
                lineage_narrative_raw += f' It has active {rn} access on {rname}.'
            else:
                lineage_narrative_raw += f' It has active {rn} access.'

        # ── Static Intelligence (M1-M5) ─────────────────────────────
        def _parse_jsonb(val):
            if isinstance(val, str):
                try:
                    return json.loads(val)
                except Exception:
                    return None
            return val

        static_intelligence = {
            'oauth2_grants': {
                'api_usage_pattern': identity.get('api_usage_pattern'),
                'resource_apis': _parse_jsonb(identity.get('oauth2_resource_apis')),
            },
            'required_resource_access': {
                'permissions': _parse_jsonb(identity.get('app_reg_required_permission_ids')),
                'high_risk_manifest_permissions': _parse_jsonb(identity.get('app_reg_high_risk_manifest_perms')),
            },
            'audit_provenance': {
                'created_by': identity.get('audit_created_by'),
                'creation_method': identity.get('audit_creation_method'),
                'creation_date': identity['audit_creation_date'].isoformat() if identity.get('audit_creation_date') and hasattr(identity['audit_creation_date'], 'isoformat') else identity.get('audit_creation_date'),
                'recent_modifications': _parse_jsonb(identity.get('audit_recent_modifications')),
                'modification_count_90d': identity.get('audit_modification_count_90d'),
            },
            'signin_intelligence': {
                'ips': _parse_jsonb(identity.get('signin_ips')),
                'resources_accessed': _parse_jsonb(identity.get('signin_resources_accessed')),
                'locations': _parse_jsonb(identity.get('signin_locations')),
                'client_apps': _parse_jsonb(identity.get('signin_client_apps')),
                'failure_count_30d': identity.get('signin_failure_count_30d'),
                'success_count_30d': identity.get('signin_success_count_30d'),
                'total_events_30d': identity.get('signin_total_events_30d'),
            },
            'owned_objects': {
                'owned': _parse_jsonb(identity.get('owned_objects')),
                'created': _parse_jsonb(identity.get('created_objects')),
                'owned_count': identity.get('owned_object_count', 0),
                'created_count': identity.get('created_object_count', 0),
                'is_platform_spn': identity.get('is_platform_spn', False),
                'platform_evidence': _parse_jsonb(identity.get('platform_spn_evidence')),
            },
        }

        # ── Auth history (last 5 sign-in events) ──
        auth_history = []
        try:
            cursor.execute("SAVEPOINT lin_auth_hist")
            cursor.execute("""
                SELECT created_datetime, ip_address,
                       CONCAT_WS(', ', location_city, location_country) AS location,
                       app_display_name
                FROM workload_signin_events
                WHERE identity_db_id = %s AND status = 'success'
                ORDER BY created_datetime DESC
                LIMIT 5
            """, (db_id,))
            for r in cursor.fetchall():
                auth_history.append({
                    'signed_in_at': r['created_datetime'].isoformat() if r['created_datetime'] else None,
                    'ip_address': r['ip_address'],
                    'location': r['location'] if r['location'] and r['location'].strip(', ') else None,
                    'app_used': r['app_display_name'],
                })
            cursor.execute("RELEASE SAVEPOINT lin_auth_hist")
        except Exception:
            try: cursor.connection.rollback()
            except Exception: pass
            try:
                cursor.execute("ROLLBACK TO SAVEPOINT lin_auth_hist")
            except Exception:
                try: cursor.connection.rollback()
                except Exception: pass
                pass

        auth_source = 'static_analysis_only'
        if auth_history:
            auth_source = 'entra_signin_log'
        elif identity.get('last_sign_in'):
            auth_source = 'aad_audit'

        # ── Signal conflict detection ──────────────────────────────
        signal_conflicts = []

        # 1. unused_with_active_deps: verdict=UNUSED but deps exist
        if rec_action == 'UNUSED' and len(dep_resources) > 0:
            signal_conflicts.append({
                'conflict_type': 'unused_with_active_deps',
                'description': 'Verdict is UNUSED but active dependency bindings exist — deletion could break workloads.',
                'severity': 'critical',
                'resolution': 'Escalated from UNUSED to AT_RISK due to confirmed managed identity binding',
            })
            rec_action = 'AT_RISK'

        # 2. orphaned_with_recent_auth: verdict=ORPHANED but recent sign-in
        if rec_action == 'ORPHANED' and auth_history:
            from datetime import datetime as _dt_conflict, timedelta
            try:
                last_auth_str = auth_history[0].get('signed_in_at')
                if last_auth_str:
                    last_auth_dt = _dt_conflict.fromisoformat(last_auth_str.replace('Z', '+00:00').replace('+00:00', ''))
                    if (_dt_conflict.utcnow() - last_auth_dt) < timedelta(days=30):
                        signal_conflicts.append({
                            'conflict_type': 'orphaned_with_recent_auth',
                            'description': 'Verdict is ORPHANED but authentication detected within last 30 days.',
                            'severity': 'critical',
                            'resolution': 'Recent authentication detected — may be legitimately used without owner assignment',
                        })
                        rec_action = 'AT_RISK'
            except Exception:
                pass

        # 3. healthy_with_no_workload: verdict=HEALTHY but no workload origin
        wo_origin = identity.get('workload_origin') or ''
        if rec_action == 'HEALTHY' and (not wo_origin or wo_origin == 'Unknown'):
            signal_conflicts.append({
                'conflict_type': 'healthy_with_no_workload',
                'description': 'Verdict is HEALTHY but workload origin could not be confirmed.',
                'severity': 'warning',
                'resolution': 'Authentication confirmed but workload origin unverified — manual review recommended',
            })

        # 4. stale_with_sensitive_scope: verdict=STALE but privileged roles
        _PRIV_ROLES = {'owner', 'contributor', 'user access administrator'}
        if rec_action == 'STALE':
            import re as _re_conflict
            for ra in role_assignments:
                rn = (ra.get('role_name') or '').lower()
                scope = ra.get('scope') or ''
                is_sub_scope = bool(_re_conflict.match(r'^/subscriptions/[^/]+$', scope)) or scope == '/'
                if rn in _PRIV_ROLES and is_sub_scope:
                    signal_conflicts.append({
                        'conflict_type': 'stale_with_sensitive_scope',
                        'description': f'Verdict is STALE but identity holds {ra.get("role_name")} at subscription scope.',
                        'severity': 'critical',
                        'resolution': 'Stale identity with privileged scope — risk profile elevated',
                    })
                    rec_action = 'AT_RISK'
                    break

        cursor.close()
        return jsonify({
            # Identity context
            'identity_id': identity['identity_id'],
            'display_name': identity['display_name'],
            'identity_category': identity['identity_category'],
            'cloud': identity['cloud'],

            # Workload origin
            'workload_origin': {
                'origin': identity.get('workload_origin') or 'Unknown',
                'source': identity.get('workload_origin_source') or 'none',
                'workload_type': identity.get('workload_type'),
                'workload_confidence': identity.get('workload_confidence') or 0,
                'is_discovery_connector': identity.get('is_discovery_connector', False),
            },

            # Confidence
            'confidence': {
                'level': identity.get('verdict_confidence') or 'low',
                'score': identity.get('verdict_score') or 0,
                'enrichment_tier': enrichment_tier,
                'signals': signals,
            },

            # ARM resource associations (appId/clientId binding)
            'arm_associations': arm_associations,

            # Managed identity bindings (system/user-assigned)
            'managed_identity_bindings': managed_identity_bindings,

            # Federated credentials (GitHub Actions, AKS OIDC, etc.)
            'federated_credentials': federated_credentials,

            # Dependency impact — what breaks if deleted
            'dependency_impact': {
                'level': dep_impact_raw,
                'resources': dep_resources,
                'statement': impact_stmt,
                'total_bound': len(dep_resources),
            },

            # Recommended action
            'recommended_action': {
                'action': rec_action or 'NEEDS_REVIEW',
                'action_text': identity.get('verdict_action_text') or '',
                'orphan_status': orphan_badge,
                'risk_summary': risk_summary,
                'active_role_count': active_role_count,
            },

            # Human-readable lineage (executive display)
            'lineage_signals': lineage_signals,
            'lineage_narrative': lineage_narrative_raw,
            'lineage_warnings': lineage_warnings,

            # Effective last used (MAX of observed + Azure sign-in)
            'effective_last_used': eff_last_used.isoformat() if eff_last_used else None,
            'effective_last_used_source': eff_source,

            # Sign-in authentication provenance
            'auth_history': auth_history,
            'last_signin_at': auth_history[0]['signed_in_at'] if auth_history else None,
            'last_signin_ip': auth_history[0]['ip_address'] if auth_history else None,
            'auth_source': auth_source,

            # Signal conflicts
            'signal_conflicts': signal_conflicts,

            # Supplementary data (for panels that need it)
            'role_topology': role_topology,
            'app_registration': app_registration,
            'sign_in': sign_in,

            # Static Intelligence (M1-M5)
            'staticIntelligence': static_intelligence,
        })
    except Exception as e:
        logger.error(f"Identity lineage failed: {e}", exc_info=True)
        return jsonify({'error': 'Internal server error'}), 500
    finally:
        db.close()


# Backward-compatible alias — old SPN lineage endpoint calls unified handler
get_spn_lineage = get_identity_lineage


# ──────────────────────────────────────────────────────────
# App Registration Audit (Phase 74)
# ──────────────────────────────────────────────────────────

def get_app_reg_stats():
    """GET /api/app-registrations/stats — summary cards."""
    db = _db()
    try:
        db._ensure_app_registrations_table()
        organization_id = _org_id()
        cursor = db.conn.cursor(cursor_factory=RealDictCursor)
        run_ids = _latest_run_ids(cursor, organization_id, _connection_id())
        if not run_ids:
            cursor.close()
            return jsonify({
                'total': 0, 'by_risk': {}, 'ownerless': 0, 'stale': 0,
                'expired_credentials': 0, 'expiring_soon': 0,
                'multi_tenant': 0, 'third_party': 0, 'by_audience': {},
            })

        base = "FROM app_registrations ar WHERE ar.discovery_run_id = ANY(%s)"
        params = [run_ids]

        cursor.execute(f"SELECT COUNT(*) as total {base}", params)
        total = cursor.fetchone()['total']

        # By risk
        cursor.execute(f"""
            SELECT COALESCE(ar.risk_level, 'info') as rl, COUNT(*) as c
            {base} GROUP BY rl
        """, params)
        by_risk = {r['rl']: r['c'] for r in cursor.fetchall()}

        # Ownerless
        cursor.execute(f"SELECT COUNT(*) as c {base} AND ar.owner_count = 0", params)
        ownerless = cursor.fetchone()['c']

        # Stale (has SPN but SPN is stale/never_used)
        cursor.execute(f"""
            SELECT COUNT(*) as c {base}
            AND ar.has_service_principal = true
            AND ar.spn_activity_status IN ('stale', 'never_used', 'inactive')
        """, params)
        stale = cursor.fetchone()['c']

        # Also count apps with no SPN at all as potentially stale
        cursor.execute(f"SELECT COUNT(*) as c {base} AND ar.has_service_principal = false", params)
        no_spn = cursor.fetchone()['c']

        # Credentials
        cursor.execute(f"""
            SELECT
                COUNT(*) FILTER (WHERE ar.has_expired_credential = true) as expired,
                COUNT(*) FILTER (WHERE ar.has_expiring_soon = true) as expiring_soon
            {base}
        """, params)
        cred_row = dict(cursor.fetchone())

        # Multi-org
        cursor.execute(f"""
            SELECT COUNT(*) as c {base}
            AND ar.sign_in_audience IN ('AzureADMultipleOrgs', 'AzureADandPersonalMicrosoftAccount')
        """, params)
        multi_org = cursor.fetchone()['c']

        # Third-party
        cursor.execute(f"SELECT COUNT(*) as c {base} AND ar.is_third_party = true", params)
        third_party = cursor.fetchone()['c']

        # By audience
        cursor.execute(f"""
            SELECT COALESCE(ar.sign_in_audience, 'Unknown') as aud, COUNT(*) as c
            {base} GROUP BY aud
        """, params)
        by_audience = {r['aud']: r['c'] for r in cursor.fetchall()}

        cursor.close()
        return jsonify({
            'total': total,
            'by_risk': by_risk,
            'ownerless': ownerless,
            'stale': stale,
            'no_spn': no_spn,
            'expired_credentials': cred_row['expired'],
            'expiring_soon': cred_row['expiring_soon'],
            'multi_tenant': multi_org,
            'third_party': third_party,
            'by_audience': by_audience,
        })
    except Exception as e:
        try: cursor.connection.rollback()
        except Exception: pass
        logger.error(f"App registration stats failed: {e}", exc_info=True)
        return jsonify({'error': 'Internal server error'}), 500
    finally:
        db.close()


def get_app_reg_list():
    """GET /api/app-registrations — paginated list with filters."""
    db = _db()
    try:
        db._ensure_app_registrations_table()
        organization_id = _org_id()
        cursor = db.conn.cursor(cursor_factory=RealDictCursor)
        run_ids = _latest_run_ids(cursor, organization_id, _connection_id())
        if not run_ids:
            cursor.close()
            return jsonify({'items': [], 'total': 0})

        limit = _safe_query_int('limit', 50, 200)
        offset = _safe_query_int('offset', 0)
        risk_filter = request.args.get('risk_level', '')
        cred_filter = request.args.get('credential_status', '')
        audience_filter = request.args.get('audience', '')
        search = request.args.get('search', '').strip()
        sort_field = request.args.get('sort', 'risk_score')
        sort_dir = request.args.get('dir', 'desc')

        where = ["ar.discovery_run_id = ANY(%s)"]
        params: list = [run_ids]

        where.append("ar.is_third_party = false")
        where.append("ar.app_owner_organization_id != ''")

        if risk_filter:
            where.append("ar.risk_level = %s")
            params.append(risk_filter)
        if cred_filter == 'expired':
            where.append("ar.has_expired_credential = true")
        elif cred_filter == 'expiring':
            where.append("ar.has_expiring_soon = true")
        elif cred_filter == 'healthy':
            where.append("ar.has_expired_credential = false AND ar.has_expiring_soon = false")
        if audience_filter:
            where.append("ar.sign_in_audience = %s")
            params.append(audience_filter)
        if search:
            where.append("ar.display_name ILIKE %s")
            params.append(f'%{search}%')

        where_sql = " AND ".join(where)

        ALLOWED_SORT = {
            'risk_score': 'ar.risk_score',
            'display_name': 'ar.display_name',
            'permission_count': 'ar.permission_count',
            'owner_count': 'ar.owner_count',
            'next_expiry': 'ar.next_expiry',
            'created_datetime': 'ar.created_datetime',
            'application_permission_count': 'ar.application_permission_count',
        }
        order_col = ALLOWED_SORT.get(sort_field, 'ar.risk_score')
        order_dir = 'ASC' if sort_dir.lower() == 'asc' else 'DESC'

        cursor.execute(f"SELECT COUNT(*) as total FROM app_registrations ar WHERE {where_sql}", params)
        total = cursor.fetchone()['total']

        cursor.execute(f"""
            SELECT ar.id, ar.app_id, ar.app_object_id, ar.display_name,
                   ar.risk_level, ar.risk_score,
                   ar.permission_count, ar.application_permission_count,
                   ar.delegated_permission_count, ar.high_risk_permissions,
                   ar.secret_count, ar.certificate_count,
                   ar.next_expiry, ar.has_expired_credential, ar.has_expiring_soon,
                   ar.owner_count, ar.primary_owner,
                   ar.sign_in_audience, ar.is_third_party,
                   ar.has_service_principal, ar.spn_activity_status,
                   ar.created_datetime
            FROM app_registrations ar
            WHERE {where_sql}
            ORDER BY {order_col} {order_dir} NULLS LAST
            LIMIT %s OFFSET %s
        """, params + [limit, offset])
        items = [dict(r) for r in cursor.fetchall()]

        # Serialize datetimes
        for item in items:
            for k in ('next_expiry', 'created_datetime'):
                if item.get(k) and hasattr(item[k], 'isoformat'):
                    item[k] = item[k].isoformat()

        cursor.close()
        return jsonify({'items': items, 'total': total})
    except Exception as e:
        try: cursor.connection.rollback()
        except Exception: pass
        logger.error(f"App registration list failed: {e}", exc_info=True)
        return jsonify({'error': 'Internal server error'}), 500
    finally:
        db.close()


def get_app_reg_detail(app_id):
    """GET /api/app-registrations/<app_id> — full detail."""
    db = _db()
    try:
        db._ensure_app_registrations_table()
        organization_id = _org_id()
        cursor = db.conn.cursor(cursor_factory=RealDictCursor)
        run_ids = _latest_run_ids(cursor, organization_id, _connection_id())
        if not run_ids:
            cursor.close()
            return jsonify({'error': 'No discovery run'}), 404

        cursor.execute("""
            SELECT * FROM app_registrations ar
            WHERE ar.discovery_run_id = ANY(%s) AND ar.app_id = %s
        """, (run_ids, app_id))
        row = cursor.fetchone()
        if not row:
            cursor.close()
            return jsonify({'error': 'App registration not found'}), 404

        data = dict(row)

        # Serialize datetimes
        for k in ('next_expiry', 'created_datetime', 'spn_last_sign_in', 'created_at'):
            if data.get(k) and hasattr(data[k], 'isoformat'):
                data[k] = data[k].isoformat()

        # Linked SPN info
        linked_spn = None
        if data.get('linked_spn_id'):
            cursor.execute("""
                SELECT id, identity_id, display_name, identity_category, risk_level, activity_status
                FROM identities WHERE id = %s
            """, (data['linked_spn_id'],))
            spn_row = cursor.fetchone()
            if spn_row:
                linked_spn = dict(spn_row)

        # Generate recommendations
        recommendations = []
        if data.get('owner_count', 0) == 0:
            recommendations.append({
                'priority': 'critical',
                'action': 'Assign an owner to this application',
                'reason': 'Ownerless apps have no accountability for credential rotation or access review.',
            })
        if data.get('has_expired_credential'):
            recommendations.append({
                'priority': 'high',
                'action': 'Remove or rotate expired credentials',
                'reason': 'Expired credentials indicate abandoned lifecycle management.',
            })
        if data.get('has_expiring_soon'):
            recommendations.append({
                'priority': 'high',
                'action': 'Rotate credentials before expiry',
                'reason': 'Credentials expiring soon may cause service disruption.',
            })
        if data.get('application_permission_count', 0) > 5:
            recommendations.append({
                'priority': 'high',
                'action': 'Review and reduce Application-level permissions',
                'reason': f'{data["application_permission_count"]} Application permissions is excessive — apply least-privilege.',
            })
        high_risk_perms = data.get('high_risk_permissions') or []
        if high_risk_perms:
            recommendations.append({
                'priority': 'critical',
                'action': 'Audit high-risk permissions',
                'reason': f'Dangerous permissions: {", ".join(high_risk_perms[:3])}',
            })
        audience = data.get('sign_in_audience', '')
        if audience in ('AzureADMultipleOrgs', 'AzureADandPersonalMicrosoftAccount'):
            recommendations.append({
                'priority': 'medium',
                'action': 'Restrict audience to single tenant if possible',
                'reason': 'Multi-tenant apps expand blast radius across organizations.',
            })
        if data.get('has_localhost_redirect'):
            recommendations.append({
                'priority': 'medium',
                'action': 'Remove localhost redirect URIs',
                'reason': 'Localhost URIs suggest dev/test configuration left in production.',
            })
        if data.get('has_http_redirect'):
            recommendations.append({
                'priority': 'medium',
                'action': 'Upgrade redirect URIs to HTTPS',
                'reason': 'Non-HTTPS redirect URIs expose tokens to interception.',
            })
        if not data.get('has_service_principal'):
            recommendations.append({
                'priority': 'info',
                'action': 'Verify if this app registration is still needed',
                'reason': 'No Service Principal means this app has never been consented or used.',
            })

        cursor.close()
        return jsonify({
            'app_registration': data,
            'linked_spn': linked_spn,
            'recommendations': recommendations,
        })
    except Exception as e:
        logger.error(f"App registration detail failed: {e}", exc_info=True)
        return jsonify({'error': 'Internal server error'}), 500
    finally:
        db.close()


def run_manual_cleanup():
    """Trigger a manual data cleanup using retention settings."""
    db = _db()
    try:
        settings = db.get_settings(organization_id=_org_id())
        results = {}

        discovery_days = int(settings.get('retention_discovery_days', '90'))
        drift_days = int(settings.get('retention_drift_days', '90'))
        activity_days = int(settings.get('retention_activity_days', '180'))
        anomalies_days = int(settings.get('retention_anomalies_days', '90'))
        soar_days = int(settings.get('retention_soar_days', '90'))
        notif_days = int(settings.get('retention_notifications_days', '90'))

        run_counts = db.cleanup_old_discovery_runs(days=discovery_days)
        results['discovery_runs'] = run_counts.get('discovery_runs', 0)
        results['risk_scores'] = run_counts.get('risk_scores', 0)
        results['drift_reports'] = db.cleanup_old_drift_reports(days=drift_days)
        results['activity_log'] = db.cleanup_old_activity_log(days=activity_days)
        results['anomalies'] = db.cleanup_old_anomalies(days=anomalies_days)
        results['soar_actions'] = db.cleanup_old_soar_actions(days=soar_days)
        results['notifications'] = db.cleanup_old_notifications(days=notif_days)

        total = sum(results.values())
        _log(db, 'data_cleanup', f'Manual cleanup: {total} records deleted', {
            'results': results,
            'retention_settings': {
                'discovery_days': discovery_days,
                'drift_days': drift_days,
                'activity_days': activity_days,
                'anomalies_days': anomalies_days,
                'soar_days': soar_days,
                'notifications_days': notif_days,
            }
        })

        return jsonify({
            'deleted': results,
            'total': total,
        })
    finally:
        db.close()


# ============================================================
# Phase 78: Tenant Logo Upload/Delete
# ============================================================

def upload_organization_logo(organization_id):
    """POST /api/organizations/<id>/logo — Upload organization logo (base64, max 500KB). Superadmin/poweradmin only."""
    data = request.get_json(silent=True) or {}
    logo_data = data.get('logo_data', '')
    content_type = str(data.get('content_type', '')).lower()

    if not logo_data:
        return jsonify({'error': 'logo_data is required (base64-encoded)'}), 400

    valid_types = {'image/png', 'image/jpeg', 'image/svg+xml'}
    if content_type not in valid_types:
        return jsonify({'error': f'Invalid content_type. Must be one of: {", ".join(valid_types)}'}), 400

    # Check size (base64 is ~33% larger than binary, so 500KB binary ≈ 667KB base64)
    import base64
    try:
        raw = base64.b64decode(logo_data)
    except Exception:
        return jsonify({'error': 'Invalid base64 data'}), 400

    if len(raw) > 500 * 1024:
        return jsonify({'error': 'Logo must be under 500KB'}), 400

    logo_url = f'data:{content_type};base64,{logo_data}'

    db = _db()
    try:
        org = db.get_organization_by_id(organization_id)
        if not org:
            return jsonify({'error': 'Tenant not found'}), 404

        cursor = db.conn.cursor()
        cursor.execute("UPDATE organizations SET logo_url = %s, updated_at = NOW() WHERE id = %s", (logo_url, organization_id))
        db._commit()
        cursor.close()

        _log(db, 'org_logo_uploaded', f'Logo uploaded for org "{org["name"]}"',
             {'organization_id': organization_id})

        return jsonify({'message': 'Logo uploaded', 'logo_url': logo_url})
    finally:
        db.close()


def delete_organization_logo(organization_id):
    """DELETE /api/organizations/<id>/logo — Remove organization logo. Superadmin/poweradmin only."""
    db = _db()
    try:
        org = db.get_organization_by_id(organization_id)
        if not org:
            return jsonify({'error': 'Tenant not found'}), 404

        cursor = db.conn.cursor()
        cursor.execute("UPDATE organizations SET logo_url = NULL, updated_at = NOW() WHERE id = %s", (organization_id,))
        db._commit()
        cursor.close()

        _log(db, 'org_logo_deleted', f'Logo removed for org "{org["name"]}"',
             {'organization_id': organization_id})

        return jsonify({'message': 'Logo removed'})
    finally:
        db.close()


