# Phase 78: Tier Limits
# ============================================================

TIER_LIMITS = {
    'free': {'max_identities': 500, 'max_subscriptions': 2, 'expires_days': None, 'can_upgrade': True, 'blocked_features': ['soar', 'api_keys', 'advanced_query', 'custom_risk_rules', 'ai_copilot', 'scheduled_reports', 'compliance_export', 'sso']},
    'trial': {'max_identities': None, 'max_subscriptions': None, 'expires_days': 30, 'can_upgrade': True, 'blocked_features': []},
    'pro': {'max_identities': None, 'max_subscriptions': None, 'expires_days': None, 'can_upgrade': False, 'blocked_features': []},
    'enterprise': {'max_identities': None, 'max_subscriptions': None, 'expires_days': None, 'can_upgrade': False, 'blocked_features': []},
}


def _check_tier_limits(db, organization_id):
    """Check if organization is within tier limits. Returns (ok, error_dict) tuple."""
    org = db.get_organization_by_id(organization_id)
    if not org:
        return True, None

    plan = org.get('plan', 'free')
    limits = TIER_LIMITS.get(plan, TIER_LIMITS['free'])

    # Check identity count limit
    if limits.get('max_identities'):
        cursor = db.conn.cursor()
        cursor.execute("""
            SELECT COUNT(*) FROM identities i
            JOIN discovery_runs dr ON dr.id = i.discovery_run_id
            WHERE dr.organization_id = %s AND i.discovery_run_id = (
                SELECT id FROM discovery_runs WHERE organization_id = %s ORDER BY id DESC LIMIT 1
            )
        """, (organization_id, organization_id))
        count = _scalar(cursor, 0)
        cursor.close()
        if count >= limits['max_identities']:
            return False, {
                'error': f'{plan.capitalize()} plan is limited to {limits["max_identities"]} identities. Current: {count}.',
                'upgrade_required': True,
                'current_plan': plan,
            }

    # Check trial expiry using trial_expires_at (set at signup: NOW() + 30 days)
    if plan == 'trial':
        trial_expires = org.get('trial_expires_at')
        if trial_expires:
            if isinstance(trial_expires, str):
                try:
                    trial_expires = datetime.fromisoformat(trial_expires.replace('Z', '+00:00'))
                except (ValueError, TypeError):
                    trial_expires = None
            if trial_expires:
                now = datetime.now(trial_expires.tzinfo if trial_expires.tzinfo else timezone.utc)
                if now > trial_expires:
                    return False, {
                        'error': 'Your 30-day trial has ended. Upgrade to Pro to continue.',
                        'upgrade_required': True,
                        'current_plan': plan,
                        'upgrade_url': '/subscriptions',
                    }

    return True, None


# ── Phase 79: AI Security Copilot ──────────────────────────────

def copilot_chat():
    """POST /api/copilot/chat — send a message to the AI copilot."""
    from app.ai.copilot_gateway import get_gateway
    gateway = get_gateway()

    data = request.get_json(silent=True) or {}
    message = data.get('message', '').strip()
    conversation_id = data.get('conversation_id')

    if not message:
        return jsonify({'error': 'Message is required'}), 400

    service, svc_err = gateway.check_available()
    if not service:
        return jsonify({
            'error': 'not_configured',
            'response': svc_err,
            'conversation_id': None,
            'suggestions': [],
        })

    user_id = _current_user_id()
    org_id = _org_id()
    db = _db()
    try:
        # Rate limit
        plan = _get_org_plan(db, org_id)
        allowed, rate_err = gateway.check_rate_limit(db, org_id, plan)
        if not allowed:
            return jsonify({'error': rate_err}), 429

        # Load or create conversation
        conv = None
        messages_history = []
        if conversation_id:
            conv = db.get_copilot_conversation(conversation_id, user_id)
            if conv:
                messages_history = conv.get('messages', [])

        message = gateway.truncate_prompt(message)

        try:
            response_text = service.ask(message, messages_history, db)
        except Exception as e:
            try: db.conn.rollback()
            except Exception: pass
            logger.error(f"AI copilot service error: {e}", exc_info=True)
            try:
                db._rollback()
            except Exception:
                try: db.conn.rollback()
                except Exception: pass
                pass
            return jsonify({'error': f'AI service error: {type(e).__name__}: {e}'}), 502

        # Save conversation
        messages_history.append({'role': 'user', 'content': message})
        messages_history.append({'role': 'assistant', 'content': response_text})

        if conv:
            db.update_copilot_conversation(conversation_id, user_id, messages_history)
        else:
            title = message[:60] + ('...' if len(message) > 60 else '')
            conv = db.create_copilot_conversation(user_id, org_id, title, messages_history)
            conversation_id = conv['id']

        suggestions = service.get_suggestions(db)
        gateway.log_usage(db, org_id, user_id, 'chat')
        _log_ai_audit(db, 'chat',
                      {'message': message},
                      response_text)

        return jsonify({
            'response': response_text,
            'conversation_id': conversation_id,
            'suggestions': suggestions,
        })
    finally:
        db.close()


