def get_identity_effective_access(identity_id: str):
    """GET /api/identities/<id>/effective-access — resolve actual permissions per role."""
    db = _db()
    cursor = db.conn.cursor()

    try:
        run_ids = _latest_run_ids(cursor, _org_id(), _connection_id())
        if not run_ids:
            return jsonify({'error': 'Identity not found'}), 404

        cursor.execute(
            "SELECT id, display_name FROM identities WHERE identity_id = %s AND discovery_run_id = ANY(%s) ORDER BY discovery_run_id DESC LIMIT 1",
            (identity_id, run_ids))
        id_row = cursor.fetchone()
        if not id_row:
            return jsonify({'error': 'Identity not found'}), 404

        db_id = id_row[0]
        display_name = id_row[1]

        # Fetch Azure RBAC assignments (role_assignments has no discovery_run_id — scoped via identity_db_id)
        cursor.execute("""
            SELECT role_name, scope, scope_type, resource_type, resource_name,
                   role_type, risk_level, created_on, usage_status, why_critical
            FROM role_assignments
            WHERE identity_db_id = %s
            ORDER BY CASE WHEN risk_level = 'critical' THEN 0 WHEN risk_level = 'high' THEN 1
                          WHEN risk_level = 'medium' THEN 2 ELSE 3 END
        """, (db_id,))
        rbac_rows = cursor.fetchall()

        cursor.execute("""
            SELECT role_name, directory_scope, role_type, risk_level, assigned_on, usage_status, why_critical
            FROM entra_role_assignments
            WHERE identity_db_id = %s
            ORDER BY CASE WHEN risk_level = 'critical' THEN 0 WHEN risk_level = 'high' THEN 1
                          WHEN risk_level = 'medium' THEN 2 ELSE 3 END
        """, (db_id,))
        entra_rows = cursor.fetchall()

        effective_access = []
        admin_scopes = 0
        write_scopes = 0
        read_scopes = 0
        total_permissions = 0
        categories_seen = set()

        for r in rbac_rows:
            role_name = r[0] or 'Unknown'
            role_info = AZURE_ROLE_PERMISSIONS.get(role_name, {
                'access_level': 'Write', 'category': 'Custom',
                'permissions': [f'Custom role: {role_name}'],
            })
            access_level = role_info['access_level']
            perms = role_info['permissions']

            if access_level == 'Admin':
                admin_scopes += 1
            elif access_level == 'Write':
                write_scopes += 1
            else:
                read_scopes += 1
            total_permissions += len(perms)
            categories_seen.add(role_info['category'])

            scope_str = r[1] or '/'
            scope_display = scope_str
            if r[4]:
                scope_display = r[4]
            elif '/subscriptions/' in scope_str:
                parts = scope_str.split('/')
                if 'resourceGroups' in parts:
                    rg_idx = parts.index('resourceGroups')
                    scope_display = parts[rg_idx + 1] if rg_idx + 1 < len(parts) else scope_str
                else:
                    scope_display = parts[-1] if len(parts) > 2 else scope_str

            effective_access.append({
                'role_name': role_name,
                'role_source': 'azure_rbac',
                'access_level': access_level,
                'category': role_info['category'],
                'scope': scope_str,
                'scope_display': scope_display,
                'scope_type': r[2] or 'unknown',
                'resource_type': r[3] or None,
                'risk_level': r[6] or 'info',
                'assigned_on': r[7].isoformat() if r[7] else None,
                'usage_status': r[8] or 'unknown',
                'permissions': perms,
                'why_critical': r[9] or None,
            })

        for r in entra_rows:
            role_name = r[0] or 'Unknown'
            role_info = ENTRA_ROLE_PERMISSIONS.get(role_name, {
                'access_level': 'Write', 'category': 'Directory',
                'permissions': [f'Entra role: {role_name}'],
            })
            access_level = role_info['access_level']
            perms = role_info['permissions']

            if access_level == 'Admin':
                admin_scopes += 1
            elif access_level == 'Write':
                write_scopes += 1
            else:
                read_scopes += 1
            total_permissions += len(perms)
            categories_seen.add(role_info['category'])

            effective_access.append({
                'role_name': role_name,
                'role_source': 'entra_directory',
                'access_level': access_level,
                'category': role_info['category'],
                'scope': r[1] or '/',
                'scope_display': 'Tenant-wide' if not r[1] or r[1] == '/' else r[1],
                'scope_type': 'directory',
                'resource_type': None,
                'risk_level': r[3] or 'info',
                'assigned_on': r[4].isoformat() if r[4] else None,
                'usage_status': r[5] or 'unknown',
                'permissions': perms,
                'why_critical': r[6] or None,
            })

        cursor.close()

        return jsonify({
            'identity_id': identity_id,
            'display_name': display_name,
            'effective_access': effective_access,
            'summary': {
                'admin_scopes': admin_scopes,
                'write_scopes': write_scopes,
                'read_scopes': read_scopes,
                'total_roles': len(effective_access),
                'total_permissions': total_permissions,
                'categories': sorted(categories_seen),
            },
        })
    finally:
        db.close()


# ── Phase 83: Slack/Teams Integrations Settings ────────────────

def get_integration_settings():
    """GET /api/settings/integrations — return webhook URLs (masked) + event config."""
    db = _db()
    try:
        tid = _org_id()
        slack_url = db.get_setting('slack_webhook_url', '', organization_id=tid)
        teams_url = db.get_setting('teams_webhook_url', '', organization_id=tid)
        slack_events = db.get_setting('slack_events', '[]', organization_id=tid)
        teams_events = db.get_setting('teams_events', '[]', organization_id=tid)

        def mask_url(url):
            if not url or len(url) < 20:
                return ''
            return url[:15] + '...' + url[-6:]

        return jsonify({
            'slack': {
                'configured': bool(slack_url),
                'webhook_url_masked': mask_url(slack_url),
                'events': json.loads(slack_events) if slack_events else [],
            },
            'teams': {
                'configured': bool(teams_url),
                'webhook_url_masked': mask_url(teams_url),
                'events': json.loads(teams_events) if teams_events else [],
            },
        })
    finally:
        db.close()


def save_integration_settings():
    """POST /api/settings/integrations — save webhook URLs + event config."""
    data = request.get_json(silent=True) or {}
    db = _db()
    try:
        if 'slack_webhook_url' in data:
            db.save_setting('slack_webhook_url', data['slack_webhook_url'])
        if 'teams_webhook_url' in data:
            db.save_setting('teams_webhook_url', data['teams_webhook_url'])
        if 'slack_events' in data:
            db.save_setting('slack_events', json.dumps(data['slack_events']))
        if 'teams_events' in data:
            db.save_setting('teams_events', json.dumps(data['teams_events']))

        _log(db, 'integrations_updated', 'Integration settings updated')
        return jsonify({'success': True})
    finally:
        db.close()


def test_integration_webhook():
    """POST /api/settings/integrations/test — send test message to verify webhook."""
    data = request.get_json(silent=True) or {}
    platform = data.get('platform')
    webhook_url = data.get('webhook_url')

    if not platform or not webhook_url:
        return jsonify({'error': 'platform and webhook_url required'}), 400

    from app.services.notification_dispatcher import NotificationDispatcher
    dispatcher = NotificationDispatcher()

    try:
        if platform == 'slack':
            success = dispatcher.send_slack(webhook_url, {
                'event_type': 'test',
                'title': 'AuditGraph Test Notification',
                'description': 'This is a test message from AuditGraph. If you see this, your Slack integration is working correctly.',
                'severity': 'info',
            })
        elif platform == 'teams':
            success = dispatcher.send_teams(webhook_url, {
                'event_type': 'test',
                'title': 'AuditGraph Test Notification',
                'description': 'This is a test message from AuditGraph. If you see this, your Teams integration is working correctly.',
                'severity': 'info',
            })
        else:
            return jsonify({'error': 'Invalid platform. Use slack or teams.'}), 400

        if success:
            return jsonify({'success': True, 'message': f'Test message sent to {platform}'})
        else:
            return jsonify({'success': False, 'message': f'Failed to send to {platform}. Check the webhook URL.'}), 400
    except Exception as e:
        logger.error("Notification test failed: %s", str(e), exc_info=True)
        return jsonify({'success': False, 'message': 'An internal error occurred while sending the test notification'}), 500


def check_feature_gate(feature_name):
    """Check if a feature is available for the current organization's plan.
    Delegates to the entitlements engine (per-org overrides, trial expiry, plan check)."""
    from app.entitlements.service import is_feature_enabled
    db = _db()
    try:
        organization_id = _org_id()
        if not organization_id:
            return True, None
        return is_feature_enabled(db, organization_id, feature_name)
    finally:
        db.close()


