def get_subscriptions_list():
    """GET /api/subscriptions — list cloud subscriptions for current org.
    For admin users, includes billing breakdown.
    Optional query params: cloud, connection_id (for per-connection filtering).
    """
    db = _db()
    try:
        cloud = request.args.get('cloud')
        connection_id = request.args.get('connection_id', type=int)
        tid = _org_id()
        subs = db.get_cloud_subscriptions(tid, cloud=cloud, connection_id=connection_id)
        result = {'subscriptions': subs}

        # Include billing for admin users
        user = getattr(g, 'current_user', None)
        role = user.get('role', '') if user else ''
        if role in ('admin', 'security_admin'):
            from app.pricing import calculate_billing
            admin_db = Database(_admin_reason='subscriptions_list: read org plan for billing calc')
            try:
                org = admin_db.get_organization_by_id(tid)
                if org:
                    result['billing'] = calculate_billing(org, subs)
            finally:
                admin_db.close()

        return jsonify(result)
    finally:
        db.close()


def get_subscriptions_stats():
    """GET /api/subscriptions/stats — summary counts."""
    db = _db()
    try:
        stats = db.get_subscription_stats(_org_id())
        return jsonify(stats)
    finally:
        db.close()


def activate_subscription():
    """POST /api/subscriptions/activate — activate a subscription for monitoring."""
    db = _db()
    try:
        data = request.get_json(silent=True) or {}
        sub_id = data.get('id')
        if not sub_id:
            return jsonify({'error': 'Subscription id is required'}), 400

        tid = _org_id()

        # Check plan limits before activation
        from app.pricing import can_activate_subscription
        admin_db = Database(_admin_reason='activate_subscription: read org plan for limit check')
        try:
            org = admin_db.get_organization_by_id(tid)
            if org:
                stats = db.get_subscription_stats(tid)
                allowed, err_msg = can_activate_subscription(org, stats.get('active', 0))
                if not allowed:
                    return jsonify({'error': err_msg, 'upgrade_required': True}), 403
        finally:
            admin_db.close()

        user = getattr(g, 'current_user', None)
        user_id = user.get('id') if user else None
        result = db.activate_cloud_subscription(sub_id, user_id, organization_id=tid)
        if not result:
            return jsonify({'error': 'Subscription not found'}), 404

        _log(db, 'subscription_activated', f"Activated subscription {result.get('account_id')}", {'subscription_id': sub_id})

        # Track usage
        from app.entitlements.service import track_usage
        track_usage(db, tid, 'subscription', str(sub_id), 'activated')

        # Advance org stage to 'active' if still in onboarding
        try:
            adm = Database(_admin_reason='activate_subscription: advance onboarding stage')
            try:
                o = adm.get_organization_by_id(tid)
                if o and o.get('onboarding_stage') in ('connections', 'locked', 'authenticating', 'password_change'):
                    adm.update_organization(tid, onboarding_stage='active')
            finally:
                adm.close()
        except Exception:
            pass

        # Trigger initial discovery scan in background
        import threading
        from app.scheduler import trigger_manual_discovery
        _org_name = g.current_user.get('org_name') if hasattr(g, 'current_user') and g.current_user else None
        _conn_id = result.get('cloud_connection_id')
        def _run_discovery():
            try:
                trigger_manual_discovery(
                    scan_mode='deep',
                    db_org_id=tid,
                    org_name=_org_name,
                    connection_id=_conn_id,
                )
            except Exception as e:
                logging.getLogger(__name__).error(f"Discovery after subscription activation failed: {e}")
        thread = threading.Thread(target=_run_discovery, daemon=True)
        thread.start()

        result['activated'] = True
        result['subscription_id'] = sub_id
        return jsonify(result)
    finally:
        db.close()


def activate_all_subscriptions():
    """POST /api/subscriptions/activate-all — activate all discovered subscriptions for monitoring."""
    db = _db()
    try:
        user = getattr(g, 'current_user', None)
        user_id = user.get('id') if user else None
        tid = _org_id()
        activated = db.activate_all_cloud_subscriptions(user_id, organization_id=tid)
        if activated:
            _log(db, 'subscriptions_bulk_activated', f"Bulk activated {len(activated)} subscription(s)", {'count': len(activated)})

            # Advance org stage to 'active' if still in onboarding
            try:
                adm = Database(_admin_reason='activate_all: advance onboarding stage')
                try:
                    o = adm.get_organization_by_id(tid)
                    if o and o.get('onboarding_stage') in ('locked', 'authenticating', 'password_change'):
                        adm.update_organization(tid, onboarding_stage='active')
                finally:
                    adm.close()
            except Exception:
                try: db.conn.rollback()
                except Exception: pass
                pass

            # Trigger discovery scan in background
            import threading
            from app.scheduler import trigger_manual_discovery
            _org_name = g.current_user.get('org_name') if hasattr(g, 'current_user') and g.current_user else None
            def _run_discovery():
                try:
                    trigger_manual_discovery(
                        scan_mode='deep',
                        db_org_id=tid,
                        org_name=_org_name,
                    )
                except Exception as e:
                    logging.getLogger(__name__).error(f"Discovery after bulk activation failed: {e}")
            thread = threading.Thread(target=_run_discovery, daemon=True)
            thread.start()

        return jsonify({'activated': len(activated), 'subscriptions': activated})
    finally:
        db.close()


def deactivate_subscription(sub_id):
    """PUT /api/subscriptions/<id>/deactivate — stop monitoring."""
    db = _db()
    try:
        tid = _org_id()
        result = db.deactivate_cloud_subscription(sub_id, organization_id=tid)
        if not result:
            return jsonify({'error': 'Subscription not found'}), 404

        _log(db, 'subscription_deactivated', f"Deactivated subscription {result.get('account_id')}", {'subscription_id': sub_id})

        # Track usage
        from app.entitlements.service import track_usage
        track_usage(db, tid, 'subscription', str(sub_id), 'deactivated')

        return jsonify(result)
    finally:
        db.close()


def reconcile_subscriptions():
    """POST /api/subscriptions/reconcile — FIX1C.1: Identify and soft-delete orphaned subscriptions,
    reset usage counters, rebuild from actual monitored state. Admin only."""
    tid = _org_id()
    if not tid or tid == -1:
        return jsonify({'error': 'Tenant context required'}), 403

    db = _db()
    try:
        result = db.reconcile_subscriptions(tid)
        _log(db, 'subscription_reconciliation', f'Reconciled subscriptions: {result["deleted_count"]} removed, {result["active_after_reconciliation"]} active',
             {'orphaned_found': result['orphaned_found'], 'deleted_count': result['deleted_count']})
        return jsonify(result)
    finally:
        db.close()


def get_subscriptions_distinct():
    """GET /api/subscriptions/distinct — individual subscriptions with activation status.

    Query params:
        activated_only: If 'true', return only monitored (activated) subscriptions.
    """
    db = _db()
    try:
        cursor = db.conn.cursor()
        org_id = _org_id()
        conn_id = _connection_id()
        activated_only = request.args.get('activated_only', 'false').lower() == 'true'
        monitored_clause = " AND monitored = true" if activated_only else ""

        # Query cloud_subscriptions for individual rows with monitored status
        if conn_id:
            cursor.execute(f"""
                SELECT account_id, account_name, monitored, status
                FROM cloud_subscriptions
                WHERE organization_id = %s AND cloud_connection_id = %s AND deleted = false{monitored_clause}
                ORDER BY monitored DESC, account_name
            """, (org_id, conn_id))
        else:
            cursor.execute(f"""
                SELECT account_id, account_name, monitored, status
                FROM cloud_subscriptions
                WHERE organization_id = %s AND deleted = false{monitored_clause}
                ORDER BY monitored DESC, account_name
            """, (org_id,))

        rows = cursor.fetchall()
        cursor.close()

        if rows:
            return jsonify({'subscriptions': [
                {
                    'subscription_id': r[0],
                    'subscription_name': r[1] or r[0],
                    'monitored': r[2],
                    'status': r[3],
                }
                for r in rows
            ]})

        # When activated_only is requested and cloud_subscriptions returned nothing,
        # return empty — the fallback cannot determine activation status and must
        # NOT fabricate monitored=True for all discovered subscriptions.
        if activated_only:
            return jsonify({'subscriptions': []})

        # Fallback: parse from discovery_runs for backward compat (only when
        # NOT filtering by activated_only — shows all discovered subs)
        cur2 = db.conn.cursor()
        run_ids = _latest_run_ids(cur2, org_id, conn_id)
        if not run_ids:
            cur2.close()
            return jsonify({'subscriptions': []})
        cur2.execute("""
            SELECT DISTINCT subscription_id, subscription_name
            FROM discovery_runs
            WHERE id = ANY(%s)
              AND subscription_id IS NOT NULL
              AND subscription_id != ''
            ORDER BY subscription_name
        """, (run_ids,))
        fallback_rows = cur2.fetchall()
        cur2.close()
        # Fallback subs are discovered-only — mark monitored=False since we
        # cannot determine their activation status from discovery_runs alone.
        return jsonify({'subscriptions': [
            {'subscription_id': r[0], 'subscription_name': r[1] or r[0], 'monitored': False, 'status': 'discovered'}
            for r in fallback_rows
        ]})
    except Exception:
        return jsonify({'subscriptions': []})
    finally:
        db.close()


def get_subscriptions_scope_summary():
    """GET /api/subscriptions/scope-summary — activated vs discovered subscription counts."""
    db = _db()
    try:
        cursor = db.conn.cursor()
        org_id = _org_id()
        conn_id = _connection_id()

        if conn_id:
            cursor.execute("""
                SELECT
                    COUNT(*) FILTER (WHERE monitored = true) AS activated,
                    COUNT(*) FILTER (WHERE monitored = false) AS discovered
                FROM cloud_subscriptions
                WHERE organization_id = %s AND cloud_connection_id = %s AND deleted = false
            """, (org_id, conn_id))
        else:
            cursor.execute("""
                SELECT
                    COUNT(*) FILTER (WHERE monitored = true) AS activated,
                    COUNT(*) FILTER (WHERE monitored = false) AS discovered
                FROM cloud_subscriptions
                WHERE organization_id = %s AND deleted = false
            """, (org_id,))

        row = cursor.fetchone()
        cursor.close()

        activated = row[0] if row else 0
        discovered = row[1] if row else 0

        # Get tenant name from JWT context
        user = getattr(g, 'current_user', None)
        tenant_name = ''
        if user:
            tenant_name = user.get('tenant_name') or user.get('org_name') or ''

        return jsonify({
            'activated': activated,
            'discovered': discovered,
            'tenant_name': tenant_name,
        })
    except Exception:
        return jsonify({'activated': 0, 'discovered': 0, 'tenant_name': ''})
    finally:
        db.close()


def get_identity_subscriptions(identity_id):
    """GET /api/identities/<identity_id>/subscriptions — all subscription access for an identity."""
    db = _db()
    try:
        # Resolve identity_id to identity_db_id from latest run
        cursor = db.conn.cursor()
        run_ids = _latest_run_ids(cursor, _org_id(), _connection_id())
        cursor.execute("""
            SELECT i.id FROM identities i
            WHERE i.identity_id = %s AND i.discovery_run_id = ANY(%s)
            ORDER BY i.discovery_run_id DESC LIMIT 1
        """, (identity_id, run_ids))
        row = cursor.fetchone()
        cursor.close()
        if not row:
            return jsonify({'subscriptions': [], 'count': 0})
        identity_db_id = row[0]
        subs = db.get_identity_subscription_access(identity_db_id)
        # Group by subscription for a cleaner response
        by_sub = {}
        for s in subs:
            sub_id = s['subscription_id']
            if sub_id not in by_sub:
                by_sub[sub_id] = {
                    'subscription_id': sub_id,
                    'subscription_name': s['subscription_name'],
                    'roles': [],
                }
            by_sub[sub_id]['roles'].append({
                'rbac_role': s['rbac_role'],
                'scope': s['scope'],
                'scope_type': s['scope_type'],
                'risk_level': s['risk_level'],
            })
        result = sorted(by_sub.values(), key=lambda x: x['subscription_name'] or '')
        return jsonify({'subscriptions': result, 'count': len(result)})
    except Exception as e:
        logger.error(f"Subscription data load failed: {e}", exc_info=True)
        return jsonify({'error': 'Failed to load data'}), 500
    finally:
        db.close()


# ================================================================
# Client Subscription Activation (REST path-param style)
# ================================================================

def activate_client_subscription(subscription_id):
    """POST /api/client/subscriptions/<id>/activate — activate a single subscription.

    Uses the subscription_id from the URL path (not request body).
    Returns {"activated": true} on success and triggers discovery.
    """
    db = _db()
    try:
        tid = _org_id()
        if not tid or tid == -1:
            return jsonify({'error': 'Organization context required'}), 403

        # Plan limit check
        from app.pricing import can_activate_subscription
        admin_db = Database(_admin_reason='client_activate: plan limit check')
        try:
            org = admin_db.get_organization_by_id(tid)
            if org:
                stats = db.get_subscription_stats(tid)
                allowed, err_msg = can_activate_subscription(org, stats.get('active', 0))
                if not allowed:
                    return jsonify({'error': err_msg, 'upgrade_required': True}), 403
        finally:
            admin_db.close()

        user = getattr(g, 'current_user', None)
        user_id = user.get('id') if user else None
        result = db.activate_cloud_subscription(subscription_id, user_id, organization_id=tid)
        if not result:
            return jsonify({'error': 'Subscription not found'}), 404

        _log(db, 'subscription_activated',
             f"Activated subscription {result.get('account_id')}",
             {'subscription_id': subscription_id})

        # Track usage
        from app.entitlements.service import track_usage
        track_usage(db, tid, 'subscription', str(subscription_id), 'activated')

        # Advance onboarding stage
        try:
            adm = Database(_admin_reason='client_activate: advance onboarding')
            try:
                o = adm.get_organization_by_id(tid)
                if o and o.get('onboarding_stage') in ('connections', 'locked', 'authenticating', 'password_change'):
                    adm.update_organization(tid, onboarding_stage='active')
            finally:
                adm.close()
        except Exception:
            pass

        return jsonify({'activated': True})
    finally:
        db.close()


