def get_discovery_status():
    """GET /api/discovery/status — check if any snapshots exist for the org."""
    db = _db()
    try:
        tid = _org_id()
        cursor = db.conn.cursor()
        cursor.execute("""
            SELECT id, status, started_at, completed_at,
                   total_identities, critical_count, high_count
            FROM discovery_runs
            WHERE organization_id = %s
            ORDER BY id DESC LIMIT 1
        """, (tid,))
        row = cursor.fetchone()

        cursor.execute("""
            SELECT COUNT(*) FROM discovery_runs
            WHERE organization_id = %s AND status = 'completed'
        """, (tid,))
        total_completed = _scalar(cursor, 0)
        cursor.close()

        if row:
            latest = {
                'id': row[0],
                'status': row[1],
                'started_at': row[2].isoformat() if row[2] else None,
                'completed_at': row[3].isoformat() if row[3] else None,
                'total_identities': row[4],
                'critical_count': row[5],
                'high_count': row[6],
            }
        else:
            latest = None

        # Phase 3: Include recent snapshot jobs
        jobs = []
        try:
            jobs = db.get_snapshot_jobs_for_org(tid, limit=10)
        except Exception:
            try: db.conn.rollback()
            except Exception: pass
            pass

        return jsonify({
            'has_snapshot': total_completed > 0,
            'total_completed': total_completed,
            'latest_run': latest,
            'jobs': jobs,
        })
    finally:
        db.close()


