def get_admin_action_log():
    """GET /api/admin/action-log — unified admin audit + billing events."""
    db = Database(_admin_reason='admin_action_log')
    try:
        source = request.args.get('source', 'all')  # admin_audit | billing | all
        action = request.args.get('action', '')
        limit = min(request.args.get('limit', 50, type=int), 200)
        offset = request.args.get('offset', 0, type=int)

        cursor = db.conn.cursor(cursor_factory=RealDictCursor)

        parts = []
        params = []

        if source in ('all', 'admin_audit'):
            audit_where = ''
            if action:
                audit_where = 'WHERE a.action = %s'
                params.append(action)
            parts.append(f"""
                SELECT a.id, a.action AS action_type, 'admin_audit' AS source,
                       a.admin_user_id, u.username AS admin_username,
                       a.target_organization_id, o.name AS target_org_name,
                       a.details, a.ip_address, a.created_at
                FROM admin_audit_log a
                LEFT JOIN users u ON u.id = a.admin_user_id
                LEFT JOIN organizations o ON o.id = a.target_organization_id
                {audit_where}
            """)

        if source in ('all', 'billing'):
            billing_where = ''
            if action:
                billing_where = 'WHERE b.event_type = %s'
                params.append(action)
            parts.append(f"""
                SELECT b.id, b.event_type AS action_type, 'billing' AS source,
                       b.changed_by AS admin_user_id, u.username AS admin_username,
                       b.organization_id AS target_organization_id, o.name AS target_org_name,
                       jsonb_build_object('field_changed', b.field_changed,
                                          'old_value', b.old_value,
                                          'new_value', b.new_value,
                                          'metadata', b.metadata) AS details,
                       NULL AS ip_address, b.created_at
                FROM billing_events b
                LEFT JOIN users u ON u.id = b.changed_by
                LEFT JOIN organizations o ON o.id = b.organization_id
                {billing_where}
            """)

        if not parts:
            return jsonify({'events': [], 'limit': limit, 'offset': offset})

        query = ' UNION ALL '.join(parts)
        query += ' ORDER BY created_at DESC LIMIT %s OFFSET %s'
        params.extend([limit, offset])

        cursor.execute(query, params)
        rows = [dict(r) for r in cursor.fetchall()]

        for row in rows:
            if row.get('created_at'):
                row['created_at'] = row['created_at'].isoformat()
            if row.get('details') and not isinstance(row['details'], dict):
                import json as _json
                try:
                    row['details'] = _json.loads(row['details']) if isinstance(row['details'], str) else row['details']
                except Exception:
                    try: cursor.connection.rollback()
                    except Exception: pass
                    pass

        cursor.close()
        return jsonify({'events': rows, 'limit': limit, 'offset': offset})
    finally:
        db.close()


def get_group_waste_stats():
    """GET /api/group-waste — measure group expansion waste for current org.

    Returns counts of groups with/without Azure RBAC or Entra roles,
    showing how many groups are expanded unnecessarily during scans.
    Org scoped via JWT — no hardcoding.
    """
    org_id = _org_id()
    if not org_id or org_id == -1:
        return jsonify({'error': 'No organization context'}), 403

    db = _db()
    try:
        cursor = db.conn.cursor(cursor_factory=RealDictCursor)

        # Get latest completed run for this org
        run_ids = _latest_run_ids(cursor, org_id)
        if not run_ids:
            cursor.close()
            return jsonify({'error': 'No completed discovery runs found'}), 404
        run_id = run_ids[0]

        cursor.execute("""
            WITH role_bearing AS (
                SELECT DISTINCT group_id FROM entra_groups
                WHERE organization_id = %(org)s AND discovery_run_id = ANY(%(runs)s)
                  AND rbac_roles IS NOT NULL AND rbac_roles != '[]'::jsonb
            ),
            entra_role_bearing AS (
                SELECT DISTINCT i.object_id AS group_id
                FROM entra_role_assignments era
                JOIN identities i ON i.id = era.identity_db_id
                WHERE era.organization_id = %(org)s
                  AND i.object_id IN (
                      SELECT group_id FROM entra_groups
                      WHERE organization_id = %(org)s AND discovery_run_id = ANY(%(runs)s)
                  )
            ),
            all_role_groups AS (
                SELECT group_id FROM role_bearing
                UNION
                SELECT group_id FROM entra_role_bearing
            ),
            totals AS (
                SELECT COUNT(*) AS total FROM entra_groups
                WHERE organization_id = %(org)s AND discovery_run_id = ANY(%(runs)s)
            )
            SELECT
                (SELECT total FROM totals) AS total_groups,
                (SELECT COUNT(*) FROM all_role_groups) AS groups_with_roles,
                (SELECT total FROM totals) - (SELECT COUNT(*) FROM all_role_groups) AS groups_without_roles,
                CASE WHEN (SELECT total FROM totals) > 0 THEN
                    ROUND(
                        ((SELECT total FROM totals) - (SELECT COUNT(*) FROM all_role_groups))
                        * 100.0 / (SELECT total FROM totals), 1
                    )
                ELSE 0 END AS waste_percentage
        """, {'org': org_id, 'runs': run_ids})

        row = cursor.fetchone()
        cursor.close()

        return jsonify({
            'organization_id': org_id,
            'discovery_run_ids': run_ids,
            'total_groups': row['total_groups'],
            'groups_with_roles': row['groups_with_roles'],
            'groups_without_roles': row['groups_without_roles'],
            'waste_percentage': float(row['waste_percentage']),
        })
    except Exception as e:
        logger.error("Group waste stats error: %s", e)
        try:
            db.conn.rollback()
        except Exception:
            pass
        return jsonify({'error': str(e)}), 500
    finally:
        db.close()


def admin_impersonate():
    """POST /api/admin/impersonate — generate org-scoped tokens for admin impersonation.
    Phase 1C: 15-min hard cap, impersonated_by claim, audit logging."""
    from app.api.auth import generate_access_token, generate_refresh_token
    user = g.current_user
    data = request.get_json(silent=True) or {}
    target_organization_id = data.get('organization_id')
    target_role = data.get('role', 'admin')

    if not target_organization_id:
        return jsonify({'error': 'organization_id is required'}), 400

    db = Database(_admin_reason='admin_impersonate')
    try:
        org = db.get_organization_by_id(int(target_organization_id))
        if not org:
            return jsonify({'error': 'Tenant not found'}), 404

        slug = org.get('slug')

        # Build synthetic impersonation user
        impersonation_user = {
            'id': user['id'],
            'username': user['username'],
            'display_name': user.get('display_name', user['username']),
            'role': target_role,
            'organization_id': org['id'],
            'org_name': org.get('name'),
            'is_superadmin': False,
            'portal_role': None,
            'impersonating': True,
            'impersonator_id': user['id'],
            'impersonator_username': user['username'],
        }

        # Log impersonation start to admin_audit_log
        try:
            cursor = db.conn.cursor()
            cursor.execute("""
                INSERT INTO admin_audit_log (admin_user_id, action, target_organization_id, details, ip_address)
                VALUES (%s, %s, %s, %s, %s)
            """, (
                user['id'],
                'impersonation_start',
                org['id'],
                json.dumps({
                    'target_role': target_role,
                    'org_name': org.get('name'),
                    'impersonator': user['username'],
                    'max_duration_min': 15,
                }),
                request.remote_addr,
            ))
            db._commit()
            cursor.close()
        except Exception:
            try: db.conn.rollback()
            except Exception: pass
            pass
    finally:
        db.close()

    access_token = generate_access_token(impersonation_user, portal='client', org_slug=slug)
    refresh_token = generate_refresh_token(impersonation_user, portal='client')

    from flask import make_response as _mkr
    from app.api.auth import set_auth_cookies, _cookie_name, _IS_SECURE_COOKIE, COOKIE_DOMAIN, REFRESH_TOKEN_EXPIRY
    resp = _mkr(jsonify({
        'access_token': access_token,
        'refresh_token': refresh_token,
        'org_slug': slug,
        'org_name': org.get('name'),
        'impersonation': True,
        'expires_in_minutes': 15,
    }))
    # Set impersonation tokens as client cookies
    set_auth_cookies(resp, access_token, refresh_token, 'client')
    # Backup admin tokens in httpOnly cookies for exit-impersonation restore
    admin_access = request.cookies.get(_cookie_name('admin', 'access'), '')
    admin_refresh = request.cookies.get(_cookie_name('admin', 'refresh'), '')
    if admin_access:
        resp.set_cookie('ag_admin_backup_access', value=admin_access, httponly=True,
                        secure=_IS_SECURE_COOKIE, samesite='Lax',
                        max_age=int(REFRESH_TOKEN_EXPIRY.total_seconds()),
                        path='/', domain=COOKIE_DOMAIN)
    if admin_refresh:
        resp.set_cookie('ag_admin_backup_refresh', value=admin_refresh, httponly=True,
                        secure=_IS_SECURE_COOKIE, samesite='Lax',
                        max_age=int(REFRESH_TOKEN_EXPIRY.total_seconds()),
                        path='/api/auth/', domain=COOKIE_DOMAIN)
    return resp


def admin_end_impersonation():
    """POST /api/admin/impersonate/end — log impersonation end."""
    user = g.current_user
    if not user.get('impersonating'):
        return jsonify({'error': 'Not currently impersonating'}), 400

    db = Database(_admin_reason='admin_end_impersonate')
    try:
        cursor = db.conn.cursor()
        cursor.execute("""
            INSERT INTO admin_audit_log (admin_user_id, action, target_organization_id, details, ip_address)
            VALUES (%s, %s, %s, %s, %s)
        """, (
            user.get('impersonator_id', user['id']),
            'impersonation_end',
            user.get('organization_id'),
            json.dumps({
                'impersonator': user.get('impersonated_by', user.get('impersonator_username')),
                'org_name': user.get('org_name'),
            }),
            request.remote_addr,
        ))
        db._commit()
        cursor.close()
    except Exception:
        try: db.conn.rollback()
        except Exception: pass
        pass
    finally:
        db.close()

    # Phase S1: Restore admin cookies from backup, clear client + backup cookies
    from flask import make_response as _mkr
    from app.api.auth import clear_auth_cookies, _cookie_name, _IS_SECURE_COOKIE, COOKIE_DOMAIN, \
        ADMIN_TOKEN_EXPIRY, REFRESH_TOKEN_EXPIRY
    resp = _mkr(jsonify({'message': 'Impersonation ended'}))
    # Clear impersonation client cookies
    clear_auth_cookies(resp, 'client')
    # Restore admin cookies from backup
    backup_access = request.cookies.get('ag_admin_backup_access', '')
    backup_refresh = request.cookies.get('ag_admin_backup_refresh', '')
    if backup_access:
        resp.set_cookie(_cookie_name('admin', 'access'), value=backup_access,
                        httponly=True, secure=_IS_SECURE_COOKIE, samesite='Lax',
                        max_age=int(ADMIN_TOKEN_EXPIRY.total_seconds()),
                        path='/', domain=COOKIE_DOMAIN)
    if backup_refresh:
        resp.set_cookie(_cookie_name('admin', 'refresh'), value=backup_refresh,
                        httponly=True, secure=_IS_SECURE_COOKIE, samesite='Lax',
                        max_age=int(REFRESH_TOKEN_EXPIRY.total_seconds()),
                        path='/api/auth/', domain=COOKIE_DOMAIN)
    # Clear backup cookies
    resp.delete_cookie('ag_admin_backup_access', path='/', domain=COOKIE_DOMAIN)
    resp.delete_cookie('ag_admin_backup_refresh', path='/api/auth/', domain=COOKIE_DOMAIN)
    return resp


