def save_correlation_config():
    """PUT /api/correlation/config — save ICE settings."""
    from app.engines.correlation.identity_correlator import DEFAULT_CONFIG
    db = _db()
    try:
        data = request.get_json(force=True)
        cursor = db.conn.cursor()
        try:
            for key in DEFAULT_CONFIG:
                if key in data:
                    cursor.execute("""
                        INSERT INTO settings (key, value, organization_id)
                        VALUES (%s, %s, %s)
                        ON CONFLICT (key, organization_id) DO UPDATE SET value = EXCLUDED.value, updated_at = NOW()
                    """, (key, str(data[key]), _org_id()))
            db._commit()
        finally:
            cursor.close()
        _log(db, 'correlation_config', 'Updated ICE configuration')
        return jsonify({'status': 'saved'})
    finally:
        db.close()


# ── Dashboard Summary ──

def get_dashboard_identity_correlation():
    """GET /api/dashboard/identity-correlation — summary stats for dashboard."""
    db = _db()
    try:
        tid = _org_id()
        cursor = db.conn.cursor(cursor_factory=RealDictCursor)
        try:
            # Count linked humans
            cursor.execute("SELECT COUNT(*) as cnt FROM human_identities WHERE organization_id = %s", (tid,))
            humans = cursor.fetchone()['cnt']

            # Count links
            cursor.execute("SELECT COUNT(*) as cnt FROM identity_links WHERE organization_id = %s", (tid,))
            links = cursor.fetchone()['cnt']

            # Count open findings by severity
            cursor.execute("""
                SELECT severity, COUNT(*) as cnt
                FROM orphaned_privileged_findings
                WHERE organization_id = %s AND status = 'open'
                GROUP BY severity
            """, (tid,))
            findings_by_severity = {r['severity']: r['cnt'] for r in cursor.fetchall()}

            # Total open findings
            total_findings = sum(findings_by_severity.values())

            # Zombie persona count
            zombie_count = 0
            zombie_pairs = []
            try:
                cursor.execute("""
                    SELECT DISTINCT ON (hi.id)
                        hi.id AS human_id, hi.display_name AS human_name,
                        i1.display_name AS disabled_name, i1.upn AS disabled_upn,
                        i2.display_name AS active_name, i2.upn AS active_upn,
                        i2.risk_score AS active_risk
                    FROM human_identities hi
                    JOIN identity_links il1 ON il1.human_identity_id = hi.id
                    JOIN identity_links il2 ON il2.human_identity_id = hi.id
                        AND il2.identity_db_id != il1.identity_db_id
                    JOIN identities i1 ON i1.id = il1.identity_db_id
                    JOIN identities i2 ON i2.id = il2.identity_db_id
                    WHERE hi.organization_id = %s
                      AND (i1.enabled = FALSE OR i1.deleted_at IS NOT NULL)
                      AND i2.enabled = TRUE AND i2.deleted_at IS NULL
                    ORDER BY hi.id
                """, (tid,))
                rows = cursor.fetchall()
                zombie_count = len(rows)
                zombie_pairs = [
                    {
                        'human_name': r['human_name'],
                        'disabled_name': r['disabled_name'] or r['disabled_upn'],
                        'active_name': r['active_name'] or r['active_upn'],
                        'active_risk': r['active_risk'],
                    }
                    for r in rows
                ]
            except Exception:
                try: cursor.connection.rollback()
                except Exception: pass
                pass

            return jsonify({
                'humans_linked': humans,
                'total_links': links,
                'open_findings': total_findings,
                'findings_by_severity': findings_by_severity,
                'zombie_count': zombie_count,
                'zombie_pairs': zombie_pairs,
            })
        except Exception:
            return jsonify({
                'humans_linked': 0, 'total_links': 0,
                'open_findings': 0, 'findings_by_severity': {},
                'zombie_count': 0, 'zombie_pairs': [],
            })
        finally:
            cursor.close()
    finally:
        db.close()


def get_correlation_accounts():
    """GET /api/correlation/accounts — correlated accounts for a given identity."""
    db = _db()
    identity_id = request.args.get('identity_id')
    object_id = request.args.get('object_id')

    if not identity_id and not object_id:
        db.close()
        return jsonify({'error': 'identity_id or object_id required'}), 400

    cursor = db.conn.cursor(cursor_factory=RealDictCursor)
    try:
        # Resolve identity_id: accept both int (db_id) and UUID string
        resolved_db_id = None
        if identity_id:
            try:
                resolved_db_id = int(identity_id)
            except (ValueError, TypeError):
                # It's a UUID string — look up the db_id from identities table
                run_ids = _latest_run_ids(cursor, _org_id(), _connection_id())
                if run_ids:
                    cursor.execute(
                        "SELECT id FROM identities WHERE identity_id = %s AND discovery_run_id = ANY(%s) ORDER BY discovery_run_id DESC LIMIT 1",
                        (identity_id, run_ids))
                    id_row = cursor.fetchone()
                    if id_row:
                        resolved_db_id = id_row['id']

        # Find the identity_link for the given identity
        if resolved_db_id:
            cursor.execute(
                "SELECT human_identity_id FROM identity_links WHERE identity_db_id = %s LIMIT 1",
                (resolved_db_id,))
        else:
            cursor.execute(
                "SELECT human_identity_id FROM identity_links WHERE account_object_id = %s LIMIT 1",
                (object_id,))

        link_row = cursor.fetchone()
        if not link_row:
            return jsonify({'human_identity': None, 'accounts': [], 'zombie_persona': False})

        human_id = link_row['human_identity_id']

        # Fetch human identity
        cursor.execute(
            "SELECT id, display_name, employee_id, department FROM human_identities WHERE id = %s",
            (human_id,))
        human = cursor.fetchone()

        # Fetch all linked accounts
        cursor.execute("""
            SELECT il.identity_db_id, il.account_type, il.account_upn,
                   il.account_object_id, il.account_enabled, il.link_method,
                   il.link_confidence, il.verified,
                   i.display_name, i.enabled, i.deleted_at, i.risk_score,
                   i.risk_level, i.privilege_tier, i.identity_category, i.identity_id
            FROM identity_links il
            JOIN identities i ON i.id = il.identity_db_id
            WHERE il.human_identity_id = %s
            ORDER BY il.account_type
        """, (human_id,))
        links = cursor.fetchall()

        # Determine zombie status: any disabled+active pair?
        has_disabled = any(
            (not l['enabled'] or l['deleted_at'] is not None) for l in links
        )
        has_active = any(
            (l['enabled'] and l['deleted_at'] is None) for l in links
        )
        is_zombie = has_disabled and has_active

        accounts = []
        for l in links:
            accounts.append({
                'id': l['identity_db_id'],
                'identity_id': l['identity_id'],
                'object_id': l['account_object_id'],
                'display_name': l['display_name'] or l['account_upn'],
                'upn': l['account_upn'],
                'account_type': l['account_type'],
                'enabled': l['enabled'],
                'deleted': l['deleted_at'] is not None,
                'is_zombie': (not l['enabled'] or l['deleted_at'] is not None) and is_zombie,
                'risk_score': l['risk_score'],
                'risk_level': l['risk_level'],
                'privilege_tier': f"T{l['tier']}" if l['tier'] is not None else 'T3',
                'link_method': l['link_method'],
                'link_confidence': l['link_confidence'],
                'verified': l['verified'],
            })

        return jsonify({
            'human_identity': dict(human) if human else None,
            'accounts': accounts,
            'zombie_persona': is_zombie,
            'link_method': links[0]['link_method'] if links else None,
            'link_confidence': links[0]['link_confidence'] if links else None,
        })

    except Exception as e:
        logger.error(f"Identity correlation failed: {e}", exc_info=True)
        return jsonify({'error': 'Internal server error'}), 500
    finally:
        cursor.close()
        db.close()


# ─── AGIRS: Identity Risk Summary ────────────────────────────────

def get_identity_risk_summary():
    """SSOT endpoint for all AGIRS data. Reads from risk_summary table (canonical source)."""
    db = _db()
    try:
        latest, previous = db.get_latest_risk_summaries()

        if not latest:
            return jsonify({
                'agirs': None,
                'hiri': None,
                'nhiri': None,
                'gei': None,
                'dangerous_identities': [],
                'previous': None,
            })

        hiri_bd = latest.get('hiri_breakdown') or {}
        nhiri_bd = latest.get('nhiri_breakdown') or {}
        gei_bd = latest.get('gei_breakdown') or {}

        # Tier from persisted agirs_tier, fallback to score-based
        agirs_score = latest.get('agirs_score')
        tier = latest.get('agirs_tier') or 'F'
        if tier == 'F' and agirs_score is not None:
            if agirs_score >= 90:
                tier = 'A'
            elif agirs_score >= 75:
                tier = 'B'
            elif agirs_score >= 60:
                tier = 'C'
            elif agirs_score >= 40:
                tier = 'D'

        # Delta from previous
        delta = None
        if previous and agirs_score is not None and previous.get('agirs_score') is not None:
            delta = round(agirs_score - previous['agirs_score'], 2)

        result = {
            'agirs': {
                'score': agirs_score,
                'tier': tier,
                'delta': delta,
            },
            'hiri': {
                'score': hiri_bd.get('score'),
                'human_count': latest.get('human_count', hiri_bd.get('human_count', 0)),
                'h1_ghost': hiri_bd.get('h1_ghost', 0),
                'h2_dormant_priv': hiri_bd.get('h2_dormant_priv', 0),
                'h3_over_priv': hiri_bd.get('h3_over_priv', 0),
                'h4_ext_guest': hiri_bd.get('h4_ext_guest', 0),
                'h5_zombie': hiri_bd.get('h5_zombie', 0),
            } if hiri_bd else None,
            'nhiri': {
                'score': nhiri_bd.get('score'),
                'nhi_count': latest.get('nhi_count', nhiri_bd.get('nhi_count', 0)),
                'phantom_breakdown': nhiri_bd.get('phantom_breakdown', {}),
            } if nhiri_bd else None,
            'gei': {
                'score': gei_bd.get('score'),
                'components': gei_bd.get('components', []),
            } if gei_bd else None,
            'dangerous_identities': latest.get('dangerous_identities', []),
            'previous': {
                'agirs': previous.get('agirs_score'),
                'hiri': (previous.get('hiri_breakdown') or {}).get('score'),
                'nhiri': (previous.get('nhiri_breakdown') or {}).get('score'),
                'gei': (previous.get('gei_breakdown') or {}).get('score'),
            } if previous else None,
            'source': 'risk_summary',
        }

        return jsonify(result)
    except Exception as e:
        logger.error(f"Posture snapshot failed: {e}", exc_info=True)
        return jsonify({'error': 'Internal server error'}), 500
    finally:
        db.close()


def get_dangerous_identities():
    """Return top N identities by blast_radius_score with drill-down data."""
    db = _db()
    try:
        limit = request.args.get('limit', 5, type=int)
        category = request.args.get('category', 'all')

        cursor = db.conn.cursor()
        run_ids = _latest_run_ids(cursor, _org_id(), _connection_id())
        if not run_ids:
            cursor.close()
            return jsonify({'identities': []})

        rid_tuple = tuple(run_ids)
        cat_filter = ""
        if category == 'human':
            cat_filter = "AND i.identity_category IN ('human_user', 'guest')"
        elif category == 'nhi':
            cat_filter = "AND i.identity_category IN ('service_principal', 'managed_identity_system', 'managed_identity_user')"

        cursor.execute(f"""
            SELECT
                i.id,
                i.display_name,
                i.identity_category,
                COALESCE(i.blast_radius_score, 0) as blast_radius_score,
                COALESCE(i.risk_score, 0) as risk_score,
                COALESCE(i.privilege_tier, 'T3') as tier,
                COALESCE(i.activity_status, 'unknown') as activity_status
            FROM identities i
            WHERE i.discovery_run_id IN %s
              AND COALESCE(i.deleted_at, '9999-01-01') > NOW()
              AND COALESCE(i.blast_radius_score, 0) > 0
              {cat_filter}
            ORDER BY i.blast_radius_score DESC
            LIMIT %s
        """, (rid_tuple, limit))

        identities = []
        for row in cursor.fetchall():
            id_, name, cat, br_score, risk, tier, activity = row
            risk_factors = []
            if tier in ('T0', 'T1'):
                risk_factors.append(f'{tier} Privilege')
            if activity in ('stale', 'never_used'):
                risk_factors.append(f'Dormant ({activity})')
            if risk >= 70:
                risk_factors.append(f'Risk score {risk}')

            identities.append({
                'id': id_,
                'display_name': name or 'Unknown',
                'identity_category': cat,
                'blast_radius_score': float(br_score),
                'risk_score': int(risk),
                'tier': tier,
                'key_risk_factors': risk_factors[:5],
                'navigateTo': f'/identities/{id_}',
            })

        cursor.close()
        return jsonify({'identities': identities})
    except Exception as e:
        logger.error(f"Dangerous identities query failed: {e}", exc_info=True)
        return jsonify({'error': 'Internal server error'}), 500
    finally:
        db.close()


