def get_stripe_status():
    """GET /api/billing/stripe-status — check Stripe integration status."""
    stripe_key = os.environ.get('STRIPE_SECRET_KEY', '')
    configured = bool(stripe_key and stripe_key.startswith('sk_'))
    return jsonify({
        'configured': configured,
        'mode': 'live' if stripe_key.startswith('sk_live_') else 'test' if configured else 'none',
        'webhook_url': '/api/billing/stripe-webhook',
    })


def stripe_webhook_handler():
    """POST /api/billing/stripe-webhook — handle Stripe webhook events.

    Events handled:
    - invoice.payment_succeeded → mark invoice as paid
    - invoice.payment_failed → log billing event
    - customer.subscription.updated → sync plan changes
    """
    import json as json_mod
    stripe_key = os.environ.get('STRIPE_SECRET_KEY', '')
    webhook_secret = os.environ.get('STRIPE_WEBHOOK_SECRET', '')

    if not stripe_key:
        return jsonify({'error': 'Stripe not configured'}), 503

    if not webhook_secret:
        logger.warning("STRIPE_WEBHOOK_SECRET is not set — rejecting webhook")
        return jsonify({'error': 'Webhook verification not configured'}), 503

    if not webhook_secret:
        logger.error("STRIPE_WEBHOOK_SECRET not configured — rejecting webhook")
        return jsonify({'error': 'Webhook verification not configured'}), 503

    payload = request.get_data(as_text=True)
    sig_header = request.headers.get('Stripe-Signature', '')

    if not sig_header:
        return jsonify({'error': 'Missing Stripe-Signature header'}), 401

    # Verify webhook signature (always required)
    import hmac as _hmac
    parts = dict(p.split('=', 1) for p in sig_header.split(',') if '=' in p)
    timestamp = parts.get('t', '')
    signature = parts.get('v1', '')
    if not timestamp or not signature:
        return jsonify({'error': 'Invalid signature format'}), 401
    signed_payload = f"{timestamp}.{payload}"
    expected = _hmac.new(webhook_secret.encode(), signed_payload.encode(), hashlib.sha256).hexdigest()
    if not _hmac.compare_digest(expected, signature):
        return jsonify({'error': 'Invalid signature'}), 401

    try:
        event = json_mod.loads(payload)
    except Exception:
        return jsonify({'error': 'Invalid payload'}), 400

    event_type = event.get('type', '')
    event_data = event.get('data', {}).get('object', {})

    db = Database(_admin_reason='stripe webhook: process billing event')
    try:
        if event_type == 'invoice.payment_succeeded':
            # Find our invoice by Stripe invoice ID
            stripe_invoice_id = event_data.get('id', '')
            customer_id = event_data.get('customer', '')
            amount = event_data.get('amount_paid', 0)

            db.log_billing_event(
                organization_id=None,
                event_type='stripe_payment_succeeded',
                field_changed='stripe_invoice',
                old_value=None,
                new_value=stripe_invoice_id,
                changed_by=None,
                metadata={'amount_cents': amount, 'customer': customer_id}
            )

        elif event_type == 'invoice.payment_failed':
            stripe_invoice_id = event_data.get('id', '')
            customer_id = event_data.get('customer', '')

            db.log_billing_event(
                organization_id=None,
                event_type='stripe_payment_failed',
                field_changed='stripe_invoice',
                old_value=None,
                new_value=stripe_invoice_id,
                changed_by=None,
                metadata={'customer': customer_id, 'failure_reason': event_data.get('last_payment_error', {}).get('message', '')}
            )

        elif event_type == 'customer.subscription.updated':
            customer_id = event_data.get('customer', '')
            status = event_data.get('status', '')

            db.log_billing_event(
                organization_id=None,
                event_type='stripe_subscription_updated',
                field_changed='stripe_subscription_status',
                old_value=None,
                new_value=status,
                changed_by=None,
                metadata={'customer': customer_id}
            )

        return jsonify({'received': True})
    finally:
        db.close()


def create_stripe_customer_handler(organization_id):
    """POST /api/admin/organizations/<id>/stripe-customer — create Stripe customer for org."""
    stripe_key = os.environ.get('STRIPE_SECRET_KEY', '')
    if not stripe_key:
        return jsonify({'error': 'Stripe not configured. Set STRIPE_SECRET_KEY environment variable.'}), 503

    db = Database(_admin_reason='admin: create Stripe customer')
    try:
        cursor = db.conn.cursor(cursor_factory=RealDictCursor)
        cursor.execute("SELECT * FROM organizations WHERE id = %s", (organization_id,))
        org = cursor.fetchone()
        cursor.close()

        if not org:
            return jsonify({'error': 'Tenant not found'}), 404

        if org.get('stripe_customer_id'):
            return jsonify({
                'message': 'Stripe customer already exists',
                'stripe_customer_id': org['stripe_customer_id']
            })

        try:
            import stripe
            stripe.api_key = stripe_key
            customer = stripe.Customer.create(
                name=org.get('name', ''),
                email=org.get('billing_email') or org.get('root_email', ''),
                metadata={
                    'auditgraph_organization_id': str(organization_id),
                    'plan': org.get('plan', 'free'),
                }
            )

            cursor = db.conn.cursor()
            cursor.execute(
                "UPDATE organizations SET stripe_customer_id = %s WHERE id = %s",
                (customer.id, organization_id))
            db._commit()
            cursor.close()

            db.log_billing_event(
                organization_id, 'stripe_customer_created',
                'stripe_customer_id', None, customer.id,
                changed_by=g.current_user.get('id'),
                metadata={'stripe_mode': 'live' if stripe_key.startswith('sk_live_') else 'test'})

            return jsonify({'stripe_customer_id': customer.id})

        except ImportError:
            return jsonify({'error': 'stripe Python package not installed. Run: pip install stripe'}), 503
        except Exception as e:
            try: db.conn.rollback()
            except Exception: pass
            logger.error(f"Stripe API error: {e}", exc_info=True)
            return jsonify({'error': 'Billing service temporarily unavailable'}), 502
    finally:
        db.close()


