def manage_agent_delegation():
    """POST /api/agent-identities/delegations — create/update a delegation edge.

    Body: { source_identity_id, target_identity_id, delegation_type? }
    Admin-only. Supports manual override of agent-to-agent delegation.
    """
    from app.config import FEATURE_AI_AGENT_GOVERNANCE
    if not FEATURE_AI_AGENT_GOVERNANCE:
        return jsonify({'error': 'Not found'}), 404

    db = _db()
    try:
        data = request.get_json(force=True)
        source_id = data.get('source_identity_id')
        target_id = data.get('target_identity_id')
        if not source_id or not target_id:
            return jsonify({'error': 'source_identity_id and target_identity_id required'}), 400
        if source_id == target_id:
            return jsonify({'error': 'Cannot delegate to self'}), 400

        delegation_type = data.get('delegation_type', 'manual')

        cursor = db.conn.cursor()
        run_ids = _latest_run_ids(cursor, _org_id(), _connection_id())

        # Resolve both identities
        cursor.execute("""
            SELECT id, identity_id, display_name FROM identities
            WHERE identity_id = %s AND discovery_run_id = ANY(%s) LIMIT 1
        """, (source_id, run_ids))
        src = cursor.fetchone()
        cursor.execute("""
            SELECT id, identity_id, display_name FROM identities
            WHERE identity_id = %s AND discovery_run_id = ANY(%s) LIMIT 1
        """, (target_id, run_ids))
        tgt = cursor.fetchone()
        cursor.close()

        if not src or not tgt:
            return jsonify({'error': 'One or both identities not found'}), 404

        db.upsert_agent_delegation(
            source_db_id=src[0], source_id=src[1], source_name=src[2],
            target_db_id=tgt[0], target_id=tgt[1], target_name=tgt[2],
            delegation_type=delegation_type, confidence=1.0 if delegation_type == 'manual' else 0.8,
        )

        _log(db, 'agent_delegation_created',
             f"Agent delegation: {src[2]} → {tgt[2]} ({delegation_type})",
             {'source': source_id, 'target': target_id, 'type': delegation_type})

        return jsonify({
            'message': 'Delegation created',
            'source': {'identity_id': src[1], 'display_name': src[2]},
            'target': {'identity_id': tgt[1], 'display_name': tgt[2]},
            'delegation_type': delegation_type,
        })
    except Exception as e:
        logger.error("manage_agent_delegation failed: %s", e, exc_info=True)
        return jsonify({'error': 'Internal server error'}), 500
    finally:
        db.close()


def delete_agent_delegation():
    """DELETE /api/agent-identities/delegations — remove a delegation edge.

    Body: { source_identity_id, target_identity_id }
    """
    from app.config import FEATURE_AI_AGENT_GOVERNANCE
    if not FEATURE_AI_AGENT_GOVERNANCE:
        return jsonify({'error': 'Not found'}), 404

    db = _db()
    try:
        data = request.get_json(force=True)
        source_id = data.get('source_identity_id')
        target_id = data.get('target_identity_id')
        if not source_id or not target_id:
            return jsonify({'error': 'source_identity_id and target_identity_id required'}), 400

        cursor = db.conn.cursor()
        run_ids = _latest_run_ids(cursor, _org_id(), _connection_id())

        cursor.execute("SELECT id FROM identities WHERE identity_id = %s AND discovery_run_id = ANY(%s) LIMIT 1",
                       (source_id, run_ids))
        src = cursor.fetchone()
        cursor.execute("SELECT id FROM identities WHERE identity_id = %s AND discovery_run_id = ANY(%s) LIMIT 1",
                       (target_id, run_ids))
        tgt = cursor.fetchone()
        cursor.close()

        if not src or not tgt:
            return jsonify({'error': 'Identity not found'}), 404

        deleted = db.delete_agent_delegation(src[0], tgt[0])
        if deleted:
            _log(db, 'agent_delegation_deleted',
                 f"Agent delegation removed: {source_id} → {target_id}",
                 {'source': source_id, 'target': target_id})

        return jsonify({'message': 'Delegation removed' if deleted else 'No delegation found',
                        'deleted': deleted})
    except Exception as e:
        try: db.conn.rollback()
        except Exception: pass
        logger.error("delete_agent_delegation failed: %s", e, exc_info=True)
        return jsonify({'error': 'Internal server error'}), 500
    finally:
        db.close()


def get_agent_blast_radius(identity_id):
    """GET /api/agent-identities/<id>/blast-radius — blast radius for an AI agent SPN.

    Follows the ai_agent → SPN → role_assignments → resources traversal.
    Returns same shape as GET /api/identities/<id>/blast-radius.
    """
    from app.config import FEATURE_AI_AGENT_GOVERNANCE
    if not FEATURE_AI_AGENT_GOVERNANCE:
        return jsonify({'error': 'Not found'}), 404

    db = _db()
    try:
        cursor = db.conn.cursor()
        # Resolve identity_id (Azure GUID string) → DB PK
        run_ids = _latest_run_ids(cursor, _org_id(), _connection_id())
        cursor.execute("""
            SELECT i.id
            FROM identities i
            JOIN agent_classifications ac ON ac.identity_db_id = i.id
            WHERE i.identity_id = %s
              AND i.discovery_run_id = ANY(%s)
              AND ac.agent_identity_type IN ('ai_agent', 'possible_ai_agent')
            LIMIT 1
        """, (identity_id, run_ids))
        row = cursor.fetchone()
        cursor.close()

        if not row:
            return jsonify({'error': 'Agent identity not found'}), 404

        db_id = row[0]
        result = db.get_blast_radius_for_identity(db_id)

        if not result:
            return jsonify({
                'identity_id': db_id,
                'identity_name': '',
                'reachable_resource_count': 0,
                'reachable_subscription_count': 0,
                'reachable_resource_group_count': 0,
                'sensitive_resource_count': 0,
                'privilege_escalation_paths': 0,
                'identity_exposure_level': 'LOW',
                'risk_score': 0,
                'resource_breakdown': {},
            })

        # Add agent delegation info if any
        try:
            dcursor = db.conn.cursor()
            dcursor.execute("""
                SELECT target_identity_id, target_display_name, delegation_type, confidence
                FROM agent_delegations
                WHERE source_identity_db_id = %s
            """, (db_id,))
            delegations = []
            for drow in dcursor.fetchall():
                delegations.append({
                    'target_identity_id': drow[0],
                    'target_display_name': drow[1],
                    'delegation_type': drow[2],
                    'confidence': float(drow[3] or 0),
                })
            dcursor.close()
            if delegations:
                result['delegations'] = delegations
                # Compute combined blast radius
                combined_resources = result.get('reachable_resource_count', 0)
                combined_subs = result.get('reachable_subscription_count', 0)
                for d in delegations:
                    dcursor2 = db.conn.cursor()
                    dcursor2.execute("""
                        SELECT i.id FROM identities i
                        WHERE i.identity_id = %s AND i.discovery_run_id = ANY(%s)
                        LIMIT 1
                    """, (d['target_identity_id'], run_ids))
                    trow = dcursor2.fetchone()
                    dcursor2.close()
                    if trow:
                        delegate_br = db.get_blast_radius_for_identity(trow[0])
                        if delegate_br:
                            combined_resources += delegate_br.get('reachable_resource_count', 0)
                            combined_subs += delegate_br.get('reachable_subscription_count', 0)
                result['combined_blast_radius'] = {
                    'reachable_resource_count': combined_resources,
                    'reachable_subscription_count': combined_subs,
                    'includes_delegations': [d['target_display_name'] for d in delegations],
                }
        except Exception:
            try: db.conn.rollback()
            except Exception: pass
            pass  # agent_delegations table may not exist yet

        return jsonify(result)
    except Exception as e:
        try: db.conn.rollback()
        except Exception: pass
        logger.error("get_agent_blast_radius failed: %s", e, exc_info=True)
        return jsonify({'error': 'Internal server error'}), 500
    finally:
        db.close()


def scan_orphan_agents():
    """POST /api/agent-identities/scan-orphans — on-demand orphan detection.

    Admin-only. Runs auto-resolve + detection for the caller's latest run.
    """
    from app.config import FEATURE_AI_AGENT_GOVERNANCE
    if not FEATURE_AI_AGENT_GOVERNANCE:
        return jsonify({'error': 'Not found'}), 404

    db = _db()
    try:
        org_id = _org_id()
        if not org_id:
            return jsonify({'error': 'Organization context required'}), 400

        # Get latest run for this org
        cursor = db.conn.cursor()
        cursor.execute("""
            SELECT id FROM discovery_runs
            WHERE organization_id = %s
            ORDER BY id DESC LIMIT 1
        """, (org_id,))
        row = cursor.fetchone()
        cursor.close()

        if not row:
            return jsonify({'error': 'No discovery runs found'}), 404

        run_id = row[0]

        from app.engines.agent_orphan_detector import AgentOrphanDetector
        detector = AgentOrphanDetector(db)

        # Auto-resolve first, then detect
        resolved = detector.auto_resolve(run_id)
        findings = detector.analyze(run_id)

        if findings:
            saved = db.save_security_findings(run_id, findings)
        else:
            saved = 0

        _log(db, 'agent_orphan_scan',
             f"Orphan scan: {len(findings)} found, {resolved} resolved, {saved} saved",
             {'findings': len(findings), 'resolved': resolved, 'saved': saved})

        return jsonify({
            'message': 'Orphan scan complete',
            'findings_count': len(findings),
            'resolved_count': resolved,
            'saved_count': saved,
            'run_id': run_id,
        })
    except Exception as e:
        try: db.conn.rollback()
        except Exception: pass
        logger.error("scan_orphan_agents failed: %s", e, exc_info=True)
        return jsonify({'error': 'Internal server error'}), 500
    finally:
        db.close()


def get_agent_evidence(identity_id):
    """GET /api/identities/<identity_id>/ai-evidence — classification proof panel.

    Returns structured evidence explaining WHY this identity was classified as
    an AI agent, including matched signals, AI resource connections, and risk context.
    """
    from app.config import FEATURE_AI_AGENT_GOVERNANCE
    if not FEATURE_AI_AGENT_GOVERNANCE:
        return jsonify({'error': 'Not found'}), 404

    db = _db()
    try:
        cursor = db.conn.cursor()
        org_id = _org_id()

        # Resolve identity via org-scoped discovery runs
        run_ids = _latest_run_ids(cursor, org_id, _connection_id())
        if not run_ids:
            cursor.close()
            return jsonify({'error': 'No discovery data'}), 404

        cursor.execute("""
            SELECT i.id, i.display_name, i.app_id, i.identity_type,
                   i.identity_category, i.risk_score, i.risk_level,
                   i.agent_identity_type
            FROM identities i
            WHERE i.identity_id = %s AND i.discovery_run_id = ANY(%s)
            ORDER BY i.discovery_run_id DESC LIMIT 1
        """, (identity_id, run_ids))
        ident = cursor.fetchone()
        if not ident:
            cursor.close()
            return jsonify({'error': 'Identity not found'}), 404

        db_id, display_name, app_id, identity_type, category, risk_score, risk_level, agent_type = ident

        # Get classification record
        cursor.execute("""
            SELECT agent_identity_type, classification_confidence,
                   classification_reason, detected_platform, pattern_version,
                   classified_at
            FROM agent_classifications
            WHERE identity_db_id = %s
            ORDER BY classified_at DESC LIMIT 1
        """, (db_id,))
        classification_row = cursor.fetchone()

        if not classification_row:
            cursor.close()
            return jsonify({
                'classified': False,
                'agent_identity_type': agent_type or 'unknown',
                'classification': None,
                'evidence_signals': [],
                'ai_connections': [],
                'risk_context': None,
            })

        c_type, c_confidence, c_reason, c_platform, c_version, c_at = classification_row

        # Only show evidence for actual AI classifications
        if c_type not in ('ai_agent', 'possible_ai_agent', 'ai_privileged_human'):
            cursor.close()
            return jsonify({
                'classified': False,
                'agent_identity_type': c_type or 'unknown',
                'classification': None,
                'evidence_signals': [],
                'ai_connections': [],
                'risk_context': None,
            })

        # Parse signal type from classification_reason (e.g. "app_id_match: openai")
        signal_type = c_reason.split(':')[0].strip() if c_reason else 'unknown'

        # Build evidence signals list
        evidence_signals = []

        # Signal 1: The primary classification signal
        evidence_text = _build_evidence_text(signal_type, c_platform, display_name, app_id)
        evidence_signals.append({
            'signal_type': signal_type,
            'confidence': c_confidence,
            'platform': c_platform,
            'evidence_text': evidence_text,
            'is_primary': True,
        })

        # Signal 2: Check for corroborating role assignments on AI scopes
        try:
            cursor.execute("SAVEPOINT _ev_roles")
            cursor.execute("""
                SELECT role_name, scope, last_used_at FROM role_assignments
                WHERE identity_db_id = %s
            """, (db_id,))
            roles = cursor.fetchall()
            cursor.execute("RELEASE SAVEPOINT _ev_roles")
        except Exception:
            roles = []
            try:
                cursor.execute("ROLLBACK TO SAVEPOINT _ev_roles")
            except Exception:
                pass

        ai_roles = []
        from app.engines.discovery.agent_pattern_loader import match_roles
        if roles:
            role_dicts = [{'role_name': r[0], 'scope': r[1]} for r in roles]
            role_platform, role_conf = match_roles(role_dicts)
            if role_platform:
                # Find which specific roles matched
                from app.engines.discovery.agent_pattern_loader import _role_names_set, _scope_patterns_lower
                for r in roles:
                    rn = r[0] or ''
                    scope = (r[1] or '').lower()
                    last_used = r[2].isoformat() if r[2] else None
                    if rn in _role_names_set:
                        ai_roles.append({'role_name': rn, 'scope': r[1], 'match_type': 'role_name', 'last_used_at': last_used})
                    else:
                        for pat in _scope_patterns_lower:
                            if pat in scope:
                                ai_roles.append({'role_name': rn, 'scope': r[1], 'match_type': 'scope_pattern', 'matched_pattern': pat, 'last_used_at': last_used})
                                break

                if ai_roles and signal_type != 'role_scope_match':
                    evidence_signals.append({
                        'signal_type': 'role_scope_match',
                        'confidence': role_conf,
                        'platform': role_platform,
                        'evidence_text': f"Has {len(ai_roles)} AI-related role assignment(s): {', '.join(r['role_name'] for r in ai_roles[:3])}",
                        'is_primary': False,
                    })

        # Signal 3: Check for AI-related permissions
        try:
            cursor.execute("SAVEPOINT _ev_perms")
            cursor.execute("""
                SELECT permissions FROM identity_permissions
                WHERE identity_db_id = %s ORDER BY id DESC LIMIT 1
            """, (db_id,))
            perm_row = cursor.fetchone()
            cursor.execute("RELEASE SAVEPOINT _ev_perms")
        except Exception:
            perm_row = None
            try:
                cursor.execute("ROLLBACK TO SAVEPOINT _ev_perms")
            except Exception:
                pass

        ai_permissions = []
        if perm_row and perm_row[0]:
            import json as _json
            perms = perm_row[0]
            if isinstance(perms, str):
                perms = _json.loads(perms)
            if isinstance(perms, list):
                from app.engines.discovery.agent_pattern_loader import match_permissions
                perm_strings = []
                for p in perms:
                    if isinstance(p, dict):
                        perm_strings.append(p.get('permission', ''))
                        perm_strings.append(p.get('resource', ''))
                    else:
                        perm_strings.append(str(p))
                matches = match_permissions(perm_strings)
                for pname, pconf, pplat in matches:
                    ai_permissions.append({'permission': pname, 'confidence': pconf, 'platform': pplat})

                if ai_permissions and signal_type != 'permission_match':
                    evidence_signals.append({
                        'signal_type': 'permission_match',
                        'confidence': ai_permissions[0]['confidence'],
                        'platform': ai_permissions[0]['platform'],
                        'evidence_text': f"Has {len(ai_permissions)} AI-related API permission(s): {', '.join(p['permission'] for p in ai_permissions[:3])}",
                        'is_primary': False,
                    })

        # Build AI connections (role assignments on AI resources)
        ai_connections = []
        for ar in ai_roles:
            last_used = ar.get('last_used_at')
            if last_used:
                source = f"P2 sign-in log \u00b7 {last_used[:10]}"
            else:
                source = "ARM role assignment \u00b7 Static analysis"
            ai_connections.append({
                'type': 'rbac_role',
                'role_name': ar['role_name'],
                'scope': ar['scope'],
                'match_type': ar['match_type'],
                'last_used_at': last_used,
                'source_of_evidence': source,
            })
        for ap in ai_permissions:
            ai_connections.append({
                'type': 'api_permission',
                'permission': ap['permission'],
                'platform': ap['platform'],
                'last_used_at': None,
                'source_of_evidence': "ARM role assignment \u00b7 Static analysis",
            })

        # Risk context
        risk_context = {
            'risk_score': risk_score,
            'risk_level': risk_level,
            'identity_type': identity_type,
            'identity_category': category,
            'has_owner': False,
            'credential_count': 0,
        }
        # Fetch owner/cred info
        try:
            cursor.execute("SAVEPOINT _ev_ctx")
            cursor.execute("""
                SELECT owner_count, credential_count FROM identities WHERE id = %s
            """, (db_id,))
            ctx_row = cursor.fetchone()
            cursor.execute("RELEASE SAVEPOINT _ev_ctx")
            if ctx_row:
                risk_context['has_owner'] = (ctx_row[0] or 0) > 0
                risk_context['credential_count'] = ctx_row[0] or 0
        except Exception:
            try:
                cursor.execute("ROLLBACK TO SAVEPOINT _ev_ctx")
            except Exception:
                pass

        cursor.close()

        return jsonify({
            'classified': True,
            'agent_identity_type': c_type,
            'classification': {
                'confidence': c_confidence,
                'reason': c_reason,
                'platform': c_platform,
                'pattern_version': c_version,
                'classified_at': c_at.isoformat() if c_at else None,
            },
            'evidence_signals': evidence_signals,
            'ai_connections': ai_connections,
            'risk_context': risk_context,
        })
    except Exception as e:
        try:
            db.conn.rollback()
        except Exception:
            pass
        logger.error("get_agent_evidence failed for %s: %s", identity_id, e, exc_info=True)
        return jsonify({'error': 'Internal server error'}), 500
    finally:
        db.close()


def _build_evidence_text(signal_type, platform, display_name, app_id):
    """Generate human-readable evidence explanation for classification signal."""
    platform_labels = {
        'copilot_studio': 'Microsoft Copilot Studio',
        'power_virtual_agents': 'Power Virtual Agents',
        'openai': 'OpenAI',
        'anthropic': 'Anthropic Claude',
        'azure_ai_studio': 'Azure AI Studio',
        'azure_ml': 'Azure Machine Learning',
        'azure_ai': 'Azure AI Services',
        'azure_cognitive': 'Azure Cognitive Services',
        'bot_framework': 'Microsoft Bot Framework',
    }
    label = platform_labels.get(platform, platform or 'Unknown Platform')

    if signal_type == 'app_id_match':
        return f"Application ID ({app_id}) is a registered {label} enterprise application"
    elif signal_type == 'role_scope_match':
        return f"Has RBAC role assignments on {label} resource scopes, confirming AI workload access"
    elif signal_type == 'display_name_match':
        return f"Display name \"{display_name}\" matches known {label} naming pattern"
    elif signal_type == 'permission_match':
        return f"Has API permissions granting access to {label} services"
    else:
        return f"Classified as {label} AI agent identity"


