def get_entra_groups():
    """GET /api/entra-groups — list Entra security groups with filters."""
    db = _db()
    try:
        db._ensure_entra_group_tables()
        organization_id = _org_id()
        cursor = db.conn.cursor()
        run_ids = _latest_run_ids(cursor, organization_id, _connection_id())
        cursor.close()
        if not run_ids:
            return jsonify({'groups': [], 'count': 0, 'total': 0})

        filters = {
            'search': request.args.get('search', ''),
            'is_privileged': request.args.get('is_privileged', '') == 'true',
            'limit': min(request.args.get('limit', 50, type=int), 200),
            'offset': request.args.get('offset', 0, type=int),
        }
        groups, total = db.get_entra_groups(run_ids, filters)
        return jsonify({
            'groups': groups,
            'count': len(groups),
            'total': total,
        })
    finally:
        db.close()


def get_entra_group_stats():
    """GET /api/entra-groups/stats — Entra group summary statistics."""
    db = _db()
    try:
        db._ensure_entra_group_tables()
        organization_id = _org_id()
        cursor = db.conn.cursor(cursor_factory=RealDictCursor)
        run_ids = _latest_run_ids(cursor, organization_id, _connection_id())
        if not run_ids:
            cursor.close()
            return jsonify({
                'total': 0, 'privileged': 0,
                'role_assignable': 0, 'avg_member_count': 0,
            })

        cursor.execute("""
            SELECT COUNT(*) as total,
                   COUNT(*) FILTER (WHERE is_privileged = true) as privileged,
                   COUNT(*) FILTER (WHERE is_role_assignable = true) as role_assignable,
                   COALESCE(ROUND(AVG(member_count)), 0) as avg_member_count
            FROM entra_groups
            WHERE discovery_run_id = ANY(%s)
        """, (run_ids,))
        row = dict(cursor.fetchone())
        cursor.close()
        return jsonify({
            'total': row['total'],
            'privileged': row['privileged'],
            'role_assignable': row['role_assignable'],
            'avg_member_count': int(row['avg_member_count']),
        })
    finally:
        db.close()


def get_identity_entra_groups(identity_id: str):
    """GET /api/identities/<id>/entra-groups — groups the identity belongs to.

    Query params:
      access_only  – 'true' (default) returns only groups with Azure RBAC roles.
                     'false' returns all groups (for debugging).
    """
    db = _db()
    try:
        db._ensure_entra_group_tables()
        organization_id = _org_id()
        access_only = request.args.get('access_only', 'true').lower() != 'false'
        cursor = db.conn.cursor()
        run_ids = _latest_run_ids(cursor, organization_id, _connection_id())
        if not run_ids:
            cursor.close()
            return jsonify({'groups': [], 'count': 0, 'total_groups': 0, 'with_azure_access': 0})

        # Look up the identity's object_id — the Graph object ID used as
        # member_object_id in entra_group_memberships. identity_id is app_id for
        # SPNs, which differs from object_id stored in memberships.
        cursor.execute("""
            SELECT object_id FROM identities
            WHERE identity_id = %s AND discovery_run_id = ANY(%s)
            LIMIT 1
        """, (identity_id, run_ids))
        row = cursor.fetchone()
        cursor.close()
        if not row or not row[0]:
            return jsonify({'groups': [], 'count': 0, 'total_groups': 0, 'with_azure_access': 0})

        azure_object_id = row[0]
        all_groups = db.get_identity_entra_groups(azure_object_id, run_ids)
        total_groups = len(all_groups)
        with_azure_access = sum(
            1 for g in all_groups
            if g.get('rbac_roles') and len(g['rbac_roles']) > 0
        )

        if access_only:
            groups = [g for g in all_groups
                      if (g.get('rbac_roles') and len(g['rbac_roles']) > 0)]
        else:
            groups = all_groups

        return jsonify({
            'groups': groups,
            'count': len(groups),
            'total_groups': total_groups,
            'with_azure_access': with_azure_access,
        })
    finally:
        db.close()


